-- ========== 20251231152151_7ec35066-262b-4063-80eb-f7120bb2be9a.sql ==========
-- Ensure profile gets current_organization_id even if membership is created before profile row exists

CREATE OR REPLACE FUNCTION public.sync_profile_current_org_from_members()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  IF NEW.current_organization_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  SELECT om.organization_id
    INTO v_org_id
  FROM public.organization_members om
  WHERE om.user_id = NEW.id
  ORDER BY om.created_at ASC NULLS LAST
  LIMIT 1;

  IF v_org_id IS NOT NULL THEN
    UPDATE public.profiles
    SET current_organization_id = v_org_id
    WHERE id = NEW.id AND current_organization_id IS NULL;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_profile_current_org_from_members ON public.profiles;
CREATE TRIGGER trg_sync_profile_current_org_from_members
AFTER INSERT ON public.profiles
FOR EACH ROW
EXECUTE FUNCTION public.sync_profile_current_org_from_members();
-- ========== 20251231152644_c09fcb7b-1fee-4ae5-9ccc-46f980afa592.sql ==========
-- Fix the trigger function to not use non-existent created_at column
CREATE OR REPLACE FUNCTION public.sync_profile_current_org_from_members()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  IF NEW.current_organization_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Get any organization membership for this user (without ordering by created_at)
  SELECT om.organization_id
    INTO v_org_id
  FROM public.organization_members om
  WHERE om.user_id = NEW.id
  LIMIT 1;

  IF v_org_id IS NOT NULL THEN
    UPDATE public.profiles
    SET current_organization_id = v_org_id
    WHERE id = NEW.id AND current_organization_id IS NULL;
  END IF;

  RETURN NEW;
END;
$$;
-- ========== 20251231153115_51b21ebc-d68a-43ea-bf6b-ec6fab5bbd47.sql ==========
-- Ensure profile gets current_organization_id regardless of insert order (profile first or membership first)

-- 1) Trigger on organization_members to sync into profiles
CREATE OR REPLACE FUNCTION public.sync_profile_current_org_from_member_insert()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- If profile exists and doesn't have a current org yet, set it
  UPDATE public.profiles
  SET current_organization_id = NEW.organization_id
  WHERE id = NEW.user_id
    AND current_organization_id IS NULL;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_profile_current_org_from_member_insert ON public.organization_members;
CREATE TRIGGER trg_sync_profile_current_org_from_member_insert
AFTER INSERT ON public.organization_members
FOR EACH ROW
EXECUTE FUNCTION public.sync_profile_current_org_from_member_insert();

-- 2) One-time backfill for any existing users missing current_organization_id but having membership
UPDATE public.profiles p
SET current_organization_id = om.organization_id
FROM public.organization_members om
WHERE om.user_id = p.id
  AND p.current_organization_id IS NULL;
