-- Add 'new_member' notification type if not exists and create trigger for admin notifications

-- First, let's add the new notification type by altering the check constraint if it exists
-- or just allow it since the type column appears to be text

-- Create function to notify admins when a new member joins
CREATE OR REPLACE FUNCTION public.notify_admins_new_member()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_admin_id uuid;
  v_new_user_name text;
  v_new_user_email text;
  v_org_name text;
  v_role_label text;
BEGIN
  -- Get new user info
  SELECT full_name, email INTO v_new_user_name, v_new_user_email
  FROM public.profiles
  WHERE id = NEW.user_id;

  -- Get organization name
  SELECT name INTO v_org_name
  FROM public.organizations
  WHERE id = NEW.organization_id;

  -- Map role to Spanish label
  v_role_label := CASE NEW.role::text
    WHEN 'admin' THEN 'Administrador'
    WHEN 'creator' THEN 'Creador'
    WHEN 'editor' THEN 'Editor'
    WHEN 'client' THEN 'Cliente'
    WHEN 'strategist' THEN 'Estratega'
    WHEN 'ambassador' THEN 'Embajador'
    ELSE NEW.role::text
  END;

  -- Insert notification for each admin/owner in the organization (except the new user themselves)
  FOR v_admin_id IN
    SELECT DISTINCT om.user_id
    FROM public.organization_members om
    LEFT JOIN public.organization_member_roles omr ON om.user_id = omr.user_id AND om.organization_id = omr.organization_id
    WHERE om.organization_id = NEW.organization_id
      AND om.user_id != NEW.user_id
      AND (omr.role = 'admin' OR om.is_owner = true)
  LOOP
    INSERT INTO public.user_notifications (
      user_id,
      organization_id,
      type,
      title,
      message,
      entity_type,
      entity_id,
      is_read
    ) VALUES (
      v_admin_id,
      NEW.organization_id,
      'assignment',
      'Nuevo miembro registrado',
      COALESCE(v_new_user_name, v_new_user_email) || ' se ha registrado como ' || v_role_label,
      'profile',
      NEW.user_id,
      false
    );
  END LOOP;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_notify_admins_new_member ON public.organization_members;
CREATE TRIGGER trg_notify_admins_new_member
AFTER INSERT ON public.organization_members
FOR EACH ROW
EXECUTE FUNCTION public.notify_admins_new_member();
-- ========== 20251231160211_8d2f8cf5-34af-4cbf-b276-412d23e09d84.sql ==========
CREATE OR REPLACE FUNCTION public.register_user_to_organization(
  p_organization_id UUID,
  p_user_id UUID,
  p_role TEXT DEFAULT 'creator'
)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
DECLARE
  v_role public.app_role;
BEGIN
  -- Validate role
  BEGIN
    v_role := p_role::public.app_role;
  EXCEPTION
    WHEN invalid_text_representation THEN
      RAISE EXCEPTION 'INVALID_ROLE: %', p_role;
  END;

  INSERT INTO public.organization_members (organization_id, user_id, role, is_owner)
  VALUES (p_organization_id, p_user_id, v_role, false)
  ON CONFLICT (organization_id, user_id) DO NOTHING;

  INSERT INTO public.organization_member_roles (organization_id, user_id, role)
  VALUES (p_organization_id, p_user_id, v_role)
  ON CONFLICT (organization_id, user_id, role) DO NOTHING;

  UPDATE public.profiles
  SET current_organization_id = p_organization_id,
      organization_status = 'pending'
  WHERE id = p_user_id;

  RETURN TRUE;
EXCEPTION
  WHEN OTHERS THEN
    -- Return a real error to the client so we don't silently create users without org
    RAISE EXCEPTION 'REGISTER_USER_TO_ORG_FAILED' USING DETAIL = SQLERRM;
END;
$$;

-- Keep grants (idempotent)
GRANT EXECUTE ON FUNCTION public.register_user_to_organization TO anon;
GRANT EXECUTE ON FUNCTION public.register_user_to_organization TO authenticated;
-- ========== 20251231160608_6e9fec1e-8079-40a1-a4ca-016c6f3d3184.sql ==========
-- Fix the register_user_to_organization function to use correct organization_status value
CREATE OR REPLACE FUNCTION public.register_user_to_organization(
  p_organization_id UUID,
  p_user_id UUID,
  p_role TEXT DEFAULT 'creator'
)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
DECLARE
  v_role public.app_role;
BEGIN
  -- Validate role
  BEGIN
    v_role := p_role::public.app_role;
  EXCEPTION
    WHEN invalid_text_representation THEN
      RAISE EXCEPTION 'INVALID_ROLE: %', p_role;
  END;

  -- Insert into organization_members
  INSERT INTO public.organization_members (organization_id, user_id, role, is_owner)
  VALUES (p_organization_id, p_user_id, v_role, false)
  ON CONFLICT (organization_id, user_id) DO NOTHING;

  -- Insert into organization_member_roles
  INSERT INTO public.organization_member_roles (organization_id, user_id, role)
  VALUES (p_organization_id, p_user_id, v_role)
  ON CONFLICT (organization_id, user_id, role) DO NOTHING;

  -- Update profile with correct status value (pending_assignment, not pending)
  UPDATE public.profiles
  SET current_organization_id = p_organization_id,
      organization_status = 'pending_assignment'
  WHERE id = p_user_id;

  RETURN TRUE;
EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'REGISTER_USER_TO_ORG_FAILED: %', SQLERRM;
END;
$$;

-- Keep grants
GRANT EXECUTE ON FUNCTION public.register_user_to_organization TO anon;
GRANT EXECUTE ON FUNCTION public.register_user_to_organization TO authenticated;
-- ========== 20251231162618_1c41fc8a-edd4-4247-a7e3-59699a615ace.sql ==========
-- Update register_user_to_organization to set organization_status = 'active' for immediate access
CREATE OR REPLACE FUNCTION public.register_user_to_organization(
  p_organization_id UUID,
  p_user_id UUID,
  p_role TEXT DEFAULT 'creator'
)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
DECLARE
  v_role public.app_role;
BEGIN
  -- Validate role
  BEGIN
    v_role := p_role::public.app_role;
  EXCEPTION
    WHEN invalid_text_representation THEN
      RAISE EXCEPTION 'INVALID_ROLE: %', p_role;
  END;

  -- Insert into organization_members
  INSERT INTO public.organization_members (organization_id, user_id, role, is_owner)
  VALUES (p_organization_id, p_user_id, v_role, false)
  ON CONFLICT (organization_id, user_id) DO NOTHING;

  -- Insert into organization_member_roles
  INSERT INTO public.organization_member_roles (organization_id, user_id, role)
  VALUES (p_organization_id, p_user_id, v_role)
  ON CONFLICT (organization_id, user_id, role) DO NOTHING;

  -- Update profile with ACTIVE status for immediate access
  UPDATE public.profiles
  SET current_organization_id = p_organization_id,
      organization_status = 'active'
  WHERE id = p_user_id;

  RETURN TRUE;
EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'REGISTER_USER_TO_ORG_FAILED: %', SQLERRM;
END;
$$;
