-- ========== 20260130123447_8744e955-ea4a-4ec8-8e5e-4ba0a78de294.sql ==========
-- Ensure role-check function exists (avoids RLS recursion)
create or replace function public.has_role(_user_id uuid, _role public.app_role)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.user_roles
    where user_id = _user_id
      and role = _role
  )
$$;

-- Grant minimal execute
grant execute on function public.has_role(uuid, public.app_role) to authenticated;

-- PROFILES: allow platform admins to read/update profiles (needed for root org switcher + platform users)
-- Use DO blocks to avoid "policy already exists" errors.
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies 
    WHERE schemaname = 'public'
      AND tablename = 'profiles'
      AND policyname = 'Admins can read all profiles'
  ) THEN
    CREATE POLICY "Admins can read all profiles"
    ON public.profiles
    FOR SELECT
    TO authenticated
    USING (public.has_role(auth.uid(), 'admin'));
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies 
    WHERE schemaname = 'public'
      AND tablename = 'profiles'
      AND policyname = 'Admins can update any profile'
  ) THEN
    CREATE POLICY "Admins can update any profile"
    ON public.profiles
    FOR UPDATE
    TO authenticated
    USING (public.has_role(auth.uid(), 'admin'))
    WITH CHECK (public.has_role(auth.uid(), 'admin'));
  END IF;
END $$;

-- ========== 20260130232052_74ca8278-bbe9-419e-bb07-bb9606db2a8a.sql ==========

-- Corregir la política RLS de profiles que tiene los argumentos invertidos
-- La función is_org_member tiene firma: is_org_member(_user_id uuid, _org_id uuid)
-- La política actual está pasando: is_org_member(org_id, profile_id) - INCORRECTO

-- Eliminar la política incorrecta
DROP POLICY IF EXISTS "Org members can view org profiles" ON public.profiles;

-- Crear la política corregida con los argumentos en el orden correcto
-- Necesitamos verificar que el perfil que queremos ver pertenece a nuestra organización
-- Un perfil pertenece a una org si: profiles.current_organization_id = nuestra org actual
CREATE POLICY "Org members can view org profiles"
ON public.profiles
FOR SELECT
USING (
  (get_current_organization_id(auth.uid()) IS NOT NULL)
  AND (
    -- El perfil pertenece a la misma organización que el usuario actual
    current_organization_id = get_current_organization_id(auth.uid())
    -- O es el propio usuario
    OR id = auth.uid()
  )
);

-- ========== 20260130232448_94ca048b-18ef-4f2c-8ec7-5087e6e6e6b4.sql ==========

-- Mejorar la función is_platform_root para verificar también por email en auth.jwt()
-- Esto permite que el root admin funcione incluso si hay desajuste de IDs

CREATE OR REPLACE FUNCTION public.is_platform_root(_user_id uuid)
RETURNS boolean
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  user_email text;
  root_emails text[] := ARRAY['jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com'];
BEGIN
  -- Primero intentar por ID en profiles
  SELECT email INTO user_email
  FROM public.profiles
  WHERE id = _user_id;
  
  IF user_email IS NOT NULL AND user_email = ANY(root_emails) THEN
    RETURN TRUE;
  END IF;
  
  -- Fallback: verificar email en JWT claims directamente
  BEGIN
    user_email := auth.jwt()->>'email';
    IF user_email IS NOT NULL AND user_email = ANY(root_emails) THEN
      RETURN TRUE;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    -- Si falla, ignorar
    NULL;
  END;
  
  RETURN FALSE;
END;
$$;

-- También agregar una política más permisiva para los root admins basada en email del JWT
CREATE OR REPLACE FUNCTION public.is_root_by_jwt_email()
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT COALESCE(
    (auth.jwt()->>'email') = ANY(ARRAY['jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com']),
    FALSE
  )
$$;

-- Agregar política adicional para que root admins puedan ver todos los perfiles
DROP POLICY IF EXISTS "Root admins by email can read all profiles" ON public.profiles;
CREATE POLICY "Root admins by email can read all profiles"
ON public.profiles
FOR SELECT
USING (is_root_by_jwt_email());

-- Agregar política para que root admins puedan ver todo el contenido
DROP POLICY IF EXISTS "Root admins by email can view all content" ON public.content;
CREATE POLICY "Root admins by email can view all content"
ON public.content
FOR SELECT
USING (is_root_by_jwt_email());

-- ========== 20260131000000_create_waitlist_table.sql ==========
-- Create waitlist table for feature waitlists (e.g., Live Shopping)
CREATE TABLE IF NOT EXISTS waitlist (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT NOT NULL,
  feature TEXT NOT NULL DEFAULT 'live_shopping',
  source TEXT DEFAULT 'landing',
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  notified_at TIMESTAMP WITH TIME ZONE,
  
  -- Prevent duplicate emails per feature
  UNIQUE(email, feature)
);

-- Create index for faster lookups
CREATE INDEX IF NOT EXISTS idx_waitlist_feature ON waitlist(feature);
CREATE INDEX IF NOT EXISTS idx_waitlist_email ON waitlist(email);
CREATE INDEX IF NOT EXISTS idx_waitlist_created_at ON waitlist(created_at DESC);

-- Enable RLS
ALTER TABLE waitlist ENABLE ROW LEVEL SECURITY;

-- Policies (DROP IF EXISTS for idempotency on re-runs)
DROP POLICY IF EXISTS "Anyone can join waitlist" ON waitlist;
DROP POLICY IF EXISTS "Admins can read waitlist" ON waitlist;
DROP POLICY IF EXISTS "Admins can update waitlist" ON waitlist;

-- Policy: Anyone can insert (public waitlist signup)
CREATE POLICY "Anyone can join waitlist"
  ON waitlist
  FOR INSERT
  TO anon, authenticated
  WITH CHECK (true);

-- Policy: Only platform admins can read waitlist
CREATE POLICY "Admins can read waitlist"
  ON waitlist
  FOR SELECT
  TO authenticated
  USING (public.is_platform_admin(auth.uid()));

-- Policy: Only platform admins can update waitlist (e.g., mark as notified)
CREATE POLICY "Admins can update waitlist"
  ON waitlist
  FOR UPDATE
  TO authenticated
  USING (public.is_platform_admin(auth.uid()));

-- Comment on table
COMMENT ON TABLE waitlist IS 'Stores email signups for upcoming features like Live Shopping';
COMMENT ON COLUMN waitlist.feature IS 'The feature being waited for (e.g., live_shopping)';
COMMENT ON COLUMN waitlist.source IS 'Where the signup came from (landing, features, pricing, etc.)';
COMMENT ON COLUMN waitlist.notified_at IS 'When the user was notified that the feature is available';

