-- ========== 20260131173717_5735d128-4e0e-43c0-9889-b2f5f06db5ba.sql ==========
-- Update register_user_to_organization to set active_role for immediate access
CREATE OR REPLACE FUNCTION public.register_user_to_organization(
  p_organization_id uuid, 
  p_user_id uuid, 
  p_role text DEFAULT 'creator'::text
)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
SET row_security TO 'off'
AS $function$
DECLARE
  v_role public.app_role;
BEGIN
  -- Validate role
  BEGIN
    v_role := p_role::public.app_role;
  EXCEPTION
    WHEN invalid_text_representation THEN
      RAISE EXCEPTION 'INVALID_ROLE: %', p_role;
  END;

  -- Insert into organization_members
  INSERT INTO public.organization_members (organization_id, user_id, role, is_owner)
  VALUES (p_organization_id, p_user_id, v_role, false)
  ON CONFLICT (organization_id, user_id) DO NOTHING;

  -- Insert into organization_member_roles
  INSERT INTO public.organization_member_roles (organization_id, user_id, role)
  VALUES (p_organization_id, p_user_id, v_role)
  ON CONFLICT (organization_id, user_id, role) DO NOTHING;

  -- Update profile with ACTIVE status AND active_role for immediate access
  UPDATE public.profiles
  SET current_organization_id = p_organization_id,
      organization_status = 'active',
      active_role = p_role,
      is_active = true
  WHERE id = p_user_id;

  RETURN TRUE;
EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'REGISTER_USER_TO_ORG_FAILED: %', SQLERRM;
END;
$function$;
-- ========== 20260131180000_fix_kanban_config_rls.sql ==========
-- =====================================================
-- Fix RLS for kanban_config and state_permissions
-- Allow org owners, platform admins, and org admins/strategists/team_leaders to manage
-- =====================================================

-- Helper: user can configure kanban (org owner, platform admin, or org member with config role)
CREATE OR REPLACE FUNCTION public.is_org_configurer(_user_id uuid, _org_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT (
    -- Platform admin
    public.has_role(_user_id, 'admin'::app_role)
    OR
    -- Org owner
    public.is_org_owner(_user_id, _org_id)
    OR
    -- Org member with config role (admin, strategist, team_leader)
    EXISTS (
      SELECT 1 FROM public.organization_members om
      WHERE om.user_id = _user_id AND om.organization_id = _org_id
      AND om.role::text IN ('admin', 'strategist', 'team_leader')
    )
    OR
    -- organization_member_roles (multiple roles per user)
    EXISTS (
      SELECT 1 FROM public.organization_member_roles omr
      WHERE omr.user_id = _user_id AND omr.organization_id = _org_id
      AND omr.role::text IN ('admin', 'strategist', 'team_leader')
    )
  );
$$;

GRANT EXECUTE ON FUNCTION public.is_org_configurer(uuid, uuid) TO authenticated;

