-- ========== 20260202000000_campaign_context_view.sql ==========
-- Vista y función para contexto de campaña unificado
-- Agrega producto + research + contenidos para uso en módulos IA

-- Vista que agrega contexto de campaña
CREATE OR REPLACE VIEW campaign_context AS
SELECT
  c.id AS content_id,
  c.title,
  c.status,
  c.sales_angle,
  c.sphere_phase,
  c.deadline,
  c.created_at,
  c.creator_id,
  c.editor_id,

  -- Producto
  p.id AS product_id,
  p.name AS product_name,
  p.description AS product_description,
  p.market_research,
  p.avatar_profiles,
  p.sales_angles_data,
  p.content_strategy,
  p.brief_status,

  -- Cliente
  cl.id AS client_id,
  cl.name AS client_name,

  -- Campaña de marketing (si existe)
  mc.id AS campaign_id,
  mc.name AS campaign_name,
  mc.start_date AS campaign_start,
  mc.end_date AS campaign_end,

  -- Organización
  c.organization_id

FROM content c
LEFT JOIN products p ON c.product_id = p.id
LEFT JOIN clients cl ON c.client_id = cl.id
LEFT JOIN marketing_campaigns mc ON c.marketing_campaign_id = mc.id;

-- RLS: la vista hereda permisos de las tablas subyacentes
-- Grant para roles autenticados
GRANT SELECT ON campaign_context TO authenticated;
GRANT SELECT ON campaign_context TO service_role;

COMMENT ON VIEW campaign_context IS 'Contexto unificado de campaña: content + product + client + marketing_campaign para uso en módulos IA';

-- Función RPC para obtener contexto completo por content_id
CREATE OR REPLACE FUNCTION get_campaign_context(p_content_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public
AS $$
DECLARE
  result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'content', jsonb_build_object(
      'id', c.id,
      'title', c.title,
      'status', c.status,
      'sales_angle', c.sales_angle,
      'sphere_phase', c.sphere_phase,
      'deadline', c.deadline
    ),
    'product', CASE
      WHEN p.id IS NOT NULL THEN jsonb_build_object(
        'id', p.id,
        'name', p.name,
        'description', p.description,
        'primary_avatar', (p.avatar_profiles->'profiles'->0),
        'sales_angles', COALESCE(
          (p.sales_angles_data->'angles'),
          (p.sales_angles_data->'angulos'),
          to_jsonb(COALESCE(p.sales_angles, ARRAY[]::text[]))
        ),
        'pains', COALESCE(
          ((p.market_research)::jsonb->'pains'),
          ((p.market_research)::jsonb->'dolores'),
          '[]'::jsonb
        ),
        'desires', COALESCE(
          ((p.market_research)::jsonb->'desires'),
          ((p.market_research)::jsonb->'deseos'),
          '[]'::jsonb
        )
      )
      ELSE NULL
    END,
    'client', CASE
      WHEN cl.id IS NOT NULL THEN jsonb_build_object(
        'id', cl.id,
        'name', cl.name
      )
      ELSE NULL
    END,
    'campaign', CASE
      WHEN mc.id IS NOT NULL THEN jsonb_build_object(
        'id', mc.id,
        'name', mc.name,
        'dates', jsonb_build_object(
          'start', mc.start_date,
          'end', mc.end_date
        )
      )
      ELSE NULL
    END
  ) INTO result
  FROM content c
  LEFT JOIN products p ON c.product_id = p.id
  LEFT JOIN clients cl ON c.client_id = cl.id
  LEFT JOIN marketing_campaigns mc ON c.marketing_campaign_id = mc.id
  WHERE c.id = p_content_id;

  RETURN result;
END;
$$;

COMMENT ON FUNCTION get_campaign_context(UUID) IS 'Devuelve contexto completo de campaña (content + product + client + campaign) para content_id dado. Usa SECURITY INVOKER para respetar RLS.';

-- ========== 20260202100000_research_progress_column.sql ==========
-- Columna para guardar progreso parcial del research por pasos
ALTER TABLE public.products
ADD COLUMN IF NOT EXISTS research_progress JSONB DEFAULT NULL;

COMMENT ON COLUMN public.products.research_progress IS 'Progreso parcial del research: { completed_steps: string[], partial_results: object, updated_at: string }';

-- ========== 20260202120000_ai_usage_logs_extended.sql ==========
-- Extender ai_usage_logs para monitoreo avanzado y vista agregada diaria

-- Columnas adicionales (la tabla ya existe con: id, organization_id, user_id, provider, model, module, action, tokens_input, tokens_output, estimated_cost, success, error_message, created_at)
ALTER TABLE public.ai_usage_logs
  ADD COLUMN IF NOT EXISTS edge_function TEXT,
  ADD COLUMN IF NOT EXISTS request_payload JSONB,
  ADD COLUMN IF NOT EXISTS variables_used TEXT[],
  ADD COLUMN IF NOT EXISTS response_status TEXT,
  ADD COLUMN IF NOT EXISTS response_time_ms INTEGER,
  ADD COLUMN IF NOT EXISTS user_rating INTEGER CHECK (user_rating IS NULL OR (user_rating >= 1 AND user_rating <= 5)),
  ADD COLUMN IF NOT EXISTS was_regenerated BOOLEAN DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS was_edited BOOLEAN DEFAULT FALSE;

-- Backfill response_status desde success/error_message
UPDATE public.ai_usage_logs
SET response_status = CASE
  WHEN success THEN 'success'
  WHEN error_message IS NOT NULL AND error_message != '' THEN 'error'
  ELSE 'unknown'
END
WHERE response_status IS NULL;

COMMENT ON COLUMN public.ai_usage_logs.edge_function IS 'Nombre de la Edge Function invocada';
COMMENT ON COLUMN public.ai_usage_logs.request_payload IS 'Payload de la solicitud (sanitizado)';
COMMENT ON COLUMN public.ai_usage_logs.response_status IS 'success, error, timeout';
COMMENT ON COLUMN public.ai_usage_logs.response_time_ms IS 'Tiempo de respuesta en ms';
COMMENT ON COLUMN public.ai_usage_logs.user_rating IS 'Rating 1-5 del usuario';
COMMENT ON COLUMN public.ai_usage_logs.was_regenerated IS 'Si el usuario regeneró la respuesta';
COMMENT ON COLUMN public.ai_usage_logs.was_edited IS 'Si el usuario editó la respuesta';

-- Índice por módulo para dashboards
CREATE INDEX IF NOT EXISTS idx_ai_usage_logs_module_created
  ON public.ai_usage_logs(module, created_at DESC);

-- Vista agregada por día (usa columnas existentes + nuevas)
CREATE OR REPLACE VIEW public.ai_usage_daily AS
SELECT
  organization_id,
  module AS module_key,
  DATE(created_at) AS date,
  COUNT(*) AS total_calls,
  COUNT(*) FILTER (WHERE COALESCE(response_status, CASE WHEN success THEN 'success' ELSE 'error' END) = 'success') AS successful_calls,
  ROUND(AVG(response_time_ms)::numeric, 0)::INTEGER AS avg_response_time,
  COALESCE(SUM(tokens_input), 0)::BIGINT AS total_input_tokens,
  COALESCE(SUM(tokens_output), 0)::BIGINT AS total_output_tokens,
  COALESCE(SUM(estimated_cost), 0)::NUMERIC(12, 6) AS total_cost,
  ROUND(AVG(user_rating) FILTER (WHERE user_rating IS NOT NULL)::numeric, 2) AS avg_rating
FROM public.ai_usage_logs
GROUP BY organization_id, module, DATE(created_at);

COMMENT ON VIEW public.ai_usage_daily IS 'Uso de IA agregado por organización, módulo y día para dashboards';

GRANT SELECT ON public.ai_usage_daily TO authenticated;
GRANT SELECT ON public.ai_usage_daily TO service_role;

-- ========== 20260202130000_ai_usage_feedback_columns.sql ==========
-- Columnas para feedback loop en ai_usage_logs

ALTER TABLE public.ai_usage_logs
  ADD COLUMN IF NOT EXISTS user_feedback TEXT,
  ADD COLUMN IF NOT EXISTS feedback_tags TEXT[],
  ADD COLUMN IF NOT EXISTS regeneration_count INTEGER DEFAULT 0,
  ADD COLUMN IF NOT EXISTS edit_distance INTEGER,
  ADD COLUMN IF NOT EXISTS edited_content TEXT,
  ADD COLUMN IF NOT EXISTS was_used BOOLEAN DEFAULT FALSE;

COMMENT ON COLUMN public.ai_usage_logs.user_feedback IS 'Comentario libre del usuario sobre el resultado';
COMMENT ON COLUMN public.ai_usage_logs.feedback_tags IS 'Tags de feedback: too_long, off_topic, great_hooks, etc.';
COMMENT ON COLUMN public.ai_usage_logs.regeneration_count IS 'Veces que el usuario regeneró la respuesta';
COMMENT ON COLUMN public.ai_usage_logs.edit_distance IS 'Distancia de edición (Levenshtein o %) entre original y editado';
COMMENT ON COLUMN public.ai_usage_logs.edited_content IS 'Contenido final después de edición del usuario';
COMMENT ON COLUMN public.ai_usage_logs.was_used IS 'Si el output se usó realmente (publicó, asignó, etc.)';

-- ========== 20260202150000_perplexity_org_config.sql ==========
-- Configuración de Perplexity por organización
-- API Key: organization_ai_providers (provider_key='perplexity')
-- Modelo y features: organization_ai_defaults + organization_ai_modules

-- 1. Añadir columnas a organization_ai_defaults para Perplexity
ALTER TABLE public.organization_ai_defaults
  ADD COLUMN IF NOT EXISTS perplexity_model TEXT DEFAULT 'llama-3.1-sonar-large-128k-online',
  ADD COLUMN IF NOT EXISTS perplexity_features JSONB DEFAULT '{"scripts": true, "research": true, "board": false, "talent": false, "live": false}'::jsonb;

COMMENT ON COLUMN public.organization_ai_defaults.perplexity_model IS 'Modelo de Perplexity preferido';
COMMENT ON COLUMN public.organization_ai_defaults.perplexity_features IS 'Dónde habilitar Perplexity: scripts, research, board, talent, live';

-- 2. Añadir columna config a organization_ai_modules (si no existe)
ALTER TABLE public.organization_ai_modules
  ADD COLUMN IF NOT EXISTS config JSONB DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.organization_ai_modules.config IS 'Configuración adicional del módulo (ej. features para research.perplexity)';

-- 3. Insertar módulo research.perplexity para cada organización
INSERT INTO public.organization_ai_modules (
  organization_id,
  module_key,
  module_name,
  description,
  is_active,
  provider,
  model,
  config
)
SELECT 
  o.id,
  'research.perplexity',
  'Perplexity - Investigación en Tiempo Real',
  'Búsquedas de tendencias, hooks y análisis competitivo con Perplexity',
  false,
  'perplexity',
  'llama-3.1-sonar-large-128k-online',
  '{"features": {"scripts": true, "research": true, "board": false, "talent": false, "live": false}}'::jsonb
FROM public.organizations o
WHERE NOT EXISTS (
  SELECT 1 FROM public.organization_ai_modules m
  WHERE m.organization_id = o.id AND m.module_key = 'research.perplexity'
);

-- 4. Crear entradas en organization_ai_providers para Perplexity (para que puedan guardar API key)
INSERT INTO public.organization_ai_providers (
  organization_id,
  provider_key,
  is_enabled,
  available_models
)
SELECT 
  o.id,
  'perplexity',
  false,
  ARRAY['llama-3.1-sonar-small-128k-online', 'llama-3.1-sonar-large-128k-online', 'llama-3.1-sonar-huge-128k-online']
FROM public.organizations o
WHERE NOT EXISTS (
  SELECT 1 FROM public.organization_ai_providers p
  WHERE p.organization_id = o.id AND p.provider_key = 'perplexity'
);

-- ========== 20260202160000_ai_tokens_tables.sql ==========
-- Sistema de tokenización de IA para control de uso por plan

-- 1. Tabla organization_ai_tokens (cuota por organización)
CREATE TABLE public.organization_ai_tokens (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,

  -- Tokens del plan
  monthly_tokens_included INTEGER NOT NULL DEFAULT 0,
  tokens_remaining INTEGER NOT NULL DEFAULT 0,
  tokens_used_this_period INTEGER NOT NULL DEFAULT 0,

  -- Tokens extra comprados
  purchased_tokens INTEGER NOT NULL DEFAULT 0,

  -- Reset mensual
  period_start_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  period_end_date TIMESTAMPTZ NOT NULL DEFAULT (NOW() + INTERVAL '1 month'),

  -- APIs propias conectadas (bypass tokens)
  custom_api_enabled BOOLEAN DEFAULT false,

  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

  UNIQUE(organization_id)
);

COMMENT ON TABLE public.organization_ai_tokens IS 'Control de tokens de IA por organización y plan';
COMMENT ON COLUMN public.organization_ai_tokens.monthly_tokens_included IS 'Tokens incluidos en el plan cada mes';
COMMENT ON COLUMN public.organization_ai_tokens.tokens_remaining IS 'Tokens disponibles en el periodo actual';
COMMENT ON COLUMN public.organization_ai_tokens.custom_api_enabled IS 'Si true, usa API propia sin consumir tokens de cuota';

-- 2. Tabla ai_token_transactions (historial de uso y créditos)
CREATE TABLE public.ai_token_transactions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,

  type TEXT NOT NULL, -- 'usage', 'purchase', 'plan_credit', 'refund'
  tokens_amount INTEGER NOT NULL, -- negativo para uso, positivo para créditos

  -- Contexto del uso
  module_key TEXT,
  action TEXT,

  -- Metadata
  ai_provider TEXT,
  ai_model TEXT,
  input_tokens INTEGER,
  output_tokens INTEGER,

  description TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE public.ai_token_transactions IS 'Historial de transacciones de tokens (uso, compras, créditos)';
COMMENT ON COLUMN public.ai_token_transactions.type IS 'usage=consumo, purchase=compra, plan_credit=crédito por plan, refund=reembolso';

-- Índices
CREATE INDEX idx_organization_ai_tokens_org ON public.organization_ai_tokens(organization_id);
CREATE INDEX idx_ai_token_transactions_org ON public.ai_token_transactions(organization_id);
CREATE INDEX idx_ai_token_transactions_created ON public.ai_token_transactions(created_at DESC);
CREATE INDEX idx_ai_token_transactions_type ON public.ai_token_transactions(type);

-- Trigger updated_at para organization_ai_tokens
CREATE TRIGGER update_organization_ai_tokens_updated_at
  BEFORE UPDATE ON public.organization_ai_tokens
  FOR EACH ROW
  EXECUTE FUNCTION public.handle_updated_at();

-- RLS
ALTER TABLE public.organization_ai_tokens ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.ai_token_transactions ENABLE ROW LEVEL SECURITY;

-- Políticas: miembros de org pueden leer, configurers/admins pueden modificar
CREATE POLICY "Org members can read ai tokens"
  ON public.organization_ai_tokens FOR SELECT
  USING (public.is_org_member(auth.uid(), organization_id));

CREATE POLICY "Org configurers can manage ai tokens"
  ON public.organization_ai_tokens FOR ALL
  USING (public.is_org_configurer(auth.uid(), organization_id))
  WITH CHECK (public.is_org_configurer(auth.uid(), organization_id));

CREATE POLICY "Org members can read token transactions"
  ON public.ai_token_transactions FOR SELECT
  USING (public.is_org_member(auth.uid(), organization_id));

-- Las transacciones las inserta el backend (service role); no exponer INSERT a usuarios
CREATE POLICY "Org configurers can insert token transactions"
  ON public.ai_token_transactions FOR INSERT
  WITH CHECK (public.is_org_configurer(auth.uid(), organization_id));

-- ========== 20260202161000_deduct_ai_tokens_rpc.sql ==========
-- RPC atómica para deducir tokens de IA y registrar transacción

CREATE OR REPLACE FUNCTION public.deduct_ai_tokens(
  p_org_id UUID,
  p_cost INTEGER,
  p_module_key TEXT DEFAULT NULL,
  p_action TEXT DEFAULT NULL,
  p_ai_provider TEXT DEFAULT NULL,
  p_ai_model TEXT DEFAULT NULL,
  p_input_tokens INTEGER DEFAULT NULL,
  p_output_tokens INTEGER DEFAULT NULL,
  p_description TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_row RECORD;
  v_deduct_from_remaining INTEGER;
  v_deduct_from_purchased INTEGER;
  v_new_remaining INTEGER;
  v_new_purchased INTEGER;
BEGIN
  -- 1. Bloquear y obtener fila
  SELECT tokens_remaining, purchased_tokens, tokens_used_this_period
    INTO v_row
    FROM public.organization_ai_tokens
   WHERE organization_id = p_org_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'tokens_remaining', 0, 'error', 'no_token_record');
  END IF;

  IF (v_row.tokens_remaining + v_row.purchased_tokens) < p_cost THEN
    RETURN jsonb_build_object(
      'ok', false,
      'tokens_remaining',
      v_row.tokens_remaining + v_row.purchased_tokens
    );
  END IF;

  -- 2. Deducir primero del plan (tokens_remaining), luego de purchased
  v_deduct_from_remaining := LEAST(v_row.tokens_remaining, p_cost);
  v_deduct_from_purchased := p_cost - v_deduct_from_remaining;
  v_new_remaining := v_row.tokens_remaining - v_deduct_from_remaining;
  v_new_purchased := GREATEST(0, v_row.purchased_tokens - v_deduct_from_purchased);

  -- 3. Actualizar tokens
  UPDATE public.organization_ai_tokens
     SET tokens_remaining = v_new_remaining,
         purchased_tokens = v_new_purchased,
         tokens_used_this_period = tokens_used_this_period + p_cost,
         updated_at = NOW()
   WHERE organization_id = p_org_id;

  -- 4. Registrar transacción
  INSERT INTO public.ai_token_transactions (
    organization_id,
    type,
    tokens_amount,
    module_key,
    action,
    ai_provider,
    ai_model,
    input_tokens,
    output_tokens,
    description
  ) VALUES (
    p_org_id,
    'usage',
    -p_cost,
    p_module_key,
    p_action,
    p_ai_provider,
    p_ai_model,
    p_input_tokens,
    p_output_tokens,
    p_description
  );

  RETURN jsonb_build_object(
    'ok', true,
    'tokens_remaining', v_new_remaining + v_new_purchased
  );
END;
$$;

COMMENT ON FUNCTION public.deduct_ai_tokens IS 'Deducción atómica de tokens de IA para una organización';

-- Permitir ejecución por service role (Edge Functions) y authenticated si se usa desde RPC
GRANT EXECUTE ON FUNCTION public.deduct_ai_tokens(UUID, INTEGER, TEXT, TEXT, TEXT, TEXT, INTEGER, INTEGER, TEXT) TO service_role;

-- ========== 20260202170000_fix_ai_tokens_rls_grants.sql ==========
-- Fix 403 Forbidden: grants y políticas para organization_ai_tokens y ai_token_transactions
-- Error: permission denied for table organization_ai_tokens (42501)

-- 1. Grants explícitos para el rol authenticated
GRANT SELECT, INSERT, UPDATE, DELETE ON public.organization_ai_tokens TO authenticated;
GRANT SELECT, INSERT ON public.ai_token_transactions TO authenticated;

-- 2. Política adicional: platform admins pueden gestionar tokens de cualquier org
-- (por si is_org_configurer no aplica por contexto de org)
CREATE POLICY "Platform admins can manage all ai tokens"
  ON public.organization_ai_tokens FOR ALL
  USING (public.is_platform_admin(auth.uid()))
  WITH CHECK (public.is_platform_admin(auth.uid()));

CREATE POLICY "Platform admins can manage token transactions"
  ON public.ai_token_transactions FOR ALL
  USING (public.is_platform_admin(auth.uid()))
  WITH CHECK (public.is_platform_admin(auth.uid()));

-- ========== 20260202180000_fix_client_strategists_rls.sql ==========
-- Fix 403: client_strategists - grants y políticas para org_member_roles y platform admins

-- 1. Grants explícitos
GRANT SELECT, INSERT, UPDATE, DELETE ON public.client_strategists TO authenticated;

-- 2. Política: org members vía organization_member_roles pueden ver
DROP POLICY IF EXISTS "Org members can view client strategists" ON public.client_strategists;
CREATE POLICY "Org members can view client strategists"
ON public.client_strategists
FOR SELECT
USING (
  EXISTS (
    SELECT 1 FROM public.organization_members om
    WHERE om.organization_id = client_strategists.organization_id
    AND om.user_id = auth.uid()
  )
  OR EXISTS (
    SELECT 1 FROM public.organization_member_roles omr
    WHERE omr.organization_id = client_strategists.organization_id
    AND omr.user_id = auth.uid()
  )
);

-- 3. Política: platform admins pueden ver
CREATE POLICY "Platform admins can view client strategists"
ON public.client_strategists
FOR SELECT
USING (public.is_platform_admin(auth.uid()));

