-- ========== 20260205120000_fix_client_brief_content_insert.sql ==========
-- Fix: Clientes no pueden guardar brief ni crear contenido desde el wizard
--
-- Problemas resueltos:
-- 1. Falta GRANT INSERT en content para rol authenticated
-- 2. Falta política RLS INSERT en content para client_users
-- 3. Falta GRANT INSERT en content para el rol authenticated (similar al fix de products/clients en 20260202210000)

-- 1. Asegurar que el rol authenticated tiene permisos CRUD en content
GRANT SELECT, INSERT, UPDATE, DELETE ON public.content TO authenticated;

-- 2. Política RLS: client users pueden INSERT contenido para sus clientes
-- (Necesario para que el wizard del brief cree los creativos por fase Esfera)
DROP POLICY IF EXISTS "Client users can insert content for their clients" ON public.content;
CREATE POLICY "Client users can insert content for their clients"
ON public.content
FOR INSERT
WITH CHECK (
  EXISTS (
    SELECT 1 FROM public.client_users
    WHERE client_users.client_id = content.client_id
    AND client_users.user_id = auth.uid()
  )
);

-- 3. Índice para acelerar la verificación RLS en content (evitar timeouts)
CREATE INDEX IF NOT EXISTS idx_content_client_id ON public.content(client_id);

-- ========== 20260205160000_fix_permissive_rls_policies.sql ==========
-- =====================================================
-- FIX: Tighten permissive RLS policies
-- products, notifications, goals
-- =====================================================

-- PRODUCTS: Restrict to org members via client ownership
DROP POLICY IF EXISTS "Authenticated can view products" ON products;
CREATE POLICY "Users can view products in their org"
  ON products FOR SELECT
  TO authenticated
  USING (
    client_id IN (
      SELECT c.id FROM clients c
      JOIN organization_members om ON om.organization_id = c.organization_id
      WHERE om.user_id = auth.uid()
    )
  );

-- NOTIFICATIONS: Restrict to own notifications only
DROP POLICY IF EXISTS "Users can view own notifications" ON notifications;
CREATE POLICY "Users can view own notifications"
  ON notifications FOR SELECT
  TO authenticated
  USING (user_id = auth.uid());

DROP POLICY IF EXISTS "Service can insert notifications" ON notifications;
CREATE POLICY "Service can insert notifications"
  ON notifications FOR INSERT
  TO authenticated
  WITH CHECK (true);

DROP POLICY IF EXISTS "Users can update own notifications" ON notifications;
CREATE POLICY "Users can update own notifications"
  ON notifications FOR UPDATE
  TO authenticated
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

-- GOALS: Restrict to org members
DROP POLICY IF EXISTS "Authenticated can view goals" ON goals;
CREATE POLICY "Org members can view goals"
  ON goals FOR SELECT
  TO authenticated
  USING (
    organization_id IN (
      SELECT organization_id FROM organization_members
      WHERE user_id = auth.uid()
    )
  );

-- ========== 20260205180000_fix_handle_new_user_trigger.sql ==========
-- =====================================================
-- FIX: Handle new user trigger improvements
-- Addresses "Database error saving new user" issue
-- =====================================================

-- First, let's update the handle_new_user function to be more robust
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
DECLARE
  user_full_name TEXT;
  user_email TEXT;
BEGIN
  -- Get email with fallback
  user_email := COALESCE(NEW.email, 'user_' || NEW.id::text || '@temp.kreoon.com');

  -- Get full_name with multiple fallbacks
  user_full_name := COALESCE(
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'name',
    split_part(user_email, '@', 1)
  );

  -- Ensure full_name is not empty
  IF user_full_name IS NULL OR user_full_name = '' THEN
    user_full_name := 'Usuario ' || substr(NEW.id::text, 1, 8);
  END IF;

  -- Insert into profiles with conflict handling
  INSERT INTO public.profiles (id, email, full_name)
  VALUES (NEW.id, user_email, user_full_name)
  ON CONFLICT (id) DO UPDATE SET
    email = EXCLUDED.email,
    full_name = EXCLUDED.full_name,
    updated_at = NOW();

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Log the error but don't fail the auth signup
  RAISE WARNING 'Error creating profile for user %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;

-- Recreate the trigger
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- Also improve the username generation function to handle edge cases
CREATE OR REPLACE FUNCTION public.generate_username_from_name(full_name TEXT)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
DECLARE
  base_username TEXT;
  final_username TEXT;
  counter INTEGER := 0;
  max_attempts INTEGER := 100;
BEGIN
  -- Handle NULL or empty input
  IF full_name IS NULL OR full_name = '' THEN
    base_username := 'user' || substr(md5(random()::text), 1, 8);
  ELSE
    -- Convert full_name to lowercase, keep only alphanumeric
    base_username := lower(regexp_replace(full_name, '[^a-zA-Z0-9]', '', 'g'));
  END IF;

  -- If still empty after processing, use random
  IF base_username = '' OR base_username IS NULL THEN
    base_username := 'user' || substr(md5(random()::text), 1, 8);
  END IF;

  -- Truncate to 20 chars max
  base_username := substr(base_username, 1, 20);

  final_username := base_username;

  -- Check for uniqueness with a limit to prevent infinite loops
  WHILE EXISTS(SELECT 1 FROM public.profiles WHERE username = final_username) AND counter < max_attempts LOOP
    counter := counter + 1;
    final_username := base_username || counter::text;
  END LOOP;

  -- If we hit max attempts, add random suffix
  IF counter >= max_attempts THEN
    final_username := base_username || '_' || substr(md5(random()::text), 1, 6);
  END IF;

  RETURN final_username;
END;
$$;

-- Update the auto_generate_username trigger function
CREATE OR REPLACE FUNCTION public.auto_generate_username()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.username IS NULL OR NEW.username = '' THEN
    NEW.username := public.generate_username_from_name(COALESCE(NEW.full_name, NEW.email, 'user'));
  END IF;
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- If username generation fails, use a UUID-based fallback
  NEW.username := 'user_' || substr(md5(random()::text), 1, 12);
  RETURN NEW;
END;
$$;

-- Recreate the trigger
DROP TRIGGER IF EXISTS trigger_auto_generate_username ON public.profiles;
CREATE TRIGGER trigger_auto_generate_username
  BEFORE INSERT ON public.profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.auto_generate_username();

