ALTER PUBLICATION supabase_realtime ADD TABLE public.marketplace_org_invitations;
ALTER PUBLICATION supabase_realtime ADD TABLE public.org_inquiries;

-- ========== 20260208220000_sync_profiles_to_marketplace.sql ==========
-- Migration: Sync existing profiles to marketplace creator_profiles
-- Populates creator_profiles from profiles that have published content or marketplace enabled
-- Also migrates portfolio_posts and published content to portfolio_items

-- ── Step 1: Create creator_profiles from existing profiles ────────────────

INSERT INTO public.creator_profiles (
  user_id,
  display_name,
  slug,
  bio,
  avatar_url,
  location_city,
  location_country,
  categories,
  languages,
  social_links,
  base_price,
  currency,
  is_available,
  is_active,
  rating_avg,
  completed_projects,
  platforms
)
SELECT
  p.id,
  COALESCE(p.full_name, 'Creador'),
  p.username,
  p.bio,
  p.avatar_url,
  p.city,
  COALESCE(p.country, 'CO'),
  COALESCE(p.content_categories, '{}'),
  COALESCE(p.languages, '{es}'),
  jsonb_build_object(
    'instagram', COALESCE(p.instagram, ''),
    'tiktok', COALESCE(p.tiktok, '')
  ) - '' ,  -- remove empty values
  p.minimum_budget,
  'USD',
  COALESCE(p.is_available_for_hire, true),
  true,
  COALESCE(p.avg_rating, 0),
  COALESCE(p.total_contracts_completed, 0),
  '{}'::text[]
FROM public.profiles p
WHERE p.id NOT IN (SELECT user_id FROM public.creator_profiles)
  AND (
    p.marketplace_enabled = true
    OR EXISTS (
      SELECT 1 FROM public.content c
      WHERE c.creator_id = p.id
        AND c.is_published = true
        AND (c.video_url IS NOT NULL OR c.bunny_embed_url IS NOT NULL)
    )
    OR EXISTS (
      SELECT 1 FROM public.portfolio_posts pp
      WHERE pp.user_id = p.id
    )
  )
ON CONFLICT (user_id) DO NOTHING;

-- ── Step 2: Migrate published content videos to portfolio_items ──────────

INSERT INTO public.portfolio_items (
  creator_id,
  title,
  media_type,
  media_url,
  thumbnail_url,
  bunny_video_id,
  is_public,
  is_featured,
  display_order,
  category
)
SELECT
  cp.id,
  c.title,
  'video',
  COALESCE(
    (c.video_urls::text[])[1],   -- Direct CDN URL first
    c.bunny_embed_url,            -- Then embed URL
    c.video_url                   -- Then legacy video_url
  ),
  c.thumbnail_url,
  -- Extract bunny video ID from embed URL
  CASE
    WHEN c.bunny_embed_url ~ '[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}'
    THEN (regexp_match(c.bunny_embed_url, '([a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12})'))[1]
    ELSE NULL
  END,
  true,
  false,
  ROW_NUMBER() OVER (PARTITION BY cp.id ORDER BY c.created_at DESC) - 1,
  NULL
FROM public.content c
JOIN public.creator_profiles cp ON cp.user_id = c.creator_id
WHERE c.is_published = true
  AND (c.video_url IS NOT NULL OR c.bunny_embed_url IS NOT NULL OR c.video_urls IS NOT NULL)
  AND NOT EXISTS (
    SELECT 1 FROM public.portfolio_items pi
    WHERE pi.creator_id = cp.id
      AND pi.media_url = COALESCE(
        (c.video_urls::text[])[1],
        c.bunny_embed_url,
        c.video_url
      )
  )
LIMIT 500;  -- Safety limit for initial migration

-- ── Step 3: Migrate portfolio_posts (videos and images) to portfolio_items ──

INSERT INTO public.portfolio_items (
  creator_id,
  title,
  media_type,
  media_url,
  thumbnail_url,
  is_public,
  is_featured,
  display_order
)
SELECT
  cp.id,
  pp.caption,
  pp.media_type,
  pp.media_url,
  pp.thumbnail_url,
  true,
  false,
  (
    SELECT COALESCE(MAX(pi2.display_order), -1) + 1
    FROM public.portfolio_items pi2
    WHERE pi2.creator_id = cp.id
  ) + ROW_NUMBER() OVER (PARTITION BY cp.id ORDER BY pp.created_at DESC) - 1
FROM public.portfolio_posts pp
JOIN public.creator_profiles cp ON cp.user_id = pp.user_id
WHERE pp.media_url IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM public.portfolio_items pi
    WHERE pi.creator_id = cp.id
      AND pi.media_url = pp.media_url
  )
LIMIT 1000;  -- Safety limit

-- ── Step 4: Create a reusable function for future syncs ──────────────────

CREATE OR REPLACE FUNCTION public.sync_profile_to_marketplace(target_user_id uuid)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  creator_id uuid;
BEGIN
  -- Check if already exists
  SELECT id INTO creator_id
  FROM public.creator_profiles
  WHERE user_id = target_user_id;

  IF creator_id IS NOT NULL THEN
    RETURN creator_id;
  END IF;

  -- Create creator_profile from profiles
  INSERT INTO public.creator_profiles (
    user_id, display_name, slug, bio, avatar_url,
    location_city, location_country, categories, languages,
    social_links, base_price, is_available, is_active
  )
  SELECT
    p.id,
    COALESCE(p.full_name, 'Creador'),
    p.username,
    p.bio,
    p.avatar_url,
    p.city,
    COALESCE(p.country, 'CO'),
    COALESCE(p.content_categories, '{}'),
    COALESCE(p.languages, '{es}'),
    jsonb_build_object(
      'instagram', COALESCE(p.instagram, ''),
      'tiktok', COALESCE(p.tiktok, '')
    ),
    p.minimum_budget,
    COALESCE(p.is_available_for_hire, true),
    true
  FROM public.profiles p
  WHERE p.id = target_user_id
  RETURNING id INTO creator_id;

  -- Migrate content videos
  INSERT INTO public.portfolio_items (
    creator_id, title, media_type, media_url, thumbnail_url, bunny_video_id,
    is_public, display_order
  )
  SELECT
    creator_id,
    c.title,
    'video',
    COALESCE((c.video_urls::text[])[1], c.bunny_embed_url, c.video_url),
    c.thumbnail_url,
    CASE
      WHEN c.bunny_embed_url ~ '[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}'
      THEN (regexp_match(c.bunny_embed_url, '([a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12})'))[1]
      ELSE NULL
    END,
    true,
    ROW_NUMBER() OVER (ORDER BY c.created_at DESC) - 1
  FROM public.content c
  WHERE c.creator_id = target_user_id
    AND c.is_published = true
    AND (c.video_url IS NOT NULL OR c.bunny_embed_url IS NOT NULL);

  -- Migrate portfolio posts
  INSERT INTO public.portfolio_items (
    creator_id, title, media_type, media_url, thumbnail_url,
    is_public, display_order
  )
  SELECT
    creator_id,
    pp.caption,
    pp.media_type,
    pp.media_url,
    pp.thumbnail_url,
    true,
    (SELECT COALESCE(MAX(display_order), -1) + 1 FROM public.portfolio_items WHERE portfolio_items.creator_id = sync_profile_to_marketplace.creator_id)
      + ROW_NUMBER() OVER (ORDER BY pp.created_at DESC) - 1
  FROM public.portfolio_posts pp
  WHERE pp.user_id = target_user_id
    AND pp.media_url IS NOT NULL;

  RETURN creator_id;
END;
$$;

-- Grant execute to authenticated users
GRANT EXECUTE ON FUNCTION public.sync_profile_to_marketplace(uuid) TO authenticated;

-- ========== 20260208230000_auto_create_marketplace_profiles.sql ==========
-- Migration: Auto-create marketplace profiles for ALL existing users
-- + Trigger to auto-create for new users
-- + Fix RLS to allow own profile viewing

-- ============================================
-- 1. Bulk create creator_profiles for ALL remaining users
-- ============================================

INSERT INTO public.creator_profiles (
  user_id,
  display_name,
  slug,
  bio,
  avatar_url,
  location_city,
  location_country,
  categories,
  languages,
  social_links,
  is_available,
  is_active,
  platforms,
  marketplace_roles,
  content_types
)
SELECT
  p.id,
  COALESCE(NULLIF(TRIM(p.full_name), ''), 'Creador'),
  NULL, -- slug auto-generated by trigger
  p.bio,
  p.avatar_url,
  p.city,
  COALESCE(p.country, 'CO'),
  COALESCE(p.content_categories, '{}'::text[]),
  COALESCE(p.languages, '{es}'::text[]),
  jsonb_strip_nulls(jsonb_build_object(
    'instagram', NULLIF(p.instagram, ''),
    'tiktok', NULLIF(p.tiktok, '')
  )),
  true,
  true, -- active by default so they appear in marketplace
  '{}'::text[],
  '{}'::text[],
  '{}'::text[]
FROM public.profiles p
JOIN auth.users u ON u.id = p.id  -- exclude orphaned profiles
WHERE p.id NOT IN (SELECT user_id FROM public.creator_profiles)
ON CONFLICT (user_id) DO NOTHING;

-- ============================================
-- 2. Activate any existing draft profiles
-- ============================================

UPDATE public.creator_profiles
SET is_active = true
WHERE is_active = false;

-- ============================================
-- 3. Trigger: auto-create creator_profile on new user signup
-- ============================================

CREATE OR REPLACE FUNCTION public.auto_create_creator_profile()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  INSERT INTO public.creator_profiles (
    user_id,
    display_name,
    bio,
    avatar_url,
    location_city,
    location_country,
    categories,
    languages,
    social_links,
    is_available,
    is_active,
    platforms,
    marketplace_roles,
    content_types
  )
  VALUES (
    NEW.id,
    COALESCE(NULLIF(TRIM(NEW.full_name), ''), 'Creador'),
    NEW.bio,
    NEW.avatar_url,
    NEW.city,
    COALESCE(NEW.country, 'CO'),
    COALESCE(NEW.content_categories, '{}'::text[]),
    COALESCE(NEW.languages, '{es}'::text[]),
    jsonb_strip_nulls(jsonb_build_object(
      'instagram', NULLIF(NEW.instagram, ''),
      'tiktok', NULLIF(NEW.tiktok, '')
    )),
    true,
    true,
    '{}'::text[],
    '{}'::text[],
    '{}'::text[]
  )
  ON CONFLICT (user_id) DO NOTHING;

  RETURN NEW;
END;
$$;

-- Drop existing trigger if any, then create
DROP TRIGGER IF EXISTS trigger_auto_create_creator_profile ON public.profiles;

CREATE TRIGGER trigger_auto_create_creator_profile
  AFTER INSERT ON public.profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.auto_create_creator_profile();

-- ============================================
-- 4. Fix RLS: allow users to see their own profile (even drafts)
-- ============================================

DROP POLICY IF EXISTS "Creator profiles are publicly readable" ON public.creator_profiles;

CREATE POLICY "Creator profiles are publicly readable"
  ON public.creator_profiles FOR SELECT
  USING (
    is_active = true
    OR user_id = auth.uid()
  );

-- ============================================
-- 5. Keep profile data in sync on updates
-- ============================================

CREATE OR REPLACE FUNCTION public.sync_profile_updates_to_marketplace()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE public.creator_profiles
  SET
    display_name = COALESCE(NULLIF(TRIM(NEW.full_name), ''), display_name),
    avatar_url = COALESCE(NEW.avatar_url, avatar_url),
    location_city = COALESCE(NEW.city, location_city),
    location_country = COALESCE(NEW.country, location_country),
    social_links = jsonb_strip_nulls(
      COALESCE(social_links, '{}'::jsonb)
      || jsonb_build_object(
        'instagram', NULLIF(NEW.instagram, ''),
        'tiktok', NULLIF(NEW.tiktok, '')
      )
    ),
    updated_at = now()
  WHERE user_id = NEW.id;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trigger_sync_profile_to_marketplace ON public.profiles;

CREATE TRIGGER trigger_sync_profile_to_marketplace
  AFTER UPDATE ON public.profiles
  FOR EACH ROW
  WHEN (
    OLD.full_name IS DISTINCT FROM NEW.full_name
    OR OLD.avatar_url IS DISTINCT FROM NEW.avatar_url
    OR OLD.city IS DISTINCT FROM NEW.city
    OR OLD.country IS DISTINCT FROM NEW.country
    OR OLD.instagram IS DISTINCT FROM NEW.instagram
    OR OLD.tiktok IS DISTINCT FROM NEW.tiktok
  )
  EXECUTE FUNCTION public.sync_profile_updates_to_marketplace();

-- ========== 20260208231000_fix_portfolio_likes_comments_grants.sql ==========
-- Fix 403: portfolio_post_likes and portfolio_post_comments missing GRANT to authenticated role
-- These tables were created with RLS policies but without explicit GRANT statements,
-- causing PostgREST to return 403 Forbidden for authenticated users.

GRANT SELECT, INSERT, DELETE ON public.portfolio_post_likes TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.portfolio_post_comments TO authenticated;

-- ========== 20260208300000_campaign_visibility_system.sql ==========
-- =============================================================================
-- CAMPAIGN VISIBILITY SYSTEM
-- =============================================================================
-- Adds configurable visibility (public/internal/selective) to campaigns,
-- organization support alongside brands, invitation system for selective
-- campaigns, and campaign deliverables table.
-- =============================================================================

-- ============================================
-- 1. HELPER FUNCTIONS
-- ============================================

-- is_org_member: check if current user belongs to an organization
CREATE OR REPLACE FUNCTION public.is_org_member(_org_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE organization_id = _org_id
      AND user_id = auth.uid()
  );
$$;

-- is_org_admin: check if current user is admin of an organization
CREATE OR REPLACE FUNCTION public.is_org_admin(_org_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE organization_id = _org_id
      AND user_id = auth.uid()
      AND role IN ('admin', 'team_leader')
  );
$$;

-- can_see_campaign: visibility-aware campaign access check
CREATE OR REPLACE FUNCTION public.can_see_campaign(_campaign_id uuid, _user_id uuid)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
STABLE
AS $$
DECLARE
  _visibility text;
  _org_id uuid;
  _brand_id uuid;
  _status text;
BEGIN
  SELECT visibility, organization_id, brand_id, status
  INTO _visibility, _org_id, _brand_id, _status
  FROM public.marketplace_campaigns
  WHERE id = _campaign_id;

  IF NOT FOUND THEN
    RETURN false;
  END IF;

  -- Campaign creator can always see their own
  IF EXISTS (
    SELECT 1 FROM public.marketplace_campaigns
    WHERE id = _campaign_id AND created_by = _user_id
  ) THEN
    RETURN true;
  END IF;

  -- Brand members can always see their brand's campaigns
  IF _brand_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.brand_members
    WHERE brand_id = _brand_id AND user_id = _user_id AND status = 'active'
  ) THEN
    RETURN true;
  END IF;

  -- Org members can always see their org's campaigns
  IF _org_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE organization_id = _org_id AND user_id = _user_id
  ) THEN
    RETURN true;
  END IF;

  -- Public campaigns: visible to all if active/in_progress/completed
  IF _visibility = 'public' AND _status IN ('active', 'in_progress', 'completed') THEN
    RETURN true;
  END IF;

  -- Internal campaigns: only org members (already checked above)
  IF _visibility = 'internal' THEN
    RETURN false;
  END IF;

  -- Selective campaigns: only if invited
  IF _visibility = 'selective' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.campaign_invitations
      WHERE campaign_id = _campaign_id
        AND invited_profile_id = _user_id
        AND status IN ('pending', 'accepted')
    );
  END IF;

  RETURN false;
END;
$$;

-- ============================================
-- 2. ALTER marketplace_campaigns
-- ============================================

-- Visibility & organization support
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS visibility text NOT NULL DEFAULT 'public'
    CHECK (visibility IN ('public', 'internal', 'selective'));

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS organization_id uuid REFERENCES public.organizations(id) ON DELETE SET NULL;

-- Make brand_id nullable (campaigns can belong to org OR brand)
ALTER TABLE public.marketplace_campaigns
  ALTER COLUMN brand_id DROP NOT NULL;

-- Brief & extended branding
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS brief text;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS brand_name_override varchar(200);

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS brand_logo_override text;

-- Compensation
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS compensation_type varchar(30) DEFAULT 'paid'
    CHECK (compensation_type IN ('paid', 'product_exchange', 'hybrid', 'credits'));

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS compensation_description text;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS product_value numeric(10,2);

-- Extended deadlines
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS application_deadline timestamptz;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS content_deadline timestamptz;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS campaign_start_date timestamptz;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS campaign_end_date timestamptz;

-- Capacity
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS max_applications integer;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS current_applications integer DEFAULT 0;

-- Configuration
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS auto_approve_applications boolean DEFAULT false;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS requires_portfolio boolean DEFAULT true;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS allow_counter_offers boolean DEFAULT false;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS nda_required boolean DEFAULT false;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS usage_rights text DEFAULT 'platform_only'
    CHECK (usage_rights IN ('platform_only', 'social_media', 'all_channels', 'exclusive', 'custom'));

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS usage_rights_description text;

-- Flags
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS is_urgent boolean DEFAULT false;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS published_at timestamptz;

-- Content guidelines
ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS content_guidelines text;

ALTER TABLE public.marketplace_campaigns
  ADD COLUMN IF NOT EXISTS reference_urls text[] DEFAULT '{}';

-- Indexes
CREATE INDEX IF NOT EXISTS idx_campaigns_visibility ON public.marketplace_campaigns(visibility);
CREATE INDEX IF NOT EXISTS idx_campaigns_org_id ON public.marketplace_campaigns(organization_id);

-- ============================================
-- 3. CREATE campaign_invitations
-- ============================================

CREATE TABLE IF NOT EXISTS public.campaign_invitations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id uuid NOT NULL REFERENCES public.marketplace_campaigns(id) ON DELETE CASCADE,
  invited_profile_id uuid NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  invited_by uuid NOT NULL REFERENCES auth.users(id),
  message text,
  status text NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'accepted', 'declined', 'expired')),
  sent_at timestamptz DEFAULT now(),
  responded_at timestamptz,
  expires_at timestamptz DEFAULT (now() + interval '7 days'),
  CONSTRAINT campaign_invitations_unique UNIQUE (campaign_id, invited_profile_id)
);

CREATE INDEX IF NOT EXISTS idx_invitations_campaign ON public.campaign_invitations(campaign_id);
CREATE INDEX IF NOT EXISTS idx_invitations_profile ON public.campaign_invitations(invited_profile_id);
CREATE INDEX IF NOT EXISTS idx_invitations_status ON public.campaign_invitations(status);

-- Enable RLS
ALTER TABLE public.campaign_invitations ENABLE ROW LEVEL SECURITY;

-- Triggers
CREATE OR REPLACE TRIGGER trigger_invitations_updated_at
  BEFORE UPDATE ON public.campaign_invitations
  FOR EACH ROW EXECUTE FUNCTION public.handle_updated_at();

-- ============================================
-- 4. CREATE campaign_deliverables
-- ============================================

CREATE TABLE IF NOT EXISTS public.campaign_deliverables (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id uuid NOT NULL REFERENCES public.marketplace_campaigns(id) ON DELETE CASCADE,
  creator_id uuid NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  application_id uuid REFERENCES public.campaign_applications(id) ON DELETE SET NULL,
  -- Content
  title varchar(200),
  description text,
  file_url text NOT NULL,
  file_type text DEFAULT 'video' CHECK (file_type IN ('video', 'image', 'document')),
  thumbnail_url text,
  duration_seconds integer,
  file_size_mb numeric(10,2),
  -- Revision tracking
  revision_number integer DEFAULT 1,
  max_revisions integer DEFAULT 2,
  -- Status
  status text NOT NULL DEFAULT 'submitted'
    CHECK (status IN ('submitted', 'revision_requested', 'approved', 'rejected')),
  feedback text,
  approved_by uuid REFERENCES auth.users(id),
  -- Timestamps
  submitted_at timestamptz DEFAULT now(),
  reviewed_at timestamptz,
  updated_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_deliverables_campaign ON public.campaign_deliverables(campaign_id);
CREATE INDEX IF NOT EXISTS idx_deliverables_creator ON public.campaign_deliverables(creator_id);
CREATE INDEX IF NOT EXISTS idx_deliverables_application ON public.campaign_deliverables(application_id);
CREATE INDEX IF NOT EXISTS idx_deliverables_status ON public.campaign_deliverables(status);

-- Enable RLS
ALTER TABLE public.campaign_deliverables ENABLE ROW LEVEL SECURITY;

-- Triggers
CREATE OR REPLACE TRIGGER trigger_deliverables_updated_at
  BEFORE UPDATE ON public.campaign_deliverables
  FOR EACH ROW EXECUTE FUNCTION public.handle_updated_at();

-- ============================================
-- 5. RLS POLICIES
-- ============================================

-- ---- Drop & recreate campaign SELECT policy to add visibility logic ----
DROP POLICY IF EXISTS "Active campaigns are publicly readable" ON public.marketplace_campaigns;

CREATE POLICY "Campaigns visible based on visibility rules"
  ON public.marketplace_campaigns FOR SELECT
  USING (
    -- Creator of the campaign
    created_by = auth.uid()
    -- Brand member
    OR (brand_id IS NOT NULL AND public.is_brand_member(brand_id))
    -- Org member (always sees org campaigns)
    OR (organization_id IS NOT NULL AND public.is_org_member(organization_id))
    -- Public campaigns that are active/in_progress/completed
    OR (visibility = 'public' AND status IN ('active', 'in_progress', 'completed'))
    -- Selective campaigns: user is invited
    OR (
      visibility = 'selective'
      AND status IN ('active', 'in_progress', 'completed')
      AND EXISTS (
        SELECT 1 FROM public.campaign_invitations ci
        WHERE ci.campaign_id = marketplace_campaigns.id
          AND ci.invited_profile_id = auth.uid()
          AND ci.status IN ('pending', 'accepted')
      )
    )
  );

-- Update INSERT policy to allow org members to create campaigns
DROP POLICY IF EXISTS "Brand members can create campaigns" ON public.marketplace_campaigns;

CREATE POLICY "Brand or org members can create campaigns"
  ON public.marketplace_campaigns FOR INSERT
  WITH CHECK (
    auth.uid() = created_by
    AND (
      (brand_id IS NOT NULL AND public.is_brand_member(brand_id))
      OR (organization_id IS NOT NULL AND public.is_org_member(organization_id))
      OR (brand_id IS NULL AND organization_id IS NULL) -- Allow standalone creation
    )
  );

-- Update UPDATE policy
DROP POLICY IF EXISTS "Brand admins can update campaigns" ON public.marketplace_campaigns;

CREATE POLICY "Campaign owners can update campaigns"
  ON public.marketplace_campaigns FOR UPDATE
  USING (
    created_by = auth.uid()
    OR (brand_id IS NOT NULL AND public.is_brand_admin(brand_id))
    OR (organization_id IS NOT NULL AND public.is_org_admin(organization_id))
  )
  WITH CHECK (
    created_by = auth.uid()
    OR (brand_id IS NOT NULL AND public.is_brand_admin(brand_id))
    OR (organization_id IS NOT NULL AND public.is_org_admin(organization_id))
  );

-- Update DELETE policy
DROP POLICY IF EXISTS "Brand admins can delete draft campaigns" ON public.marketplace_campaigns;

CREATE POLICY "Admins can delete draft campaigns"
  ON public.marketplace_campaigns FOR DELETE
  USING (
    status = 'draft'
    AND (
      created_by = auth.uid()
      OR (brand_id IS NOT NULL AND public.is_brand_admin(brand_id))
      OR (organization_id IS NOT NULL AND public.is_org_admin(organization_id))
    )
  );

-- ---- campaign_invitations policies ----

CREATE POLICY "Invitation visible to invited user and campaign org"
  ON public.campaign_invitations FOR SELECT
  USING (
    invited_profile_id = auth.uid()
    OR invited_by = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_invitations.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_member(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_member(mc.organization_id))
        )
    )
  );

CREATE POLICY "Campaign managers can create invitations"
  ON public.campaign_invitations FOR INSERT
  WITH CHECK (
    auth.uid() = invited_by
    AND EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_invitations.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_admin(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_admin(mc.organization_id))
        )
    )
  );

CREATE POLICY "Invited users can respond to invitations"
  ON public.campaign_invitations FOR UPDATE
  USING (
    invited_profile_id = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_invitations.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_admin(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_admin(mc.organization_id))
        )
    )
  );

CREATE POLICY "Campaign managers can delete invitations"
  ON public.campaign_invitations FOR DELETE
  USING (
    EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_invitations.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_admin(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_admin(mc.organization_id))
        )
    )
  );

-- ---- campaign_deliverables policies ----

CREATE POLICY "Deliverables visible to campaign participants"
  ON public.campaign_deliverables FOR SELECT
  USING (
    creator_id = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_deliverables.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_member(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_member(mc.organization_id))
        )
    )
  );

CREATE POLICY "Creators can submit deliverables"
  ON public.campaign_deliverables FOR INSERT
  WITH CHECK (
    auth.uid() = creator_id
    AND EXISTS (
      SELECT 1 FROM public.campaign_applications ca
      WHERE ca.id = campaign_deliverables.application_id
        AND ca.status IN ('approved', 'assigned')
    )
  );

CREATE POLICY "Participants can update deliverables"
  ON public.campaign_deliverables FOR UPDATE
  USING (
    creator_id = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_deliverables.campaign_id
        AND (
          mc.created_by = auth.uid()
          OR (mc.brand_id IS NOT NULL AND public.is_brand_admin(mc.brand_id))
          OR (mc.organization_id IS NOT NULL AND public.is_org_admin(mc.organization_id))
        )
    )
  );

-- ============================================
-- 6. GRANTS
-- ============================================

GRANT ALL ON public.campaign_invitations TO authenticated;
GRANT ALL ON public.campaign_deliverables TO authenticated;

