    AND policyname = 'Platform rules readable by all authenticated'
  ) THEN
    CREATE POLICY "Platform rules readable by all authenticated"
      ON ai_negative_rules
      FOR SELECT
      TO authenticated
      USING (is_platform = true);
  END IF;
END $$;

DO $$ BEGIN
