-- ========== 20260209180000_content_rpc_functions.sql ==========
-- SECURITY DEFINER functions for content table operations.
-- These bypass the 18 RLS policies on the content table by checking
-- authorization once (org membership) instead of per-row evaluation.

-- Fetch a single content row by ID (bypasses RLS)
CREATE OR REPLACE FUNCTION get_content_by_id(p_content_id uuid)
RETURNS SETOF content
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  -- Get the organization of this content
  SELECT organization_id INTO v_org_id
  FROM content WHERE id = p_content_id;

  IF v_org_id IS NULL THEN
    RETURN;
  END IF;

  -- Verify caller is a member of that organization
  IF NOT EXISTS (
    SELECT 1 FROM organization_member_roles
    WHERE organization_id = v_org_id AND user_id = auth.uid()
  ) AND NOT EXISTS (
    SELECT 1 FROM client_users cu
    JOIN clients c ON c.id = cu.client_id
    WHERE c.organization_id = v_org_id AND cu.user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  RETURN QUERY SELECT * FROM content WHERE id = p_content_id;
END;
$$;

-- Update a content row by ID using JSONB payload (bypasses RLS)
DROP FUNCTION IF EXISTS update_content_by_id(uuid, jsonb);
CREATE OR REPLACE FUNCTION update_content_by_id(p_content_id uuid, p_updates jsonb)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  k text;
  v text;
  set_clauses text[] := '{}';
  sql text;
BEGIN
  -- Get the organization of this content
  SELECT organization_id INTO v_org_id
  FROM content WHERE id = p_content_id;

  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Content not found';
  END IF;

  -- Verify caller is a member of that organization
  IF NOT EXISTS (
    SELECT 1 FROM organization_member_roles
    WHERE organization_id = v_org_id AND user_id = auth.uid()
  ) AND NOT EXISTS (
    SELECT 1 FROM client_users cu
    JOIN clients c ON c.id = cu.client_id
    WHERE c.organization_id = v_org_id AND cu.user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  -- Build dynamic UPDATE from JSONB keys
  FOR k IN SELECT jsonb_object_keys(p_updates) LOOP
    -- Use parameterized values via format to prevent SQL injection
    set_clauses := set_clauses || format('%I = %L', k,
      CASE
        WHEN jsonb_typeof(p_updates->k) = 'null' THEN NULL
        WHEN jsonb_typeof(p_updates->k) = 'string' THEN p_updates->>k
        WHEN jsonb_typeof(p_updates->k) = 'boolean' THEN p_updates->>k
        WHEN jsonb_typeof(p_updates->k) = 'number' THEN p_updates->>k
        WHEN jsonb_typeof(p_updates->k) = 'array' THEN p_updates->k::text
        ELSE p_updates->>k
      END
    );
  END LOOP;

  IF array_length(set_clauses, 1) IS NULL THEN
    RETURN; -- nothing to update
  END IF;

  sql := format('UPDATE content SET %s WHERE id = %L',
    array_to_string(set_clauses, ', '),
    p_content_id
  );
  EXECUTE sql;
END;
$$;

-- Grant execute to authenticated users
GRANT EXECUTE ON FUNCTION get_content_by_id(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION update_content_by_id(uuid, jsonb) TO authenticated;

-- ========== 20260209200000_org_products_packages_rpc.sql ==========
-- RPCs to replace massive .in('client_id', [...500+ UUIDs]) queries
-- which exceed HTTP URL length limits (400 Bad Request) and overload the DB.
-- These do the JOIN server-side with a single organization_id parameter.

-- 1. Get all products for an organization (used by ContentBoard filters)
CREATE OR REPLACE FUNCTION get_org_products(p_organization_id uuid)
RETURNS TABLE (id uuid, name text, client_id uuid, client_name text)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT p.id, p.name::text, p.client_id, c.name::text AS client_name
  FROM products p
  JOIN clients c ON c.id = p.client_id
  WHERE c.organization_id = p_organization_id
  ORDER BY p.name;
$$;

-- 2. Get active client packages for an organization (used by Dashboard billing)
-- Uses SETOF to match the exact table schema (avoids column mismatch issues)
CREATE OR REPLACE FUNCTION get_org_client_packages(p_organization_id uuid)
RETURNS SETOF client_packages
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT cp.*
  FROM client_packages cp
  JOIN clients c ON c.id = cp.client_id
  WHERE c.organization_id = p_organization_id
  AND cp.is_active = true;
$$;

-- Grant execute
GRANT EXECUTE ON FUNCTION get_org_products(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION get_org_client_packages(uuid) TO authenticated;

-- ========== 20260209210000_unique_internal_brand_per_org.sql ==========
-- Prevent duplicate internal brand clients per organization.
-- Root cause: useInternalBrandClient hook had a race condition + .maybeSingle() feedback loop
-- that created 740+ duplicates in a single day.

-- Safety: clean up any residual duplicates (keep oldest per org)
DELETE FROM public.clients
WHERE is_internal_brand = true
  AND id NOT IN (
    SELECT DISTINCT ON (organization_id) id
    FROM public.clients
    WHERE is_internal_brand = true
    ORDER BY organization_id, created_at ASC
  );

-- Partial unique index: one internal brand client per organization
CREATE UNIQUE INDEX IF NOT EXISTS idx_unique_internal_brand_per_org
  ON public.clients (organization_id)
  WHERE is_internal_brand = true;

-- ========== 20260209220000_fix_update_content_rpc.sql ==========
-- Fix update_content_by_id: JSON arrays were incompatible with text[] columns.
-- '["a","b"]' (JSON format) != '{"a","b"}' (PostgreSQL array format).
-- Also: return void instead of RAISE EXCEPTION to avoid 400 from PostgREST.

CREATE OR REPLACE FUNCTION update_content_by_id(p_content_id uuid, p_updates jsonb)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  k text;
  col_type text;
  set_clauses text[] := '{}';
  sql text;
BEGIN
  -- Get the organization of this content
  SELECT organization_id INTO v_org_id
  FROM content WHERE id = p_content_id;

  IF v_org_id IS NULL THEN
    RETURN; -- Content not found: silently return instead of RAISE EXCEPTION (avoids 400)
  END IF;

  -- Verify caller is a member of that organization
  IF NOT EXISTS (
    SELECT 1 FROM organization_member_roles
    WHERE organization_id = v_org_id AND user_id = auth.uid()
  ) AND NOT EXISTS (
    SELECT 1 FROM client_users cu
    JOIN clients c ON c.id = cu.client_id
    WHERE c.organization_id = v_org_id AND cu.user_id = auth.uid()
  ) THEN
    RETURN; -- Not authorized: silently return instead of RAISE EXCEPTION (avoids 400)
  END IF;

  -- Build dynamic UPDATE from JSONB keys
  FOR k IN SELECT jsonb_object_keys(p_updates) LOOP
    -- Skip keys that are not real columns (e.g. joined fields like 'client', 'creator')
    SELECT data_type INTO col_type
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'content' AND column_name = k;

    IF col_type IS NULL THEN
      CONTINUE; -- skip non-existent columns
    END IF;

    IF jsonb_typeof(p_updates->k) = 'null' THEN
      set_clauses := set_clauses || format('%I = NULL', k);
    ELSIF jsonb_typeof(p_updates->k) = 'array' THEN
      -- Convert JSON array to PostgreSQL array (text[]) via subquery
      set_clauses := set_clauses || format(
        '%I = ARRAY(SELECT jsonb_array_elements_text(%L::jsonb))',
        k, p_updates->k::text
      );
    ELSIF jsonb_typeof(p_updates->k) = 'object' THEN
      -- JSON objects go to jsonb columns with explicit cast
      set_clauses := set_clauses || format('%I = %L::jsonb', k, p_updates->k::text);
    ELSE
      -- Scalars (string, number, boolean): text literal, PostgreSQL handles implicit casting
      set_clauses := set_clauses || format('%I = %L', k, p_updates->>k);
    END IF;
  END LOOP;

  IF array_length(set_clauses, 1) IS NULL THEN
    RETURN; -- nothing to update
  END IF;

  sql := format('UPDATE content SET %s WHERE id = %L',
    array_to_string(set_clauses, ', '),
    p_content_id
  );
  EXECUTE sql;
END;
$$;

-- ========== 20260209230000_fix_service_types_unaccent.sql ==========
-- Fix: unaccent(text) does not exist when creating a service
-- The generate_service_slug function (created outside migrations) calls unaccent().
-- Also: expand service_type CHECK constraint to support all marketplace roles.

-- 1. Install unaccent extension (fixes the immediate error)
CREATE EXTENSION IF NOT EXISTS unaccent SCHEMA public;

-- 2. Replace generate_service_slug to use unaccent extension
CREATE OR REPLACE FUNCTION public.generate_service_slug(p_title text)
RETURNS text
LANGUAGE plpgsql
AS $$
DECLARE
  _slug text;
BEGIN
  _slug := public.unaccent(lower(trim(p_title)));
  _slug := regexp_replace(_slug, '[^a-z0-9]+', '-', 'g');
  _slug := regexp_replace(_slug, '^-|-$', '', 'g');
  _slug := left(_slug, 80);
  RETURN _slug;
END;
$$;

-- 3. Replace auto_generate_service_slug trigger function to be safe
CREATE OR REPLACE FUNCTION public.auto_generate_service_slug()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  IF NEW.slug IS NULL OR NEW.slug = '' THEN
    NEW.slug := public.generate_service_slug(NEW.title);
    -- Append random suffix for uniqueness
    NEW.slug := NEW.slug || '-' || substr(md5(random()::text), 1, 6);
  END IF;
  RETURN NEW;
END;
$$;

-- Ensure trigger exists
DROP TRIGGER IF EXISTS trigger_auto_service_slug ON public.creator_services;
CREATE TRIGGER trigger_auto_service_slug
  BEFORE INSERT ON public.creator_services
  FOR EACH ROW EXECUTE FUNCTION public.auto_generate_service_slug();

-- 4. Drop the old inline CHECK constraint on service_type
--    PostgreSQL names it: {table}_{column}_check
ALTER TABLE public.creator_services DROP CONSTRAINT IF EXISTS creator_services_service_type_check;

-- 5. Add expanded CHECK constraint covering all marketplace roles
ALTER TABLE public.creator_services ADD CONSTRAINT creator_services_service_type_check
  CHECK (service_type IN (
    -- Content Creation
    'ugc_video', 'ugc_photo', 'ugc_carousel', 'photography', 'live_streaming',
    'voice_over', 'script_writing', 'podcast_production', 'influencer_post', 'graphic_design',
    -- Post-Production
    'video_editing', 'motion_graphics', 'thumbnail_design', 'sound_design',
    'color_grading', 'animation_2d3d', 'creative_direction', 'audiovisual_production',
    -- Strategy & Marketing
    'social_management', 'content_strategy', 'community_management', 'digital_strategy',
    'paid_advertising', 'seo_sem', 'email_marketing', 'growth_hacking',
    'crm_management', 'conversion_optimization',
    -- Technology
    'web_development', 'app_development', 'ai_automation',
    -- Education
    'online_courses', 'workshops',
    -- General
    'consulting', 'custom'
  ));

-- Grant
GRANT EXECUTE ON FUNCTION public.generate_service_slug(text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.auto_generate_service_slug() TO authenticated;

-- ========== 20260209240000_user_org_context_rpc.sql ==========
-- Single RPC to replace 3 separate queries on every page load:
--   1. organization_members?select=is_owner (useOrgOwner)
--   2. organizations?select=name (useOrgOwner)
--   3. organizations?select=marketplace_enabled (useOrgMarketplace)
-- Reduces 3 round-trips to 1.

CREATE OR REPLACE FUNCTION get_user_org_context(p_organization_id uuid)
RETURNS TABLE (
  is_owner boolean,
  org_name text,
  marketplace_enabled boolean
)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT
    COALESCE(om.is_owner, false) AS is_owner,
    o.name::text AS org_name,
    COALESCE(o.marketplace_enabled, true) AS marketplace_enabled
  FROM organizations o
  LEFT JOIN organization_members om
    ON om.organization_id = o.id
    AND om.user_id = auth.uid()
  WHERE o.id = p_organization_id;
$$;

GRANT EXECUTE ON FUNCTION get_user_org_context(uuid) TO authenticated;

-- ========== 20260209300000_unified_reputation_system.sql ==========
-- =============================================================
-- UNIFIED REPUTATION SYSTEM
-- Replaces: up_creadores, up_editores, up_creadores_totals, up_editores_totals
-- Extends: UP Engine 2.0 (up_events, up_rules, emit_up_event)
-- =============================================================

-- 1. NEW TABLE: up_user_scores (role-agnostic, replaces *_totals)
CREATE TABLE IF NOT EXISTS public.up_user_scores (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  role TEXT NOT NULL DEFAULT 'other',
  season_id UUID REFERENCES public.up_seasons(id) ON DELETE SET NULL,

  -- Aggregated metrics
  total_points INTEGER NOT NULL DEFAULT 0,
  current_level TEXT NOT NULL DEFAULT 'bronze',
  total_deliveries INTEGER NOT NULL DEFAULT 0,
  on_time_deliveries INTEGER NOT NULL DEFAULT 0,
  late_deliveries INTEGER NOT NULL DEFAULT 0,
  total_issues INTEGER NOT NULL DEFAULT 0,
  clean_approvals INTEGER NOT NULL DEFAULT 0,
  reassignments INTEGER NOT NULL DEFAULT 0,

  -- Quality metrics
  avg_rating NUMERIC(3,2) DEFAULT 0,
  rating_count INTEGER DEFAULT 0,
  quality_score NUMERIC(5,2) DEFAULT 0,
  reliability_score NUMERIC(5,2) DEFAULT 0,
  velocity_score NUMERIC(5,2) DEFAULT 0,

  -- Timestamps
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Unique constraint: one row per user+org+role+season
-- season_id can be NULL (all-time), so we need a partial approach
CREATE UNIQUE INDEX IF NOT EXISTS idx_up_user_scores_unique_with_season
  ON public.up_user_scores (user_id, organization_id, role, season_id)
  WHERE season_id IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS idx_up_user_scores_unique_no_season
  ON public.up_user_scores (user_id, organization_id, role)
  WHERE season_id IS NULL;

CREATE INDEX IF NOT EXISTS idx_up_user_scores_org_points
  ON public.up_user_scores (organization_id, total_points DESC);

CREATE INDEX IF NOT EXISTS idx_up_user_scores_user
  ON public.up_user_scores (user_id);

CREATE INDEX IF NOT EXISTS idx_up_user_scores_role
  ON public.up_user_scores (role);

-- RLS
ALTER TABLE public.up_user_scores ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own scores"
  ON public.up_user_scores FOR SELECT
  USING (user_id = auth.uid());

CREATE POLICY "Org members can view org scores"
  ON public.up_user_scores FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.organization_members om
      WHERE om.organization_id = up_user_scores.organization_id
        AND om.user_id = auth.uid()
    )
  );

CREATE POLICY "System can manage scores"
  ON public.up_user_scores FOR ALL
  USING (true)
  WITH CHECK (true);

ALTER TABLE public.up_user_scores REPLICA IDENTITY FULL;
ALTER PUBLICATION supabase_realtime ADD TABLE public.up_user_scores;


-- 2. NEW TABLE: reputation_global (public marketplace profile)
CREATE TABLE IF NOT EXISTS public.reputation_global (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL UNIQUE REFERENCES auth.users(id) ON DELETE CASCADE,

  -- Cross-org aggregated (no org-specific data)
  global_points INTEGER NOT NULL DEFAULT 0,
  global_level TEXT NOT NULL DEFAULT 'pro',  -- pro, elite, master, legend

  -- Weighted scores
  avg_quality NUMERIC(5,2) DEFAULT 0,
  avg_reliability NUMERIC(5,2) DEFAULT 0,
  avg_velocity NUMERIC(5,2) DEFAULT 0,
  composite_score NUMERIC(5,2) DEFAULT 0,

  -- Aggregate counts
  total_projects_completed INTEGER DEFAULT 0,
  total_on_time_pct NUMERIC(5,2) DEFAULT 0,
  total_reviews INTEGER DEFAULT 0,
  avg_review_rating NUMERIC(3,2) DEFAULT 0,

  -- Badges
  badges TEXT[] DEFAULT '{}',

  -- Marketplace visibility
  is_visible BOOLEAN DEFAULT true,

  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_reputation_global_level
  ON public.reputation_global (global_level);

CREATE INDEX IF NOT EXISTS idx_reputation_global_score
  ON public.reputation_global (composite_score DESC);

-- RLS: public read, system write
ALTER TABLE public.reputation_global ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view public reputation"
  ON public.reputation_global FOR SELECT
  USING (is_visible = true);

CREATE POLICY "Users can view own reputation"
  ON public.reputation_global FOR SELECT
  USING (user_id = auth.uid());

CREATE POLICY "System can manage reputation"
  ON public.reputation_global FOR ALL
  USING (true)
  WITH CHECK (true);


-- 3. NEW TABLE: reputation_configs (point rules per role/event)
CREATE TABLE IF NOT EXISTS public.reputation_configs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  role TEXT NOT NULL,
  event_key TEXT NOT NULL,
  base_points INTEGER NOT NULL DEFAULT 0,
  day_range_min INTEGER,
  day_range_max INTEGER,
  label TEXT NOT NULL,
  description TEXT,
  is_bonus BOOLEAN DEFAULT false,
  is_penalty BOOLEAN DEFAULT false,
  is_active BOOLEAN DEFAULT true,
