  WITH CHECK (
    organization_id IS NOT NULL AND
    EXISTS (
      SELECT 1 FROM public.organization_members om
      WHERE om.organization_id = role_archetypes.organization_id
        AND om.user_id = auth.uid()
        AND om.role IN ('admin', 'team_leader')
