  p_role TEXT DEFAULT NULL,
  p_limit INTEGER DEFAULT 100
)
RETURNS TABLE(
  id UUID,
  organization_id UUID,
  role_key VARCHAR,
  reference_type VARCHAR,
  reference_id UUID,
  event_type VARCHAR,
  event_subtype VARCHAR,
  final_points INT,
  calculation_breakdown JSONB,
