-- ═══════════════════════════════════════════════════
-- 7. HELPER FUNCTIONS
-- ═══════════════════════════════════════════════════

-- Generate a unique referral code for a user
CREATE OR REPLACE FUNCTION public.generate_referral_code(
  p_user_id UUID,
  p_organization_id UUID
)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_name TEXT;
  v_code TEXT;
  v_attempt INT := 0;
BEGIN
  -- Get user name prefix
  SELECT UPPER(LEFT(REGEXP_REPLACE(COALESCE(full_name, 'USER'), '[^A-Za-z]', '', 'g'), 4))
  INTO v_name
  FROM public.profiles
  WHERE id = p_user_id;

  -- Generate unique code
  LOOP
    v_code := v_name || '-' || UPPER(SUBSTR(MD5(RANDOM()::TEXT), 1, 4));
    v_attempt := v_attempt + 1;

    -- Check uniqueness
    IF NOT EXISTS (SELECT 1 FROM public.referral_codes WHERE code = v_code) THEN
      EXIT;
    END IF;

    IF v_attempt > 10 THEN
      v_code := v_name || '-' || UPPER(SUBSTR(MD5(RANDOM()::TEXT || NOW()::TEXT), 1, 6));
      EXIT;
    END IF;
  END LOOP;

  -- Insert the code
  INSERT INTO public.referral_codes (user_id, organization_id, code)
  VALUES (p_user_id, p_organization_id, v_code)
  ON CONFLICT (user_id, organization_id) DO NOTHING;

  RETURN v_code;
END;
$$;

-- Get referral stats for a user
CREATE OR REPLACE FUNCTION public.get_referral_stats(
  p_user_id UUID,
  p_organization_id UUID
)
RETURNS TABLE (
  total_referrals BIGINT,
  active_referrals BIGINT,
  converted_referrals BIGINT,
  total_earnings DECIMAL,
  pending_earnings DECIMAL,
  paid_earnings DECIMAL
)
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT
    COUNT(r.id) AS total_referrals,
    COUNT(r.id) FILTER (WHERE r.status = 'active') AS active_referrals,
    COUNT(r.id) FILTER (WHERE r.status = 'converted') AS converted_referrals,
    COALESCE(SUM(rc.commission_amount), 0) AS total_earnings,
    COALESCE(SUM(rc.commission_amount) FILTER (WHERE rc.status = 'pending' OR rc.status = 'approved'), 0) AS pending_earnings,
    COALESCE(SUM(rc.commission_amount) FILTER (WHERE rc.status = 'paid'), 0) AS paid_earnings
  FROM public.referral_codes c
  LEFT JOIN public.org_referrals r ON r.referral_code_id = c.id
  LEFT JOIN public.org_referral_commissions rc ON rc.referral_id = r.id AND rc.referrer_id = p_user_id
  WHERE c.user_id = p_user_id
    AND c.organization_id = p_organization_id;
$$;

-- Update referral code stats (denormalized counts)
CREATE OR REPLACE FUNCTION public.update_referral_code_stats()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE public.referral_codes
  SET
    total_signups = (
      SELECT COUNT(*) FROM public.org_referrals
      WHERE referral_code_id = COALESCE(NEW.referral_code_id, OLD.referral_code_id)
        AND signed_up_at IS NOT NULL
    ),
    total_conversions = (
      SELECT COUNT(*) FROM public.org_referrals
      WHERE referral_code_id = COALESCE(NEW.referral_code_id, OLD.referral_code_id)
        AND status = 'converted'
    )
  WHERE id = COALESCE(NEW.referral_code_id, OLD.referral_code_id);

  RETURN COALESCE(NEW, OLD);
END;
$$;

CREATE TRIGGER trg_update_referral_code_stats
  AFTER INSERT OR UPDATE OR DELETE ON public.org_referrals
  FOR EACH ROW EXECUTE FUNCTION public.update_referral_code_stats();

-- Update referral code earnings (denormalized)
CREATE OR REPLACE FUNCTION public.update_referral_code_earnings()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_code_id UUID;
BEGIN
  SELECT r.referral_code_id INTO v_code_id
  FROM public.org_referrals r
  WHERE r.id = COALESCE(NEW.referral_id, OLD.referral_id);

  IF v_code_id IS NOT NULL THEN
    UPDATE public.referral_codes
    SET total_earnings = (
      SELECT COALESCE(SUM(commission_amount), 0)
      FROM public.org_referral_commissions rc
      JOIN public.org_referrals r ON r.id = rc.referral_id
      WHERE r.referral_code_id = v_code_id
        AND rc.status IN ('approved', 'paid')
    )
    WHERE id = v_code_id;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;

CREATE TRIGGER trg_update_referral_earnings
  AFTER INSERT OR UPDATE OR DELETE ON public.org_referral_commissions
  FOR EACH ROW EXECUTE FUNCTION public.update_referral_code_earnings();

-- ========== 20260210300001_fix_org_services_rls.sql ==========
-- Fix org_services RLS policies
-- Problem: policies used direct subqueries against organization_members which has
-- its own heavy RLS, causing recursive RLS evaluation → 403 on both SELECT and INSERT.
-- Fix: use existing SECURITY DEFINER helper functions that bypass organization_members RLS.

-- Drop existing policies
DROP POLICY IF EXISTS "org_services_member_select" ON public.org_services;
DROP POLICY IF EXISTS "org_services_public_read" ON public.org_services;
DROP POLICY IF EXISTS "org_services_admin_insert" ON public.org_services;
DROP POLICY IF EXISTS "org_services_admin_update" ON public.org_services;
DROP POLICY IF EXISTS "org_services_admin_delete" ON public.org_services;

-- SELECT: org members can read (SECURITY DEFINER — bypasses organization_members RLS)
CREATE POLICY "org_services_member_select" ON public.org_services
  FOR SELECT USING (is_org_member(organization_id));

-- SELECT: public read for visible orgs
CREATE POLICY "org_services_public_read" ON public.org_services
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.organizations
      WHERE organizations.id = org_services.organization_id
      AND organizations.org_profile_public = true
      AND organizations.org_marketplace_visible = true
    )
  );

-- INSERT: org admins/owners (SECURITY DEFINER helpers)
CREATE POLICY "org_services_admin_insert" ON public.org_services
  FOR INSERT WITH CHECK (
    is_org_owner(auth.uid(), organization_id)
    OR is_org_configurer(auth.uid(), organization_id)
  );

-- UPDATE: org admins/owners
CREATE POLICY "org_services_admin_update" ON public.org_services
  FOR UPDATE USING (
    is_org_owner(auth.uid(), organization_id)
    OR is_org_configurer(auth.uid(), organization_id)
  );

-- DELETE: org admins/owners
CREATE POLICY "org_services_admin_delete" ON public.org_services
  FOR DELETE USING (
    is_org_owner(auth.uid(), organization_id)
    OR is_org_configurer(auth.uid(), organization_id)
  );

-- ========== 20260210400000_fix_client_content_filter.sql ==========
-- Fix: get_org_content should filter content for client role
-- Previously: creators/editors saw only their assigned content, but clients saw ALL org content
-- Now: clients only see content belonging to their associated clients (via client_users junction)

CREATE OR REPLACE FUNCTION public.get_org_content(
  p_organization_id uuid,
  p_role text DEFAULT NULL,
  p_user_id uuid DEFAULT NULL,
  p_client_id uuid DEFAULT NULL,
  p_creator_id uuid DEFAULT NULL,
  p_editor_id uuid DEFAULT NULL,
  p_limit integer DEFAULT 500
)
RETURNS SETOF content
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_is_member boolean := false;
BEGIN
  -- Check org membership (roles table)
  SELECT EXISTS(
    SELECT 1 FROM organization_member_roles
    WHERE organization_id = p_organization_id AND user_id = v_uid
  ) INTO v_is_member;

  -- Check client_users junction (client access)
  IF NOT v_is_member THEN
    SELECT EXISTS(
      SELECT 1 FROM client_users cu
      JOIN clients c ON c.id = cu.client_id
      WHERE c.organization_id = p_organization_id AND cu.user_id = v_uid
    ) INTO v_is_member;
  END IF;

  -- Platform root fallback
  IF NOT v_is_member THEN
    SELECT EXISTS(
      SELECT 1 FROM auth.users
      WHERE id = v_uid AND email IN ('alexander@kreoon.com', 'admin@kreoon.com')
    ) INTO v_is_member;
  END IF;

  IF NOT v_is_member THEN
    RETURN;
  END IF;

  RETURN QUERY
    SELECT * FROM content c
    WHERE c.organization_id = p_organization_id
      AND (p_client_id IS NULL OR c.client_id = p_client_id)
      AND (p_creator_id IS NULL OR c.creator_id = p_creator_id)
      AND (p_editor_id IS NULL OR c.editor_id = p_editor_id)
      -- Role-based filtering
      AND (
        p_role IS NULL
        OR p_role NOT IN ('creator', 'editor', 'client')
        OR (p_role = 'creator' AND c.creator_id = p_user_id)
        OR (p_role = 'editor' AND c.editor_id = p_user_id)
        OR (p_role = 'client' AND c.client_id IN (
          SELECT cu.client_id FROM client_users cu WHERE cu.user_id = p_user_id
        ))
      )
    ORDER BY c.created_at DESC
    LIMIT p_limit;
END;
$function$;

-- ========== 20260210500000_fix_content_update_rls.sql ==========
-- Fix: Replace heavy ALL policies on content table with fast SECURITY DEFINER versions
-- Root cause: "Org members can manage content" calls get_my_organization_ids() (returns SET, re-evaluated per row)
--             "Platform admins can manage content" calls has_role() + get_current_organization_id() multiple times
-- These block ALL direct .from('content').update() calls (30+ across the codebase)

-- Step 0: Create is_content_org_member() that checks ALL membership tables
-- (organization_member_roles has 103 rows vs organization_members 83 rows — 15 users only in roles table)
CREATE OR REPLACE FUNCTION public.is_content_org_member(_user_id uuid, _org_id uuid)
RETURNS boolean
LANGUAGE sql STABLE SECURITY DEFINER
SET search_path TO 'public'
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.organization_member_roles
    WHERE user_id = _user_id AND organization_id = _org_id
  ) OR EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE user_id = _user_id AND organization_id = _org_id
  ) OR EXISTS (
    SELECT 1 FROM public.client_users cu
    JOIN public.clients c ON c.id = cu.client_id
    WHERE cu.user_id = _user_id AND c.organization_id = _org_id
  )
$$;

-- Step 1: Drop the two heavy ALL policies
DROP POLICY IF EXISTS "Org members can manage content" ON public.content;
DROP POLICY IF EXISTS "Platform admins can manage content in current org" ON public.content;

-- Also drop any previous versions of these policies (from earlier migration attempt)
DROP POLICY IF EXISTS "content_org_member_select" ON public.content;
DROP POLICY IF EXISTS "content_org_member_insert" ON public.content;
DROP POLICY IF EXISTS "content_org_member_update" ON public.content;
DROP POLICY IF EXISTS "content_org_member_delete" ON public.content;

-- Step 2: Add fast replacements using is_content_org_member() (single indexed EXISTS per row)

-- SELECT: org members can see their org's content
CREATE POLICY "content_org_member_select" ON public.content
  FOR SELECT
  USING (
    is_content_org_member(auth.uid(), organization_id)
    OR (organization_id IS NULL AND client_id IS NOT NULL AND EXISTS (
      SELECT 1 FROM clients c
      JOIN organization_members om ON om.organization_id = c.organization_id
      WHERE c.id = content.client_id AND om.user_id = auth.uid()
    ))
  );

-- INSERT: org members can create content in their org
CREATE POLICY "content_org_member_insert" ON public.content
  FOR INSERT
  WITH CHECK (
    is_content_org_member(auth.uid(), organization_id)
  );

-- UPDATE: org members can update content in their org
CREATE POLICY "content_org_member_update" ON public.content
  FOR UPDATE
  USING (
    is_content_org_member(auth.uid(), organization_id)
    OR (organization_id IS NULL AND client_id IS NOT NULL AND EXISTS (
      SELECT 1 FROM clients c
      JOIN organization_members om ON om.organization_id = c.organization_id
      WHERE c.id = content.client_id AND om.user_id = auth.uid()
    ))
  );

-- DELETE: org members can delete content in their org
CREATE POLICY "content_org_member_delete" ON public.content
  FOR DELETE
  USING (
    is_content_org_member(auth.uid(), organization_id)
    OR (organization_id IS NULL AND client_id IS NOT NULL AND EXISTS (
      SELECT 1 FROM clients c
      JOIN organization_members om ON om.organization_id = c.organization_id
      WHERE c.id = content.client_id AND om.user_id = auth.uid()
    ))
  );

-- ========== 20260210600000_fix_emit_up_event_409_conflict.sql ==========
-- Fix: 409 Conflict error when changing content status
-- Root cause: Two triggers (trigger_up_event_on_status, trigger_up_events_on_content)
-- both fire on content UPDATE and call emit_up_event() with overlapping event types
-- (content_delivered, content_approved, correction_requested).
-- Both INSERTs hit the dedup unique index:
--   idx_up_events_dedup ON up_events (user_id, content_id, event_type_key) WHERE content_id IS NOT NULL
-- Second INSERT fails with 409 (unique constraint violation).
--
-- Fix: Add ON CONFLICT DO NOTHING to both emit_up_event overloads.
-- Duplicate events are silently skipped, no points double-counted.

-- Overload 1: 8-param version (called by emit_up_event_on_status_change trigger)
CREATE OR REPLACE FUNCTION public.emit_up_event(
  _org_id uuid,
  _user_id uuid,
  _event_type_key text,
  _content_id uuid DEFAULT NULL::uuid,
  _event_data jsonb DEFAULT '{}'::jsonb,
  _ai_inferred boolean DEFAULT false,
  _ai_confidence numeric DEFAULT NULL::numeric,
  _ai_evidence jsonb DEFAULT NULL::jsonb
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  event_id uuid;
  rule_rec RECORD;
  total_points integer := 0;
  can_apply boolean;
  events_today integer;
  events_week integer;
  events_content integer;
BEGIN
  -- Insert the event (skip if duplicate per dedup index)
  INSERT INTO public.up_events (
    organization_id, user_id, content_id, event_type_key,
    event_data, ai_inferred, ai_confidence, ai_evidence
  )
  VALUES (
    _org_id, _user_id, _content_id, _event_type_key,
    _event_data, _ai_inferred, _ai_confidence, _ai_evidence
  )
  ON CONFLICT (user_id, content_id, event_type_key) WHERE content_id IS NOT NULL DO NOTHING
  RETURNING id INTO event_id;

  -- If event was a duplicate, skip processing
  IF event_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Find matching rules and calculate points
  FOR rule_rec IN
    SELECT * FROM public.up_rules
    WHERE organization_id = _org_id
      AND event_type_key = _event_type_key
      AND is_active = true
    ORDER BY priority DESC
  LOOP
    can_apply := true;

    -- Check daily limit
    IF rule_rec.max_per_day IS NOT NULL THEN
      SELECT COUNT(*) INTO events_today
      FROM public.up_events
      WHERE user_id = _user_id
        AND rule_id = rule_rec.id
        AND created_at > now() - interval '1 day';

      IF events_today >= rule_rec.max_per_day THEN
        can_apply := false;
      END IF;
    END IF;

    -- Check weekly limit
    IF can_apply AND rule_rec.max_per_week IS NOT NULL THEN
      SELECT COUNT(*) INTO events_week
      FROM public.up_events
      WHERE user_id = _user_id
        AND rule_id = rule_rec.id
        AND created_at > now() - interval '7 days';

      IF events_week >= rule_rec.max_per_week THEN
        can_apply := false;
      END IF;
    END IF;

    -- Check per-content limit
    IF can_apply AND rule_rec.max_per_content IS NOT NULL AND _content_id IS NOT NULL THEN
      SELECT COUNT(*) INTO events_content
      FROM public.up_events
      WHERE user_id = _user_id
        AND content_id = _content_id
        AND rule_id = rule_rec.id;

      IF events_content >= rule_rec.max_per_content THEN
        can_apply := false;
      END IF;
    END IF;

    -- Apply rule if all checks pass
    IF can_apply THEN
      total_points := total_points + rule_rec.points;

      -- Update event with rule info
      UPDATE public.up_events
      SET rule_id = rule_rec.id, points_awarded = rule_rec.points, processed_at = now()
      WHERE id = event_id;

      -- Add to point_transactions for backward compatibility
      INSERT INTO public.point_transactions (user_id, content_id, transaction_type, points, description)
      VALUES (
        _user_id,
        _content_id,
        CASE WHEN rule_rec.points >= 0 THEN 'base_completion' ELSE 'correction_needed' END,
        rule_rec.points,
        rule_rec.name || ' (' || _event_type_key || ')'
      );

      -- Update user_points
      UPDATE public.user_points
      SET
        total_points = GREATEST(0, user_points.total_points + rule_rec.points),
        updated_at = now()
      WHERE user_points.user_id = _user_id;

      EXIT; -- Apply only first matching rule (highest priority)
    END IF;
  END LOOP;

  RETURN event_id;
END;
$function$;

-- Overload 2: 4-param version (called by trigger_emit_up_event_on_status trigger)
CREATE OR REPLACE FUNCTION public.emit_up_event(
  _event_type_key text,
  _user_id uuid,
  _content_id uuid DEFAULT NULL::uuid,
  _event_data jsonb DEFAULT '{}'::jsonb
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  event_id uuid;
  org_id uuid;
  matched_rule RECORD;
  total_points integer := 0;
  rule_applied_id uuid;
  today_count integer;
  week_count integer;
  content_count integer;
BEGIN
  -- Get organization_id from content or user's current org
  IF _content_id IS NOT NULL THEN
    SELECT organization_id INTO org_id FROM public.content WHERE id = _content_id;
  END IF;

  IF org_id IS NULL THEN
    SELECT om.organization_id INTO org_id
    FROM public.organization_members om
    WHERE om.user_id = _user_id
    LIMIT 1;
  END IF;

  IF org_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Find matching rules for this event type
  FOR matched_rule IN
    SELECT * FROM public.up_rules
    WHERE organization_id = org_id
      AND event_type_key = _event_type_key
      AND is_active = true
    ORDER BY priority DESC
  LOOP
    -- Check daily limit
    IF matched_rule.max_per_day IS NOT NULL AND matched_rule.max_per_day > 0 THEN
      SELECT COUNT(*) INTO today_count
      FROM public.up_events
      WHERE user_id = _user_id
        AND rule_id = matched_rule.id
        AND created_at >= CURRENT_DATE;

      IF today_count >= matched_rule.max_per_day THEN
        CONTINUE;
      END IF;
    END IF;

    -- Check weekly limit
    IF matched_rule.max_per_week IS NOT NULL AND matched_rule.max_per_week > 0 THEN
      SELECT COUNT(*) INTO week_count
      FROM public.up_events
      WHERE user_id = _user_id
        AND rule_id = matched_rule.id
        AND created_at >= date_trunc('week', CURRENT_DATE);

      IF week_count >= matched_rule.max_per_week THEN
        CONTINUE;
      END IF;
    END IF;

    -- Check per-content limit
    IF _content_id IS NOT NULL AND matched_rule.max_per_content IS NOT NULL AND matched_rule.max_per_content > 0 THEN
      SELECT COUNT(*) INTO content_count
      FROM public.up_events
      WHERE user_id = _user_id
        AND rule_id = matched_rule.id
        AND content_id = _content_id;

      IF content_count >= matched_rule.max_per_content THEN
        CONTINUE;
      END IF;
    END IF;

    -- Apply points (negative for penalties)
    total_points := CASE WHEN matched_rule.is_penalty THEN -matched_rule.points ELSE matched_rule.points END;
    rule_applied_id := matched_rule.id;
    EXIT; -- Use first matching rule only
  END LOOP;

  -- Insert the event (skip if duplicate per dedup index)
  INSERT INTO public.up_events (
    organization_id,
    user_id,
    content_id,
    event_type_key,
    event_data,
    points_awarded,
    rule_id,
    ai_inferred,
    ai_confidence
  ) VALUES (
    org_id,
    _user_id,
    _content_id,
    _event_type_key,
    _event_data,
    COALESCE(total_points, 0),
    rule_applied_id,
    false,
    NULL
  )
  ON CONFLICT (user_id, content_id, event_type_key) WHERE content_id IS NOT NULL DO NOTHING
  RETURNING id INTO event_id;

  -- If event was a duplicate, skip point updates
  IF event_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Update user points if points were awarded
  IF total_points != 0 THEN
    INSERT INTO public.point_transactions (user_id, content_id, transaction_type, points, description)
    VALUES (_user_id, _content_id, 'manual_adjustment'::point_transaction_type, total_points, 'UP Engine: ' || _event_type_key);

    UPDATE public.user_points
    SET
      total_points = GREATEST(0, total_points + total_points),
      current_level = public.calculate_up_level(GREATEST(0, user_points.total_points + total_points)),
      updated_at = now()
    WHERE user_id = _user_id;
  END IF;

  RETURN event_id;
END;
$function$;

-- ========== 20260211000000_client_dna.sql ==========
-- ADN del Cliente: captura la identidad de marca via audio + IA
-- Gemini para transcripción + análisis emocional, Perplexity para ADN estratégico

CREATE TABLE public.client_dna (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  client_id UUID NOT NULL REFERENCES public.clients(id) ON DELETE CASCADE,

  -- Transcripción y análisis emocional de Gemini
  transcription TEXT,
  emotional_analysis JSONB DEFAULT '{}'::jsonb,

  -- Ubicaciones seleccionadas
  audience_locations JSONB DEFAULT '[]'::jsonb,

  -- ADN generado por Perplexity
  dna_data JSONB NOT NULL DEFAULT '{}'::jsonb,

  -- Versionamiento
  version INTEGER NOT NULL DEFAULT 1,
  status TEXT NOT NULL DEFAULT 'completed'
    CHECK (status IN ('processing', 'completed', 'error')),

  -- Solo un ADN activo por cliente
  is_active BOOLEAN NOT NULL DEFAULT true,

  -- Timestamps
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Indexes
CREATE INDEX idx_client_dna_client ON public.client_dna(client_id);
CREATE INDEX idx_client_dna_active ON public.client_dna(client_id, is_active) WHERE is_active = true;
CREATE UNIQUE INDEX idx_unique_active_dna_per_client ON public.client_dna(client_id) WHERE is_active = true;

-- RLS
ALTER TABLE public.client_dna ENABLE ROW LEVEL SECURITY;

-- Org admins/owners have full access via clients → organization_members
CREATE POLICY "Org admins can manage DNA" ON public.client_dna
  FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.clients c
      JOIN public.organization_members om ON om.organization_id = c.organization_id
      WHERE c.id = client_dna.client_id
        AND om.user_id = auth.uid()
        AND (om.role = 'admin' OR om.is_owner = true)
    )
  );

-- Any org member can view DNA (for collaboration)
CREATE POLICY "Org members can view DNA" ON public.client_dna
  FOR SELECT TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.clients c
      JOIN public.organization_members om ON om.organization_id = c.organization_id
      WHERE c.id = client_dna.client_id
        AND om.user_id = auth.uid()
    )
  );

-- Client users (via client_users junction) can manage their own DNA
CREATE POLICY "Client users can manage own DNA" ON public.client_dna
  FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.client_users cu
      WHERE cu.client_id = client_dna.client_id
        AND cu.user_id = auth.uid()
    )
  );

-- Grant permissions
GRANT SELECT, INSERT, UPDATE, DELETE ON public.client_dna TO authenticated;
GRANT ALL ON public.client_dna TO service_role;

-- Auto-update updated_at
CREATE TRIGGER update_client_dna_updated_at
  BEFORE UPDATE ON public.client_dna
  FOR EACH ROW
  EXECUTE FUNCTION public.update_updated_at();

-- ========== 20260211000001_video_hashes_dedup.sql ==========
-- Video deduplication: prevent same video from being uploaded multiple times to Bunny Stream.
-- Uses a partial file hash (first 2MB + last 2MB + file size) for fast fingerprinting.
-- Client computes hash → checks via RPC → if match, reuses existing embed_url.
-- Edge function saves hash after successful upload.

CREATE TABLE IF NOT EXISTS public.video_hashes (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  file_hash text NOT NULL UNIQUE,
  file_size bigint NOT NULL,
  bunny_video_id text NOT NULL,
  embed_url text NOT NULL,
  thumbnail_url text,
  mp4_url text,
  created_by uuid REFERENCES auth.users(id),
  created_at timestamptz DEFAULT now() NOT NULL
);

CREATE INDEX idx_video_hashes_created_at ON public.video_hashes(created_at DESC);

-- RLS enabled but no direct policies needed:
-- Reads go through SECURITY DEFINER RPC, writes go through edge function (service role)
ALTER TABLE public.video_hashes ENABLE ROW LEVEL SECURITY;

-- RPC for client-side dedup check (any authenticated user can check)
CREATE OR REPLACE FUNCTION public.check_video_hash(p_file_hash text)
RETURNS TABLE(embed_url text, thumbnail_url text, bunny_video_id text)
LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public'
AS $$
  SELECT vh.embed_url, vh.thumbnail_url, vh.bunny_video_id
  FROM public.video_hashes vh
  WHERE vh.file_hash = p_file_hash
  LIMIT 1;
$$;

GRANT EXECUTE ON FUNCTION public.check_video_hash(text) TO authenticated;
GRANT SELECT, INSERT ON public.video_hashes TO service_role;

-- ========== 20260211100000_expand_video_service_types.sql ==========
