GRANT USAGE, SELECT ON SEQUENCE invoice_number_seq TO authenticated;

-- ========== 20260216960000_create_finance_functions.sql ==========
-- =====================================================
-- KREOON FINANCE MODULE - FUNCTIONS
-- Migration: 20260216960000_create_finance_functions
-- Functions: get_platform_finance_stats,
--            get_org_finance_stats,
--            get_creator_finance_stats,
--            request_creator_payout,
--            get_revenue_by_month
-- =====================================================

-- =====================================================
-- 1. get_platform_finance_stats
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_finance_stats(p_days INTEGER DEFAULT 30)
RETURNS JSON
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSON;
    start_date TIMESTAMPTZ := NOW() - (p_days || ' days')::INTERVAL;
    prev_start_date TIMESTAMPTZ := NOW() - (p_days * 2 || ' days')::INTERVAL;
BEGIN
    SELECT json_build_object(
        -- MRR (Monthly Recurring Revenue)
        'mrr', COALESCE((
            SELECT SUM(amount_monthly)
            FROM platform_subscriptions
            WHERE status = 'active'
        ), 0),

        -- ARR (Annual Recurring Revenue)
        'arr', COALESCE((
            SELECT SUM(amount_monthly) * 12
            FROM platform_subscriptions
            WHERE status = 'active'
        ), 0),

        -- Ingresos del período
        'revenue_period', COALESCE((
            SELECT SUM(amount)
            FROM platform_transactions
            WHERE transaction_type IN ('subscription_payment', 'campaign_payment', 'platform_fee')
            AND status = 'completed'
            AND created_at >= start_date
        ), 0),

        -- Ingresos período anterior (para comparar)
        'revenue_previous', COALESCE((
            SELECT SUM(amount)
            FROM platform_transactions
            WHERE transaction_type IN ('subscription_payment', 'campaign_payment', 'platform_fee')
            AND status = 'completed'
            AND created_at >= prev_start_date
            AND created_at < start_date
        ), 0),

        -- Pagos a creadores del período
        'payouts_period', COALESCE((
            SELECT SUM(net_amount)
            FROM platform_payouts
            WHERE status = 'completed'
            AND completed_at >= start_date
        ), 0),

        -- Pagos pendientes a creadores
        'payouts_pending', COALESCE((
            SELECT SUM(net_amount)
            FROM platform_payouts
            WHERE status IN ('pending', 'approved', 'processing')
        ), 0),

        -- Facturas por cobrar
        'invoices_pending_amount', COALESCE((
            SELECT SUM(total)
            FROM platform_invoices
            WHERE status IN ('sent', 'overdue')
        ), 0),

        'invoices_pending_count', (
            SELECT COUNT(*)
            FROM platform_invoices
            WHERE status IN ('sent', 'overdue')
        ),

        -- Facturas vencidas
        'invoices_overdue_amount', COALESCE((
            SELECT SUM(total)
            FROM platform_invoices
            WHERE status = 'overdue'
        ), 0),

        'invoices_overdue_count', (
            SELECT COUNT(*)
            FROM platform_invoices
            WHERE status = 'overdue'
        ),

        -- Suscripciones por plan
        'subscriptions_by_plan', (
            SELECT COALESCE(json_agg(json_build_object('plan', plan, 'count', count, 'mrr', mrr)), '[]'::json)
            FROM (
                SELECT plan, COUNT(*) as count, SUM(amount_monthly) as mrr
                FROM platform_subscriptions
                WHERE status = 'active'
                GROUP BY plan
            ) s
        ),

        -- Transacciones del período
        'transactions_count', (
            SELECT COUNT(*)
            FROM platform_transactions
            WHERE created_at >= start_date
        ),

        -- Comisiones ganadas
        'fees_earned', COALESCE((
            SELECT SUM(fee_amount)
            FROM platform_transactions
            WHERE status = 'completed'
            AND created_at >= start_date
        ), 0)
    ) INTO result;

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_platform_finance_stats(INTEGER) TO authenticated;

-- =====================================================
-- 2. get_org_finance_stats
-- =====================================================

CREATE OR REPLACE FUNCTION get_org_finance_stats(p_org_id UUID, p_days INTEGER DEFAULT 30)
RETURNS JSON
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSON;
    start_date TIMESTAMPTZ := NOW() - (p_days || ' days')::INTERVAL;
BEGIN
    SELECT json_build_object(
        -- Total gastado histórico
        'total_spent', COALESCE((
            SELECT SUM(amount)
            FROM platform_transactions
            WHERE organization_id = p_org_id
            AND transaction_type IN ('campaign_payment', 'subscription_payment')
            AND status = 'completed'
        ), 0),

        -- Gastado en el período
        'spent_period', COALESCE((
            SELECT SUM(amount)
            FROM platform_transactions
            WHERE organization_id = p_org_id
            AND transaction_type IN ('campaign_payment', 'subscription_payment')
            AND status = 'completed'
            AND created_at >= start_date
        ), 0),

        -- Pagado a creadores histórico
        'total_paid_creators', COALESCE((
            SELECT SUM(total_paid)
            FROM org_creator_relationships
            WHERE organization_id = p_org_id
        ), 0),

        -- Suscripción actual
        'subscription', (
            SELECT json_build_object(
                'plan', plan,
                'status', status,
                'amount_monthly', amount_monthly,
                'current_period_end', current_period_end,
                'days_until_renewal', EXTRACT(DAY FROM current_period_end - NOW())
            )
            FROM platform_subscriptions
            WHERE organization_id = p_org_id
            LIMIT 1
        ),

        -- Facturas pendientes
        'invoices_pending', COALESCE((
            SELECT SUM(total)
            FROM platform_invoices
            WHERE organization_id = p_org_id
            AND status IN ('sent', 'overdue')
        ), 0),

        'invoices_pending_count', (
            SELECT COUNT(*)
            FROM platform_invoices
            WHERE organization_id = p_org_id
            AND status IN ('sent', 'overdue')
        ),

        -- Última factura pagada
        'last_payment', (
            SELECT json_build_object(
                'amount', total,
                'paid_at', paid_at
            )
            FROM platform_invoices
            WHERE organization_id = p_org_id
            AND status = 'paid'
            ORDER BY paid_at DESC
            LIMIT 1
        ),

        -- Transacciones recientes count
        'transactions_count_period', (
            SELECT COUNT(*)
            FROM platform_transactions
            WHERE organization_id = p_org_id
            AND created_at >= start_date
        ),

        -- Campañas pagadas
        'campaigns_paid_count', (
            SELECT COUNT(DISTINCT campaign_id)
            FROM platform_transactions
            WHERE organization_id = p_org_id
            AND transaction_type = 'campaign_payment'
            AND status = 'completed'
        )
    ) INTO result;

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_org_finance_stats(UUID, INTEGER) TO authenticated;

-- =====================================================
-- 3. get_creator_finance_stats
-- =====================================================

CREATE OR REPLACE FUNCTION get_creator_finance_stats(p_creator_id UUID)
RETURNS JSON
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSON;
BEGIN
    SELECT json_build_object(
        -- Wallet info
        'wallet', (
            SELECT json_build_object(
                'available_balance', available_balance,
                'pending_balance', pending_balance,
                'total_earned', total_earned,
                'total_withdrawn', total_withdrawn,
                'minimum_payout', minimum_payout,
                'payment_info_verified', payment_info_verified
            )
            FROM creator_wallets
            WHERE creator_id = p_creator_id
        ),

        -- Ganancias este mes
        'earnings_this_month', COALESCE((
            SELECT SUM(amount)
            FROM creator_wallet_transactions
            WHERE creator_id = p_creator_id
            AND transaction_type IN ('earning', 'bonus', 'referral_bonus')
            AND created_at >= DATE_TRUNC('month', NOW())
        ), 0),

        -- Ganancias mes pasado
        'earnings_last_month', COALESCE((
            SELECT SUM(amount)
            FROM creator_wallet_transactions
            WHERE creator_id = p_creator_id
            AND transaction_type IN ('earning', 'bonus', 'referral_bonus')
            AND created_at >= DATE_TRUNC('month', NOW() - INTERVAL '1 month')
            AND created_at < DATE_TRUNC('month', NOW())
        ), 0),

        -- Payouts completados
        'total_payouts', (
            SELECT COUNT(*)
            FROM platform_payouts
            WHERE creator_id = p_creator_id
            AND status = 'completed'
        ),

        -- Último payout
        'last_payout', (
            SELECT json_build_object(
                'amount', net_amount,
                'completed_at', completed_at,
                'payment_method', payment_method
            )
            FROM platform_payouts
            WHERE creator_id = p_creator_id
            AND status = 'completed'
            ORDER BY completed_at DESC
            LIMIT 1
        ),

        -- Payout pendiente
        'pending_payout', (
            SELECT json_build_object(
                'id', id,
                'amount', net_amount,
                'status', status,
                'requested_at', requested_at
            )
            FROM platform_payouts
            WHERE creator_id = p_creator_id
            AND status IN ('pending', 'approved', 'processing')
            LIMIT 1
        ),

        -- Ganancias por tipo
        'earnings_by_type', (
            SELECT COALESCE(json_agg(json_build_object('type', transaction_type, 'total', total)), '[]'::json)
            FROM (
                SELECT transaction_type, SUM(amount) as total
                FROM creator_wallet_transactions
                WHERE creator_id = p_creator_id
                AND amount > 0
                GROUP BY transaction_type
            ) t
        )
    ) INTO result;

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_creator_finance_stats(UUID) TO authenticated;

-- =====================================================
-- 4. request_creator_payout
-- =====================================================

CREATE OR REPLACE FUNCTION request_creator_payout(
    p_creator_id UUID,
    p_amount DECIMAL(12,2),
    p_payment_method TEXT
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_wallet creator_wallets%ROWTYPE;
    v_payout_id UUID;
    v_platform_fee DECIMAL(12,2);
BEGIN
    -- Obtener wallet
    SELECT * INTO v_wallet
    FROM creator_wallets
    WHERE creator_id = p_creator_id;

    IF NOT FOUND THEN
        RETURN json_build_object('success', false, 'error', 'Wallet no encontrado');
    END IF;

    -- Verificar balance disponible
    IF v_wallet.available_balance < p_amount THEN
        RETURN json_build_object('success', false, 'error', 'Balance insuficiente');
    END IF;

    -- Verificar mínimo
    IF p_amount < v_wallet.minimum_payout THEN
        RETURN json_build_object('success', false, 'error', 'Monto menor al mínimo permitido');
    END IF;

    -- Verificar que no hay payout pendiente
    IF EXISTS (
        SELECT 1 FROM platform_payouts
        WHERE creator_id = p_creator_id
        AND status IN ('pending', 'approved', 'processing')
    ) THEN
        RETURN json_build_object('success', false, 'error', 'Ya tienes un pago en proceso');
    END IF;

    -- Calcular comisión (5%)
    v_platform_fee := p_amount * 0.05;

    -- Crear payout
    INSERT INTO platform_payouts (
        creator_id,
        gross_amount,
        platform_fee,
        payment_method,
        status
    ) VALUES (
        p_creator_id,
        p_amount,
        v_platform_fee,
        p_payment_method,
        'pending'
    ) RETURNING id INTO v_payout_id;

    -- Actualizar wallet (restar del disponible, añadir a pending)
    UPDATE creator_wallets
    SET
        available_balance = available_balance - p_amount,
        pending_balance = pending_balance + p_amount,
        updated_at = NOW()
    WHERE creator_id = p_creator_id;

    -- Registrar transacción en wallet
    INSERT INTO creator_wallet_transactions (
        wallet_id,
        creator_id,
        transaction_type,
        amount,
        balance_after,
        description,
        payout_id
    ) VALUES (
        v_wallet.id,
        p_creator_id,
        'payout_request',
        -p_amount,
        v_wallet.available_balance - p_amount,
        'Solicitud de pago #' || v_payout_id::TEXT,
        v_payout_id
    );

    RETURN json_build_object(
        'success', true,
        'payout_id', v_payout_id,
        'net_amount', p_amount - v_platform_fee
    );
END;
$$;

GRANT EXECUTE ON FUNCTION request_creator_payout(UUID, DECIMAL, TEXT) TO authenticated;

-- =====================================================
-- 5. get_revenue_by_month
-- =====================================================

CREATE OR REPLACE FUNCTION get_revenue_by_month(p_months INTEGER DEFAULT 12)
RETURNS TABLE (
    month TEXT,
    revenue DECIMAL(12,2),
    payouts DECIMAL(12,2),
    net DECIMAL(12,2)
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    RETURN QUERY
    WITH months AS (
        SELECT generate_series(
            DATE_TRUNC('month', NOW() - (p_months || ' months')::INTERVAL),
            DATE_TRUNC('month', NOW()),
            '1 month'::INTERVAL
        ) AS month_start
    ),
    revenue_data AS (
        SELECT
            DATE_TRUNC('month', pt.created_at) as m,
            SUM(CASE WHEN pt.transaction_type IN ('subscription_payment', 'campaign_payment', 'platform_fee')
                THEN pt.amount ELSE 0 END) as rev,
            SUM(CASE WHEN pt.transaction_type = 'creator_payout'
                THEN pt.amount ELSE 0 END) as pay
        FROM platform_transactions pt
        WHERE pt.status = 'completed'
        AND pt.created_at >= DATE_TRUNC('month', NOW() - (p_months || ' months')::INTERVAL)
        GROUP BY DATE_TRUNC('month', pt.created_at)
    )
    SELECT
        TO_CHAR(ms.month_start, 'Mon YY') as month,
        COALESCE(r.rev, 0)::DECIMAL(12,2) as revenue,
        COALESCE(r.pay, 0)::DECIMAL(12,2) as payouts,
        (COALESCE(r.rev, 0) - COALESCE(r.pay, 0))::DECIMAL(12,2) as net
    FROM months ms
    LEFT JOIN revenue_data r ON ms.month_start = r.m
    ORDER BY ms.month_start;
END;
$$;

GRANT EXECUTE ON FUNCTION get_revenue_by_month(INTEGER) TO authenticated;

-- ========== 20260217100000_kreoon_analytics_engine.sql ==========
-- ============================================================
-- KREOON ANALYTICS ENGINE (KAE) - Database Schema
-- Migration: 20260217100000_kreoon_analytics_engine.sql
--
-- Replaces the old KTE (Kreoon Tracking Engine) with a
-- server-side analytics system supporting:
-- - Identity resolution (anonymous_id → user_id)
-- - UTM & click ID capture (fbclid, gclid, ttclid, li_fat_id)
-- - Server-side event forwarding (Meta CAPI, TikTok, Google, LinkedIn)
-- - Conversion funnel tracking
-- ============================================================

-- 1. VISITORS TABLE (pre-signup identity resolution)
CREATE TABLE IF NOT EXISTS public.kae_visitors (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    anonymous_id TEXT NOT NULL UNIQUE,

    -- First Touch Attribution
    first_utm_source TEXT,
    first_utm_medium TEXT,
    first_utm_campaign TEXT,
    first_utm_content TEXT,
    first_utm_term TEXT,
    first_referrer TEXT,
    first_landing_page TEXT,

    -- Click IDs (for ad platform matching)
    fbclid TEXT,
    ttclid TEXT,
    gclid TEXT,
    li_fat_id TEXT,

    -- Platform identifiers (browser cookies/pixels)
    fbc TEXT,
    fbp TEXT,
    ttp TEXT,

    -- Device & Geo (enriched server-side)
    user_agent TEXT,
    device_type TEXT,
    browser TEXT,
    os TEXT,
    country TEXT,
    region TEXT,
    city TEXT,
    ip_hash TEXT,

    -- Identity resolution
    user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    converted_at TIMESTAMPTZ,

    -- Timestamps
    first_seen_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    last_seen_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 2. SESSIONS TABLE
CREATE TABLE IF NOT EXISTS public.kae_sessions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    anonymous_id TEXT NOT NULL REFERENCES public.kae_visitors(anonymous_id) ON DELETE CASCADE,
    user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    session_id TEXT NOT NULL UNIQUE,

    -- Session-level Attribution (may differ from first touch)
    utm_source TEXT,
    utm_medium TEXT,
    utm_campaign TEXT,
    utm_content TEXT,
    utm_term TEXT,
    referrer TEXT,
    landing_page TEXT,

    -- Session metrics (updated by kae-event-router)
    page_views INTEGER NOT NULL DEFAULT 0,
    events_count INTEGER NOT NULL DEFAULT 0,
    duration_seconds INTEGER NOT NULL DEFAULT 0,

    -- Device & Geo
    device_type TEXT,
    browser TEXT,
    os TEXT,
    country TEXT,
    city TEXT,

    -- Timestamps
    started_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    ended_at TIMESTAMPTZ,
    last_activity_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 3. EVENTS TABLE (PARTITIONED by month)
-- NOTE: PRIMARY KEY must include partition key (created_at)
CREATE TABLE IF NOT EXISTS public.kae_events (
    id UUID NOT NULL DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    -- Identity
    anonymous_id TEXT NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    session_id TEXT,

    -- Event
    event_name TEXT NOT NULL,
    event_category TEXT NOT NULL DEFAULT 'interaction',

    -- Event properties (flexible JSONB)
    properties JSONB DEFAULT '{}'::jsonb,

    -- Page context
    page_url TEXT,
    page_path TEXT,
    page_title TEXT,
    page_referrer TEXT,

    -- Device
    device_type TEXT,
    browser TEXT,
    os TEXT,
    screen_width INTEGER,
    screen_height INTEGER,

    -- Geo
    country TEXT,
    region TEXT,
    city TEXT,

    -- Server-side forwarding status
    sent_to_meta BOOLEAN NOT NULL DEFAULT FALSE,
    sent_to_tiktok BOOLEAN NOT NULL DEFAULT FALSE,
    sent_to_google BOOLEAN NOT NULL DEFAULT FALSE,
    sent_to_linkedin BOOLEAN NOT NULL DEFAULT FALSE,

    -- Client timestamp (may differ from server created_at)
    client_timestamp TIMESTAMPTZ,

    PRIMARY KEY (id, created_at)
) PARTITION BY RANGE (created_at);

-- Create 12 monthly partitions
DO $$
DECLARE
    start_date DATE := DATE_TRUNC('month', CURRENT_DATE);
    partition_date DATE;
    partition_name TEXT;
BEGIN
    FOR i IN 0..12 LOOP
        partition_date := start_date + (i || ' months')::INTERVAL;
        partition_name := 'kae_events_' || TO_CHAR(partition_date, 'YYYY_MM');

        EXECUTE format(
            'CREATE TABLE IF NOT EXISTS public.%I PARTITION OF public.kae_events
             FOR VALUES FROM (%L) TO (%L)',
            partition_name,
            partition_date,
            partition_date + INTERVAL '1 month'
        );
    END LOOP;
END $$;

-- 4. CONVERSIONS TABLE (high-value funnel events)
-- NOTE: event_id has NO FK to kae_events (can't FK to partitioned table with composite PK)
CREATE TABLE IF NOT EXISTS public.kae_conversions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    -- Identity
    anonymous_id TEXT NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,

    -- Reference to source event (no FK, application-level integrity)
    event_id UUID,
    event_created_at TIMESTAMPTZ,

    -- Conversion type (funnel steps)
    conversion_type TEXT NOT NULL CHECK (conversion_type IN (
        'page_view',
        'signup',
        'trial_start',
        'subscription',
        'content_created'
    )),

    -- Value
    value_usd DECIMAL(10,2),
    currency TEXT DEFAULT 'USD',

    -- Attribution snapshot at conversion time
    attributed_source TEXT,
    attributed_medium TEXT,
    attributed_campaign TEXT,
    attribution_model TEXT NOT NULL DEFAULT 'last_touch',

    -- Click IDs for server-side tracking
    fbclid TEXT,
    ttclid TEXT,
    gclid TEXT,
    li_fat_id TEXT,

    -- Server-side tracking response IDs
    meta_event_id TEXT,
    tiktok_event_id TEXT,
    google_conversion_id TEXT,
    linkedin_event_id TEXT,

    -- Timestamps
    converted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 5. AD PLATFORMS CONFIG (global, no org_id)
CREATE TABLE IF NOT EXISTS public.kae_ad_platforms (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    platform TEXT NOT NULL UNIQUE CHECK (platform IN (
        'meta', 'tiktok', 'google', 'linkedin'
    )),

    enabled BOOLEAN NOT NULL DEFAULT FALSE,

    -- Credentials
    pixel_id TEXT,
    access_token TEXT,
    dataset_id TEXT,
    api_version TEXT,

    -- Testing
    test_mode BOOLEAN NOT NULL DEFAULT TRUE,
    test_event_code TEXT,

    -- Event mapping (KAE event → platform event name)
    event_mapping JSONB NOT NULL DEFAULT '{
        "signup": "CompleteRegistration",
        "trial_start": "StartTrial",
        "subscription": "Purchase",
        "content_created": "CustomEvent"
    }'::jsonb,

    -- Platform-specific config
    config JSONB DEFAULT '{}'::jsonb,

    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 6. PLATFORM LOGS (API call debugging)
-- NOTE: event_id has NO FK to kae_events (partitioned table)
CREATE TABLE IF NOT EXISTS public.kae_platform_logs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    platform TEXT NOT NULL,
    event_id UUID,
    event_created_at TIMESTAMPTZ,
    conversion_id UUID REFERENCES public.kae_conversions(id) ON DELETE SET NULL,

    -- Request/Response
    request_payload JSONB,
    response_status INTEGER,
    response_body JSONB,

    -- Status
    success BOOLEAN NOT NULL DEFAULT FALSE,
    error_message TEXT,
    latency_ms INTEGER,

    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- INDEXES
-- ============================================================

-- Visitors
CREATE INDEX IF NOT EXISTS idx_kae_visitors_user_id ON public.kae_visitors(user_id) WHERE user_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_visitors_fbclid ON public.kae_visitors(fbclid) WHERE fbclid IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_visitors_ttclid ON public.kae_visitors(ttclid) WHERE ttclid IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_visitors_gclid ON public.kae_visitors(gclid) WHERE gclid IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_visitors_first_seen ON public.kae_visitors(first_seen_at DESC);

-- Sessions
CREATE INDEX IF NOT EXISTS idx_kae_sessions_anonymous_id ON public.kae_sessions(anonymous_id);
CREATE INDEX IF NOT EXISTS idx_kae_sessions_user_id ON public.kae_sessions(user_id) WHERE user_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_sessions_started_at ON public.kae_sessions(started_at DESC);

-- Events (indexes are created on the parent, propagated to partitions)
CREATE INDEX IF NOT EXISTS idx_kae_events_anonymous_id ON public.kae_events(anonymous_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_kae_events_user_id ON public.kae_events(user_id, created_at DESC) WHERE user_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_events_event_name ON public.kae_events(event_name, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_kae_events_category ON public.kae_events(event_category, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_kae_events_session ON public.kae_events(session_id, created_at DESC) WHERE session_id IS NOT NULL;

-- Conversions
CREATE INDEX IF NOT EXISTS idx_kae_conversions_user_id ON public.kae_conversions(user_id) WHERE user_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_conversions_type ON public.kae_conversions(conversion_type, converted_at DESC);
CREATE INDEX IF NOT EXISTS idx_kae_conversions_source ON public.kae_conversions(attributed_source, converted_at DESC) WHERE attributed_source IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_kae_conversions_anonymous ON public.kae_conversions(anonymous_id, converted_at DESC);

-- Platform logs
CREATE INDEX IF NOT EXISTS idx_kae_platform_logs_platform ON public.kae_platform_logs(platform, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_kae_platform_logs_success ON public.kae_platform_logs(success, created_at DESC);

