ALTER TABLE public.kae_visitors ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.kae_sessions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.kae_events ENABLE ROW LEVEL SECURITY;
