-- ========== 20260217200001_workflow_notification_triggers.sql ==========
-- ============================================================
-- Workflow Notification Triggers
--
-- Fires pg_net HTTP calls to the workflow-notifications edge
-- function when relevant status changes occur.
--
-- Notifications:
--   Creator: content assigned, content approved, application approved, project created
--   Editor:  content recorded (ready for editing)
--   Issues:  notify responsible party
--
-- Clients get a DAILY DIGEST (via daily-reminders cron), NOT real-time.
-- ============================================================

-- ─── Content status change trigger ──────────────────────
CREATE OR REPLACE FUNCTION public.notify_content_status_change()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  _payload jsonb;
  _type text;
  _url text;
BEGIN
  -- Only fire on actual status changes
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Determine notification type based on new status
  CASE NEW.status
    WHEN 'assigned' THEN
      -- Creator assigned content (only if creator_id just set or status changed to assigned)
      IF NEW.creator_id IS NOT NULL THEN
        _type := 'content_assigned';
      END IF;
    WHEN 'recorded' THEN
      -- Editor notified that content is ready for editing
      IF NEW.editor_id IS NOT NULL THEN
        _type := 'content_recorded';
      END IF;
    WHEN 'approved' THEN
      -- Creator notified their content was approved
      IF NEW.creator_id IS NOT NULL THEN
        _type := 'content_approved';
      END IF;
    WHEN 'issue' THEN
      -- Notify the person responsible for fixing
      _type := 'content_issue';
    ELSE
      -- No notification needed for other statuses
      RETURN NEW;
  END CASE;

  IF _type IS NULL THEN
    RETURN NEW;
  END IF;

  _payload := jsonb_build_object(
    'type', _type,
    'record', jsonb_build_object(
      'id', NEW.id,
      'title', NEW.title,
      'status', NEW.status,
      'creator_id', NEW.creator_id,
      'editor_id', NEW.editor_id,
      'client_id', NEW.client_id,
      'organization_id', NEW.organization_id
    ),
    'old_record', jsonb_build_object(
      'status', OLD.status
    )
  );

  _url := current_setting('app.settings.supabase_url', true);
  IF _url IS NULL OR _url = '' THEN
    _url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co';
  END IF;

  -- Fire and forget via pg_net
  PERFORM net.http_post(
    url := _url || '/functions/v1/workflow-notifications',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true),
      'Content-Type', 'application/json'
    ),
    body := _payload
  );

  RETURN NEW;
END;
$$;

-- Attach trigger to content table
DROP TRIGGER IF EXISTS trg_content_workflow_notification ON public.content;
CREATE TRIGGER trg_content_workflow_notification
  AFTER UPDATE OF status ON public.content
  FOR EACH ROW
  EXECUTE FUNCTION public.notify_content_status_change();

-- ─── Creator assignment trigger (when creator_id changes) ──
CREATE OR REPLACE FUNCTION public.notify_creator_assigned()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  _payload jsonb;
  _url text;
BEGIN
  -- Only fire when creator_id is newly set (was NULL, now has value)
  IF OLD.creator_id IS NOT NULL OR NEW.creator_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Don't double-fire if status also changed to 'assigned' (the other trigger handles it)
  IF NEW.status = 'assigned' AND OLD.status != 'assigned' THEN
    RETURN NEW;
  END IF;

  _payload := jsonb_build_object(
    'type', 'content_assigned',
    'record', jsonb_build_object(
      'id', NEW.id,
      'title', NEW.title,
      'status', NEW.status,
      'creator_id', NEW.creator_id,
      'editor_id', NEW.editor_id,
      'client_id', NEW.client_id,
      'organization_id', NEW.organization_id
    )
  );

  _url := current_setting('app.settings.supabase_url', true);
  IF _url IS NULL OR _url = '' THEN
    _url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co';
  END IF;

  PERFORM net.http_post(
    url := _url || '/functions/v1/workflow-notifications',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true),
      'Content-Type', 'application/json'
    ),
    body := _payload
  );

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_content_creator_assigned ON public.content;
CREATE TRIGGER trg_content_creator_assigned
  AFTER UPDATE OF creator_id ON public.content
  FOR EACH ROW
  EXECUTE FUNCTION public.notify_creator_assigned();

-- ─── Campaign application approved trigger ──────────────
CREATE OR REPLACE FUNCTION public.notify_application_status_change()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  _payload jsonb;
  _url text;
BEGIN
  -- Only fire when status changes to 'approved'
  IF OLD.status = NEW.status OR NEW.status != 'approved' THEN
    RETURN NEW;
  END IF;

  _payload := jsonb_build_object(
    'type', 'application_approved',
    'record', jsonb_build_object(
      'id', NEW.id,
      'campaign_id', NEW.campaign_id,
      'creator_id', NEW.creator_id,
      'status', NEW.status
    )
  );

  _url := current_setting('app.settings.supabase_url', true);
  IF _url IS NULL OR _url = '' THEN
    _url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co';
  END IF;

  PERFORM net.http_post(
    url := _url || '/functions/v1/workflow-notifications',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true),
      'Content-Type', 'application/json'
    ),
    body := _payload
  );

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_application_approved ON public.campaign_applications;
CREATE TRIGGER trg_application_approved
  AFTER UPDATE OF status ON public.campaign_applications
  FOR EACH ROW
  EXECUTE FUNCTION public.notify_application_status_change();

-- ─── Marketplace project created trigger ────────────────
CREATE OR REPLACE FUNCTION public.notify_project_created()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  _payload jsonb;
  _url text;
BEGIN
  -- Only fire when a new project is created with a creator
  IF NEW.creator_id IS NULL THEN
    RETURN NEW;
  END IF;

  _payload := jsonb_build_object(
    'type', 'project_created',
    'record', jsonb_build_object(
      'id', NEW.id,
      'title', NEW.title,
      'brand_id', NEW.brand_id,
      'creator_id', NEW.creator_id,
      'status', NEW.status
    )
  );

  _url := current_setting('app.settings.supabase_url', true);
  IF _url IS NULL OR _url = '' THEN
    _url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co';
  END IF;

  PERFORM net.http_post(
    url := _url || '/functions/v1/workflow-notifications',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true),
      'Content-Type', 'application/json'
    ),
    body := _payload
  );

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_marketplace_project_created ON public.marketplace_projects;
CREATE TRIGGER trg_marketplace_project_created
  AFTER INSERT ON public.marketplace_projects
  FOR EACH ROW
  EXECUTE FUNCTION public.notify_project_created();

-- ========== 20260217200002_unified_project_types.sql ==========
-- ============================================================
-- UNIFIED PROJECT TYPES
-- Adds project_type to marketplace_projects and creates
-- org-level type configuration table.
-- ============================================================

-- 1. Create enum for project types
DO $$ BEGIN
  CREATE TYPE project_type AS ENUM (
    'content_creation',
    'post_production',
    'strategy_marketing',
    'technology',
    'education'
  );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- 2. Add project_type column to marketplace_projects
ALTER TABLE marketplace_projects
  ADD COLUMN IF NOT EXISTS project_type project_type NOT NULL DEFAULT 'content_creation';

-- Index for filtering by type
CREATE INDEX IF NOT EXISTS idx_marketplace_projects_type
  ON marketplace_projects(project_type);

-- Composite index for org + type queries
CREATE INDEX IF NOT EXISTS idx_marketplace_projects_org_type
  ON marketplace_projects(organization_id, project_type);

-- 3. Organization-level type configuration overrides
CREATE TABLE IF NOT EXISTS project_type_configs (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  project_type project_type NOT NULL,
  visible_sections text[] NOT NULL DEFAULT '{}',
  workspace_type text NOT NULL DEFAULT 'script',
  custom_brief_fields jsonb DEFAULT '[]'::jsonb,
  allowed_roles text[] DEFAULT '{}',
  enabled_features jsonb DEFAULT '{}'::jsonb,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE(organization_id, project_type)
);

-- RLS for project_type_configs
ALTER TABLE project_type_configs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "ptc_select_members"
  ON project_type_configs FOR SELECT
  USING (
    organization_id IN (
      SELECT organization_id FROM organization_members WHERE user_id = auth.uid()
    )
  );

CREATE POLICY "ptc_all_admins"
  ON project_type_configs FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM organization_members
      WHERE user_id = auth.uid()
        AND organization_id = project_type_configs.organization_id
        AND role = 'admin'
    )
  );

-- Grant access to authenticated role
GRANT SELECT ON project_type_configs TO authenticated;
GRANT INSERT, UPDATE, DELETE ON project_type_configs TO authenticated;

-- Updated_at trigger
CREATE OR REPLACE FUNCTION update_project_type_configs_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_project_type_configs_updated_at ON project_type_configs;
CREATE TRIGGER trg_project_type_configs_updated_at
  BEFORE UPDATE ON project_type_configs
  FOR EACH ROW EXECUTE FUNCTION update_project_type_configs_updated_at();

-- ========== 20260217300000_project_assignments.sql ==========
-- =============================================================
-- project_assignments: Multi-talent assignment system
-- Polymorphic FK to content OR marketplace_projects
-- =============================================================

CREATE TABLE public.project_assignments (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  -- Polymorphic reference
  project_source TEXT NOT NULL CHECK (project_source IN ('content', 'marketplace')),
  content_id UUID REFERENCES public.content(id) ON DELETE CASCADE,
  marketplace_project_id UUID REFERENCES public.marketplace_projects(id) ON DELETE CASCADE,

  -- Who is assigned
  user_id UUID NOT NULL REFERENCES auth.users(id),
  role_id TEXT NOT NULL,       -- 'ugc_creator', 'video_editor', 'web_developer', etc.
  role_group TEXT NOT NULL,    -- 'creator', 'editor', 'strategist', 'tech', 'education'

  -- Sequential flow
  phase INTEGER NOT NULL DEFAULT 1,
  depends_on UUID[] DEFAULT '{}',

  -- Assignment lifecycle
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN (
    'pending',
    'invited',
    'accepted',
    'in_progress',
    'delivered',
    'in_review',
    'changes_requested',
    'approved',
    'paid',
    'cancelled'
  )),

  -- Payment
  payment_amount DECIMAL(10,2),
  payment_currency TEXT DEFAULT 'COP',
  payment_method TEXT CHECK (payment_method IN ('payment', 'exchange')),
  is_paid BOOLEAN DEFAULT FALSE,
  paid_at TIMESTAMPTZ,

  -- Associated workspace block
  workspace_block_type TEXT,

  -- Lifecycle timestamps
  invited_at TIMESTAMPTZ,
  accepted_at TIMESTAMPTZ,
  started_at TIMESTAMPTZ,
  delivered_at TIMESTAMPTZ,
  approved_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),

  -- Exactly one FK must be set
  CONSTRAINT valid_project_reference CHECK (
    (project_source = 'content' AND content_id IS NOT NULL AND marketplace_project_id IS NULL) OR
    (project_source = 'marketplace' AND marketplace_project_id IS NOT NULL AND content_id IS NULL)
  )
);

-- =============================================================
-- Unique partial indexes: prevent duplicate role per user per project
-- =============================================================

CREATE UNIQUE INDEX idx_assignment_unique_user_role_content
  ON public.project_assignments(content_id, user_id, role_id)
  WHERE content_id IS NOT NULL;

CREATE UNIQUE INDEX idx_assignment_unique_user_role_marketplace
  ON public.project_assignments(marketplace_project_id, user_id, role_id)
  WHERE marketplace_project_id IS NOT NULL;

-- =============================================================
-- Lookup indexes
-- =============================================================

CREATE INDEX idx_assignments_content ON public.project_assignments(content_id) WHERE content_id IS NOT NULL;
CREATE INDEX idx_assignments_marketplace ON public.project_assignments(marketplace_project_id) WHERE marketplace_project_id IS NOT NULL;
CREATE INDEX idx_assignments_user ON public.project_assignments(user_id);
CREATE INDEX idx_assignments_status ON public.project_assignments(status);
CREATE INDEX idx_assignments_phase ON public.project_assignments(content_id, phase) WHERE content_id IS NOT NULL;
CREATE INDEX idx_assignments_phase_mp ON public.project_assignments(marketplace_project_id, phase) WHERE marketplace_project_id IS NOT NULL;

-- =============================================================
-- RLS
-- =============================================================

ALTER TABLE public.project_assignments ENABLE ROW LEVEL SECURITY;

-- SELECT: assigned user, or org member (content), or project participant (marketplace)
CREATE POLICY "assignments_select" ON public.project_assignments FOR SELECT USING (
  auth.uid() = user_id
  OR (content_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.content c
    JOIN public.clients cl ON cl.id = c.client_id
    JOIN public.organization_members om ON om.organization_id = cl.organization_id
    WHERE c.id = project_assignments.content_id AND om.user_id = auth.uid()
  ))
  OR (marketplace_project_id IS NOT NULL AND public.is_project_participant(marketplace_project_id))
);

-- INSERT: org member (content) or project participant (marketplace)
CREATE POLICY "assignments_insert" ON public.project_assignments FOR INSERT WITH CHECK (
  (content_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.content c
    JOIN public.clients cl ON cl.id = c.client_id
    JOIN public.organization_members om ON om.organization_id = cl.organization_id
    WHERE c.id = project_assignments.content_id AND om.user_id = auth.uid()
  ))
  OR (marketplace_project_id IS NOT NULL AND public.is_project_participant(marketplace_project_id))
);

-- UPDATE: assigned user or org member or project participant
CREATE POLICY "assignments_update" ON public.project_assignments FOR UPDATE USING (
  auth.uid() = user_id
  OR (content_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.content c
    JOIN public.clients cl ON cl.id = c.client_id
    JOIN public.organization_members om ON om.organization_id = cl.organization_id
    WHERE c.id = project_assignments.content_id AND om.user_id = auth.uid()
  ))
  OR (marketplace_project_id IS NOT NULL AND public.is_project_participant(marketplace_project_id))
);

-- DELETE: admin/team_leader (content) or brand admin (marketplace)
CREATE POLICY "assignments_delete" ON public.project_assignments FOR DELETE USING (
  (content_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.content c
    JOIN public.clients cl ON cl.id = c.client_id
    JOIN public.organization_members om ON om.organization_id = cl.organization_id
    WHERE c.id = project_assignments.content_id
      AND om.user_id = auth.uid()
      AND om.role IN ('admin', 'team_leader')
  ))
  OR (marketplace_project_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.marketplace_projects mp
    WHERE mp.id = project_assignments.marketplace_project_id
      AND (
        public.is_brand_admin(mp.brand_id)
        OR (mp.organization_id IS NOT NULL AND EXISTS (
          SELECT 1 FROM public.organization_members om
          WHERE om.organization_id = mp.organization_id
            AND om.user_id = auth.uid()
            AND om.role = 'admin'
        ))
      )
  ))
);

GRANT ALL ON public.project_assignments TO authenticated;

-- =============================================================
-- Auto-update updated_at
-- =============================================================

CREATE TRIGGER set_project_assignments_updated_at
  BEFORE UPDATE ON public.project_assignments
  FOR EACH ROW
  EXECUTE FUNCTION public.update_updated_at_column();

-- =============================================================
-- Update is_project_participant to also check assignments
-- =============================================================

CREATE OR REPLACE FUNCTION public.is_project_participant(_project_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.marketplace_projects mp
    WHERE mp.id = _project_id
      AND (
        mp.creator_id = auth.uid()
        OR mp.editor_id = auth.uid()
        OR (mp.brand_id IS NOT NULL AND EXISTS (
          SELECT 1 FROM public.brand_members bm
          WHERE bm.brand_id = mp.brand_id
            AND bm.user_id = auth.uid()
            AND bm.status = 'active'
        ))
        OR (mp.organization_id IS NOT NULL AND EXISTS (
          SELECT 1 FROM public.organization_members om
          WHERE om.organization_id = mp.organization_id
            AND om.user_id = auth.uid()
        ))
        -- NEW: check project_assignments table
        OR EXISTS (
          SELECT 1 FROM public.project_assignments pa
          WHERE pa.marketplace_project_id = _project_id
            AND pa.user_id = auth.uid()
            AND pa.status NOT IN ('cancelled')
        )
      )
  );
$$;

-- ========== 20260217400000_crm_full_detail_rpcs.sql ==========
-- =====================================================
-- CRM Full Detail RPCs + Custom Field Definitions
-- =====================================================

-- 1. Custom field definitions table
CREATE TABLE IF NOT EXISTS crm_custom_field_definitions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  entity_type TEXT NOT NULL CHECK (entity_type IN ('user', 'creator', 'org_creator', 'contact', 'lead')),
  name TEXT NOT NULL,
  field_type TEXT NOT NULL CHECK (field_type IN ('text','textarea','number','date','datetime','select','multiselect','checkbox','currency','url','email','phone','rating','color','tags')),
  options TEXT[] DEFAULT NULL,
  is_required BOOLEAN NOT NULL DEFAULT FALSE,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_crm_cf_defs_org_entity
  ON crm_custom_field_definitions(organization_id, entity_type)
  WHERE is_active = TRUE;

ALTER TABLE crm_custom_field_definitions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "org_members_can_read_crm_cf_defs"
  ON crm_custom_field_definitions FOR SELECT
  USING (
    organization_id IN (
      SELECT organization_id FROM organization_members WHERE user_id = auth.uid()
    )
  );

CREATE POLICY "org_admins_can_insert_crm_cf_defs"
  ON crm_custom_field_definitions FOR INSERT
  WITH CHECK (
    organization_id IN (
      SELECT om.organization_id FROM organization_members om
      JOIN organization_member_roles omr ON omr.user_id = om.user_id AND omr.organization_id = om.organization_id
      WHERE om.user_id = auth.uid() AND omr.role IN ('admin', 'team_leader')
    )
  );

CREATE POLICY "org_admins_can_update_crm_cf_defs"
  ON crm_custom_field_definitions FOR UPDATE
  USING (
    organization_id IN (
      SELECT om.organization_id FROM organization_members om
      JOIN organization_member_roles omr ON omr.user_id = om.user_id AND omr.organization_id = om.organization_id
      WHERE om.user_id = auth.uid() AND omr.role IN ('admin', 'team_leader')
    )
  );

CREATE POLICY "org_admins_can_delete_crm_cf_defs"
  ON crm_custom_field_definitions FOR DELETE
  USING (
    organization_id IN (
      SELECT om.organization_id FROM organization_members om
      JOIN organization_member_roles omr ON omr.user_id = om.user_id AND omr.organization_id = om.organization_id
      WHERE om.user_id = auth.uid() AND omr.role IN ('admin', 'team_leader')
    )
  );

GRANT ALL ON crm_custom_field_definitions TO authenticated;

-- 2. Add custom_fields JSONB to profiles and org_creator_relationships
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS crm_custom_fields JSONB DEFAULT '{}';
ALTER TABLE org_creator_relationships ADD COLUMN IF NOT EXISTS custom_fields JSONB DEFAULT '{}';

-- =====================================================
-- 3. get_full_user_detail(p_user_id) - comprehensive user data
-- =====================================================
CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB;
BEGIN
  SELECT jsonb_build_object(
    -- profiles
    'id', p.id,
    'email', p.email,
    'full_name', p.full_name,
    'username', p.username,
    'avatar_url', p.avatar_url,
    'phone', p.phone,
    'bio', p.bio,
    'tagline', p.tagline,
    'cover_url', p.cover_url,
    'document_type', p.document_type,
    'document_number', p.document_number,
    'address', p.address,
    'city', p.city,
    'country', p.country,
    'instagram', p.instagram,
    'tiktok', p.tiktok,
    'facebook', p.facebook,
    'social_linkedin', p.social_linkedin,
    'social_twitter', p.social_twitter,
    'social_youtube', p.social_youtube,
    'portfolio_url', p.portfolio_url,
    'featured_video_url', p.featured_video_url,
    'experience_level', p.experience_level,
    'availability_status', p.availability_status,
    'best_at', p.best_at,
    'content_categories', COALESCE(p.content_categories, ARRAY[]::TEXT[]),
    'specialties_tags', COALESCE(p.specialties_tags, ARRAY[]::TEXT[]),
    'style_keywords', COALESCE(p.style_keywords, ARRAY[]::TEXT[]),
    'industries', COALESCE(p.industries, ARRAY[]::TEXT[]),
    'interests', COALESCE(p.interests, ARRAY[]::TEXT[]),
    'languages', COALESCE(p.languages, ARRAY[]::TEXT[]),
    'rate_per_content', p.rate_per_content,
    'rate_currency', p.rate_currency,
    'quality_score_avg', p.quality_score_avg,
    'reliability_score', p.reliability_score,
    'velocity_score', p.velocity_score,
    'editor_rating', p.editor_rating,
    'is_ambassador', COALESCE(p.is_ambassador, false),
    'is_platform_founder', COALESCE(p.is_platform_founder, false),
    'founder_badge_type', p.founder_badge_type,
    'active_role', p.active_role,
    'ai_recommended_level', p.ai_recommended_level,
    'ai_risk_flag', p.ai_risk_flag,
    'is_active', COALESCE(p.is_active, true),
    'crm_custom_fields', COALESCE(p.crm_custom_fields, '{}'::jsonb),
    'created_at', p.created_at,
    -- creator_profiles (nullable)
    'creator_profile_id', cp.id,
    'slug', cp.slug,
    'bio_full', cp.bio_full,
    'banner_url', cp.banner_url,
    'creator_social_links', cp.social_links,
    'level', cp.level,
    'is_verified', COALESCE(cp.is_verified, false),
    'is_available', COALESCE(cp.is_available, false),
    'rating_avg', COALESCE(cp.rating_avg, 0),
    'rating_count', COALESCE(cp.rating_count, 0),
    'completed_projects', COALESCE(cp.completed_projects, 0),
    'base_price', cp.base_price,
    'currency', COALESCE(cp.currency, 'USD'),
    'categories', COALESCE(cp.categories, ARRAY[]::TEXT[]),
    'content_types', COALESCE(cp.content_types, ARRAY[]::TEXT[]),
    'platforms', COALESCE(cp.platforms, ARRAY[]::TEXT[]),
    'marketplace_roles', COALESCE(cp.marketplace_roles, ARRAY[]::TEXT[]),
    'accepts_product_exchange', COALESCE(cp.accepts_product_exchange, false),
    'response_time_hours', cp.response_time_hours,
    'on_time_delivery_pct', cp.on_time_delivery_pct,
    'repeat_clients_pct', cp.repeat_clients_pct,
    'showreel_video_id', cp.showreel_video_id,
    'showreel_url', cp.showreel_url,
    'showreel_thumbnail', cp.showreel_thumbnail,
    -- health
    'health_score', COALESCE(h.health_score, 0),
    'health_status', COALESCE(h.health_status, 'healthy'),
    'total_logins', COALESCE(h.total_logins, 0),
    'days_since_last_activity', h.days_since_last_activity,
    'last_login_at', h.last_login_at,
    'total_actions', COALESCE(
      (SELECT COUNT(*) FROM auth.sessions WHERE user_id = p_user_id)::int, 0
    ),
    'needs_attention', COALESCE(h.needs_attention, false),
    'total_applications', COALESCE(h.total_applications, 0),
    'total_completed_projects', COALESCE(h.total_completed_projects, 0),
    'total_spent', COALESCE(h.total_spent, 0),
    -- org context
    'organization_id', om.organization_id,
    'organization_name', o.name,
    'is_owner', COALESCE(om.is_owner, false),
    'ambassador_level', om.ambassador_level,
    -- nested arrays
    'roles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'role', omr.role,
        'organization_id', omr.organization_id,
        'organization_name', o2.name
      ))
      FROM organization_member_roles omr
      LEFT JOIN organizations o2 ON o2.id = omr.organization_id
      WHERE omr.user_id = p_user_id
    ), '[]'::jsonb),
    'badges', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'badge', omb.badge,
        'level', omb.level,
        'is_active', omb.is_active,
        'granted_at', omb.granted_at
      ))
      FROM organization_member_badges omb
      WHERE omb.user_id = p_user_id AND omb.is_active = true
    ), '[]'::jsonb),
    'portfolio', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', pi.id,
        'title', pi.title,
        'media_type', pi.media_type,
        'media_url', pi.media_url,
        'thumbnail_url', pi.thumbnail_url,
        'bunny_video_id', pi.bunny_video_id,
        'category', pi.category,
        'is_featured', pi.is_featured
      ) ORDER BY pi.is_featured DESC, pi.display_order ASC)
      FROM portfolio_items pi
      WHERE pi.creator_id = cp.id AND pi.is_public = true
      LIMIT 12
    ), '[]'::jsonb),
    'services', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', cs.id,
        'title', cs.title,
        'service_type', cs.service_type,
        'price_type', cs.price_type,
        'price_amount', cs.price_amount,
        'price_currency', cs.price_currency,
        'delivery_days', cs.delivery_days,
        'is_featured', cs.is_featured
      ) ORDER BY cs.is_featured DESC, cs.display_order ASC)
      FROM creator_services cs
      WHERE cs.user_id = p_user_id AND cs.is_active = true
    ), '[]'::jsonb)
  ) INTO result
  FROM profiles p
  LEFT JOIN creator_profiles cp ON cp.user_id = p.id
  LEFT JOIN platform_user_health h ON h.user_id = p.id
  LEFT JOIN organization_members om ON om.user_id = p.id
    AND om.organization_id = p.current_organization_id
  LEFT JOIN organizations o ON o.id = om.organization_id
  WHERE p.id = p_user_id;

  RETURN result;
END;
$$;

