-- ========== 20260217600000_unified_views_rpcs.sql ==========
-- =====================================================
-- get_unified_talent: Single RPC merging ALL org members + external CRM talent
-- Returns every person in the organization (any role) + external CRM relationships
-- =====================================================

CREATE OR REPLACE FUNCTION get_unified_talent(p_org_id uuid)
RETURNS TABLE (
  id uuid,
  full_name text,
  email text,
  avatar_url text,
  phone text,
  bio text,
  source text,              -- 'internal' | 'external' | 'both'
  -- Internal fields
  org_role text,            -- primary role (highest priority) or null
  all_roles text[],         -- all roles for this member
  is_owner boolean,
  content_count bigint,
  is_ambassador boolean,
  ambassador_level text,
  quality_score_avg numeric,
  reliability_score numeric,
  velocity_score numeric,
  ai_recommended_level text,
  ai_risk_flag text,
  active_tasks bigint,
  up_points numeric,
  up_level text,
  avg_star_rating numeric,
  rated_content_count bigint,
  -- External CRM fields
  relationship_id uuid,
  relationship_type text,
  times_worked_together integer,
  total_paid numeric,
  average_rating_given numeric,
  last_collaboration_at timestamptz,
  internal_notes text,
  internal_tags text[],
  list_name text,
  -- Marketplace fields
  creator_profile_id uuid,
  categories text[],
  content_types text[],
  platforms text[],
  slug text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  WITH
  -- ALL internal org members (every role, including admin/team_leader/trafficker)
  internal_members AS (
    SELECT
      om.user_id,
      om.is_owner,
      -- Aggregate all roles for this user (cast enum to text)
      ARRAY_AGG(omr.role::text ORDER BY
        CASE omr.role::text
          WHEN 'admin' THEN 1
          WHEN 'team_leader' THEN 2
          WHEN 'strategist' THEN 3
          WHEN 'trafficker' THEN 4
          WHEN 'creator' THEN 5
          WHEN 'editor' THEN 6
          WHEN 'client' THEN 7
          ELSE 8
        END
      ) FILTER (WHERE omr.role IS NOT NULL) AS roles,
      -- Primary role = highest priority
      MIN(CASE omr.role::text
        WHEN 'admin' THEN 1
        WHEN 'team_leader' THEN 2
        WHEN 'strategist' THEN 3
        WHEN 'trafficker' THEN 4
        WHEN 'creator' THEN 5
        WHEN 'editor' THEN 6
        WHEN 'client' THEN 7
        ELSE 8
      END) AS role_priority
    FROM organization_members om
    LEFT JOIN organization_member_roles omr
      ON omr.organization_id = om.organization_id
      AND omr.user_id = om.user_id
    WHERE om.organization_id = p_org_id
    GROUP BY om.user_id, om.is_owner
  ),
  -- Compute primary role from priority
  internal_with_role AS (
    SELECT
      im.user_id,
      im.is_owner,
      im.roles,
      CASE im.role_priority
        WHEN 1 THEN 'admin'
        WHEN 2 THEN 'team_leader'
        WHEN 3 THEN 'strategist'
        WHEN 4 THEN 'trafficker'
        WHEN 5 THEN 'creator'
        WHEN 6 THEN 'editor'
        WHEN 7 THEN 'client'
        ELSE NULL
      END AS primary_role
    FROM internal_members im
  ),
  -- External CRM relationships
  external_rels AS (
    SELECT
      r.id AS rel_id,
      r.creator_id,
      r.relationship_type,
      r.times_worked_together,
      r.total_paid,
      r.average_rating_given,
      r.last_collaboration_at,
      r.internal_notes,
      r.internal_tags,
      r.list_name
    FROM org_creator_relationships r
    WHERE r.organization_id = p_org_id
  ),
  -- All unique user IDs from both sources
  all_users AS (
    SELECT iwr.user_id FROM internal_with_role iwr
    UNION
    SELECT er.creator_id FROM external_rels er
  ),
  -- Ambassador info
  ambassador_info AS (
    SELECT
      om.user_id,
      om.ambassador_level,
      EXISTS (
        SELECT 1 FROM organization_member_roles omr2
        WHERE omr2.organization_id = p_org_id
          AND omr2.user_id = om.user_id
          AND omr2.role = 'ambassador'
      ) AS is_amb_role
    FROM organization_members om
    WHERE om.organization_id = p_org_id
  ),
  -- Content counts per user (creator + editor roles)
  content_counts AS (
    SELECT user_id, SUM(cnt) AS total
    FROM (
      SELECT creator_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND creator_id IS NOT NULL
      GROUP BY creator_id
      UNION ALL
      SELECT editor_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND editor_id IS NOT NULL
      GROUP BY editor_id
      UNION ALL
      SELECT strategist_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND strategist_id IS NOT NULL
      GROUP BY strategist_id
    ) sub
    GROUP BY user_id
  ),
  -- Active tasks per user
  active_tasks_counts AS (
    SELECT user_id, SUM(cnt) AS total
    FROM (
      SELECT creator_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id
        AND status IN ('assigned','recording','recorded','editing','review','issue')
        AND creator_id IS NOT NULL
      GROUP BY creator_id
      UNION ALL
      SELECT editor_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id
        AND status IN ('assigned','recording','recorded','editing','review','issue')
        AND editor_id IS NOT NULL
      GROUP BY editor_id
    ) sub
    GROUP BY user_id
  ),
  -- UP points (aggregate across roles per user)
  up_data AS (
    SELECT user_id, SUM(total_points) AS total_points, MAX(current_level) AS current_level
    FROM up_user_scores
    WHERE organization_id = p_org_id
    GROUP BY user_id
  ),
  -- Star ratings
  star_ratings AS (
    SELECT user_id, AVG(rating) AS avg_rating, COUNT(*) AS rating_count
    FROM (
      SELECT creator_id AS user_id, creator_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND creator_rating IS NOT NULL
      UNION ALL
      SELECT editor_id AS user_id, editor_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND editor_rating IS NOT NULL
      UNION ALL
      SELECT strategist_id AS user_id, strategy_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND strategy_rating IS NOT NULL
    ) sub
    WHERE user_id IS NOT NULL
    GROUP BY user_id
  )
  SELECT
    p.id,
    p.full_name,
    p.email,
    p.avatar_url,
    p.phone,
    p.bio,
    -- Source determination
    CASE
      WHEN iwr.user_id IS NOT NULL AND er.creator_id IS NOT NULL THEN 'both'
      WHEN iwr.user_id IS NOT NULL THEN 'internal'
      ELSE 'external'
    END AS source,
    -- Internal fields
    iwr.primary_role AS org_role,
    iwr.roles AS all_roles,
    COALESCE(iwr.is_owner, false) AS is_owner,
    COALESCE(cc.total, 0)::bigint AS content_count,
    COALESCE(ai.is_amb_role, p.is_ambassador, false) AS is_ambassador,
    ai.ambassador_level,
    p.quality_score_avg,
    p.reliability_score,
    p.velocity_score,
    p.ai_recommended_level,
    p.ai_risk_flag,
    COALESCE(at.total, 0)::bigint AS active_tasks,
    COALESCE(ud.total_points, 0)::numeric AS up_points,
    ud.current_level AS up_level,
    sr.avg_rating AS avg_star_rating,
    COALESCE(sr.rating_count, 0)::bigint AS rated_content_count,
    -- External CRM fields
    er.rel_id AS relationship_id,
    er.relationship_type,
    COALESCE(er.times_worked_together, 0) AS times_worked_together,
    COALESCE(er.total_paid, 0) AS total_paid,
    er.average_rating_given,
    er.last_collaboration_at,
    er.internal_notes,
    er.internal_tags,
    er.list_name,
    -- Marketplace fields
    cp.id AS creator_profile_id,
    cp.categories,
    cp.content_types,
    cp.platforms,
    cp.slug
  FROM all_users au
  JOIN profiles p ON p.id = au.user_id
  LEFT JOIN internal_with_role iwr ON iwr.user_id = au.user_id
  LEFT JOIN external_rels er ON er.creator_id = au.user_id
  LEFT JOIN ambassador_info ai ON ai.user_id = au.user_id
  LEFT JOIN content_counts cc ON cc.user_id = au.user_id
  LEFT JOIN active_tasks_counts at ON at.user_id = au.user_id
  LEFT JOIN up_data ud ON ud.user_id = au.user_id
  LEFT JOIN star_ratings sr ON sr.user_id = au.user_id
  LEFT JOIN creator_profiles cp ON cp.user_id = au.user_id
  ORDER BY
    CASE
      WHEN iwr.user_id IS NOT NULL AND er.creator_id IS NOT NULL THEN 0
      WHEN iwr.user_id IS NOT NULL THEN 1
      ELSE 2
    END,
    p.full_name;
END;
$$;

GRANT EXECUTE ON FUNCTION get_unified_talent(uuid) TO authenticated;

-- =====================================================
-- get_unified_clients: Single RPC merging empresas + contactos
-- =====================================================

CREATE OR REPLACE FUNCTION get_unified_clients(p_org_id uuid)
RETURNS TABLE (
  id uuid,
  entity_type text,           -- 'empresa' | 'contacto'
  name text,
  email text,
  phone text,
  avatar_url text,
  created_at timestamptz,
  updated_at timestamptz,
  -- Empresa fields (null for contactos)
  is_vip boolean,
  is_internal_brand boolean,
  content_count bigint,
  active_projects bigint,
  users_count bigint,
  username text,
  client_notes text,
  -- Contacto fields (null for empresas)
  company text,
  "position" text,
  contact_type text,
  pipeline_stage text,
  deal_value numeric,
  expected_close_date date,
  relationship_strength text,
  contact_notes text,
  tags text[],
  custom_fields jsonb
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  -- Empresas (clients)
  SELECT
    c.id,
    'empresa'::text AS entity_type,
    c.name,
    c.contact_email AS email,
    c.contact_phone AS phone,
    c.logo_url AS avatar_url,
    c.created_at,
    c.created_at AS updated_at,
    COALESCE(c.is_vip, false) AS is_vip,
    COALESCE(c.is_internal_brand, false) AS is_internal_brand,
    (SELECT COUNT(*) FROM content ct WHERE ct.client_id = c.id)::bigint AS content_count,
    (SELECT COUNT(*) FROM content ct WHERE ct.client_id = c.id
      AND ct.status NOT IN ('approved','paid'))::bigint AS active_projects,
    (SELECT COUNT(*) FROM client_users cu WHERE cu.client_id = c.id)::bigint AS users_count,
    c.username,
    c.notes AS client_notes,
    -- Contacto fields = null
    NULL::text AS company,
    NULL::text AS "position",
    NULL::text AS contact_type,
    NULL::text AS pipeline_stage,
    NULL::numeric AS deal_value,
    NULL::date AS expected_close_date,
    NULL::text AS relationship_strength,
    NULL::text AS contact_notes,
    NULL::text[] AS tags,
    NULL::jsonb AS custom_fields
  FROM clients c
  WHERE c.organization_id = p_org_id

  UNION ALL

  -- Contactos (org_contacts)
  SELECT
    oc.id,
    'contacto'::text AS entity_type,
    oc.full_name AS name,
    oc.email,
    oc.phone,
    oc.avatar_url,
    oc.created_at,
    oc.updated_at,
    -- Empresa fields = null/defaults
    false AS is_vip,
    false AS is_internal_brand,
    0::bigint AS content_count,
    0::bigint AS active_projects,
    0::bigint AS users_count,
    NULL::text AS username,
    NULL::text AS client_notes,
    -- Contacto fields
    oc.company,
    oc.position,
    oc.contact_type,
    oc.pipeline_stage,
    oc.deal_value,
    oc.expected_close_date,
    oc.relationship_strength,
    oc.notes AS contact_notes,
    oc.tags,
    oc.custom_fields
  FROM org_contacts oc
  WHERE oc.organization_id = p_org_id

  ORDER BY entity_type, name;
END;
$$;

GRANT EXECUTE ON FUNCTION get_unified_clients(uuid) TO authenticated;

-- ========== 20260217700000_enhance_platform_users_rpc.sql ==========
-- =====================================================
-- Enhanced Platform Users with Health RPC
-- Migration: 20260217700000_enhance_platform_users_rpc
-- Changes: Start from auth.users (catches users without profiles),
--          add email_confirmed_at, is_banned, has_profile, is_platform_admin
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            COALESCE(om.role::text, p.active_role) AS role,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- New auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.role, om2.organization_id
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
    ) t;

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_platform_users_with_health() TO authenticated;

-- ========== 20260218000000_unified_financial_system.sql ==========
-- ============================================================================
-- KREOON UNIFIED FINANCIAL SYSTEM
-- Migración consolidada para unificar toda la arquitectura financiera
-- Fecha: 2026-02-16
-- ============================================================================

-- ============================================================================
-- PARTE 1: CLEANUP - Eliminar tablas duplicadas/obsoletas
-- ============================================================================

-- Backup de datos existentes antes de eliminar (si existen)
DO $$
BEGIN
    -- Crear tabla de backup si hay datos en creator_wallets
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'creator_wallets') THEN
        CREATE TABLE IF NOT EXISTS _backup_creator_wallets AS SELECT * FROM creator_wallets;
    END IF;
    
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'creator_wallet_transactions') THEN
        CREATE TABLE IF NOT EXISTS _backup_creator_wallet_transactions AS SELECT * FROM creator_wallet_transactions;
    END IF;
    
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'wallet_transactions') THEN
        CREATE TABLE IF NOT EXISTS _backup_wallet_transactions AS SELECT * FROM wallet_transactions;
    END IF;
    
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'platform_transactions') THEN
        CREATE TABLE IF NOT EXISTS _backup_platform_transactions AS SELECT * FROM platform_transactions;
    END IF;
END $$;

-- Drop Phase B referral tables if they exist (from migration 20260217500000)
DROP TABLE IF EXISTS referral_earnings CASCADE;
DROP TABLE IF EXISTS referral_relationships CASCADE;

-- Drop functions from Phase B migration
DROP FUNCTION IF EXISTS update_referral_relationship_timestamp() CASCADE;
DROP FUNCTION IF EXISTS update_referral_relationship_totals() CASCADE;
DROP FUNCTION IF EXISTS get_perpetual_referral_stats(UUID) CASCADE;

-- Drop tables with incompatible schema (backup first, then recreate with new schema)
DO $$
BEGIN
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'ai_token_transactions' AND table_schema = 'public') THEN
        CREATE TABLE IF NOT EXISTS _backup_ai_token_transactions AS SELECT * FROM ai_token_transactions;
    END IF;
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'referral_codes' AND table_schema = 'public') THEN
        CREATE TABLE IF NOT EXISTS _backup_referral_codes AS SELECT * FROM referral_codes;
    END IF;
END $$;
DROP TABLE IF EXISTS ai_token_transactions CASCADE;
DROP TABLE IF EXISTS referral_codes CASCADE;

-- ============================================================================
-- PARTE 2: ENUMS UNIFICADOS
-- ============================================================================

-- Tipos de wallet
DO $$ BEGIN
    CREATE TYPE wallet_type AS ENUM (
        'creator',
        'editor', 
        'brand',
        'organization',
        'agency',
        'platform'
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Estados de transacción
DO $$ BEGIN
    CREATE TYPE transaction_status AS ENUM (
        'pending',
        'processing',
        'completed',
        'failed',
        'cancelled',
        'refunded',
        'disputed'
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Tipos de transacción unificados
DO $$ BEGIN
    CREATE TYPE transaction_type AS ENUM (
        -- Depósitos/Retiros
        'deposit',
        'withdrawal',
        -- Escrow
        'escrow_hold',
        'escrow_release',
        'escrow_refund',
        'escrow_partial_release',
        -- Comisiones
        'platform_fee',
        'referral_commission',
        -- Suscripciones
