    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Estados de retiro
DO $$ BEGIN
    CREATE TYPE withdrawal_status AS ENUM (
        'pending',
        'processing',
        'completed',
        'failed',
        'cancelled'
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Tipos de suscripción
DO $$ BEGIN
