    notes TEXT,
    
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    
    CONSTRAINT agreement_entity_check CHECK (
        (user_id IS NOT NULL AND organization_id IS NULL) OR
