-- ========== 20260218100000_finance_atomic_rpcs.sql ==========
-- ============================================================================
-- KREOON: Atomic Increment RPCs + Finance Fixes
-- Fixes supabase.raw() bug across all edge functions
-- ============================================================================

-- 1. Generic atomic increment RPC (works for any table/column)
CREATE OR REPLACE FUNCTION increment_column(
  p_table TEXT,
  p_column TEXT,
  p_amount NUMERIC,
  p_id UUID
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER
AS $$
BEGIN
  EXECUTE format(
    'UPDATE %I SET %I = COALESCE(%I, 0) + $1 WHERE id = $2',
    p_table, p_column, p_column
  ) USING p_amount, p_id;
END;
$$;

-- 2. Atomic wallet balance update (for referral commissions + withdrawals)
CREATE OR REPLACE FUNCTION update_wallet_balance(
  p_wallet_id UUID,
  p_available_delta NUMERIC DEFAULT 0,
  p_reserved_delta NUMERIC DEFAULT 0,
  p_earned_delta NUMERIC DEFAULT 0
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER
AS $$
BEGIN
  UPDATE unified_wallets
  SET
    balance_available = COALESCE(balance_available, 0) + p_available_delta,
    balance_reserved = COALESCE(balance_reserved, 0) + p_reserved_delta,
    total_earned = COALESCE(total_earned, 0) + p_earned_delta,
    updated_at = now()
  WHERE id = p_wallet_id;
END;
$$;

-- 3. Atomic token credit (for purchases)
CREATE OR REPLACE FUNCTION credit_purchased_tokens(
  p_balance_id UUID,
  p_tokens INTEGER
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER
AS $$
BEGIN
  UPDATE ai_token_balances
  SET
    balance_purchased = COALESCE(balance_purchased, 0) + p_tokens,
    total_purchased = COALESCE(total_purchased, 0) + p_tokens,
    updated_at = now()
  WHERE id = p_balance_id;
END;
$$;

-- 4. Consume AI tokens atomically (checks balance, deducts, logs)
CREATE OR REPLACE FUNCTION consume_ai_tokens(
  p_user_id UUID DEFAULT NULL,
  p_org_id UUID DEFAULT NULL,
  p_action_type TEXT DEFAULT 'default',
  p_tokens INTEGER DEFAULT 40,
  p_metadata JSONB DEFAULT '{}'
) RETURNS JSONB
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_balance RECORD;
  v_remaining INTEGER;
  v_source TEXT;
  v_deduct_sub INTEGER := 0;
  v_deduct_purchased INTEGER := 0;
  v_deduct_bonus INTEGER := 0;
BEGIN
  -- Find balance
  IF p_org_id IS NOT NULL THEN
    SELECT * INTO v_balance FROM ai_token_balances WHERE organization_id = p_org_id LIMIT 1;
  ELSE
    SELECT * INTO v_balance FROM ai_token_balances WHERE user_id = p_user_id AND organization_id IS NULL LIMIT 1;
  END IF;

  IF v_balance IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No token balance found');
  END IF;

  -- Check total available
  v_remaining := COALESCE(v_balance.balance_subscription, 0)
               + COALESCE(v_balance.balance_purchased, 0)
               + COALESCE(v_balance.balance_bonus, 0);

  IF v_remaining < p_tokens THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Insufficient tokens',
      'required', p_tokens,
      'available', v_remaining
    );
  END IF;

  -- Deduct in order: subscription first, then bonus, then purchased
  v_deduct_sub := LEAST(p_tokens, COALESCE(v_balance.balance_subscription, 0));
  v_deduct_bonus := LEAST(p_tokens - v_deduct_sub, COALESCE(v_balance.balance_bonus, 0));
  v_deduct_purchased := p_tokens - v_deduct_sub - v_deduct_bonus;

  IF v_deduct_sub > 0 THEN v_source := 'subscription';
  ELSIF v_deduct_bonus > 0 THEN v_source := 'bonus';
  ELSE v_source := 'purchased';
  END IF;

  -- Update balance
  UPDATE ai_token_balances
  SET
    balance_subscription = COALESCE(balance_subscription, 0) - v_deduct_sub,
    balance_bonus = COALESCE(balance_bonus, 0) - v_deduct_bonus,
    balance_purchased = COALESCE(balance_purchased, 0) - v_deduct_purchased,
    total_consumed = COALESCE(total_consumed, 0) + p_tokens,
    updated_at = now()
  WHERE id = v_balance.id;

  -- Log transaction
  INSERT INTO ai_token_transactions (
    balance_id, transaction_type, tokens, balance_after,
    action_type, action_metadata, executed_by
  ) VALUES (
    v_balance.id, 'consumption', -p_tokens,
    v_remaining - p_tokens,
    p_action_type, p_metadata,
    COALESCE(p_user_id, p_org_id)
  );

  RETURN jsonb_build_object(
    'success', true,
    'tokens_consumed', p_tokens,
    'balance_remaining', v_remaining - p_tokens,
    'source', v_source
  );
END;
$$;

-- 5. Fix escrow_status enum: add partially_refunded
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_enum
    WHERE enumlabel = 'partially_refunded'
    AND enumtypid = (SELECT oid FROM pg_type WHERE typname = 'escrow_status')
  ) THEN
    ALTER TYPE escrow_status ADD VALUE IF NOT EXISTS 'partially_refunded';
  END IF;
EXCEPTION WHEN OTHERS THEN
  -- Type may not exist or already has the value
  NULL;
END $$;

-- 6. Admin check function
CREATE OR REPLACE FUNCTION is_platform_admin(p_user_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql SECURITY DEFINER STABLE
AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM profiles
    WHERE id = p_user_id
    AND (role = 'admin' OR is_platform_root(p_user_id))
  );
END;
$$;

-- 7. Grant execute to authenticated
GRANT EXECUTE ON FUNCTION increment_column(TEXT, TEXT, NUMERIC, UUID) TO authenticated, service_role;
GRANT EXECUTE ON FUNCTION update_wallet_balance(UUID, NUMERIC, NUMERIC, NUMERIC) TO authenticated, service_role;
GRANT EXECUTE ON FUNCTION credit_purchased_tokens(UUID, INTEGER) TO authenticated, service_role;
GRANT EXECUTE ON FUNCTION consume_ai_tokens(UUID, UUID, TEXT, INTEGER, JSONB) TO authenticated, service_role;
GRANT EXECUTE ON FUNCTION is_platform_admin(UUID) TO authenticated, service_role;

-- ========== 20260218100001_fix_users_rpc_role_source.sql ==========
-- =====================================================
-- Fix: Platform Users RPC role source
-- Migration: 20260218100000_fix_users_rpc_role_source
-- Problem: om.role from organization_members is NOT NULL DEFAULT 'creator',
--          so COALESCE(om.role, p.active_role) always returns 'creator'
--          even when the user has no assigned role.
-- Fix: Use organization_member_roles (which IS cleared) as role source,
--       falling back to p.active_role.
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            -- Use organization_member_roles as source of truth (can be empty = no role)
            -- Falls back to profiles.active_role, then NULL
            COALESCE(omr.role::text, p.active_role) AS role,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- Auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.organization_id, om2.is_owner
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN LATERAL (
            SELECT omr2.role
            FROM organization_member_roles omr2
            WHERE omr2.user_id = au.id
              AND omr2.organization_id = om.organization_id
            LIMIT 1
        ) omr ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
    ) t;

    RETURN result;
END;
$$;

-- ========== 20260218100002_white_label_schema.sql ==========
-- ============================================================
-- White-Label Schema for Organizations
--
-- Adds columns to organizations for progressive white-label
-- support based on subscription plan tier:
--   org_starter  → logo + primary color only
--   org_pro      → full visual branding + sender name
--   org_enterprise → custom domain + custom email sender + auth
--
-- Also creates resolve_org_by_domain RPC for pre-auth branding
-- and extends get_user_org_context with white-label fields.
-- ============================================================

-- ─── New columns on organizations ──────────────────────────
ALTER TABLE organizations
  ADD COLUMN IF NOT EXISTS custom_domain text,
  ADD COLUMN IF NOT EXISTS favicon_url text,
  ADD COLUMN IF NOT EXISTS logo_dark_url text,
  ADD COLUMN IF NOT EXISTS platform_name text,
  ADD COLUMN IF NOT EXISTS secondary_color text,
  ADD COLUMN IF NOT EXISTS sender_email text,
  ADD COLUMN IF NOT EXISTS sender_name text,
  ADD COLUMN IF NOT EXISTS support_email text,
  ADD COLUMN IF NOT EXISTS resend_domain_id text,
  ADD COLUMN IF NOT EXISTS resend_domain_verified boolean DEFAULT false,
  ADD COLUMN IF NOT EXISTS pwa_icon_192_url text,
  ADD COLUMN IF NOT EXISTS pwa_icon_512_url text,
  ADD COLUMN IF NOT EXISTS og_image_url text,
  ADD COLUMN IF NOT EXISTS white_label_config jsonb DEFAULT '{}'::jsonb;

-- Unique index on custom_domain (only non-null values)
CREATE UNIQUE INDEX IF NOT EXISTS idx_organizations_custom_domain
  ON organizations(custom_domain) WHERE custom_domain IS NOT NULL;

-- ─── resolve_org_by_domain RPC ─────────────────────────────
-- Public RPC callable without auth to resolve org branding
-- from hostname (for login page branding before authentication).
-- Matches by:
--   1. Exact custom_domain match
--   2. Slug = first segment of hostname (for orgslug.kreoon.com)
CREATE OR REPLACE FUNCTION public.resolve_org_by_domain(p_hostname text)
RETURNS TABLE (
  org_id uuid,
  org_name text,
  org_slug text,
  org_logo_url text,
  org_logo_dark_url text,
  org_favicon_url text,
  org_primary_color text,
  org_secondary_color text,
  org_platform_name text,
  org_og_image_url text,
  org_selected_plan text
)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT
    o.id,
    o.name::text,
    o.slug::text,
    o.logo_url::text,
    o.logo_dark_url::text,
    o.favicon_url::text,
    COALESCE(o.primary_color, '#8B5CF6')::text,
    o.secondary_color::text,
    o.platform_name::text,
    o.og_image_url::text,
    COALESCE(o.selected_plan, 'starter')::text
  FROM organizations o
  WHERE
    -- Match by exact custom domain
    (o.custom_domain IS NOT NULL AND lower(o.custom_domain) = lower(p_hostname))
    OR
    -- Match by slug as subdomain (e.g., orgslug.kreoon.com → slug = orgslug)
    (o.slug = split_part(lower(p_hostname), '.', 1)
     AND p_hostname LIKE '%.kreoon.com'
     AND p_hostname != 'kreoon.com'
     AND p_hostname != 'www.kreoon.com')
  LIMIT 1;
$$;

-- Allow anonymous and authenticated users to call this
GRANT EXECUTE ON FUNCTION public.resolve_org_by_domain(text) TO anon;
GRANT EXECUTE ON FUNCTION public.resolve_org_by_domain(text) TO authenticated;

-- ─── Extend get_user_org_context RPC ───────────────────────
-- Drop and recreate to add white-label fields
CREATE OR REPLACE FUNCTION public.get_user_org_context(p_organization_id uuid)
RETURNS TABLE (
  is_owner boolean,
  org_name text,
  marketplace_enabled boolean,
  -- White-label fields
  org_slug text,
  org_logo_url text,
  org_logo_dark_url text,
  org_favicon_url text,
  org_primary_color text,
  org_secondary_color text,
  org_platform_name text,
  org_sender_email text,
  org_sender_name text,
  org_support_email text,
  org_custom_domain text,
  org_resend_domain_verified boolean,
  org_pwa_icon_192_url text,
  org_pwa_icon_512_url text,
  org_og_image_url text,
  org_selected_plan text,
  org_white_label_config jsonb
)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT
    COALESCE(om.is_owner, false) AS is_owner,
    o.name::text AS org_name,
    COALESCE(o.marketplace_enabled, true) AS marketplace_enabled,
    -- White-label fields
    o.slug::text,
    o.logo_url::text,
    o.logo_dark_url::text,
    o.favicon_url::text,
    COALESCE(o.primary_color, '#8B5CF6')::text,
    o.secondary_color::text,
    o.platform_name::text,
    o.sender_email::text,
    o.sender_name::text,
    o.support_email::text,
    o.custom_domain::text,
    COALESCE(o.resend_domain_verified, false),
    o.pwa_icon_192_url::text,
    o.pwa_icon_512_url::text,
    o.og_image_url::text,
    COALESCE(o.selected_plan, 'starter')::text,
    COALESCE(o.white_label_config, '{}'::jsonb)
  FROM organizations o
  LEFT JOIN organization_members om
    ON om.organization_id = o.id
    AND om.user_id = auth.uid()
  WHERE o.id = p_organization_id;
$$;

GRANT EXECUTE ON FUNCTION public.get_user_org_context(uuid) TO authenticated;

-- ========== 20260218200000_client_users_rpc.sql ==========
-- =====================================================
-- Client Users RPCs for Unified Clients Page
-- Migration: 20260218200000_client_users_rpc
-- Provides: get_org_client_users, get_unassigned_client_members
-- Updated: Include all client-group roles (client, brand_manager, marketing_director)
-- =====================================================

-- =====================================================
-- get_org_client_users: Returns ALL org members with client-group
-- roles, with their linked companies aggregated as JSONB array.
-- Shows users even if they're not linked to any company.
-- =====================================================

CREATE OR REPLACE FUNCTION get_org_client_users(p_org_id uuid)
RETURNS TABLE (
  user_id uuid,
  full_name text,
  email text,
  avatar_url text,
  phone text,
  city text,
  bio text,
  created_at timestamptz,
  linked_companies jsonb
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.id AS user_id,
    p.full_name,
    p.email,
    p.avatar_url,
    p.phone,
    p.city,
    p.bio,
    p.created_at,
    COALESCE(
      (
        SELECT jsonb_agg(
          jsonb_build_object(
            'client_id', c.id,
            'client_name', c.name,
            'role', COALESCE(cu.role, 'viewer')
          )
        )
        FROM client_users cu
        JOIN clients c ON c.id = cu.client_id AND c.organization_id = p_org_id
        WHERE cu.user_id = p.id
      ),
      '[]'::jsonb
    ) AS linked_companies
  FROM organization_members om
  JOIN profiles p ON p.id = om.user_id
  WHERE om.organization_id = p_org_id
    AND (
      om.role IN ('client', 'brand_manager', 'marketing_director')
      OR EXISTS (
        SELECT 1 FROM organization_member_roles omr
        WHERE omr.organization_id = p_org_id
          AND omr.user_id = om.user_id
          AND omr.role IN ('client', 'brand_manager', 'marketing_director')
      )
    )
  ORDER BY p.full_name;
END;
$$;

GRANT EXECUTE ON FUNCTION get_org_client_users(uuid) TO authenticated;

-- =====================================================
-- get_unassigned_client_members: Returns org members with
-- client-group roles who are NOT linked to ANY company.
-- =====================================================

CREATE OR REPLACE FUNCTION get_unassigned_client_members(p_org_id uuid)
RETURNS TABLE (
  user_id uuid,
  full_name text,
  email text,
  avatar_url text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.id AS user_id,
    p.full_name,
    p.email,
    p.avatar_url
  FROM organization_members om
  JOIN profiles p ON p.id = om.user_id
  WHERE om.organization_id = p_org_id
    AND (
      om.role IN ('client', 'brand_manager', 'marketing_director')
      OR EXISTS (
        SELECT 1 FROM organization_member_roles omr
        WHERE omr.organization_id = p_org_id
          AND omr.user_id = om.user_id
          AND omr.role IN ('client', 'brand_manager', 'marketing_director')
      )
    )
    AND NOT EXISTS (
      SELECT 1
      FROM client_users cu2
      JOIN clients c2 ON c2.id = cu2.client_id AND c2.organization_id = p_org_id
      WHERE cu2.user_id = om.user_id
    )
  ORDER BY p.full_name;
END;
$$;

GRANT EXECUTE ON FUNCTION get_unassigned_client_members(uuid) TO authenticated;

