-- ========== 20260218200002_fix_app_role_enum_and_deduct_tokens.sql ==========
-- Fix 1: Add missing roles to app_role enum
-- brand_manager, marketing_director: marketplace client roles
-- developer, educator: new global niche roles for simplified 8-role system
ALTER TYPE app_role ADD VALUE IF NOT EXISTS 'brand_manager';
ALTER TYPE app_role ADD VALUE IF NOT EXISTS 'marketing_director';
ALTER TYPE app_role ADD VALUE IF NOT EXISTS 'developer';
ALTER TYPE app_role ADD VALUE IF NOT EXISTS 'educator';

-- Fix 2: Fix deduct_ai_tokens function - column 'type' doesn't exist, should be 'transaction_type'
CREATE OR REPLACE FUNCTION public.deduct_ai_tokens(
  p_org_id uuid,
  p_cost integer,
  p_module_key text DEFAULT NULL,
  p_action text DEFAULT NULL,
  p_ai_provider text DEFAULT NULL,
  p_ai_model text DEFAULT NULL,
  p_input_tokens integer DEFAULT NULL,
  p_output_tokens integer DEFAULT NULL,
  p_description text DEFAULT NULL
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  v_row RECORD;
  v_deduct_from_remaining INTEGER;
  v_deduct_from_purchased INTEGER;
  v_new_remaining INTEGER;
  v_new_purchased INTEGER;
BEGIN
  SELECT tokens_remaining, purchased_tokens, tokens_used_this_period
    INTO v_row
    FROM public.organization_ai_tokens
   WHERE organization_id = p_org_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'tokens_remaining', 0, 'error', 'no_token_record');
  END IF;

  IF (v_row.tokens_remaining + v_row.purchased_tokens) < p_cost THEN
    RETURN jsonb_build_object(
      'ok', false,
      'tokens_remaining',
      v_row.tokens_remaining + v_row.purchased_tokens
    );
  END IF;

  v_deduct_from_remaining := LEAST(v_row.tokens_remaining, p_cost);
  v_deduct_from_purchased := p_cost - v_deduct_from_remaining;
  v_new_remaining := v_row.tokens_remaining - v_deduct_from_remaining;
  v_new_purchased := GREATEST(0, v_row.purchased_tokens - v_deduct_from_purchased);

  UPDATE public.organization_ai_tokens
     SET tokens_remaining = v_new_remaining,
         purchased_tokens = v_new_purchased,
         tokens_used_this_period = tokens_used_this_period + p_cost,
         updated_at = NOW()
   WHERE organization_id = p_org_id;

  INSERT INTO public.ai_token_transactions (
    organization_id, transaction_type, tokens_amount, module_key, action,
    ai_provider, ai_model, input_tokens, output_tokens, description
  ) VALUES (
    p_org_id, 'usage', -p_cost, p_module_key, p_action,
    p_ai_provider, p_ai_model, p_input_tokens, p_output_tokens, p_description
  );

  RETURN jsonb_build_object(
    'ok', true,
    'tokens_remaining', v_new_remaining + v_new_purchased
  );
END;
$function$;

-- ========== 20260218300000_exclude_client_roles_from_talent.sql ==========
-- =====================================================
-- Fix: Exclude client-category roles from talent page
--
-- brand_manager, marketing_director, client belong to the
-- "client" category and should NOT appear in /talent.
-- They should only appear in the Clients section.
--
-- If a user has BOTH brand_manager + creator, only the
-- creator role will show in talent (correct behavior).
-- If a user ONLY has brand_manager, they won't show in
-- talent at all (they have no team role).
-- =====================================================

CREATE OR REPLACE FUNCTION get_unified_talent(p_org_id uuid)
RETURNS TABLE (
  id uuid,
  full_name text,
  email text,
  avatar_url text,
  phone text,
  bio text,
  source text,
  org_role text,
  all_roles text[],
  is_owner boolean,
  content_count bigint,
  is_ambassador boolean,
  ambassador_level text,
  quality_score_avg numeric,
  reliability_score numeric,
  velocity_score numeric,
  ai_recommended_level text,
  ai_risk_flag text,
  active_tasks bigint,
  up_points numeric,
  up_level text,
  avg_star_rating numeric,
  rated_content_count bigint,
  relationship_id uuid,
  relationship_type text,
  times_worked_together integer,
  total_paid numeric,
  average_rating_given numeric,
  last_collaboration_at timestamptz,
  internal_notes text,
  internal_tags text[],
  list_name text,
  creator_profile_id uuid,
  categories text[],
  content_types text[],
  platforms text[],
  slug text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  WITH
  -- Client-category roles to exclude from talent view
  -- These users belong in Clients, not Talent
  client_roles AS (
    SELECT unnest(ARRAY['client', 'brand_manager', 'marketing_director']) AS role_name
  ),
  -- ALL internal org members, excluding client-category roles
  internal_members AS (
    SELECT
      om.user_id,
      om.is_owner,
      ARRAY_AGG(omr.role::text ORDER BY
        CASE omr.role::text
          WHEN 'admin' THEN 1
          WHEN 'team_leader' THEN 2
          WHEN 'strategist' THEN 3
          WHEN 'trafficker' THEN 4
          WHEN 'creator' THEN 5
          WHEN 'editor' THEN 6
          ELSE 8
        END
      ) FILTER (WHERE omr.role IS NOT NULL
        AND omr.role::text NOT IN (SELECT role_name FROM client_roles)
      ) AS roles,
      MIN(CASE omr.role::text
        WHEN 'admin' THEN 1
        WHEN 'team_leader' THEN 2
        WHEN 'strategist' THEN 3
        WHEN 'trafficker' THEN 4
        WHEN 'creator' THEN 5
        WHEN 'editor' THEN 6
        ELSE NULL
      END) FILTER (WHERE omr.role::text NOT IN (SELECT role_name FROM client_roles)
      ) AS role_priority
    FROM organization_members om
    LEFT JOIN organization_member_roles omr
      ON omr.organization_id = om.organization_id
      AND omr.user_id = om.user_id
    WHERE om.organization_id = p_org_id
    GROUP BY om.user_id, om.is_owner
    -- Keep: owners (always), users with at least one non-client role, or users with NO roles (leads)
    HAVING om.is_owner = true
       OR COUNT(*) FILTER (WHERE omr.role IS NOT NULL AND omr.role::text NOT IN (SELECT role_name FROM client_roles)) > 0
       OR COUNT(*) FILTER (WHERE omr.role IS NOT NULL) = 0
  ),
  internal_with_role AS (
    SELECT
      im.user_id,
      im.is_owner,
      im.roles,
      CASE im.role_priority
        WHEN 1 THEN 'admin'
        WHEN 2 THEN 'team_leader'
        WHEN 3 THEN 'strategist'
        WHEN 4 THEN 'trafficker'
        WHEN 5 THEN 'creator'
        WHEN 6 THEN 'editor'
        ELSE NULL
      END AS primary_role
    FROM internal_members im
  ),
  external_rels AS (
    SELECT
      r.id AS rel_id,
      r.creator_id,
      r.relationship_type,
      r.times_worked_together,
      r.total_paid,
      r.average_rating_given,
      r.last_collaboration_at,
      r.internal_notes,
      r.internal_tags,
      r.list_name
    FROM org_creator_relationships r
    WHERE r.organization_id = p_org_id
  ),
  all_users AS (
    SELECT iwr.user_id FROM internal_with_role iwr
    UNION
    SELECT er.creator_id FROM external_rels er
  ),
  ambassador_info AS (
    SELECT
      om.user_id,
      om.ambassador_level,
      EXISTS (
        SELECT 1 FROM organization_member_roles omr2
        WHERE omr2.organization_id = p_org_id
          AND omr2.user_id = om.user_id
          AND omr2.role = 'ambassador'
      ) AS is_amb_role
    FROM organization_members om
    WHERE om.organization_id = p_org_id
  ),
  content_counts AS (
    SELECT user_id, SUM(cnt) AS total
    FROM (
      SELECT creator_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND creator_id IS NOT NULL
      GROUP BY creator_id
      UNION ALL
      SELECT editor_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND editor_id IS NOT NULL
      GROUP BY editor_id
      UNION ALL
      SELECT strategist_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id AND strategist_id IS NOT NULL
      GROUP BY strategist_id
    ) sub
    GROUP BY user_id
  ),
  active_tasks_counts AS (
    SELECT user_id, SUM(cnt) AS total
    FROM (
      SELECT creator_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id
        AND status IN ('assigned','recording','recorded','editing','review','issue')
        AND creator_id IS NOT NULL
      GROUP BY creator_id
      UNION ALL
      SELECT editor_id AS user_id, COUNT(*) AS cnt
      FROM content
      WHERE organization_id = p_org_id
        AND status IN ('assigned','recording','recorded','editing','review','issue')
        AND editor_id IS NOT NULL
      GROUP BY editor_id
    ) sub
    GROUP BY user_id
  ),
  up_data AS (
    SELECT user_id, SUM(total_points) AS total_points, MAX(current_level) AS current_level
    FROM up_user_scores
    WHERE organization_id = p_org_id
    GROUP BY user_id
  ),
  star_ratings AS (
    SELECT user_id, AVG(rating) AS avg_rating, COUNT(*) AS rating_count
    FROM (
      SELECT creator_id AS user_id, creator_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND creator_rating IS NOT NULL
      UNION ALL
      SELECT editor_id AS user_id, editor_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND editor_rating IS NOT NULL
      UNION ALL
      SELECT strategist_id AS user_id, strategy_rating AS rating
      FROM content
      WHERE organization_id = p_org_id AND strategy_rating IS NOT NULL
    ) sub
    WHERE user_id IS NOT NULL
    GROUP BY user_id
  )
  SELECT
    p.id,
    p.full_name,
    p.email,
    p.avatar_url,
    p.phone,
    p.bio,
    CASE
      WHEN iwr.user_id IS NOT NULL AND er.creator_id IS NOT NULL THEN 'both'
      WHEN iwr.user_id IS NOT NULL THEN 'internal'
      ELSE 'external'
    END AS source,
    iwr.primary_role AS org_role,
    iwr.roles AS all_roles,
    COALESCE(iwr.is_owner, false) AS is_owner,
    COALESCE(cc.total, 0)::bigint AS content_count,
    COALESCE(ai.is_amb_role, p.is_ambassador, false) AS is_ambassador,
    ai.ambassador_level,
    p.quality_score_avg,
    p.reliability_score,
    p.velocity_score,
    p.ai_recommended_level,
    p.ai_risk_flag,
    COALESCE(at.total, 0)::bigint AS active_tasks,
    COALESCE(ud.total_points, 0)::numeric AS up_points,
    ud.current_level AS up_level,
    sr.avg_rating AS avg_star_rating,
    COALESCE(sr.rating_count, 0)::bigint AS rated_content_count,
    er.rel_id AS relationship_id,
    er.relationship_type,
    COALESCE(er.times_worked_together, 0) AS times_worked_together,
    COALESCE(er.total_paid, 0) AS total_paid,
    er.average_rating_given,
    er.last_collaboration_at,
    er.internal_notes,
    er.internal_tags,
    er.list_name,
    cp.id AS creator_profile_id,
    cp.categories,
    cp.content_types,
    cp.platforms,
    cp.slug
  FROM all_users au
  JOIN profiles p ON p.id = au.user_id
  LEFT JOIN internal_with_role iwr ON iwr.user_id = au.user_id
  LEFT JOIN external_rels er ON er.creator_id = au.user_id
  LEFT JOIN ambassador_info ai ON ai.user_id = au.user_id
  LEFT JOIN content_counts cc ON cc.user_id = au.user_id
  LEFT JOIN active_tasks_counts at ON at.user_id = au.user_id
  LEFT JOIN up_data ud ON ud.user_id = au.user_id
  LEFT JOIN star_ratings sr ON sr.user_id = au.user_id
  LEFT JOIN creator_profiles cp ON cp.user_id = au.user_id
  ORDER BY
    CASE
      WHEN iwr.user_id IS NOT NULL AND er.creator_id IS NOT NULL THEN 0
      WHEN iwr.user_id IS NOT NULL THEN 1
      ELSE 2
    END,
    p.full_name;
END;
$$;

-- ========== 20260219000000_fix_client_users_rpc.sql ==========
-- =====================================================
-- Fix: Client Users RPC - include users from client_users table
-- Migration: 20260219000000_fix_client_users_rpc
-- Problem: get_org_client_users only checks organization_members role
--          and organization_member_roles. Users linked via client_users
--          (company contacts) but without a client org role are invisible.
-- Fix: UNION with client_users to catch all company-linked users.
-- =====================================================

CREATE OR REPLACE FUNCTION get_org_client_users(p_org_id uuid)
RETURNS TABLE (
  user_id uuid,
  full_name text,
  email text,
  avatar_url text,
  phone text,
  city text,
  bio text,
  created_at timestamptz,
  linked_companies jsonb
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  WITH client_user_ids AS (
    -- Part 1: Org members with client-group roles
    SELECT DISTINCT om.user_id
    FROM organization_members om
    WHERE om.organization_id = p_org_id
      AND (
        om.role IN ('client', 'brand_manager', 'marketing_director')
        OR EXISTS (
          SELECT 1 FROM organization_member_roles omr
          WHERE omr.organization_id = p_org_id
            AND omr.user_id = om.user_id
            AND omr.role IN ('client', 'brand_manager', 'marketing_director')
        )
      )

    UNION

    -- Part 2: Users linked via client_users to companies in this org
    -- (regardless of org membership or org role)
    SELECT DISTINCT cu.user_id
    FROM client_users cu
    JOIN clients c ON c.id = cu.client_id AND c.organization_id = p_org_id
  )
  SELECT
    p.id AS user_id,
    p.full_name,
    p.email,
    p.avatar_url,
    p.phone,
    p.city,
    p.bio,
    p.created_at,
    COALESCE(
      (
        SELECT jsonb_agg(
          jsonb_build_object(
            'client_id', c.id,
            'client_name', c.name,
            'role', COALESCE(cu.role, 'viewer')
          )
        )
        FROM client_users cu
        JOIN clients c ON c.id = cu.client_id AND c.organization_id = p_org_id
        WHERE cu.user_id = p.id
      ),
      '[]'::jsonb
    ) AS linked_companies
  FROM client_user_ids cui
  JOIN profiles p ON p.id = cui.user_id
  ORDER BY p.full_name;
END;
$$;

GRANT EXECUTE ON FUNCTION get_org_client_users(uuid) TO authenticated;

-- ========== 20260219000001_enhance_user_detail_rpc.sql ==========
-- =====================================================
-- Enhance: get_full_user_detail RPC — add organizations + companies
-- Migration: 20260219000001_enhance_user_detail_rpc
-- Adds: 'organizations' (all org memberships) and 'companies' (all client_users links)
-- =====================================================

CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB;
BEGIN
  SELECT jsonb_build_object(
    -- profiles
    'id', p.id,
    'email', p.email,
    'full_name', p.full_name,
    'username', p.username,
    'avatar_url', p.avatar_url,
    'phone', p.phone,
    'bio', p.bio,
    'tagline', p.tagline,
    'cover_url', p.cover_url,
    'document_type', p.document_type,
    'document_number', p.document_number,
    'address', p.address,
    'city', p.city,
    'country', p.country,
    'instagram', p.instagram,
    'tiktok', p.tiktok,
    'facebook', p.facebook,
    'social_linkedin', p.social_linkedin,
    'social_twitter', p.social_twitter,
    'social_youtube', p.social_youtube,
    'portfolio_url', p.portfolio_url,
    'featured_video_url', p.featured_video_url,
    'experience_level', p.experience_level,
    'availability_status', p.availability_status,
    'best_at', p.best_at,
    'content_categories', COALESCE(p.content_categories, ARRAY[]::TEXT[]),
    'specialties_tags', COALESCE(p.specialties_tags, ARRAY[]::TEXT[]),
    'style_keywords', COALESCE(p.style_keywords, ARRAY[]::TEXT[]),
    'industries', COALESCE(p.industries, ARRAY[]::TEXT[]),
    'interests', COALESCE(p.interests, ARRAY[]::TEXT[]),
    'languages', COALESCE(p.languages, ARRAY[]::TEXT[]),
    'rate_per_content', p.rate_per_content,
    'rate_currency', p.rate_currency,
    'quality_score_avg', p.quality_score_avg,
    'reliability_score', p.reliability_score,
    'velocity_score', p.velocity_score,
    'editor_rating', p.editor_rating,
    'is_ambassador', COALESCE(p.is_ambassador, false),
    'is_platform_founder', COALESCE(p.is_platform_founder, false),
    'founder_badge_type', p.founder_badge_type,
    'active_role', p.active_role,
    'ai_recommended_level', p.ai_recommended_level,
    'ai_risk_flag', p.ai_risk_flag,
    'is_active', COALESCE(p.is_active, true),
    'crm_custom_fields', COALESCE(p.crm_custom_fields, '{}'::jsonb),
    'created_at', p.created_at,
    -- creator_profiles (nullable)
    'creator_profile_id', cp.id,
    'slug', cp.slug,
    'bio_full', cp.bio_full,
    'banner_url', cp.banner_url,
    'creator_social_links', cp.social_links,
    'level', cp.level,
    'is_verified', COALESCE(cp.is_verified, false),
    'is_available', COALESCE(cp.is_available, false),
    'rating_avg', COALESCE(cp.rating_avg, 0),
    'rating_count', COALESCE(cp.rating_count, 0),
    'completed_projects', COALESCE(cp.completed_projects, 0),
    'base_price', cp.base_price,
    'currency', COALESCE(cp.currency, 'USD'),
    'categories', COALESCE(cp.categories, ARRAY[]::TEXT[]),
    'content_types', COALESCE(cp.content_types, ARRAY[]::TEXT[]),
    'platforms', COALESCE(cp.platforms, ARRAY[]::TEXT[]),
    'marketplace_roles', COALESCE(cp.marketplace_roles, ARRAY[]::TEXT[]),
    'accepts_product_exchange', COALESCE(cp.accepts_product_exchange, false),
    'response_time_hours', cp.response_time_hours,
    'on_time_delivery_pct', cp.on_time_delivery_pct,
    'repeat_clients_pct', cp.repeat_clients_pct,
    'showreel_video_id', cp.showreel_video_id,
    'showreel_url', cp.showreel_url,
    'showreel_thumbnail', cp.showreel_thumbnail,
    -- health
    'health_score', COALESCE(h.health_score, 0),
    'health_status', COALESCE(h.health_status, 'healthy'),
    'total_logins', COALESCE(h.total_logins, 0),
    'days_since_last_activity', h.days_since_last_activity,
    'last_login_at', h.last_login_at,
    'total_actions', COALESCE(
      (SELECT COUNT(*) FROM auth.sessions WHERE user_id = p_user_id)::int, 0
    ),
    'needs_attention', COALESCE(h.needs_attention, false),
    'total_applications', COALESCE(h.total_applications, 0),
    'total_completed_projects', COALESCE(h.total_completed_projects, 0),
    'total_spent', COALESCE(h.total_spent, 0),
    -- org context (current org)
    'organization_id', om.organization_id,
    'organization_name', o.name,
    'is_owner', COALESCE(om.is_owner, false),
    'ambassador_level', om.ambassador_level,
    -- ALL organization memberships (cross-org)
    'organizations', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'organization_id', om2.organization_id,
        'organization_name', o2.name,
        'role', omr2.role,
        'is_owner', om2.is_owner,
        'joined_at', om2.joined_at
      ) ORDER BY om2.joined_at ASC)
      FROM organization_members om2
      LEFT JOIN organizations o2 ON o2.id = om2.organization_id
      LEFT JOIN LATERAL (
        SELECT omr3.role FROM organization_member_roles omr3
        WHERE omr3.user_id = p.id AND omr3.organization_id = om2.organization_id
        LIMIT 1
      ) omr2 ON TRUE
      WHERE om2.user_id = p.id
    ), '[]'::jsonb),
    -- ALL linked companies (via client_users)
    'companies', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'client_id', c2.id,
        'client_name', c2.name,
        'organization_id', c2.organization_id,
        'organization_name', o3.name,
        'role', cu2.role,
        'created_at', cu2.created_at
      ) ORDER BY cu2.created_at ASC)
      FROM client_users cu2
      JOIN clients c2 ON c2.id = cu2.client_id
      LEFT JOIN organizations o3 ON o3.id = c2.organization_id
      WHERE cu2.user_id = p.id
    ), '[]'::jsonb),
    -- nested arrays
    'roles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'role', omr.role,
        'organization_id', omr.organization_id,
        'organization_name', o2.name
      ))
      FROM organization_member_roles omr
      LEFT JOIN organizations o2 ON o2.id = omr.organization_id
      WHERE omr.user_id = p_user_id
    ), '[]'::jsonb),
    'badges', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'badge', omb.badge,
        'level', omb.level,
        'is_active', omb.is_active,
        'granted_at', omb.granted_at
      ))
      FROM organization_member_badges omb
      WHERE omb.user_id = p_user_id AND omb.is_active = true
    ), '[]'::jsonb),
    'portfolio', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', pi.id,
        'title', pi.title,
        'media_type', pi.media_type,
        'media_url', pi.media_url,
        'thumbnail_url', pi.thumbnail_url,
        'bunny_video_id', pi.bunny_video_id,
        'category', pi.category,
        'is_featured', pi.is_featured
      ) ORDER BY pi.is_featured DESC, pi.display_order ASC)
      FROM portfolio_items pi
      WHERE pi.creator_id = cp.id AND pi.is_public = true
      LIMIT 12
    ), '[]'::jsonb),
    'services', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', cs.id,
        'title', cs.title,
        'service_type', cs.service_type,
        'price_type', cs.price_type,
        'price_amount', cs.price_amount,
        'price_currency', cs.price_currency,
        'delivery_days', cs.delivery_days,
        'is_featured', cs.is_featured
      ) ORDER BY cs.is_featured DESC, cs.display_order ASC)
      FROM creator_services cs
      WHERE cs.user_id = p_user_id AND cs.is_active = true
    ), '[]'::jsonb)
  ) INTO result
  FROM profiles p
  LEFT JOIN creator_profiles cp ON cp.user_id = p.id
  LEFT JOIN platform_user_health h ON h.user_id = p.id
  LEFT JOIN organization_members om ON om.user_id = p.id
    AND om.organization_id = p.current_organization_id
  LEFT JOIN organizations o ON o.id = om.organization_id
  WHERE p.id = p_user_id;

  RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_full_user_detail(uuid) TO authenticated;

-- ========== 20260219000002_referral_gating_system.sql ==========
-- ============================================================================
-- REFERRAL GATING SYSTEM
-- Users need 3 "qualified" referrals to unlock the platform.
-- Qualified = active creator_profile + avatar_url + at least 1 portfolio item.
-- Root admin can grant access manually from CRM.
-- ============================================================================

-- 1. Add column to profiles
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS platform_access_unlocked BOOLEAN DEFAULT false;

-- 2. Grandfather all existing users (they already have access)
UPDATE profiles SET platform_access_unlocked = true WHERE platform_access_unlocked = false OR platform_access_unlocked IS NULL;

-- ============================================================================
-- count_qualified_referrals: counts how many of a user's referrals are "qualified"
-- Qualified = has creator_profile with is_active=true AND avatar_url IS NOT NULL
--             AND at least 1 portfolio_item
-- ============================================================================
CREATE OR REPLACE FUNCTION count_qualified_referrals(p_user_id UUID)
RETURNS INT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(DISTINCT rr.referred_id) INTO v_count
  FROM referral_relationships rr
  JOIN creator_profiles cp ON cp.user_id = rr.referred_id
  WHERE rr.referrer_id = p_user_id
    AND rr.status = 'active'
    AND cp.is_active = true
    AND cp.avatar_url IS NOT NULL
    AND EXISTS (
      SELECT 1 FROM portfolio_items pi
      WHERE pi.creator_profile_id = cp.id
    );

  RETURN COALESCE(v_count, 0);
END;
$$;

-- ============================================================================
-- check_and_unlock_access: verifies and unlocks if >= 3 qualified referrals
-- ============================================================================
CREATE OR REPLACE FUNCTION check_and_unlock_access(p_user_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_already_unlocked BOOLEAN;
  v_qualified INT;
BEGIN
  -- Check if already unlocked
  SELECT platform_access_unlocked INTO v_already_unlocked
  FROM profiles WHERE id = p_user_id;

  IF v_already_unlocked = true THEN
    RETURN true;
  END IF;

  -- Count qualified referrals
  v_qualified := count_qualified_referrals(p_user_id);

  IF v_qualified >= 3 THEN
    UPDATE profiles SET platform_access_unlocked = true WHERE id = p_user_id;
    RETURN true;
  END IF;

  RETURN false;
END;
$$;

-- ============================================================================
-- get_referral_gate_status: returns full progress for the gate UI
-- ============================================================================
CREATE OR REPLACE FUNCTION get_referral_gate_status(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_unlocked BOOLEAN;
  v_qualified INT;
  v_referral_code TEXT;
  v_referrals JSONB;
BEGIN
  -- Current unlock status
  SELECT platform_access_unlocked INTO v_unlocked
  FROM profiles WHERE id = p_user_id;

  IF v_unlocked = true THEN
    RETURN jsonb_build_object(
      'unlocked', true,
      'qualified_count', 3,
      'remaining', 0,
      'referral_code', NULL,
      'referrals', '[]'::jsonb
    );
  END IF;

  -- Count qualified
  v_qualified := count_qualified_referrals(p_user_id);

  -- Get the user's primary referral code
  SELECT code INTO v_referral_code
  FROM referral_codes
  WHERE user_id = p_user_id AND is_active = true
  ORDER BY created_at ASC
  LIMIT 1;

  -- Get referrals with qualification details
  SELECT COALESCE(jsonb_agg(row_to_json(r)::jsonb), '[]'::jsonb) INTO v_referrals
  FROM (
    SELECT
      rr.referred_id,
      rr.status,
      rr.created_at,
      p.full_name,
      p.avatar_url AS referred_avatar,
      cp.id IS NOT NULL AND cp.is_active = true AS has_active_profile,
      cp.avatar_url IS NOT NULL AS has_avatar,
      EXISTS (
        SELECT 1 FROM portfolio_items pi WHERE pi.creator_profile_id = cp.id
      ) AS has_portfolio,
      (
        cp.id IS NOT NULL AND cp.is_active = true
        AND cp.avatar_url IS NOT NULL
        AND EXISTS (SELECT 1 FROM portfolio_items pi WHERE pi.creator_profile_id = cp.id)
      ) AS is_qualified
    FROM referral_relationships rr
    JOIN profiles p ON p.id = rr.referred_id
    LEFT JOIN creator_profiles cp ON cp.user_id = rr.referred_id
    WHERE rr.referrer_id = p_user_id
      AND rr.status = 'active'
    ORDER BY rr.created_at DESC
  ) r;

  RETURN jsonb_build_object(
    'unlocked', false,
    'qualified_count', v_qualified,
    'remaining', GREATEST(3 - v_qualified, 0),
    'referral_code', v_referral_code,
    'referrals', v_referrals
  );
END;
$$;

-- ============================================================================
-- validate_referral_slug: validates format + uniqueness + reserved words
-- ============================================================================
CREATE OR REPLACE FUNCTION validate_referral_slug(p_slug TEXT)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_normalized TEXT;
  v_exists BOOLEAN;
  v_reserved TEXT[] := ARRAY[
    'ADMIN', 'KREOON', 'SUPPORT', 'HELP', 'API', 'APP', 'WWW',
    'BLOG', 'DOCS', 'STATUS', 'LOGIN', 'AUTH', 'REGISTER',
    'MARKETPLACE', 'SETTINGS', 'DASHBOARD', 'NULL', 'UNDEFINED'
  ];
BEGIN
  -- Normalize to uppercase
  v_normalized := UPPER(TRIM(p_slug));

  -- Check length (3-30 chars)
  IF LENGTH(v_normalized) < 3 OR LENGTH(v_normalized) > 30 THEN
    RETURN jsonb_build_object('valid', false, 'error', 'El slug debe tener entre 3 y 30 caracteres');
  END IF;

  -- Check format: alphanumeric + hyphens, no leading/trailing hyphens
  IF v_normalized !~ '^[A-Z0-9][A-Z0-9\-]*[A-Z0-9]$' AND LENGTH(v_normalized) > 2 THEN
    RETURN jsonb_build_object('valid', false, 'error', 'Solo letras, numeros y guiones. No puede empezar o terminar con guion');
  END IF;

  -- Single char slug edge case
  IF LENGTH(v_normalized) <= 2 AND v_normalized !~ '^[A-Z0-9]+$' THEN
    RETURN jsonb_build_object('valid', false, 'error', 'Solo letras y numeros');
  END IF;

  -- Check reserved words
  IF v_normalized = ANY(v_reserved) THEN
    RETURN jsonb_build_object('valid', false, 'error', 'Este slug esta reservado');
  END IF;

  -- Check uniqueness (case insensitive since we store uppercase)
  SELECT EXISTS(
    SELECT 1 FROM referral_codes WHERE UPPER(code) = v_normalized
  ) INTO v_exists;

  IF v_exists THEN
    RETURN jsonb_build_object('valid', false, 'error', 'Este slug ya esta en uso');
  END IF;

  RETURN jsonb_build_object('valid', true, 'normalized', v_normalized);
END;
$$;

-- ============================================================================
-- grant_platform_access: root admin manually unlocks a user
-- ============================================================================
CREATE OR REPLACE FUNCTION grant_platform_access(p_admin_id UUID, p_target_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_is_admin BOOLEAN;
BEGIN
  -- Verify the caller is a platform admin (user_roles table)
  SELECT EXISTS(
    SELECT 1 FROM user_roles WHERE user_id = p_admin_id AND role = 'admin'
  ) INTO v_is_admin;

  -- Also check ROOT_EMAILS as fallback
  IF NOT v_is_admin THEN
    SELECT EXISTS(
      SELECT 1 FROM auth.users
      WHERE id = p_admin_id
        AND email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com')
    ) INTO v_is_admin;
  END IF;

  IF NOT v_is_admin THEN
    RETURN jsonb_build_object('success', false, 'error', 'No tienes permisos de administrador');
  END IF;

  -- Unlock the target user
  UPDATE profiles
  SET platform_access_unlocked = true
  WHERE id = p_target_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Usuario no encontrado');
  END IF;

  RETURN jsonb_build_object('success', true);
END;
$$;

-- ============================================================================
-- TRIGGERS: auto-check referrer unlock when a referred user qualifies
-- ============================================================================

-- Helper: given a user_id (the referred), find their referrer and check unlock
CREATE OR REPLACE FUNCTION trigger_check_referrer_unlock()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_referrer_id UUID;
BEGIN
  -- Find the referrer of this user
  -- For creator_profiles trigger, the user_id is on the row
  -- For portfolio_items trigger, we need to join through creator_profiles
  IF TG_TABLE_NAME = 'creator_profiles' THEN
    SELECT rr.referrer_id INTO v_referrer_id
    FROM referral_relationships rr
    WHERE rr.referred_id = NEW.user_id
      AND rr.status = 'active'
    LIMIT 1;
  ELSIF TG_TABLE_NAME = 'portfolio_items' THEN
    SELECT rr.referrer_id INTO v_referrer_id
    FROM referral_relationships rr
    JOIN creator_profiles cp ON cp.user_id = rr.referred_id
    WHERE cp.id = NEW.creator_profile_id
      AND rr.status = 'active'
    LIMIT 1;
  END IF;

  IF v_referrer_id IS NOT NULL THEN
    PERFORM check_and_unlock_access(v_referrer_id);
  END IF;

  RETURN NEW;
END;
$$;

-- Trigger on creator_profiles: when avatar_url or is_active changes
DROP TRIGGER IF EXISTS trg_check_referrer_on_profile_update ON creator_profiles;
CREATE TRIGGER trg_check_referrer_on_profile_update
  AFTER UPDATE OF avatar_url, is_active ON creator_profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- Trigger on portfolio_items: when a new item is inserted
DROP TRIGGER IF EXISTS trg_check_referrer_on_portfolio_insert ON portfolio_items;
CREATE TRIGGER trg_check_referrer_on_portfolio_insert
  AFTER INSERT ON portfolio_items
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- ============================================================================
-- GRANTS
-- ============================================================================
GRANT EXECUTE ON FUNCTION count_qualified_referrals(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION check_and_unlock_access(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_referral_gate_status(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION validate_referral_slug(TEXT) TO authenticated;
GRANT EXECUTE ON FUNCTION grant_platform_access(UUID, UUID) TO authenticated;

-- ========== 20260219100000_wallet_operational.sql ==========
-- ============================================================================
-- WALLET OPERATIONAL MIGRATION
-- Renames columns to match frontend, creates payment_methods table,
-- adds RPCs for atomic withdrawals, admin RLS, and backward-compat view.
-- ============================================================================

-- ============================================================================
-- 1a. Rename columns in unified_wallets to match frontend types
-- ============================================================================

ALTER TABLE unified_wallets RENAME COLUMN balance_available TO available_balance;
ALTER TABLE unified_wallets RENAME COLUMN balance_pending TO pending_balance;
ALTER TABLE unified_wallets RENAME COLUMN balance_reserved TO reserved_balance;
ALTER TABLE unified_wallets RENAME COLUMN preferred_currency TO currency;

-- Add status column (frontend expects text, DB had boolean is_active)
ALTER TABLE unified_wallets ADD COLUMN IF NOT EXISTS status TEXT DEFAULT 'active';
UPDATE unified_wallets SET status = CASE WHEN is_active THEN 'active' ELSE 'suspended' END;

-- Add settings column
ALTER TABLE unified_wallets ADD COLUMN IF NOT EXISTS settings JSONB DEFAULT '{}';

-- ============================================================================
-- 1b. Create payment_methods table
-- ============================================================================

CREATE TABLE IF NOT EXISTS payment_methods (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    method_type TEXT NOT NULL,
    label TEXT NOT NULL,
    details JSONB NOT NULL DEFAULT '{}',
    is_default BOOLEAN DEFAULT false,
    is_verified BOOLEAN DEFAULT false,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE payment_methods ENABLE ROW LEVEL SECURITY;

CREATE POLICY pm_select ON payment_methods FOR SELECT USING (user_id = auth.uid());
CREATE POLICY pm_insert ON payment_methods FOR INSERT WITH CHECK (user_id = auth.uid());
CREATE POLICY pm_update ON payment_methods FOR UPDATE USING (user_id = auth.uid());
