  IF NOT EXISTS (SELECT 1 FROM pg_enum WHERE enumlabel = 'daviplata' AND enumtypid = 'withdrawal_method'::regtype) THEN
    ALTER TYPE withdrawal_method ADD VALUE 'daviplata';
