-- ========== 20260219200000_social_hub.sql ==========
-- ============================================================================
-- SOCIAL HUB MODULE
-- Schedule, publish, and measure content across social media platforms
-- ============================================================================

-- ── Enums ──────────────────────────────────────────────────────────────────

DO $$ BEGIN
  CREATE TYPE social_platform AS ENUM (
    'facebook', 'instagram', 'tiktok', 'youtube', 'twitter', 'linkedin', 'pinterest'
  );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE TYPE scheduled_post_status AS ENUM (
    'draft', 'scheduled', 'publishing', 'published', 'partially_published', 'failed', 'cancelled'
  );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE TYPE social_post_type AS ENUM (
    'post', 'reel', 'story', 'short', 'carousel', 'thread', 'pin'
  );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- ── 1. social_accounts ─────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS social_accounts (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  organization_id UUID REFERENCES organizations(id) ON DELETE SET NULL,
  platform        social_platform NOT NULL,
  platform_user_id   TEXT NOT NULL,
  platform_username  TEXT,
  platform_display_name TEXT,
  platform_avatar_url   TEXT,
  platform_page_id   TEXT,       -- Facebook Pages, LinkedIn Company pages
  platform_page_name TEXT,
  access_token       TEXT NOT NULL,
  refresh_token      TEXT,
  token_expires_at   TIMESTAMPTZ,
  scopes             TEXT[] DEFAULT '{}',
  is_active          BOOLEAN DEFAULT true,
  metadata           JSONB DEFAULT '{}',
  connected_at       TIMESTAMPTZ DEFAULT now(),
  last_synced_at     TIMESTAMPTZ,
  last_error         TEXT,
  created_at         TIMESTAMPTZ DEFAULT now(),
  updated_at         TIMESTAMPTZ DEFAULT now()
);

-- Prevent duplicate connections per platform+page per user
CREATE UNIQUE INDEX IF NOT EXISTS idx_social_accounts_unique
  ON social_accounts(user_id, platform, platform_user_id, COALESCE(platform_page_id, ''))
  WHERE is_active = true;

CREATE INDEX IF NOT EXISTS idx_social_accounts_user ON social_accounts(user_id);
CREATE INDEX IF NOT EXISTS idx_social_accounts_org ON social_accounts(organization_id) WHERE organization_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_social_accounts_token_expiry ON social_accounts(token_expires_at) WHERE is_active = true;

-- ── 2. scheduled_posts ─────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS scheduled_posts (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  organization_id UUID REFERENCES organizations(id) ON DELETE SET NULL,
  content_id      UUID,  -- optional link to existing content table
  caption         TEXT,
  hashtags        TEXT[] DEFAULT '{}',
  scheduled_at    TIMESTAMPTZ,
  published_at    TIMESTAMPTZ,
  status          scheduled_post_status DEFAULT 'draft',
  post_type       social_post_type DEFAULT 'post',
  visibility      TEXT DEFAULT 'public',
  first_comment   TEXT,            -- auto-comment after publishing
  location_name   TEXT,
  media_urls      TEXT[] DEFAULT '{}',
  thumbnail_url   TEXT,
  target_accounts JSONB DEFAULT '[]',  -- [{account_id, platform}]
  publish_results JSONB DEFAULT '[]',  -- [{account_id, platform, platform_post_id, status, error, published_at}]
  retry_count     INT DEFAULT 0,
  max_retries     INT DEFAULT 3,
  error_message   TEXT,
  metadata        JSONB DEFAULT '{}',
  created_at      TIMESTAMPTZ DEFAULT now(),
  updated_at      TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_scheduled_posts_user ON scheduled_posts(user_id);
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_org ON scheduled_posts(organization_id) WHERE organization_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_status ON scheduled_posts(status, scheduled_at)
  WHERE status = 'scheduled';
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_calendar ON scheduled_posts(user_id, scheduled_at);
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_content ON scheduled_posts(content_id) WHERE content_id IS NOT NULL;

-- ── 3. social_metrics ──────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS social_metrics (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  social_account_id UUID NOT NULL REFERENCES social_accounts(id) ON DELETE CASCADE,
  scheduled_post_id UUID REFERENCES scheduled_posts(id) ON DELETE CASCADE,
  platform_post_id  TEXT,
  metric_type       TEXT NOT NULL DEFAULT 'post',  -- 'post', 'account', 'story'
  impressions       INT DEFAULT 0,
  reach             INT DEFAULT 0,
  engagement        INT DEFAULT 0,
  likes             INT DEFAULT 0,
  comments          INT DEFAULT 0,
  shares            INT DEFAULT 0,
  saves             INT DEFAULT 0,
  clicks            INT DEFAULT 0,
  video_views       INT DEFAULT 0,
  watch_time_seconds INT DEFAULT 0,
  followers_count   INT DEFAULT 0,
  followers_gained  INT DEFAULT 0,
  profile_visits    INT DEFAULT 0,
  metadata          JSONB DEFAULT '{}',
  recorded_at       TIMESTAMPTZ DEFAULT now(),
  created_at        TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_social_metrics_account ON social_metrics(social_account_id, recorded_at DESC);
CREATE INDEX IF NOT EXISTS idx_social_metrics_post ON social_metrics(scheduled_post_id) WHERE scheduled_post_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_social_metrics_type ON social_metrics(metric_type, recorded_at DESC);

-- ── 4. social_publish_logs ─────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS social_publish_logs (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  scheduled_post_id UUID NOT NULL REFERENCES scheduled_posts(id) ON DELETE CASCADE,
  social_account_id UUID NOT NULL REFERENCES social_accounts(id) ON DELETE CASCADE,
  platform          social_platform NOT NULL,
  action            TEXT NOT NULL,  -- 'publish', 'delete', 'update', 'retry'
  status            TEXT NOT NULL,  -- 'success', 'failed', 'pending'
  platform_post_id  TEXT,
  platform_response JSONB,
  error_message     TEXT,
  duration_ms       INT,
  created_at        TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_social_publish_logs_post ON social_publish_logs(scheduled_post_id, created_at DESC);

-- ── 5. Triggers for updated_at ─────────────────────────────────────────────

CREATE OR REPLACE FUNCTION update_social_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_social_accounts_updated ON social_accounts;
CREATE TRIGGER trg_social_accounts_updated
  BEFORE UPDATE ON social_accounts
  FOR EACH ROW EXECUTE FUNCTION update_social_updated_at();

DROP TRIGGER IF EXISTS trg_scheduled_posts_updated ON scheduled_posts;
CREATE TRIGGER trg_scheduled_posts_updated
  BEFORE UPDATE ON scheduled_posts
  FOR EACH ROW EXECUTE FUNCTION update_social_updated_at();

-- ── 6. RLS Policies ────────────────────────────────────────────────────────

ALTER TABLE social_accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE scheduled_posts ENABLE ROW LEVEL SECURITY;
ALTER TABLE social_metrics ENABLE ROW LEVEL SECURITY;
ALTER TABLE social_publish_logs ENABLE ROW LEVEL SECURITY;

-- social_accounts: users see/manage their own + org members see org accounts
CREATE POLICY social_accounts_select ON social_accounts FOR SELECT USING (
  user_id = auth.uid()
  OR (organization_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM organization_members om
    WHERE om.organization_id = social_accounts.organization_id
      AND om.user_id = auth.uid()
  ))
);

CREATE POLICY social_accounts_insert ON social_accounts FOR INSERT WITH CHECK (
  user_id = auth.uid()
);

CREATE POLICY social_accounts_update ON social_accounts FOR UPDATE USING (
  user_id = auth.uid()
);

CREATE POLICY social_accounts_delete ON social_accounts FOR DELETE USING (
  user_id = auth.uid()
);

-- scheduled_posts: users see/manage their own + org members see org posts
CREATE POLICY scheduled_posts_select ON scheduled_posts FOR SELECT USING (
  user_id = auth.uid()
  OR (organization_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM organization_members om
    WHERE om.organization_id = scheduled_posts.organization_id
      AND om.user_id = auth.uid()
  ))
);

CREATE POLICY scheduled_posts_insert ON scheduled_posts FOR INSERT WITH CHECK (
  user_id = auth.uid()
);

CREATE POLICY scheduled_posts_update ON scheduled_posts FOR UPDATE USING (
  user_id = auth.uid()
  OR (organization_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM organization_members om
    WHERE om.organization_id = scheduled_posts.organization_id
      AND om.user_id = auth.uid()
      AND om.role IN ('admin', 'team_leader', 'strategist')
  ))
);

CREATE POLICY scheduled_posts_delete ON scheduled_posts FOR DELETE USING (
  user_id = auth.uid()
);

-- social_metrics: read-only for account owners + org members
CREATE POLICY social_metrics_select ON social_metrics FOR SELECT USING (
  EXISTS (
    SELECT 1 FROM social_accounts sa
    WHERE sa.id = social_metrics.social_account_id
      AND (
        sa.user_id = auth.uid()
        OR (sa.organization_id IS NOT NULL AND EXISTS (
          SELECT 1 FROM organization_members om
          WHERE om.organization_id = sa.organization_id
            AND om.user_id = auth.uid()
        ))
      )
  )
);

-- social_publish_logs: read-only for post owners
CREATE POLICY social_publish_logs_select ON social_publish_logs FOR SELECT USING (
  EXISTS (
    SELECT 1 FROM scheduled_posts sp
    WHERE sp.id = social_publish_logs.scheduled_post_id
      AND sp.user_id = auth.uid()
  )
);

-- ── 7. GRANTs ──────────────────────────────────────────────────────────────

GRANT ALL ON social_accounts TO authenticated;
GRANT ALL ON social_accounts TO service_role;
GRANT ALL ON scheduled_posts TO authenticated;
GRANT ALL ON scheduled_posts TO service_role;
GRANT ALL ON social_metrics TO authenticated;
GRANT ALL ON social_metrics TO service_role;
GRANT ALL ON social_publish_logs TO authenticated;
GRANT ALL ON social_publish_logs TO service_role;

-- ── 8. Helper RPC: get upcoming scheduled posts (for scheduler cron) ───────

CREATE OR REPLACE FUNCTION get_due_scheduled_posts()
RETURNS SETOF scheduled_posts
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT *
  FROM scheduled_posts
  WHERE status = 'scheduled'
    AND scheduled_at <= now()
    AND retry_count < max_retries
  ORDER BY scheduled_at ASC
  LIMIT 50;
$$;

-- ── 9. Helper RPC: get social account with token (for service_role) ────────

CREATE OR REPLACE FUNCTION get_social_account_token(p_account_id UUID)
RETURNS TABLE(
  id UUID,
  platform social_platform,
  access_token TEXT,
  refresh_token TEXT,
  token_expires_at TIMESTAMPTZ,
  platform_user_id TEXT,
  platform_page_id TEXT,
  metadata JSONB
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT sa.id, sa.platform, sa.access_token, sa.refresh_token,
         sa.token_expires_at, sa.platform_user_id, sa.platform_page_id, sa.metadata
  FROM social_accounts sa
  WHERE sa.id = p_account_id AND sa.is_active = true;
$$;

-- ========== 20260219200001_social_hub_campaigns.sql ==========
-- ============================================================================
-- SOCIAL HUB: Campaign Activation & Brand Collaboration
-- Enables creators to post content tagging brands as collaborators,
-- track post verification, and aggregate campaign-level metrics.
-- ============================================================================

-- ── 1. Add campaign fields to scheduled_posts ──────────────────────────────

ALTER TABLE scheduled_posts
  ADD COLUMN IF NOT EXISTS campaign_id UUID REFERENCES marketplace_campaigns(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS project_id UUID REFERENCES marketplace_projects(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS brand_collaboration JSONB DEFAULT NULL,
  -- brand_collaboration: {
  --   brand_account_id: uuid (social_accounts.id of the brand),
  --   brand_username: string (e.g. @kreoon),
  --   brand_platform_id: string (platform-specific ID for collab),
  --   collaboration_type: 'collab_post' | 'mention' | 'tag' | 'branded_content',
  --   require_approval: boolean
  -- }
  ADD COLUMN IF NOT EXISTS verification_status TEXT DEFAULT NULL,
  -- null = not applicable, 'pending' = awaiting verification, 'verified' = confirmed, 'rejected' = not compliant
  ADD COLUMN IF NOT EXISTS verification_details JSONB DEFAULT NULL,
  -- verification_details: {
  --   brand_mentioned: boolean,
  --   brand_tagged: boolean,
  --   collab_active: boolean,
  --   hashtags_used: string[],
  --   verified_at: timestamp,
  --   verified_by: uuid | 'auto'
  -- }
  ADD COLUMN IF NOT EXISTS creator_id UUID REFERENCES auth.users(id) ON DELETE SET NULL;
  -- When a brand schedules on behalf of a creator's account, creator_id tracks who

CREATE INDEX IF NOT EXISTS idx_scheduled_posts_campaign ON scheduled_posts(campaign_id) WHERE campaign_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_project ON scheduled_posts(project_id) WHERE project_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_scheduled_posts_verification ON scheduled_posts(verification_status) WHERE verification_status IS NOT NULL;

-- ── 2. Campaign social metrics aggregation view ────────────────────────────

CREATE OR REPLACE VIEW campaign_social_summary AS
SELECT
  sp.campaign_id,
  COUNT(DISTINCT sp.id) AS total_posts,
  COUNT(DISTINCT sp.id) FILTER (WHERE sp.status = 'published') AS published_posts,
  COUNT(DISTINCT sp.id) FILTER (WHERE sp.verification_status = 'verified') AS verified_posts,
  COUNT(DISTINCT sp.user_id) AS unique_creators,
  COALESCE(SUM(sm.impressions), 0) AS total_impressions,
  COALESCE(SUM(sm.reach), 0) AS total_reach,
  COALESCE(SUM(sm.engagement), 0) AS total_engagement,
  COALESCE(SUM(sm.likes), 0) AS total_likes,
  COALESCE(SUM(sm.comments), 0) AS total_comments,
  COALESCE(SUM(sm.shares), 0) AS total_shares,
  COALESCE(SUM(sm.saves), 0) AS total_saves,
  COALESCE(SUM(sm.video_views), 0) AS total_video_views,
  COALESCE(SUM(sm.clicks), 0) AS total_clicks,
  CASE
    WHEN SUM(sm.impressions) > 0
    THEN ROUND((SUM(sm.engagement)::NUMERIC / SUM(sm.impressions)::NUMERIC) * 100, 2)
    ELSE 0
  END AS avg_engagement_rate
FROM scheduled_posts sp
LEFT JOIN social_publish_logs spl ON spl.scheduled_post_id = sp.id AND spl.status = 'success'
LEFT JOIN social_metrics sm ON sm.scheduled_post_id = sp.id AND sm.metric_type = 'post'
WHERE sp.campaign_id IS NOT NULL
GROUP BY sp.campaign_id;

-- ── 3. RPC: Get campaign social metrics with creator breakdown ─────────────

CREATE OR REPLACE FUNCTION get_campaign_social_metrics(p_campaign_id UUID)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'campaign_id', p_campaign_id,
    'summary', (
      SELECT row_to_json(s) FROM campaign_social_summary s WHERE s.campaign_id = p_campaign_id
    ),
    'creators', (
      SELECT json_agg(json_build_object(
        'user_id', sp.user_id,
        'display_name', COALESCE(pr.full_name, 'Creador'),
        'avatar_url', pr.avatar_url,
        'posts_count', COUNT(sp.id),
        'published_count', COUNT(sp.id) FILTER (WHERE sp.status = 'published'),
        'verified_count', COUNT(sp.id) FILTER (WHERE sp.verification_status = 'verified'),
        'total_impressions', COALESCE(SUM(sm.impressions), 0),
        'total_reach', COALESCE(SUM(sm.reach), 0),
        'total_engagement', COALESCE(SUM(sm.engagement), 0),
        'total_likes', COALESCE(SUM(sm.likes), 0),
        'total_video_views', COALESCE(SUM(sm.video_views), 0)
      ))
      FROM scheduled_posts sp
      LEFT JOIN profiles pr ON pr.id = sp.user_id
      LEFT JOIN social_metrics sm ON sm.scheduled_post_id = sp.id AND sm.metric_type = 'post'
      WHERE sp.campaign_id = p_campaign_id
      GROUP BY sp.user_id, pr.full_name, pr.avatar_url
    ),
    'posts', (
      SELECT json_agg(json_build_object(
        'id', sp.id,
        'user_id', sp.user_id,
        'caption', LEFT(sp.caption, 200),
        'status', sp.status,
        'verification_status', sp.verification_status,
        'scheduled_at', sp.scheduled_at,
        'published_at', sp.published_at,
        'thumbnail_url', sp.thumbnail_url,
        'target_accounts', sp.target_accounts,
        'publish_results', sp.publish_results,
        'brand_collaboration', sp.brand_collaboration,
        'impressions', COALESCE(sm.impressions, 0),
        'reach', COALESCE(sm.reach, 0),
        'engagement', COALESCE(sm.engagement, 0),
        'likes', COALESCE(sm.likes, 0),
        'comments', COALESCE(sm.comments, 0),
        'shares', COALESCE(sm.shares, 0),
        'video_views', COALESCE(sm.video_views, 0)
      ) ORDER BY sp.published_at DESC NULLS LAST)
      FROM scheduled_posts sp
      LEFT JOIN LATERAL (
        SELECT * FROM social_metrics mx
        WHERE mx.scheduled_post_id = sp.id AND mx.metric_type = 'post'
        ORDER BY mx.recorded_at DESC LIMIT 1
      ) sm ON true
      WHERE sp.campaign_id = p_campaign_id
    )
  ) INTO result;

  RETURN result;
END;
$$;

-- ── 4. RPC: Verify a campaign post (auto or manual) ───────────────────────

CREATE OR REPLACE FUNCTION verify_campaign_post(
  p_post_id UUID,
  p_brand_mentioned BOOLEAN DEFAULT false,
  p_brand_tagged BOOLEAN DEFAULT false,
  p_collab_active BOOLEAN DEFAULT false,
  p_hashtags_used TEXT[] DEFAULT '{}',
  p_verified_by UUID DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  UPDATE scheduled_posts
  SET
    verification_status = CASE
      WHEN p_brand_mentioned OR p_brand_tagged OR p_collab_active THEN 'verified'
      ELSE 'rejected'
    END,
    verification_details = jsonb_build_object(
      'brand_mentioned', p_brand_mentioned,
      'brand_tagged', p_brand_tagged,
      'collab_active', p_collab_active,
      'hashtags_used', p_hashtags_used,
      'verified_at', now(),
      'verified_by', COALESCE(p_verified_by::TEXT, 'auto')
    )
  WHERE id = p_post_id AND campaign_id IS NOT NULL;
END;
$$;

