-- =============================================
-- 7. RPC: get_marketing_dashboard_metrics
-- =============================================

CREATE OR REPLACE FUNCTION public.get_marketing_dashboard_metrics(
  p_org_id UUID,
  p_from DATE,
  p_to DATE
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_result JSONB;
  v_totals JSONB;
  v_per_platform JSONB;
  v_daily JSONB;
  v_top_campaigns JSONB;
BEGIN
  -- -----------------------------------------------
  -- Totals
  -- -----------------------------------------------
  SELECT jsonb_build_object(
    'total_spend', COALESCE(SUM(m.spend), 0),
    'total_impressions', COALESCE(SUM(m.impressions), 0),
    'total_clicks', COALESCE(SUM(m.clicks), 0),
    'total_conversions', COALESCE(SUM(m.conversions), 0),
    'avg_ctr', CASE
      WHEN COALESCE(SUM(m.impressions), 0) = 0 THEN 0
      ELSE ROUND((SUM(m.clicks)::NUMERIC / SUM(m.impressions)::NUMERIC) * 100, 4)
    END,
    'avg_cpc', CASE
      WHEN COALESCE(SUM(m.clicks), 0) = 0 THEN 0
      ELSE ROUND(SUM(m.spend) / SUM(m.clicks)::NUMERIC, 4)
    END,
    'avg_roas', CASE
      WHEN COALESCE(SUM(m.spend), 0) = 0 THEN 0
      ELSE ROUND(SUM(m.conversion_value) / SUM(m.spend), 4)
    END
  ) INTO v_totals
  FROM public.marketing_metrics m
  WHERE m.organization_id = p_org_id
    AND m.date >= p_from
    AND m.date <= p_to;

  -- -----------------------------------------------
  -- Per-platform breakdown
  -- -----------------------------------------------
  SELECT COALESCE(jsonb_agg(platform_row), '[]'::jsonb)
  INTO v_per_platform
  FROM (
    SELECT jsonb_build_object(
      'platform', m.platform::TEXT,
      'spend', COALESCE(SUM(m.spend), 0),
      'impressions', COALESCE(SUM(m.impressions), 0),
      'clicks', COALESCE(SUM(m.clicks), 0),
      'conversions', COALESCE(SUM(m.conversions), 0),
      'ctr', CASE
        WHEN COALESCE(SUM(m.impressions), 0) = 0 THEN 0
        ELSE ROUND((SUM(m.clicks)::NUMERIC / SUM(m.impressions)::NUMERIC) * 100, 4)
      END,
      'cpc', CASE
        WHEN COALESCE(SUM(m.clicks), 0) = 0 THEN 0
        ELSE ROUND(SUM(m.spend) / SUM(m.clicks)::NUMERIC, 4)
      END,
      'roas', CASE
        WHEN COALESCE(SUM(m.spend), 0) = 0 THEN 0
        ELSE ROUND(SUM(m.conversion_value) / SUM(m.spend), 4)
      END
    ) AS platform_row
    FROM public.marketing_metrics m
    WHERE m.organization_id = p_org_id
      AND m.date >= p_from
      AND m.date <= p_to
    GROUP BY m.platform
  ) sub;

  -- -----------------------------------------------
  -- Daily time series
  -- -----------------------------------------------
  SELECT COALESCE(jsonb_agg(daily_row ORDER BY d), '[]'::jsonb)
  INTO v_daily
  FROM (
    SELECT jsonb_build_object(
      'date', m.date::TEXT,
      'spend', COALESCE(SUM(m.spend), 0),
      'impressions', COALESCE(SUM(m.impressions), 0),
      'clicks', COALESCE(SUM(m.clicks), 0),
      'conversions', COALESCE(SUM(m.conversions), 0)
    ) AS daily_row,
    m.date AS d
    FROM public.marketing_metrics m
    WHERE m.organization_id = p_org_id
      AND m.date >= p_from
      AND m.date <= p_to
    GROUP BY m.date
  ) sub;

  -- -----------------------------------------------
  -- Top 5 campaigns by spend
  -- -----------------------------------------------
  SELECT COALESCE(jsonb_agg(camp_row), '[]'::jsonb)
  INTO v_top_campaigns
  FROM (
    SELECT jsonb_build_object(
      'campaign_id', ac.id,
      'name', ac.name,
      'platform', ac.platform::TEXT,
      'status', ac.status::TEXT,
      'objective', ac.objective::TEXT,
      'spend', COALESCE(SUM(m.spend), 0),
      'impressions', COALESCE(SUM(m.impressions), 0),
      'clicks', COALESCE(SUM(m.clicks), 0),
      'conversions', COALESCE(SUM(m.conversions), 0),
      'roas', CASE
        WHEN COALESCE(SUM(m.spend), 0) = 0 THEN 0
        ELSE ROUND(SUM(m.conversion_value) / SUM(m.spend), 4)
      END
    ) AS camp_row
    FROM public.marketing_campaigns ac
    LEFT JOIN public.marketing_metrics m
      ON m.campaign_id = ac.id
     AND m.date >= p_from
     AND m.date <= p_to
    WHERE ac.organization_id = p_org_id
    GROUP BY ac.id, ac.name, ac.platform, ac.status, ac.objective
    ORDER BY COALESCE(SUM(m.spend), 0) DESC
    LIMIT 5
  ) sub;

  -- -----------------------------------------------
  -- Assemble result
  -- -----------------------------------------------
  v_result := v_totals || jsonb_build_object(
    'per_platform', v_per_platform,
    'daily', v_daily,
    'top_campaigns', v_top_campaigns
  );

  RETURN v_result;
END;
$$;

-- Grant execute to authenticated users
GRANT EXECUTE ON FUNCTION public.get_marketing_dashboard_metrics(UUID, DATE, DATE) TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_marketing_dashboard_metrics(UUID, DATE, DATE) TO service_role;

-- ========== 20260219300001_campaign_payment_escrow.sql ==========
-- ============================================================================
-- CAMPAIGN PAYMENT & ESCROW INTEGRATION
-- Adds commission tracking, escrow integration, and activation workflow
-- Commission: 30% self-service, 40% with Kreoon Agency support
-- ============================================================================

-- ── 1. Add commission and payment columns to marketplace_campaigns ──────

ALTER TABLE marketplace_campaigns
  ADD COLUMN IF NOT EXISTS requires_agency_support BOOLEAN DEFAULT false,
  -- When true: full strategy, scripts, process support from Kreoon Agency → 40% commission
  -- When false: self-service campaign → 30% commission
  ADD COLUMN IF NOT EXISTS commission_rate NUMERIC(5,2) DEFAULT 30,
  -- 30 or 40 based on requires_agency_support
  ADD COLUMN IF NOT EXISTS payment_status TEXT DEFAULT 'unpaid',
  -- 'unpaid' | 'pending_payment' | 'in_escrow' | 'partially_released' | 'fully_released' | 'refunded'
  ADD COLUMN IF NOT EXISTS escrow_hold_id UUID REFERENCES escrow_holds(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS total_paid NUMERIC(12,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS stripe_payment_intent_id TEXT,
  ADD COLUMN IF NOT EXISTS activated_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ;

-- ── 2. Add payment fields to campaign_applications ──────────────────────

ALTER TABLE campaign_applications
  ADD COLUMN IF NOT EXISTS agreed_price NUMERIC(10,2),
  -- Final agreed price (after counter-offers)
  ADD COLUMN IF NOT EXISTS payment_status TEXT DEFAULT 'unpaid',
  -- 'unpaid' | 'in_escrow' | 'released' | 'refunded'
  ADD COLUMN IF NOT EXISTS escrow_hold_id UUID REFERENCES escrow_holds(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS includes_editing BOOLEAN DEFAULT false,
  ADD COLUMN IF NOT EXISTS estimated_delivery_days INTEGER,
  ADD COLUMN IF NOT EXISTS delivered_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS rating INTEGER CHECK (rating >= 1 AND rating <= 5);

-- ── 3. Trigger to auto-set commission rate based on agency support ──────

CREATE OR REPLACE FUNCTION auto_set_campaign_commission()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  IF NEW.requires_agency_support = true THEN
    NEW.commission_rate := 40;
  ELSE
    NEW.commission_rate := 30;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_auto_campaign_commission ON marketplace_campaigns;
CREATE TRIGGER trg_auto_campaign_commission
  BEFORE INSERT OR UPDATE OF requires_agency_support
  ON marketplace_campaigns
  FOR EACH ROW
  EXECUTE FUNCTION auto_set_campaign_commission();

-- ── 4. Function to activate a campaign (create escrow, set status) ──────

CREATE OR REPLACE FUNCTION activate_campaign(
  p_campaign_id UUID,
  p_payment_intent_id TEXT DEFAULT NULL
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_campaign RECORD;
  v_escrow_id UUID;
  v_result JSON;
BEGIN
  SELECT * INTO v_campaign
  FROM marketplace_campaigns
  WHERE id = p_campaign_id;

  IF NOT FOUND THEN
    RETURN json_build_object('success', false, 'error', 'Campaign not found');
  END IF;

  IF v_campaign.status NOT IN ('draft', 'active') THEN
    RETURN json_build_object('success', false, 'error', 'Campaign cannot be activated in current status');
  END IF;

  -- Create escrow hold for the campaign budget
  IF v_campaign.total_budget IS NOT NULL AND v_campaign.total_budget > 0 THEN
    INSERT INTO escrow_holds (
      payer_wallet_id,
      payee_wallet_id,
      amount,
      currency,
      description,
      auto_release_at,
      metadata
    )
    SELECT
      pw.id,     -- payer = brand/org wallet
      NULL,      -- payee determined per creator on release
      v_campaign.total_budget,
      COALESCE(v_campaign.currency, 'USD'),
      'Campaign escrow: ' || v_campaign.title,
      v_campaign.campaign_end_date + INTERVAL '7 days',
      jsonb_build_object(
        'campaign_id', p_campaign_id,
        'commission_rate', v_campaign.commission_rate,
        'type', 'campaign_escrow'
      )
    FROM unified_wallets pw
    WHERE pw.owner_id = COALESCE(v_campaign.organization_id::TEXT, v_campaign.created_by::TEXT)
      AND pw.wallet_type IN ('organization', 'creator')
    LIMIT 1
    RETURNING id INTO v_escrow_id;
  END IF;

  -- Update campaign
  UPDATE marketplace_campaigns
  SET
    status = 'active',
    payment_status = CASE WHEN v_escrow_id IS NOT NULL THEN 'in_escrow' ELSE 'pending_payment' END,
    escrow_hold_id = v_escrow_id,
    stripe_payment_intent_id = p_payment_intent_id,
    activated_at = NOW(),
    published_at = COALESCE(published_at, NOW())
  WHERE id = p_campaign_id;

  RETURN json_build_object(
    'success', true,
    'campaign_id', p_campaign_id,
    'escrow_hold_id', v_escrow_id,
    'payment_status', CASE WHEN v_escrow_id IS NOT NULL THEN 'in_escrow' ELSE 'pending_payment' END
  );
END;
$$;

-- ── 5. Function to approve application and create project ───────────────

CREATE OR REPLACE FUNCTION approve_campaign_application(
  p_application_id UUID,
  p_agreed_price NUMERIC DEFAULT NULL
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_app RECORD;
  v_campaign RECORD;
  v_project_id UUID;
  v_escrow_id UUID;
BEGIN
  SELECT * INTO v_app FROM campaign_applications WHERE id = p_application_id;
  IF NOT FOUND THEN
    RETURN json_build_object('success', false, 'error', 'Application not found');
  END IF;

  SELECT * INTO v_campaign FROM marketplace_campaigns WHERE id = v_app.campaign_id;

  -- Set agreed price
  UPDATE campaign_applications
  SET
    status = 'approved',
    agreed_price = COALESCE(p_agreed_price, v_app.bid_amount, v_app.proposed_price, v_campaign.budget_per_video)
  WHERE id = p_application_id;

  -- Create marketplace project
  INSERT INTO marketplace_projects (
    campaign_id,
    brand_id,
    creator_id,
    title,
    description,
    status,
    agreed_price,
    currency,
    deadline,
    metadata
  ) VALUES (
    v_campaign.id,
    v_campaign.brand_id,
    v_app.creator_id,
    v_campaign.title || ' - ' || (SELECT display_name FROM creator_profiles WHERE id = v_app.creator_id),
    v_campaign.description,
    'in_progress',
    COALESCE(p_agreed_price, v_app.bid_amount, v_app.proposed_price, v_campaign.budget_per_video),
    COALESCE(v_campaign.currency, 'USD'),
    COALESCE(v_campaign.content_deadline, v_campaign.deadline),
    jsonb_build_object(
      'campaign_id', v_campaign.id,
      'application_id', p_application_id,
      'commission_rate', v_campaign.commission_rate,
      'includes_editing', v_app.includes_editing
    )
  )
  RETURNING id INTO v_project_id;

  -- Update application with project reference
  UPDATE campaign_applications SET status = 'assigned' WHERE id = p_application_id;

  -- Update campaign approved count
  UPDATE marketplace_campaigns
  SET approved_count = approved_count + 1,
      status = CASE WHEN status = 'active' THEN 'in_progress' ELSE status END
  WHERE id = v_campaign.id;

  RETURN json_build_object(
    'success', true,
    'project_id', v_project_id,
    'application_id', p_application_id,
    'agreed_price', COALESCE(p_agreed_price, v_app.bid_amount, v_app.proposed_price)
  );
END;
$$;

-- ── 6. Function to complete a campaign project and release payment ──────

CREATE OR REPLACE FUNCTION complete_campaign_delivery(
  p_application_id UUID,
  p_rating INTEGER DEFAULT NULL
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_app RECORD;
  v_campaign RECORD;
  v_agreed_price NUMERIC;
  v_commission NUMERIC;
  v_creator_payout NUMERIC;
BEGIN
  SELECT * INTO v_app FROM campaign_applications WHERE id = p_application_id;
  IF NOT FOUND THEN
    RETURN json_build_object('success', false, 'error', 'Application not found');
  END IF;

  SELECT * INTO v_campaign FROM marketplace_campaigns WHERE id = v_app.campaign_id;

  v_agreed_price := COALESCE(v_app.agreed_price, v_app.bid_amount, v_app.proposed_price, 0);
  v_commission := v_agreed_price * (v_campaign.commission_rate / 100.0);
  v_creator_payout := v_agreed_price - v_commission;

  -- Mark application as completed
  UPDATE campaign_applications
  SET
    status = 'completed',
    payment_status = 'released',
    completed_at = NOW(),
    rating = p_rating
  WHERE id = p_application_id;

  -- Update marketplace project status
  UPDATE marketplace_projects
  SET status = 'completed',
      payment_status = 'released'
  WHERE campaign_id = v_campaign.id
    AND creator_id = v_app.creator_id;

  -- Check if all applications for this campaign are completed
  IF NOT EXISTS (
    SELECT 1 FROM campaign_applications
    WHERE campaign_id = v_campaign.id
      AND status NOT IN ('completed', 'rejected', 'withdrawn')
  ) THEN
    UPDATE marketplace_campaigns
    SET status = 'completed',
        payment_status = 'fully_released',
        completed_at = NOW()
    WHERE id = v_campaign.id;
  END IF;

  RETURN json_build_object(
    'success', true,
    'application_id', p_application_id,
    'agreed_price', v_agreed_price,
    'commission', v_commission,
    'commission_rate', v_campaign.commission_rate,
    'creator_payout', v_creator_payout,
    'requires_agency_support', v_campaign.requires_agency_support
  );
END;
$$;

-- ── 7. Indexes ──────────────────────────────────────────────────────────

CREATE INDEX IF NOT EXISTS idx_campaigns_payment_status
  ON marketplace_campaigns(payment_status)
  WHERE payment_status != 'unpaid';

CREATE INDEX IF NOT EXISTS idx_applications_payment_status
  ON campaign_applications(payment_status)
  WHERE payment_status != 'unpaid';

-- ── 8. GRANTs ───────────────────────────────────────────────────────────

GRANT EXECUTE ON FUNCTION activate_campaign(UUID, TEXT) TO authenticated;
GRANT EXECUTE ON FUNCTION activate_campaign(UUID, TEXT) TO service_role;
GRANT EXECUTE ON FUNCTION approve_campaign_application(UUID, NUMERIC) TO authenticated;
GRANT EXECUTE ON FUNCTION approve_campaign_application(UUID, NUMERIC) TO service_role;
GRANT EXECUTE ON FUNCTION complete_campaign_delivery(UUID, INTEGER) TO authenticated;
GRANT EXECUTE ON FUNCTION complete_campaign_delivery(UUID, INTEGER) TO service_role;

-- ========== 20260220000000_referral_enhancements.sql ==========
-- ============================================================================
-- REFERRAL ENHANCEMENTS: Tiers, Bilateral Rewards, Leaderboard, Promos, Nurture
-- ============================================================================

-- ─── 1A. referral_tiers (reference table) ───
CREATE TABLE IF NOT EXISTS referral_tiers (
  tier_key TEXT PRIMARY KEY,
  label TEXT NOT NULL,
  min_referrals INT NOT NULL DEFAULT 0,
  bonus_subscription_percent NUMERIC(5,2) NOT NULL DEFAULT 0,
  badge_emoji TEXT NOT NULL DEFAULT '',
  badge_color TEXT NOT NULL DEFAULT '#888',
  sort_order INT NOT NULL DEFAULT 0
);

INSERT INTO referral_tiers (tier_key, label, min_referrals, bonus_subscription_percent, badge_emoji, badge_color, sort_order)
VALUES
  ('starter',   'Starter',   0,  0, '', '#888888', 0),
  ('ambassador','Ambassador', 3,  2, '', '#9333ea', 1),
  ('champion',  'Champion',  10, 3, '', '#f59e0b', 2),
  ('elite',     'Elite',     25, 5, '', '#3b82f6', 3),
  ('legend',    'Legend',     50, 7, '', '#ef4444', 4)
ON CONFLICT (tier_key) DO NOTHING;

-- ─── 1B. ALTER referral_codes — bilateral rewards columns ───
ALTER TABLE referral_codes
  ADD COLUMN IF NOT EXISTS referred_discount_percent INT DEFAULT 30,
  ADD COLUMN IF NOT EXISTS referred_bonus_coins INT DEFAULT 25,
  ADD COLUMN IF NOT EXISTS referrer_bonus_coins INT DEFAULT 50;

-- ─── 1C. ALTER referral_relationships — coins tracking ───
ALTER TABLE referral_relationships
  ADD COLUMN IF NOT EXISTS referrer_coins_awarded INT DEFAULT 0,
  ADD COLUMN IF NOT EXISTS referred_coins_awarded INT DEFAULT 0;

-- ─── 1D. ALTER profiles — referral tier ───
ALTER TABLE profiles
  ADD COLUMN IF NOT EXISTS referral_tier TEXT DEFAULT 'starter';

-- ─── 1E. referral_leaderboard ───
CREATE TABLE IF NOT EXISTS referral_leaderboard (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  period_month TEXT NOT NULL, -- 'YYYY-MM'
  referrals_count INT NOT NULL DEFAULT 0,
  earnings_amount NUMERIC(12,2) NOT NULL DEFAULT 0,
  rank_position INT NOT NULL DEFAULT 0,
  is_featured BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(user_id, period_month)
);

CREATE INDEX IF NOT EXISTS idx_referral_leaderboard_period
  ON referral_leaderboard(period_month, rank_position);

-- ─── 1F. promotional_campaigns ───
CREATE TABLE IF NOT EXISTS promotional_campaigns (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT NOT NULL UNIQUE,
  name TEXT NOT NULL,
  description TEXT,
  start_date TIMESTAMPTZ NOT NULL DEFAULT now(),
  end_date TIMESTAMPTZ NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT true,
  referred_discount_percent INT NOT NULL DEFAULT 30,
  referred_bonus_coins INT NOT NULL DEFAULT 25,
  referrer_bonus_coins INT NOT NULL DEFAULT 50,
  referral_extra_free_months INT NOT NULL DEFAULT 0,
  max_redemptions INT,
  current_redemptions INT NOT NULL DEFAULT 0,
  promo_badge_text TEXT,
  promo_badge_color TEXT DEFAULT '#9333ea',
  metadata JSONB DEFAULT '{}',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Seed: Early Bird Marzo 2026
INSERT INTO promotional_campaigns (slug, name, description, start_date, end_date, referred_discount_percent, referred_bonus_coins, referrer_bonus_coins, referral_extra_free_months, max_redemptions, promo_badge_text, promo_badge_color)
VALUES (
  'early-bird-marzo-2026',
  'Early Bird Marzo 2026',
  'Los primeros 100 referidos reciben 40% de descuento + 50 Kreoon Coins + 1 mes gratis.',
  '2026-03-01T00:00:00Z',
  '2026-03-31T23:59:59Z',
  40, 50, 75, 1, 100,
  'Early Bird', '#f59e0b'
)
ON CONFLICT (slug) DO NOTHING;

-- ─── 1G. campaign_redemptions ───
CREATE TABLE IF NOT EXISTS campaign_redemptions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id UUID NOT NULL REFERENCES promotional_campaigns(id) ON DELETE CASCADE,
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  referral_code_used TEXT,
  free_months_granted INT NOT NULL DEFAULT 0,
  bonus_coins_granted INT NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(campaign_id, user_id)
);

-- ─── 1H. referral_nurture_queue ───
CREATE TABLE IF NOT EXISTS referral_nurture_queue (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  referred_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  referrer_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  relationship_id UUID REFERENCES referral_relationships(id) ON DELETE SET NULL,
  has_creator_profile BOOLEAN NOT NULL DEFAULT false,
  has_avatar BOOLEAN NOT NULL DEFAULT false,
  has_portfolio BOOLEAN NOT NULL DEFAULT false,
  is_qualified BOOLEAN NOT NULL DEFAULT false,
  reminder_count INT NOT NULL DEFAULT 0,
  next_reminder_at TIMESTAMPTZ DEFAULT (now() + INTERVAL '1 day'),
  completed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(referred_id)
);

-- ─── 1I-a. RPC: award_referral_coins ───
CREATE OR REPLACE FUNCTION award_referral_coins(
  p_user_id UUID,
  p_org_id UUID,
  p_amount INT,
  p_reason TEXT DEFAULT 'referral_bonus'
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER
AS $$
BEGIN
  -- Kreoon Coins = reputation points, award via reputation_events
  INSERT INTO reputation_events (
    user_id,
    organization_id,
    event_type,
    base_points,
    final_points,
    metadata
  ) VALUES (
    p_user_id,
    COALESCE(p_org_id, (
      SELECT om.organization_id FROM organization_members om
      WHERE om.user_id = p_user_id LIMIT 1
    )),
    'referral_bonus',
    p_amount,
    p_amount,
    jsonb_build_object('reason', p_reason, 'coins', p_amount)
  );
END;
$$;

-- ─── 1I-b. Function: compute_referral_tier ───
CREATE OR REPLACE FUNCTION compute_referral_tier(p_count INT)
RETURNS TEXT
LANGUAGE plpgsql IMMUTABLE
AS $$
BEGIN
  IF p_count >= 50 THEN RETURN 'legend';
  ELSIF p_count >= 25 THEN RETURN 'elite';
  ELSIF p_count >= 10 THEN RETURN 'champion';
  ELSIF p_count >= 3 THEN RETURN 'ambassador';
  ELSE RETURN 'starter';
  END IF;
END;
$$;

-- ─── 1I-c. Trigger function: update_user_referral_tier ───
CREATE OR REPLACE FUNCTION update_user_referral_tier()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_referrer_id UUID;
  v_count INT;
  v_new_tier TEXT;
  v_bonus NUMERIC;
  v_new_rate NUMERIC;
BEGIN
  v_referrer_id := NEW.referrer_id;

  -- Count active referrals for this referrer
  SELECT COUNT(*) INTO v_count
  FROM referral_relationships
  WHERE referrer_id = v_referrer_id AND status = 'active';

  -- Determine tier
  v_new_tier := compute_referral_tier(v_count);

  -- Update profile tier
  UPDATE profiles SET referral_tier = v_new_tier WHERE id = v_referrer_id;

  -- Get tier bonus
  SELECT bonus_subscription_percent INTO v_bonus
  FROM referral_tiers WHERE tier_key = v_new_tier;

  -- Calculate new rate: base 20% + tier bonus
  v_new_rate := 0.20 + COALESCE(v_bonus, 0) / 100.0;

  -- Update ALL active relationships for this referrer
  UPDATE referral_relationships
  SET subscription_rate = v_new_rate
  WHERE referrer_id = v_referrer_id AND status = 'active';

  RETURN NEW;
END;
$$;

-- Drop trigger if exists, then create
DROP TRIGGER IF EXISTS trg_update_referral_tier ON referral_relationships;
CREATE TRIGGER trg_update_referral_tier
  AFTER INSERT OR UPDATE OF status ON referral_relationships
  FOR EACH ROW
  WHEN (NEW.status = 'active')
  EXECUTE FUNCTION update_user_referral_tier();

-- ─── 1I-d. Trigger function: enqueue_referral_nurture ───
CREATE OR REPLACE FUNCTION enqueue_referral_nurture()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_has_profile BOOLEAN := false;
  v_has_avatar BOOLEAN := false;
  v_has_portfolio BOOLEAN := false;
BEGIN
  -- Check initial state
  SELECT EXISTS(SELECT 1 FROM creator_profiles WHERE user_id = NEW.referred_id)
    INTO v_has_profile;

  SELECT EXISTS(
    SELECT 1 FROM profiles WHERE id = NEW.referred_id AND avatar_url IS NOT NULL AND avatar_url <> ''
  ) INTO v_has_avatar;

  SELECT EXISTS(SELECT 1 FROM portfolio_items WHERE user_id = NEW.referred_id)
    INTO v_has_portfolio;

  -- Insert into nurture queue
  INSERT INTO referral_nurture_queue (
    referred_id, referrer_id, relationship_id,
    has_creator_profile, has_avatar, has_portfolio,
    is_qualified,
    completed_at
  ) VALUES (
    NEW.referred_id, NEW.referrer_id, NEW.id,
    v_has_profile, v_has_avatar, v_has_portfolio,
    (v_has_profile AND v_has_avatar AND v_has_portfolio),
    CASE WHEN (v_has_profile AND v_has_avatar AND v_has_portfolio) THEN now() ELSE NULL END
  )
  ON CONFLICT (referred_id) DO NOTHING;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enqueue_referral_nurture ON referral_relationships;
CREATE TRIGGER trg_enqueue_referral_nurture
  AFTER INSERT ON referral_relationships
  FOR EACH ROW
  EXECUTE FUNCTION enqueue_referral_nurture();

-- ─── 1I-e. Trigger function: check_nurture_completion (creator_profiles) ───
CREATE OR REPLACE FUNCTION check_nurture_on_profile()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_row referral_nurture_queue%ROWTYPE;
BEGIN
  SELECT * INTO v_row
  FROM referral_nurture_queue
  WHERE referred_id = NEW.user_id AND completed_at IS NULL;

  IF NOT FOUND THEN RETURN NEW; END IF;

  -- Update profile check
  UPDATE referral_nurture_queue
  SET has_creator_profile = true, updated_at = now()
  WHERE id = v_row.id;

  -- Check if fully qualified now
  IF v_row.has_avatar AND true AND v_row.has_portfolio THEN
    UPDATE referral_nurture_queue
    SET is_qualified = true, completed_at = now(), updated_at = now()
    WHERE id = v_row.id;

    -- Award coins to BOTH users
    PERFORM award_referral_coins(v_row.referrer_id, NULL, 50, 'referral_qualified');
    PERFORM award_referral_coins(v_row.referred_id, NULL, 25, 'referral_welcome_qualified');

    -- Mark coins on relationship
    UPDATE referral_relationships
    SET referrer_coins_awarded = COALESCE(referrer_coins_awarded, 0) + 50,
        referred_coins_awarded = COALESCE(referred_coins_awarded, 0) + 25
    WHERE id = v_row.relationship_id;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_nurture_check_profile ON creator_profiles;
CREATE TRIGGER trg_nurture_check_profile
  AFTER INSERT ON creator_profiles
  FOR EACH ROW
  EXECUTE FUNCTION check_nurture_on_profile();

-- ─── 1I-f. Trigger function: check_nurture_on_avatar (profiles) ───
CREATE OR REPLACE FUNCTION check_nurture_on_avatar()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_row referral_nurture_queue%ROWTYPE;
BEGIN
  -- Only fire if avatar changed to non-null
  IF NEW.avatar_url IS NULL OR NEW.avatar_url = '' THEN RETURN NEW; END IF;
  IF OLD IS NOT NULL AND OLD.avatar_url = NEW.avatar_url THEN RETURN NEW; END IF;

  SELECT * INTO v_row
  FROM referral_nurture_queue
  WHERE referred_id = NEW.id AND completed_at IS NULL;

  IF NOT FOUND THEN RETURN NEW; END IF;

  UPDATE referral_nurture_queue
  SET has_avatar = true, updated_at = now()
  WHERE id = v_row.id;

  -- Check if fully qualified
  IF v_row.has_creator_profile AND true AND v_row.has_portfolio THEN
    UPDATE referral_nurture_queue
    SET is_qualified = true, completed_at = now(), updated_at = now()
    WHERE id = v_row.id;

    PERFORM award_referral_coins(v_row.referrer_id, NULL, 50, 'referral_qualified');
    PERFORM award_referral_coins(v_row.referred_id, NULL, 25, 'referral_welcome_qualified');

    UPDATE referral_relationships
    SET referrer_coins_awarded = COALESCE(referrer_coins_awarded, 0) + 50,
        referred_coins_awarded = COALESCE(referred_coins_awarded, 0) + 25
    WHERE id = v_row.relationship_id;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_nurture_check_avatar ON profiles;
CREATE TRIGGER trg_nurture_check_avatar
  AFTER UPDATE OF avatar_url ON profiles
  FOR EACH ROW
  EXECUTE FUNCTION check_nurture_on_avatar();

-- ─── 1I-g. Trigger function: check_nurture_on_portfolio (portfolio_items) ───
CREATE OR REPLACE FUNCTION check_nurture_on_portfolio()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_row referral_nurture_queue%ROWTYPE;
BEGIN
  SELECT * INTO v_row
  FROM referral_nurture_queue
  WHERE referred_id = NEW.user_id AND completed_at IS NULL;

  IF NOT FOUND THEN RETURN NEW; END IF;

  UPDATE referral_nurture_queue
  SET has_portfolio = true, updated_at = now()
  WHERE id = v_row.id;

  -- Check if fully qualified
  IF v_row.has_creator_profile AND v_row.has_avatar AND true THEN
    UPDATE referral_nurture_queue
    SET is_qualified = true, completed_at = now(), updated_at = now()
    WHERE id = v_row.id;

    PERFORM award_referral_coins(v_row.referrer_id, NULL, 50, 'referral_qualified');
    PERFORM award_referral_coins(v_row.referred_id, NULL, 25, 'referral_welcome_qualified');

    UPDATE referral_relationships
    SET referrer_coins_awarded = COALESCE(referrer_coins_awarded, 0) + 50,
        referred_coins_awarded = COALESCE(referred_coins_awarded, 0) + 25
    WHERE id = v_row.relationship_id;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_nurture_check_portfolio ON portfolio_items;
CREATE TRIGGER trg_nurture_check_portfolio
  AFTER INSERT ON portfolio_items
  FOR EACH ROW
  EXECUTE FUNCTION check_nurture_on_portfolio();

-- ─── 1I-h. RPC: update_referral_leaderboard (monthly cron) ───
CREATE OR REPLACE FUNCTION update_referral_leaderboard()
RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
  v_period TEXT;
BEGIN
  v_period := to_char(now(), 'YYYY-MM');

  -- Delete old entries for this period
  DELETE FROM referral_leaderboard WHERE period_month = v_period;

  -- Insert aggregated data
  INSERT INTO referral_leaderboard (user_id, period_month, referrals_count, earnings_amount, rank_position, is_featured)
  SELECT
    rr.referrer_id,
    v_period,
    COUNT(*)::INT,
    COALESCE(SUM(re.commission_amount), 0),
    ROW_NUMBER() OVER (ORDER BY COUNT(*) DESC, COALESCE(SUM(re.commission_amount), 0) DESC)::INT,
    ROW_NUMBER() OVER (ORDER BY COUNT(*) DESC, COALESCE(SUM(re.commission_amount), 0) DESC) <= 10
  FROM referral_relationships rr
  LEFT JOIN referral_earnings re ON re.relationship_id = rr.id
    AND re.created_at >= date_trunc('month', now())
    AND re.created_at < date_trunc('month', now()) + INTERVAL '1 month'
  WHERE rr.created_at >= date_trunc('month', now())
    AND rr.created_at < date_trunc('month', now()) + INTERVAL '1 month'
    AND rr.status = 'active'
  GROUP BY rr.referrer_id;
END;
$$;

-- ─── 1J. Cron job (monthly leaderboard) ───
-- Requires pg_cron extension (already enabled)
SELECT cron.schedule(
  'referral-leaderboard-monthly',
  '0 1 1 * *',
  $$SELECT update_referral_leaderboard()$$
);

-- ─── 1K. RLS Policies ───

ALTER TABLE referral_tiers ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read tiers" ON referral_tiers FOR SELECT USING (true);

ALTER TABLE referral_leaderboard ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read leaderboard" ON referral_leaderboard FOR SELECT USING (true);

ALTER TABLE promotional_campaigns ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read active promos" ON promotional_campaigns FOR SELECT USING (true);

ALTER TABLE campaign_redemptions ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Users see own redemptions" ON campaign_redemptions FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Service role inserts redemptions" ON campaign_redemptions FOR INSERT WITH CHECK (true);

ALTER TABLE referral_nurture_queue ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Users see own nurture" ON referral_nurture_queue FOR SELECT USING (auth.uid() = referred_id OR auth.uid() = referrer_id);

-- ─── 1L. GRANTs ───

GRANT ALL ON referral_tiers TO authenticated;
GRANT ALL ON referral_tiers TO service_role;

GRANT ALL ON referral_leaderboard TO authenticated;
GRANT ALL ON referral_leaderboard TO service_role;

GRANT ALL ON promotional_campaigns TO authenticated;
GRANT ALL ON promotional_campaigns TO service_role;

GRANT ALL ON campaign_redemptions TO authenticated;
GRANT ALL ON campaign_redemptions TO service_role;

GRANT ALL ON referral_nurture_queue TO authenticated;
GRANT ALL ON referral_nurture_queue TO service_role;

GRANT EXECUTE ON FUNCTION award_referral_coins(UUID, UUID, INT, TEXT) TO authenticated;
GRANT EXECUTE ON FUNCTION award_referral_coins(UUID, UUID, INT, TEXT) TO service_role;

GRANT EXECUTE ON FUNCTION compute_referral_tier(INT) TO authenticated;
GRANT EXECUTE ON FUNCTION compute_referral_tier(INT) TO service_role;

GRANT EXECUTE ON FUNCTION update_referral_leaderboard() TO service_role;

-- ========== 20260220100000_add_timezone_to_org_context.sql ==========
-- Add org_timezone to get_user_org_context RPC
-- Reads organizations.timezone (already exists) and returns it alongside existing fields.
-- Must DROP first because return type changes (PostgreSQL limitation).

DROP FUNCTION IF EXISTS public.get_user_org_context(uuid);

CREATE OR REPLACE FUNCTION public.get_user_org_context(p_organization_id uuid)
RETURNS TABLE (
  is_owner boolean,
  org_name text,
  marketplace_enabled boolean,
  -- White-label fields
  org_slug text,
  org_logo_url text,
  org_logo_dark_url text,
  org_favicon_url text,
  org_primary_color text,
  org_secondary_color text,
  org_platform_name text,
  org_sender_email text,
  org_sender_name text,
  org_support_email text,
  org_custom_domain text,
  org_resend_domain_verified boolean,
  org_pwa_icon_192_url text,
  org_pwa_icon_512_url text,
  org_og_image_url text,
  org_selected_plan text,
  org_white_label_config jsonb,
  -- Timezone
  org_timezone text
)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT
    COALESCE(om.is_owner, false) AS is_owner,
    o.name::text AS org_name,
    COALESCE(o.marketplace_enabled, true) AS marketplace_enabled,
    -- White-label fields
    o.slug::text,
    o.logo_url::text,
    o.logo_dark_url::text,
    o.favicon_url::text,
    COALESCE(o.primary_color, '#8B5CF6')::text,
    o.secondary_color::text,
    o.platform_name::text,
    o.sender_email::text,
    o.sender_name::text,
    o.support_email::text,
    o.custom_domain::text,
    COALESCE(o.resend_domain_verified, false),
    o.pwa_icon_192_url::text,
    o.pwa_icon_512_url::text,
    o.og_image_url::text,
    COALESCE(o.selected_plan, 'starter')::text,
    COALESCE(o.white_label_config, '{}'::jsonb),
    -- Timezone: default to America/Bogota if not set
    COALESCE(o.timezone, 'America/Bogota')::text AS org_timezone
  FROM organizations o
  LEFT JOIN organization_members om
    ON om.organization_id = o.id
    AND om.user_id = auth.uid()
  WHERE o.id = p_organization_id;
$$;

GRANT EXECUTE ON FUNCTION public.get_user_org_context(uuid) TO authenticated;

-- ========== 20260220100001_campaign_optimization.sql ==========
-- ============================================================
-- Campaign Optimization: Templates, Smart Match, Credits, Case Studies
-- ============================================================

-- 1A. Add missing campaign_purpose column (sent from frontend but not in DB)
ALTER TABLE marketplace_campaigns ADD COLUMN IF NOT EXISTS campaign_purpose TEXT;

-- 1B. Campaign Templates table
CREATE TABLE IF NOT EXISTS campaign_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  description TEXT NOT NULL,
  icon_emoji TEXT NOT NULL DEFAULT '',
  category TEXT NOT NULL CHECK (category IN ('ugc','social','review','event','collab')),
  default_budget_min INT NOT NULL DEFAULT 100,
  default_budget_max INT NOT NULL DEFAULT 2000,
  default_currency TEXT NOT NULL DEFAULT 'USD',
  default_content_types JSONB NOT NULL DEFAULT '[]',
  default_platforms JSONB NOT NULL DEFAULT '[]',
  default_deliverables JSONB NOT NULL DEFAULT '[]',
  default_timeline_days INT NOT NULL DEFAULT 14,
  suggested_creator_count INT NOT NULL DEFAULT 5,
  is_active BOOLEAN NOT NULL DEFAULT true,
  sort_order INT NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 1C. ALTER marketplace_campaigns: template support + quick campaign + smart match
ALTER TABLE marketplace_campaigns
  ADD COLUMN IF NOT EXISTS template_id UUID REFERENCES campaign_templates(id),
  ADD COLUMN IF NOT EXISTS is_quick_campaign BOOLEAN NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS smart_match_score JSONB;

-- 1D. ALTER brands: first campaign tracking + B2B referral
ALTER TABLE brands
  ADD COLUMN IF NOT EXISTS first_campaign_used BOOLEAN NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS referred_by_brand_id UUID REFERENCES brands(id);

-- 1E. Brand Credits table
CREATE TABLE IF NOT EXISTS brand_credits (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  brand_id UUID NOT NULL REFERENCES brands(id) ON DELETE CASCADE UNIQUE,
  balance NUMERIC(12,2) NOT NULL DEFAULT 0,
  lifetime_earned NUMERIC(12,2) NOT NULL DEFAULT 0,
  lifetime_spent NUMERIC(12,2) NOT NULL DEFAULT 0,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 1F. Brand Credit Transactions table
CREATE TABLE IF NOT EXISTS brand_credit_transactions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  brand_id UUID NOT NULL REFERENCES brands(id) ON DELETE CASCADE,
  amount NUMERIC(12,2) NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('earned','spent','expired')),
  source TEXT NOT NULL CHECK (source IN ('referral','promo','manual')),
  description TEXT,
  related_campaign_id UUID REFERENCES marketplace_campaigns(id),
  related_brand_id UUID REFERENCES brands(id),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 1G. Campaign Case Studies table
CREATE TABLE IF NOT EXISTS campaign_case_studies (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id UUID NOT NULL REFERENCES marketplace_campaigns(id) ON DELETE CASCADE UNIQUE,
  brand_id UUID NOT NULL REFERENCES brands(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  summary_html TEXT,
  metrics JSONB DEFAULT '{}',
  creator_highlights JSONB DEFAULT '[]',
  gallery_urls TEXT[] DEFAULT '{}',
  is_published BOOLEAN NOT NULL DEFAULT false,
  is_featured BOOLEAN NOT NULL DEFAULT false,
  slug TEXT UNIQUE,
  published_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 1H. RPC: smart_match_creators
CREATE OR REPLACE FUNCTION smart_match_creators(p_campaign_id UUID)
RETURNS TABLE (
  creator_id UUID,
  user_id UUID,
  display_name TEXT,
  avatar_url TEXT,
  slug TEXT,
  rating_avg NUMERIC,
  completed_projects INT,
  match_score INT,
  match_reasons TEXT[]
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_content_types JSONB;
  v_category TEXT;
  v_min_rating NUMERIC;
BEGIN
  -- Get campaign requirements
  SELECT
    mc.content_requirements,
    mc.category,
    COALESCE((mc.creator_requirements->>'min_rating')::numeric, 0)
  INTO v_content_types, v_category, v_min_rating
  FROM marketplace_campaigns mc
  WHERE mc.id = p_campaign_id;

  IF v_category IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    cp.id AS creator_id,
    cp.user_id,
    cp.display_name,
    cp.avatar_url,
    cp.slug,
    COALESCE(cp.rating_avg, 0) AS rating_avg,
    COALESCE(cp.completed_projects, 0)::INT AS completed_projects,
    -- Score calculation (0-100)
    (
      -- Category match: 40 points
      CASE WHEN v_category = ANY(cp.categories) THEN 40 ELSE 0 END
      -- Rating bonus: up to 30 points
      + LEAST(30, (COALESCE(cp.rating_avg, 0) * 6)::INT)
      -- Completed projects bonus: up to 20 points
      + LEAST(20, COALESCE(cp.completed_projects, 0) * 2)
      -- Response time penalty: -10 if slow
      - CASE WHEN COALESCE(cp.response_time_hours, 48) > 24 THEN 10 ELSE 0 END
    )::INT AS match_score,
    -- Match reasons
    ARRAY_REMOVE(ARRAY[
      CASE WHEN v_category = ANY(cp.categories) THEN 'Categoría: ' || v_category END,
      CASE WHEN COALESCE(cp.rating_avg, 0) >= 4.5 THEN 'Rating ' || ROUND(cp.rating_avg, 1) || '+' END,
      CASE WHEN COALESCE(cp.completed_projects, 0) >= 5 THEN cp.completed_projects || ' proyectos completados' END,
      CASE WHEN COALESCE(cp.response_time_hours, 48) <= 12 THEN 'Respuesta rápida' END
    ], NULL) AS match_reasons
  FROM creator_profiles cp
  WHERE cp.is_available = true
    AND COALESCE(cp.rating_avg, 0) >= v_min_rating
  ORDER BY match_score DESC, cp.rating_avg DESC NULLS LAST
  LIMIT 20;
END;
$$;

-- 1I. RPC: apply_first_campaign_promo
CREATE OR REPLACE FUNCTION apply_first_campaign_promo(p_brand_id UUID, p_campaign_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_used BOOLEAN;
BEGIN
  SELECT first_campaign_used INTO v_used FROM brands WHERE id = p_brand_id;

  IF v_used IS TRUE THEN
    RETURN jsonb_build_object('success', false, 'reason', 'Promo ya utilizada');
  END IF;

  -- Set 0% commission on campaign
  UPDATE marketplace_campaigns
  SET commission_rate = 0
  WHERE id = p_campaign_id;

  -- Mark brand as having used the promo
  UPDATE brands
  SET first_campaign_used = true
  WHERE id = p_brand_id;

  RETURN jsonb_build_object('success', true, 'commission_rate', 0);
END;
$$;

-- 1J. Trigger: auto-generate case study on campaign completion
CREATE OR REPLACE FUNCTION auto_generate_case_study()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_brand_id UUID;
  v_title TEXT;
  v_total_deliveries INT;
  v_avg_rating NUMERIC;
BEGIN
  IF NEW.status = 'completed' AND (OLD.status IS NULL OR OLD.status != 'completed') THEN
    -- Get brand info
    v_brand_id := NEW.brand_id;
    v_title := NEW.title;

    -- Count deliveries and average rating for this campaign
    SELECT
      COUNT(*)::INT,
      COALESCE(AVG(NULLIF(ca.rating, 0)), 0)
    INTO v_total_deliveries, v_avg_rating
    FROM campaign_applications ca
    WHERE ca.campaign_id = NEW.id
      AND ca.status = 'completed';

    -- Insert case study draft
    INSERT INTO campaign_case_studies (campaign_id, brand_id, title, metrics, slug)
    VALUES (
      NEW.id,
      v_brand_id,
      'Caso de Éxito: ' || v_title,
      jsonb_build_object(
        'total_deliveries', v_total_deliveries,
        'avg_rating', ROUND(v_avg_rating, 1),
        'budget', COALESCE(NEW.total_budget, NEW.budget_per_video),
        'currency', COALESCE(NEW.currency, 'USD'),
        'campaign_type', NEW.campaign_type,
        'duration_days', EXTRACT(DAY FROM (now() - NEW.created_at))::INT
      ),
      'caso-' || SUBSTR(NEW.id::TEXT, 1, 8)
    )
    ON CONFLICT (campaign_id) DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_auto_case_study ON marketplace_campaigns;
CREATE TRIGGER trg_auto_case_study
  AFTER UPDATE ON marketplace_campaigns
  FOR EACH ROW
  EXECUTE FUNCTION auto_generate_case_study();

-- 1K. Trigger: award B2B referral credit
CREATE OR REPLACE FUNCTION award_brand_referral_credit()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  IF NEW.referred_by_brand_id IS NOT NULL THEN
    -- Ensure referring brand has a credits row
    INSERT INTO brand_credits (brand_id, balance, lifetime_earned)
    VALUES (NEW.referred_by_brand_id, 50, 50)
    ON CONFLICT (brand_id)
    DO UPDATE SET
      balance = brand_credits.balance + 50,
      lifetime_earned = brand_credits.lifetime_earned + 50,
      updated_at = now();

    -- Record the transaction
    INSERT INTO brand_credit_transactions (brand_id, amount, type, source, description, related_brand_id)
    VALUES (
      NEW.referred_by_brand_id,
      50,
      'earned',
      'referral',
      'Referido B2B: nueva marca registrada',
      NEW.id
    );
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_brand_referral_credit ON brands;
CREATE TRIGGER trg_brand_referral_credit
  AFTER INSERT ON brands
  FOR EACH ROW
  EXECUTE FUNCTION award_brand_referral_credit();

