-- ========== 20260220100002_grant_content_history.sql ==========
-- Fix: content_history table missing GRANT statements
-- The table had RLS policies but no GRANTs, causing 403 Forbidden on SELECT
GRANT SELECT, INSERT ON public.content_history TO authenticated;
GRANT ALL ON public.content_history TO service_role;

-- ========== 20260220200000_grant_anon_public_profile_content.sql ==========
-- Grant SELECT on content table to anon role
-- Required so anonymous (non-logged-in) visitors can see published content
-- on public creator profiles. The RLS policy "Anyone can view published content"
-- (TO anon USING (is_published = true)) already exists but was ineffective
-- without this GRANT.
GRANT SELECT ON public.content TO anon;

-- Grant SELECT on portfolio_posts table to anon role
-- Required for the public profile's social feed / video gallery tabs.
GRANT SELECT ON public.portfolio_posts TO anon;

-- RLS policy for portfolio_posts: allow anon to see public posts
-- (portfolio_posts doesn't have an anon policy yet)
CREATE POLICY "Anyone can view portfolio posts"
  ON public.portfolio_posts
  FOR SELECT
  TO anon
  USING (true);

-- ========== 20260220200001_fix_anon_marketplace_access.sql ==========
-- =============================================================================
-- Fix anonymous (non-logged-in) marketplace access
-- =============================================================================
-- Problem: content table has SELECT policies with TO public that reference
-- client_users table. The anon role can't access client_users, causing
-- "permission denied for table client_users" (42501) even though the
-- "Anyone can view published content" policy would allow the read.
--
-- PostgreSQL evaluates ALL applicable PERMISSIVE policies, and if any
-- subquery references a table the role can't access, the entire query fails.
--
-- Fix: Change content SELECT policies from TO public → TO authenticated.
-- These policies all use auth.uid() which is NULL for anon anyway.
-- =============================================================================

-- 1. "Client users can view their content" — references client_users
DROP POLICY IF EXISTS "Client users can view their content" ON public.content;
CREATE POLICY "Client users can view their content" ON public.content
  FOR SELECT TO authenticated
  USING (EXISTS (
    SELECT 1 FROM client_users
    WHERE client_users.client_id = content.client_id
    AND client_users.user_id = auth.uid()
  ));

-- 2. "Org members can view content" — calls is_org_configurer(), is_org_member()
DROP POLICY IF EXISTS "Org members can view content" ON public.content;
CREATE POLICY "Org members can view content" ON public.content
  FOR SELECT TO authenticated
  USING (
    is_org_configurer(auth.uid(), organization_id)
    OR is_org_member(auth.uid(), organization_id)
    OR creator_id = auth.uid()
    OR editor_id = auth.uid()
  );

-- 3. "Root admins by email can view all content" — calls is_root_by_jwt_email()
DROP POLICY IF EXISTS "Root admins by email can view all content" ON public.content;
CREATE POLICY "Root admins by email can view all content" ON public.content
  FOR SELECT TO authenticated
  USING (is_root_by_jwt_email());

-- 4. "Strategists can view assigned content" — uses auth.uid()
DROP POLICY IF EXISTS "Strategists can view assigned content" ON public.content;
CREATE POLICY "Strategists can view assigned content" ON public.content
  FOR SELECT TO authenticated
  USING (strategist_id = auth.uid());

-- 5. "content_org_member_select" — calls is_content_org_member()
DROP POLICY IF EXISTS "content_org_member_select" ON public.content;
CREATE POLICY "content_org_member_select" ON public.content
  FOR SELECT TO authenticated
  USING (is_content_org_member(auth.uid(), organization_id));

-- =============================================================================
-- Fix user_subscriptions for marketplace (anon needs to check paid plans)
-- =============================================================================

GRANT SELECT ON public.user_subscriptions TO anon;

CREATE POLICY "Anon can view active paid subscriptions"
  ON public.user_subscriptions
  FOR SELECT TO anon
  USING (status = 'active' AND plan != 'free');

-- =============================================================================
-- Force PostgREST to reload schema cache
-- =============================================================================
NOTIFY pgrst, 'reload schema';

-- ========== 20260220200002_social_accounts_client_association.sql ==========
-- ═══════════════════════════════════════════════════════════════════════════
-- Social Accounts: Client (Empresa) Association
-- ═══════════════════════════════════════════════════════════════════════════

-- 1. Add 'client' value to social_account_owner_type enum
ALTER TYPE social_account_owner_type ADD VALUE IF NOT EXISTS 'client';

-- 2. Add client_id column to social_accounts
ALTER TABLE social_accounts
  ADD COLUMN IF NOT EXISTS client_id UUID REFERENCES clients(id) ON DELETE SET NULL;

-- 3. Unique partial index: max 1 active account per (client_id, platform)
CREATE UNIQUE INDEX IF NOT EXISTS idx_social_accounts_client_platform_unique
  ON social_accounts (client_id, platform)
  WHERE client_id IS NOT NULL AND is_active = true;

-- 4. Lookup index for client_id
CREATE INDEX IF NOT EXISTS idx_social_accounts_client_id
  ON social_accounts (client_id)
  WHERE client_id IS NOT NULL;

-- 5. Update get_org_social_accounts RPC to include client info
CREATE OR REPLACE FUNCTION get_org_social_accounts(p_org_id UUID)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_agg(row_to_json(sa))
  INTO result
  FROM (
    SELECT
      sa.*,
      c.name AS client_name,
      c.logo_url AS client_logo_url,
      (
        SELECT json_agg(json_build_object(
          'group_id', g.id,
          'group_name', g.name,
          'group_color', g.color
        ))
        FROM social_account_group_members gm
        JOIN social_account_groups g ON g.id = gm.group_id
        WHERE gm.account_id = sa.id
      ) AS groups,
      (
        SELECT json_agg(json_build_object(
          'user_id', p.user_id,
          'can_view', p.can_view,
          'can_post', p.can_post,
          'can_schedule', p.can_schedule,
          'can_analytics', p.can_analytics,
          'can_manage', p.can_manage
        ))
        FROM social_account_permissions p
        WHERE p.account_id = sa.id
      ) AS permissions
    FROM social_accounts sa
    LEFT JOIN clients c ON c.id = sa.client_id
    WHERE sa.organization_id = p_org_id
      AND sa.is_active = true
    ORDER BY sa.platform, sa.platform_display_name
  ) sa;

  RETURN COALESCE(result, '[]'::json);
END;
$$;

-- 6. Grants
GRANT EXECUTE ON FUNCTION get_org_social_accounts(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_org_social_accounts(UUID) TO service_role;

-- ========== 20260220210000_social_accounts_connection_method.sql ==========
-- Add connection_method column to social_accounts
-- Tracks how the account was connected (e.g. 'facebook' for Meta Login, 'direct' for Instagram API)
ALTER TABLE social_accounts
ADD COLUMN IF NOT EXISTS connection_method TEXT DEFAULT 'default'
CHECK (connection_method IN ('default', 'facebook', 'direct'));

-- Update existing Meta-connected Instagram accounts to 'facebook' method
UPDATE social_accounts
SET connection_method = 'facebook'
WHERE platform = 'instagram'
  AND platform_page_id IS NOT NULL
  AND connection_method = 'default';

-- Update existing Facebook accounts to 'facebook' method
UPDATE social_accounts
SET connection_method = 'facebook'
WHERE platform = 'facebook'
  AND connection_method = 'default';

-- Index for filtering by connection method
CREATE INDEX IF NOT EXISTS idx_social_accounts_connection_method
ON social_accounts(connection_method)
WHERE is_active = true;

-- Update the get_org_social_accounts RPC to include connection_method
CREATE OR REPLACE FUNCTION get_org_social_accounts(p_org_id UUID)
RETURNS TABLE (
  id UUID,
  user_id UUID,
  organization_id UUID,
  platform TEXT,
  platform_user_id TEXT,
  platform_username TEXT,
  platform_display_name TEXT,
  platform_avatar_url TEXT,
  platform_page_id TEXT,
  platform_page_name TEXT,
  is_active BOOLEAN,
  scopes TEXT[],
  token_expires_at TIMESTAMPTZ,
  connected_at TIMESTAMPTZ,
  last_synced_at TIMESTAMPTZ,
  last_error TEXT,
  metadata JSONB,
  created_at TIMESTAMPTZ,
  updated_at TIMESTAMPTZ,
  owner_type TEXT,
  brand_id UUID,
  client_id UUID,
  account_type TEXT,
  settings JSONB,
  platform_metadata JSONB,
  connection_method TEXT,
  client_name TEXT,
  client_logo_url TEXT,
  groups JSONB,
  permissions JSONB
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    sa.id,
    sa.user_id,
    sa.organization_id,
    sa.platform,
    sa.platform_user_id,
    sa.platform_username,
    sa.platform_display_name,
    sa.platform_avatar_url,
    sa.platform_page_id,
    sa.platform_page_name,
    sa.is_active,
    sa.scopes,
    sa.token_expires_at,
    sa.connected_at,
    sa.last_synced_at,
    sa.last_error,
    sa.metadata,
    sa.created_at,
    sa.updated_at,
    sa.owner_type::TEXT,
    sa.brand_id,
    sa.client_id,
    sa.account_type::TEXT,
    sa.settings,
    sa.platform_metadata,
    sa.connection_method,
    c.name AS client_name,
    c.logo_url AS client_logo_url,
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
        'group_id', sag.group_id,
        'group_name', g.name,
        'group_color', g.color
      ))
      FROM social_account_group_members sag
      JOIN social_account_groups g ON g.id = sag.group_id
      WHERE sag.account_id = sa.id),
      '[]'::JSONB
    ) AS groups,
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
        'user_id', sap.user_id,
        'can_view', sap.can_view,
        'can_post', sap.can_post,
        'can_schedule', sap.can_schedule,
        'can_analytics', sap.can_analytics,
        'can_manage', sap.can_manage
      ))
      FROM social_account_permissions sap
      WHERE sap.account_id = sa.id),
      '[]'::JSONB
    ) AS permissions
  FROM social_accounts sa
  LEFT JOIN clients c ON c.id = sa.client_id
  WHERE sa.organization_id = p_org_id
    AND sa.is_active = true
  ORDER BY sa.platform, sa.connected_at DESC;
$$;

GRANT EXECUTE ON FUNCTION get_org_social_accounts(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_org_social_accounts(UUID) TO service_role;

-- ========== 20260220220000_social_account_snapshots.sql ==========
-- ============================================================================
-- Social Account Snapshots: daily historical metrics for connected accounts
-- ============================================================================

-- Table for daily metric snapshots per account
CREATE TABLE IF NOT EXISTS social_account_snapshots (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  account_id UUID NOT NULL REFERENCES social_accounts(id) ON DELETE CASCADE,

  -- Snapshot date (one row per account per day)
  snapshot_date DATE NOT NULL,

  -- Account-level counts
  followers_count INTEGER DEFAULT 0,
  following_count INTEGER DEFAULT 0,
  posts_count INTEGER DEFAULT 0,

  -- Period metrics (for that day)
  impressions BIGINT DEFAULT 0,
  reach BIGINT DEFAULT 0,
  profile_views INTEGER DEFAULT 0,
  accounts_engaged INTEGER DEFAULT 0,

  -- Engagement totals
  total_likes BIGINT DEFAULT 0,
  total_comments BIGINT DEFAULT 0,
  total_shares BIGINT DEFAULT 0,
  total_saves BIGINT DEFAULT 0,

  -- Video
  video_views BIGINT DEFAULT 0,

  -- Growth (computed from previous day)
  followers_gained INTEGER DEFAULT 0,
  followers_lost INTEGER DEFAULT 0,

  -- Audience demographics (JSONB for flexible structure)
  audience_demographics JSONB DEFAULT '{}',

  -- Raw API response for debugging
  raw_data JSONB DEFAULT '{}',

  created_at TIMESTAMPTZ DEFAULT NOW(),

  UNIQUE(account_id, snapshot_date)
);

-- Indexes
CREATE INDEX idx_snapshots_account_date
  ON social_account_snapshots(account_id, snapshot_date DESC);

CREATE INDEX idx_snapshots_date
  ON social_account_snapshots(snapshot_date DESC);

-- RLS
ALTER TABLE social_account_snapshots ENABLE ROW LEVEL SECURITY;

-- SELECT: users can see snapshots for their own accounts
CREATE POLICY "Users can view own account snapshots"
  ON social_account_snapshots FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM social_accounts sa
      WHERE sa.id = social_account_snapshots.account_id
        AND sa.user_id = auth.uid()
    )
  );

-- Also allow org members to see snapshots for org accounts
CREATE POLICY "Org members can view org account snapshots"
  ON social_account_snapshots FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM social_accounts sa
      JOIN organization_members om ON om.organization_id = sa.organization_id
      WHERE sa.id = social_account_snapshots.account_id
        AND om.user_id = auth.uid()
    )
  );

-- Service role needs full access for edge function inserts
GRANT ALL ON social_account_snapshots TO authenticated;
GRANT ALL ON social_account_snapshots TO service_role;

-- Fix existing bug: post_metrics column name mismatch
-- The edge function writes 'raw_response' but column is 'platform_data'
-- Add raw_response as an alias column if it doesn't exist
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'post_metrics' AND column_name = 'raw_response'
  ) THEN
    ALTER TABLE post_metrics ADD COLUMN raw_response JSONB DEFAULT '{}';
  END IF;
END $$;

-- ============================================================================
-- RPC: get_account_snapshots - fetch snapshots for a date range
-- ============================================================================
CREATE OR REPLACE FUNCTION get_account_snapshots(
  p_account_id UUID,
  p_days INTEGER DEFAULT 30
)
RETURNS SETOF social_account_snapshots
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT *
  FROM social_account_snapshots
  WHERE account_id = p_account_id
    AND snapshot_date >= (CURRENT_DATE - (p_days || ' days')::INTERVAL)
  ORDER BY snapshot_date ASC;
$$;

-- ============================================================================
-- RPC: get_org_account_snapshots - fetch snapshots for all org accounts
-- ============================================================================
CREATE OR REPLACE FUNCTION get_org_account_snapshots(
  p_org_id UUID,
  p_days INTEGER DEFAULT 30
)
RETURNS TABLE (
  account_id UUID,
  platform TEXT,
  platform_username TEXT,
  platform_display_name TEXT,
  snapshot_date DATE,
  followers_count INTEGER,
  following_count INTEGER,
  posts_count INTEGER,
  impressions BIGINT,
  reach BIGINT,
  profile_views INTEGER,
  accounts_engaged INTEGER,
  total_likes BIGINT,
  total_comments BIGINT,
  total_shares BIGINT,
  total_saves BIGINT,
  video_views BIGINT,
  followers_gained INTEGER,
  followers_lost INTEGER,
  audience_demographics JSONB
)
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT
    s.account_id,
    sa.platform::TEXT,
    sa.platform_username,
    sa.platform_display_name,
    s.snapshot_date,
    s.followers_count,
    s.following_count,
    s.posts_count,
    s.impressions,
    s.reach,
    s.profile_views,
    s.accounts_engaged,
    s.total_likes,
    s.total_comments,
    s.total_shares,
    s.total_saves,
    s.video_views,
    s.followers_gained,
    s.followers_lost,
    s.audience_demographics
  FROM social_account_snapshots s
  JOIN social_accounts sa ON sa.id = s.account_id
  WHERE sa.organization_id = p_org_id
    AND sa.is_active = true
    AND s.snapshot_date >= (CURRENT_DATE - (p_days || ' days')::INTERVAL)
  ORDER BY s.snapshot_date ASC, sa.platform;
$$;

-- ============================================================================
-- Cron job: sync social metrics daily at 6 AM UTC
-- ============================================================================
DO $$
BEGIN
  -- Only create if pg_cron extension is available
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_cron') THEN
    -- Remove old job if exists
    PERFORM cron.unschedule('sync-social-metrics-daily');

    -- Schedule daily at 6 AM UTC
    PERFORM cron.schedule(
      'sync-social-metrics-daily',
      '0 6 * * *',
      $$
      SELECT net.http_post(
        url := current_setting('app.settings.supabase_url') || '/functions/v1/social-metrics/bulk-sync',
        headers := jsonb_build_object(
          'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key'),
          'Content-Type', 'application/json'
        ),
        body := '{}'::jsonb
      );
      $$
    );
  END IF;
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'pg_cron not available or scheduling failed: %', SQLERRM;
END $$;

-- ========== 20260220230000_approved_content_for_social.sql ==========
-- ============================================================================
-- RPC: get_approved_content_for_social
-- Returns content that has passed through approved status (approved, paid, en_campaa)
-- Used by the Social Hub PostComposer content selector
-- ============================================================================

CREATE OR REPLACE FUNCTION get_approved_content_for_social(p_org_id UUID)
RETURNS TABLE (
  id UUID,
  title TEXT,
  description TEXT,
  video_url TEXT,
  video_urls TEXT[],
  thumbnail_url TEXT,
  bunny_embed_url TEXT,
  status TEXT,
  created_at TIMESTAMPTZ,
  client_id UUID,
  client_name TEXT,
  client_logo_url TEXT,
  product_id UUID,
  product_name TEXT,
  creator_id UUID,
  creator_name TEXT,
  creator_avatar TEXT,
  editor_id UUID,
  editor_name TEXT,
  sphere_phase TEXT,
  target_platform TEXT,
  content_objective TEXT,
  hook TEXT,
  cta TEXT,
  marketing_campaign_id UUID,
  marketing_campaign_name TEXT,
  sequence_number TEXT
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    c.id,
    c.title,
    c.description,
    c.video_url,
    c.video_urls,
    c.thumbnail_url,
    c.bunny_embed_url,
    c.status::TEXT,
    c.created_at,
    c.client_id,
    cl.name AS client_name,
    cl.logo_url AS client_logo_url,
    c.product_id,
    p.name AS product_name,
    c.creator_id,
    pc.full_name AS creator_name,
    pc.avatar_url AS creator_avatar,
    c.editor_id,
    pe.full_name AS editor_name,
    c.sphere_phase,
    c.target_platform,
    c.content_objective,
    c.hook,
    c.cta,
    c.marketing_campaign_id,
    mc.name AS marketing_campaign_name,
    c.sequence_number
  FROM content c
  LEFT JOIN clients cl ON cl.id = c.client_id
  LEFT JOIN products p ON p.id = c.product_id
  LEFT JOIN profiles pc ON pc.id = c.creator_id
  LEFT JOIN profiles pe ON pe.id = c.editor_id
  LEFT JOIN marketing_campaigns mc ON mc.id = c.marketing_campaign_id
  WHERE c.organization_id = p_org_id
    AND c.status IN ('approved', 'paid', 'en_campaa')
  ORDER BY c.created_at DESC
  LIMIT 200;
$$;

GRANT EXECUTE ON FUNCTION get_approved_content_for_social(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_approved_content_for_social(UUID) TO service_role;

-- ========== 20260220231000_paginated_approved_content.sql ==========
-- ============================================================================
-- RPC: get_approved_content_for_social (v2 - paginated + filters)
-- Replaces v1: adds pagination, server-side filters, and total_count
-- ============================================================================

-- Drop old single-param version
DROP FUNCTION IF EXISTS get_approved_content_for_social(UUID);

CREATE OR REPLACE FUNCTION get_approved_content_for_social(
  p_org_id UUID,
  p_limit INT DEFAULT 50,
  p_offset INT DEFAULT 0,
  p_search TEXT DEFAULT NULL,
  p_client_id UUID DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_sphere_phase TEXT DEFAULT NULL
)
RETURNS TABLE (
  id UUID,
  title TEXT,
  description TEXT,
  video_url TEXT,
  video_urls TEXT[],
  thumbnail_url TEXT,
  bunny_embed_url TEXT,
  status TEXT,
  created_at TIMESTAMPTZ,
  client_id UUID,
  client_name TEXT,
  client_logo_url TEXT,
  product_id UUID,
  product_name TEXT,
  creator_id UUID,
  creator_name TEXT,
  creator_avatar TEXT,
  editor_id UUID,
  editor_name TEXT,
  sphere_phase TEXT,
  target_platform TEXT,
  content_objective TEXT,
  hook TEXT,
  cta TEXT,
  marketing_campaign_id UUID,
  marketing_campaign_name TEXT,
  sequence_number TEXT,
  total_count BIGINT
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    c.id,
    c.title,
    c.description,
    c.video_url,
    c.video_urls,
    c.thumbnail_url,
    c.bunny_embed_url,
    c.status::TEXT,
    c.created_at,
    c.client_id,
    cl.name AS client_name,
    cl.logo_url AS client_logo_url,
    c.product_id,
    p.name AS product_name,
    c.creator_id,
    pc.full_name AS creator_name,
    pc.avatar_url AS creator_avatar,
    c.editor_id,
    pe.full_name AS editor_name,
    c.sphere_phase::TEXT,
    c.target_platform,
    c.content_objective,
    c.hook,
    c.cta,
    c.marketing_campaign_id,
    mc.name AS marketing_campaign_name,
    c.sequence_number,
    COUNT(*) OVER() AS total_count
  FROM content c
  LEFT JOIN clients cl ON cl.id = c.client_id
  LEFT JOIN products p ON p.id = c.product_id
  LEFT JOIN profiles pc ON pc.id = c.creator_id
  LEFT JOIN profiles pe ON pe.id = c.editor_id
  LEFT JOIN marketing_campaigns mc ON mc.id = c.marketing_campaign_id
  WHERE c.organization_id = p_org_id
    AND c.status IN ('approved', 'paid', 'en_campaa')
    AND (p_client_id IS NULL OR c.client_id = p_client_id)
    AND (p_status IS NULL OR c.status::TEXT = p_status)
    AND (p_sphere_phase IS NULL OR c.sphere_phase::TEXT = p_sphere_phase)
    AND (p_search IS NULL OR p_search = '' OR
         c.title ILIKE '%' || p_search || '%' OR
         cl.name ILIKE '%' || p_search || '%' OR
         pc.full_name ILIKE '%' || p_search || '%' OR
         p.name ILIKE '%' || p_search || '%' OR
         c.sequence_number ILIKE '%' || p_search || '%')
  ORDER BY c.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
$$;

GRANT EXECUTE ON FUNCTION get_approved_content_for_social(UUID, INT, INT, TEXT, UUID, TEXT, TEXT) TO authenticated;
GRANT EXECUTE ON FUNCTION get_approved_content_for_social(UUID, INT, INT, TEXT, UUID, TEXT, TEXT) TO service_role;

-- ========== 20260221000000_content_context_for_ai.sql ==========
-- ============================================================================
-- RPC: get_content_context_for_ai
-- Gathers all contextual data for a content item to feed AI caption generation
-- Joins: content + clients + products + marketing_campaigns + product_dna
-- ============================================================================

CREATE OR REPLACE FUNCTION get_content_context_for_ai(p_content_id UUID)
RETURNS JSONB
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT jsonb_build_object(
    'content', jsonb_build_object(
      'title', c.title,
      'description', c.description,
      'script', c.script,
      'hook', c.hook,
      'cta', c.cta,
      'sphere_phase', c.sphere_phase,
      'target_platform', c.target_platform,
      'content_objective', c.content_objective,
      'selected_pain', c.selected_pain,
      'selected_desire', c.selected_desire,
      'selected_objection', c.selected_objection,
      'ideal_avatar', c.ideal_avatar,
      'suggested_hooks', c.suggested_hooks,
      'narrative_structure', c.narrative_structure,
      'strategist_guidelines', c.strategist_guidelines,
      'sequence_number', c.sequence_number
    ),
    'client', CASE WHEN cl.id IS NOT NULL THEN jsonb_build_object(
      'name', cl.name,
      'bio', cl.bio,
      'category', cl.category,
      'instagram', cl.instagram,
      'tiktok', cl.tiktok,
      'facebook', cl.facebook,
      'website', cl.website
    ) ELSE NULL END,
    'product', CASE WHEN p.id IS NOT NULL THEN jsonb_build_object(
      'name', p.name,
      'description', p.description,
      'strategy', p.strategy,
      'ideal_avatar', p.ideal_avatar,
      'sales_angles', p.sales_angles,
      'brief_data', p.brief_data,
      'content_strategy', p.content_strategy
    ) ELSE NULL END,
    'campaign', CASE WHEN mc.id IS NOT NULL THEN jsonb_build_object(
      'name', mc.name,
      'objective', mc.objective,
      'performance_goal', mc.performance_goal,
      'targeting', mc.targeting,
      'creative', mc.creative,
      'ai_suggestions', mc.ai_suggestions
    ) ELSE NULL END,
    'product_dna', (
      SELECT jsonb_build_object(
        'wizard_responses', pd.wizard_responses,
        'market_research', pd.market_research,
        'content_brief', pd.content_brief,
        'strategy_recommendations', pd.strategy_recommendations
      )
      FROM product_dna pd
      WHERE pd.client_id = c.client_id
      ORDER BY pd.created_at DESC
      LIMIT 1
    )
  )
  FROM content c
  LEFT JOIN clients cl ON cl.id = c.client_id
  LEFT JOIN products p ON p.id = c.product_id
  LEFT JOIN marketing_campaigns mc ON mc.id = c.marketing_campaign_id
  WHERE c.id = p_content_id;
$$;

GRANT EXECUTE ON FUNCTION get_content_context_for_ai(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_content_context_for_ai(UUID) TO service_role;

-- ========== 20260221100000_add_client_marketplace_enabled.sql ==========
-- Add client_marketplace_enabled flag to organizations
-- Controls whether clients of the org can access the marketplace
ALTER TABLE public.organizations
  ADD COLUMN IF NOT EXISTS client_marketplace_enabled boolean DEFAULT false;

COMMENT ON COLUMN public.organizations.client_marketplace_enabled
  IS 'When false, client users of this org cannot see or access the marketplace';

-- Must DROP first since return type changes (new column added)
DROP FUNCTION IF EXISTS public.get_user_org_context(uuid);

-- Recreate with client_marketplace_enabled in the return
CREATE OR REPLACE FUNCTION public.get_user_org_context(p_organization_id uuid)
RETURNS TABLE (
  is_owner boolean,
  org_name text,
  marketplace_enabled boolean,
  client_marketplace_enabled boolean,
  org_slug text,
  org_logo_url text,
  org_logo_dark_url text,
  org_favicon_url text,
  org_primary_color text,
  org_secondary_color text,
  org_platform_name text,
  org_sender_email text,
  org_sender_name text,
  org_support_email text,
  org_custom_domain text,
  org_resend_domain_verified boolean,
  org_pwa_icon_192_url text,
  org_pwa_icon_512_url text,
  org_og_image_url text,
  org_selected_plan text,
  org_white_label_config jsonb,
  org_timezone text
)
LANGUAGE sql
SECURITY DEFINER
STABLE
SET search_path = public
AS $$
  SELECT
    COALESCE(om.is_owner, false) AS is_owner,
    o.name::text AS org_name,
    COALESCE(o.marketplace_enabled, true) AS marketplace_enabled,
    COALESCE(o.client_marketplace_enabled, false) AS client_marketplace_enabled,
    o.slug::text,
    o.logo_url::text,
    o.logo_dark_url::text,
    o.favicon_url::text,
    COALESCE(o.primary_color, '#8B5CF6')::text,
    o.secondary_color::text,
    o.platform_name::text,
    o.sender_email::text,
    o.sender_name::text,
    o.support_email::text,
    o.custom_domain::text,
    COALESCE(o.resend_domain_verified, false),
    o.pwa_icon_192_url::text,
    o.pwa_icon_512_url::text,
    o.og_image_url::text,
    COALESCE(o.selected_plan, 'starter')::text,
    COALESCE(o.white_label_config, '{}'::jsonb),
    COALESCE(o.timezone, 'America/Bogota')::text AS org_timezone
  FROM organizations o
  LEFT JOIN organization_members om
    ON om.organization_id = o.id
    AND om.user_id = auth.uid()
  WHERE o.id = p_organization_id;
$$;

GRANT EXECUTE ON FUNCTION public.get_user_org_context(uuid) TO authenticated;
NOTIFY pgrst, 'reload schema';

-- ========== 20260221100001_enhance_content_context_for_ai.sql ==========
-- ============================================================================
-- Enhanced RPC: get_content_context_for_ai
-- Now includes 3 comprehensive context layers:
--   1. Client/Brand DNA (product_dna) - from social account's client or content's client
--   2. Product DNA - ALL JSONB fields from products table
--   3. Role info - ALL role guidelines from content table
-- ============================================================================

-- Drop old single-param version
DROP FUNCTION IF EXISTS get_content_context_for_ai(UUID);

CREATE OR REPLACE FUNCTION get_content_context_for_ai(
  p_content_id UUID,
  p_account_client_id UUID DEFAULT NULL
)
RETURNS JSONB
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT jsonb_build_object(
    -- ── CONTEXT 1: Client/Brand DNA ──────────────────────────────────
    'client', CASE WHEN cl.id IS NOT NULL THEN jsonb_build_object(
      'name', cl.name,
      'bio', cl.bio,
      'category', cl.category,
      'instagram', cl.instagram,
      'tiktok', cl.tiktok,
      'facebook', cl.facebook,
      'linkedin', cl.linkedin,
      'website', cl.website
    ) ELSE NULL END,

    'client_dna', (
      SELECT jsonb_build_object(
        -- Rich JSONB data from product_dna
        'wizard_responses', pd.wizard_responses,
        'content_brief', pd.content_brief,
        'strategy_recommendations', pd.strategy_recommendations,
        'market_research', pd.market_research,
        'competitor_analysis', pd.competitor_analysis
      )
      FROM product_dna pd
      WHERE pd.client_id = COALESCE(p_account_client_id, c.client_id)
      ORDER BY pd.created_at DESC
      LIMIT 1
    ),

    -- ── CONTEXT 2: Product DNA ───────────────────────────────────────
    'product', CASE WHEN p.id IS NOT NULL THEN jsonb_build_object(
      'name', p.name,
      'description', p.description,
      'strategy', p.strategy,
      'ideal_avatar', p.ideal_avatar,
      'sales_angles', p.sales_angles,
      'market_research', p.market_research,
      -- Rich JSONB data
      'brief_data', p.brief_data,
      'content_strategy', p.content_strategy,
      'avatar_profiles', p.avatar_profiles,
      'sales_angles_data', p.sales_angles_data,
      'competitor_analysis', p.competitor_analysis,
      'launch_strategy', p.launch_strategy,
      'content_calendar', p.content_calendar
    ) ELSE NULL END,

    -- ── CONTEXT 3: Content + Role Guidelines ─────────────────────────
    'content', jsonb_build_object(
      -- Core content info
      'title', c.title,
      'description', c.description,
      'content_type', c.content_type,
      'sphere_phase', c.sphere_phase,
      'funnel_stage', c.funnel_stage,
      'target_platform', c.target_platform,
      'content_objective', c.content_objective,
      'target_country', c.target_country,
      'video_duration', c.video_duration,
      -- Creative elements
      'script', c.script,
      'hook', c.hook,
      'cta', c.cta,
      'caption', c.caption,
      'sales_angle', c.sales_angle,
      'selected_pain', c.selected_pain,
      'selected_desire', c.selected_desire,
      'selected_objection', c.selected_objection,
      'ideal_avatar', c.ideal_avatar,
      'suggested_hooks', c.suggested_hooks,
      'narrative_structure', c.narrative_structure,
      -- Role-specific guidelines
      'strategist_guidelines', c.strategist_guidelines,
      'trafficker_guidelines', c.trafficker_guidelines,
      'editor_guidelines', c.editor_guidelines,
      'designer_guidelines', c.designer_guidelines,
      'admin_guidelines', c.admin_guidelines,
      -- AI analysis
      'ai_analysis_data', c.ai_analysis_data,
      'sequence_number', c.sequence_number
    ),

    -- ── Campaign context ─────────────────────────────────────────────
    'campaign', CASE WHEN mc.id IS NOT NULL THEN jsonb_build_object(
      'name', mc.name,
      'objective', mc.objective,
      'performance_goal', mc.performance_goal,
      'targeting', mc.targeting,
      'creative', mc.creative,
      'ai_suggestions', mc.ai_suggestions
    ) ELSE NULL END
  )
  FROM content c
  LEFT JOIN clients cl ON cl.id = COALESCE(p_account_client_id, c.client_id)
  LEFT JOIN products p ON p.id = c.product_id
  LEFT JOIN marketing_campaigns mc ON mc.id = c.marketing_campaign_id
  WHERE c.id = p_content_id;
$$;

GRANT EXECUTE ON FUNCTION get_content_context_for_ai(UUID, UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_content_context_for_ai(UUID, UUID) TO service_role;

-- ========== 20260221200000_deprecate_user_subscriptions.sql ==========
-- =============================================================================
-- Migration: Deprecate user_subscriptions in favor of platform_subscriptions
-- =============================================================================
-- user_subscriptions is legacy (79 rows, all plan='free'). All subscription
-- logic now uses platform_subscriptions (Stripe-linked, org-level).
-- This migration:
--   1. Grants anon SELECT on platform_subscriptions (marketplace public access)
--   2. Grants anon SELECT on organization_members (resolve user→org)
--   3. Revokes anon access from user_subscriptions
--   4. Drops the auto-create trigger on auth.users
--   5. Renames user_subscriptions → user_subscriptions_deprecated
-- =============================================================================

-- 1. Allow anon to read active platform subscriptions (for marketplace public)
GRANT SELECT ON public.platform_subscriptions TO anon;

CREATE POLICY "Anon can view active platform subscriptions"
  ON public.platform_subscriptions
  FOR SELECT TO anon
  USING (status = 'active');

-- 2. Allow anon to resolve user→org memberships (for marketplace subscription check)
GRANT SELECT ON public.organization_members TO anon;

CREATE POLICY "Anon can view org memberships"
  ON public.organization_members
  FOR SELECT TO anon
  USING (true);

-- 3. Revoke anon from user_subscriptions (no longer needed)
DROP POLICY IF EXISTS "Anon can view active paid subscriptions" ON public.user_subscriptions;
REVOKE SELECT ON public.user_subscriptions FROM anon;

-- 4. Drop the trigger that auto-creates free user_subscriptions for new users
DROP TRIGGER IF EXISTS on_auth_user_created_subscription ON auth.users;

-- 5. Rename table as deprecated (keep data, don't drop)
ALTER TABLE public.user_subscriptions RENAME TO user_subscriptions_deprecated;

-- 6. Refresh PostgREST schema cache
NOTIFY pgrst, 'reload schema';

-- ========== 20260222200000_ad_intelligence_module.sql ==========
-- ============================================================
-- Ad Intelligence Module
-- Multi-platform ad library intelligence (Meta, TikTok, Google)
-- ============================================================

-- ── Saved Searches ──────────────────────────────────────────

CREATE TABLE ad_library_searches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by UUID NOT NULL REFERENCES auth.users(id),
  name TEXT NOT NULL,
  platform TEXT NOT NULL DEFAULT 'meta',
  search_config JSONB NOT NULL DEFAULT '{}',
  is_active BOOLEAN NOT NULL DEFAULT true,
  sync_interval_hours INT DEFAULT 24,
  last_synced_at TIMESTAMPTZ,
  total_ads_found INT DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- ── Ads Found ───────────────────────────────────────────────

CREATE TABLE ad_library_ads (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  search_id UUID REFERENCES ad_library_searches(id) ON DELETE CASCADE,
  platform TEXT NOT NULL DEFAULT 'meta',
  platform_ad_id TEXT NOT NULL,
  page_id TEXT,
  page_name TEXT,
  ad_creative_bodies TEXT[],
  ad_creative_link_titles TEXT[],
  ad_creative_link_descriptions TEXT[],
  ad_snapshot_url TEXT,
  publisher_platforms TEXT[],
  languages TEXT[],
  media_type TEXT,
  ad_delivery_start TEXT,
  ad_delivery_stop TEXT,
  is_active BOOLEAN DEFAULT true,
  spend_lower INT,
  spend_upper INT,
  impressions_lower INT,
  impressions_upper INT,
  currency TEXT,
  raw_data JSONB DEFAULT '{}',
  ai_analysis JSONB,
  ai_analyzed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(platform, platform_ad_id)
);

-- ── Collections ─────────────────────────────────────────────

CREATE TABLE ad_library_collections (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by UUID NOT NULL REFERENCES auth.users(id),
  name TEXT NOT NULL,
  description TEXT,
  color TEXT DEFAULT '#6366f1',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE ad_library_collection_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  collection_id UUID NOT NULL REFERENCES ad_library_collections(id) ON DELETE CASCADE,
  ad_id UUID NOT NULL REFERENCES ad_library_ads(id) ON DELETE CASCADE,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(collection_id, ad_id)
);

-- ── Indexes ─────────────────────────────────────────────────

CREATE INDEX idx_ad_library_ads_search_id ON ad_library_ads(search_id);
CREATE INDEX idx_ad_library_ads_page_name ON ad_library_ads(page_name);
CREATE INDEX idx_ad_library_ads_platform_ad_id ON ad_library_ads(platform, platform_ad_id);
CREATE INDEX idx_ad_library_ads_is_active ON ad_library_ads(is_active);
CREATE INDEX idx_ad_library_ads_platform ON ad_library_ads(platform);
CREATE INDEX idx_ad_library_ads_created_at ON ad_library_ads(created_at DESC);
CREATE INDEX idx_ad_library_collection_items_collection ON ad_library_collection_items(collection_id);
CREATE INDEX idx_ad_library_collection_items_ad ON ad_library_collection_items(ad_id);
CREATE INDEX idx_ad_library_searches_created_by ON ad_library_searches(created_by);

-- ── RLS ─────────────────────────────────────────────────────

ALTER TABLE ad_library_searches ENABLE ROW LEVEL SECURITY;
ALTER TABLE ad_library_ads ENABLE ROW LEVEL SECURITY;
ALTER TABLE ad_library_collections ENABLE ROW LEVEL SECURITY;
