-- ========== 20260223300000_social_scheduler_cron.sql ==========
-- ══════════════════════════════════════════════════════════════════
-- Social Scheduler Cron Job
-- Runs every 2 minutes to process scheduled posts that are due
-- ══════════════════════════════════════════════════════════════════

-- NOTE: This cron job was already applied manually on 2026-02-23
-- via: SELECT cron.schedule('social-scheduler-process', '*/2 * * * *', ...)
-- This migration documents it for future reference.

DO $outer$
BEGIN
  -- Only create if not already scheduled
  IF NOT EXISTS (SELECT 1 FROM cron.job WHERE jobname = 'social-scheduler-process') THEN
    PERFORM cron.schedule(
      'social-scheduler-process',
      '*/2 * * * *',
      $inner$SELECT net.http_post(
        url := current_setting('app.settings.supabase_url') || '/functions/v1/social-scheduler/process',
        headers := jsonb_build_object(
          'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key'),
          'Content-Type', 'application/json'
        ),
        body := '{}'::jsonb
      );$inner$
    );
  END IF;
END $outer$;

-- ========== 20260224000000_display_currency.sql ==========
-- Add display_currency to profiles (Airbnb model: store USD, display in user's local currency)
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS display_currency TEXT DEFAULT 'USD';

-- Set COP for existing Colombian users
UPDATE profiles SET display_currency = 'COP' WHERE country = 'CO' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set MXN for existing Mexican users
UPDATE profiles SET display_currency = 'MXN' WHERE country = 'MX' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set PEN for existing Peruvian users
UPDATE profiles SET display_currency = 'PEN' WHERE country = 'PE' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set CLP for existing Chilean users
UPDATE profiles SET display_currency = 'CLP' WHERE country = 'CL' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set ARS for existing Argentine users
UPDATE profiles SET display_currency = 'ARS' WHERE country = 'AR' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set BRL for existing Brazilian users
UPDATE profiles SET display_currency = 'BRL' WHERE country = 'BR' AND (display_currency IS NULL OR display_currency = 'USD');
-- Set EUR for existing European users
UPDATE profiles SET display_currency = 'EUR' WHERE country IN ('ES', 'DE', 'FR') AND (display_currency IS NULL OR display_currency = 'USD');

-- Convert existing COP campaigns to USD using current exchange rate
DO $$
DECLARE
  cop_rate NUMERIC;
BEGIN
  SELECT rate INTO cop_rate
  FROM exchange_rates
  WHERE from_currency = 'USD' AND to_currency = 'COP' AND is_active = true
  ORDER BY created_at DESC
  LIMIT 1;

  IF cop_rate IS NOT NULL AND cop_rate > 0 THEN
    UPDATE marketplace_campaigns
    SET total_budget = ROUND(total_budget / cop_rate, 2),
        budget_per_video = CASE WHEN budget_per_video IS NOT NULL
          THEN ROUND(budget_per_video / cop_rate, 2)
          ELSE NULL END,
        min_bid = CASE WHEN min_bid IS NOT NULL
          THEN ROUND(min_bid / cop_rate, 2)
          ELSE NULL END,
        max_bid = CASE WHEN max_bid IS NOT NULL
          THEN ROUND(max_bid / cop_rate, 2)
          ELSE NULL END,
        exchange_product_value = CASE WHEN exchange_product_value IS NOT NULL
          THEN ROUND(exchange_product_value / cop_rate, 2)
          ELSE NULL END,
        currency = 'USD'
    WHERE currency = 'COP';
  END IF;
END $$;

-- ========== 20260224200000_fix_social_scheduler_cron.sql ==========
-- ══════════════════════════════════════════════════════════════════
-- Fix Social Scheduler Cron Job
-- Problem: pg_cron jobs using net.http_post failed because:
--   1. The schema 'net' was not in the search_path for cron jobs
--   2. app.settings.supabase_url and service_role_key were not configured
--   3. Default timeout of 5000ms was too short for publishing
--
-- Solution: Use hardcoded project URL (not sensitive) and 60s timeout.
-- Since social-scheduler has verify_jwt=false, no auth header needed.
--
-- Applied manually on 2026-02-25.
-- ══════════════════════════════════════════════════════════════════

-- 1. Ensure pg_net extension is enabled
CREATE EXTENSION IF NOT EXISTS pg_net WITH SCHEMA extensions;

-- 2. Remove old broken cron jobs
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM cron.job WHERE jobname = 'social-scheduler-process') THEN
    PERFORM cron.unschedule('social-scheduler-process');
  END IF;
  IF EXISTS (SELECT 1 FROM cron.job WHERE jobname = 'sync-social-metrics-daily') THEN
    PERFORM cron.unschedule('sync-social-metrics-daily');
  END IF;
EXCEPTION WHEN OTHERS THEN
  NULL;
END $$;

-- 3. Create new cron job with hardcoded URL and 60s timeout
-- Runs every 2 minutes to process scheduled posts
SELECT cron.schedule(
  'social-scheduler-process',
  '*/2 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co/functions/v1/social-scheduler/process',
    headers := '{"Content-Type": "application/json"}'::jsonb,
    body := '{}'::jsonb,
    timeout_milliseconds := 60000
  )
  $$
);

-- 4. Fix social metrics cron as well (same issue)
SELECT cron.schedule(
  'sync-social-metrics-daily',
  '0 6 * * *',
  $$
  SELECT net.http_post(
    url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co/functions/v1/social-metrics/bulk-sync',
    headers := '{"Content-Type": "application/json"}'::jsonb,
    body := '{}'::jsonb,
    timeout_milliseconds := 60000
  )
  $$
);

-- 5. Add queue processing cron (every 15 minutes)
SELECT cron.schedule(
  'social-scheduler-queues',
  '*/15 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co/functions/v1/social-scheduler/process-queues',
    headers := '{"Content-Type": "application/json"}'::jsonb,
    body := '{}'::jsonb,
    timeout_milliseconds := 30000
  )
  $$
);

-- ========== 20260225100000_public_content_showcase.sql ==========
-- Migration: Public content showcase landing page
-- Adds SECURITY DEFINER functions to fetch org branding + approved content for public display.
-- "Approved" = content that has passed through approval (approved_at IS NOT NULL).
-- Returns max 50 random videos for a given organization slug.

-- 1. Simple table-returning function (kept for backward compat)
CREATE OR REPLACE FUNCTION public.get_public_org_content(org_slug text, max_items int DEFAULT 50)
RETURNS TABLE (
  id uuid,
  title text,
  description text,
  video_url text,
  bunny_embed_url text,
  thumbnail_url text,
  status text,
  views_count int,
  likes_count int,
  approved_at timestamptz,
  created_at timestamptz,
  sphere_phase text,
  creator_name text,
  creator_avatar text
)
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT
    c.id, c.title, c.description, c.video_url, c.bunny_embed_url, c.thumbnail_url,
    c.status::text, COALESCE(c.views_count, 0)::int, COALESCE(c.likes_count, 0)::int,
    c.approved_at, c.created_at, c.sphere_phase::text,
    p.full_name AS creator_name, p.avatar_url AS creator_avatar
  FROM public.content c
  JOIN public.organizations o ON o.id = c.organization_id
  LEFT JOIN public.profiles p ON p.id = c.creator_id
  WHERE o.slug = org_slug
    AND o.is_blocked IS NOT TRUE
    AND o.portfolio_enabled = true
    AND c.approved_at IS NOT NULL
    AND (c.video_url IS NOT NULL OR c.bunny_embed_url IS NOT NULL)
  ORDER BY random()
  LIMIT LEAST(max_items, 50);
$$;

GRANT EXECUTE ON FUNCTION public.get_public_org_content(text, int) TO anon, authenticated;

-- 2. Full page RPC: returns org branding + stats + content in a single call
CREATE OR REPLACE FUNCTION public.get_public_org_content_page(org_slug text, max_items int DEFAULT 50)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
STABLE
AS $$
DECLARE
  v_org jsonb;
  v_content jsonb;
  v_org_id uuid;
  v_stats jsonb;
BEGIN
  -- Fetch org info with full branding
  SELECT jsonb_build_object(
    'id', o.id, 'name', o.name, 'slug', o.slug,
    'logo_url', o.logo_url, 'description', o.description,
    'portfolio_title', o.portfolio_title, 'portfolio_description', o.portfolio_description,
    'portfolio_cover', o.portfolio_cover, 'portfolio_color', o.portfolio_color,
    'primary_color', o.primary_color,
    'org_display_name', o.org_display_name, 'org_tagline', o.org_tagline,
    'org_cover_url', o.org_cover_url, 'org_specialties', o.org_specialties,
    'org_type', o.org_type,
    'org_website', o.org_website, 'org_instagram', o.org_instagram,
    'org_tiktok', o.org_tiktok, 'org_linkedin', o.org_linkedin,
    'instagram', o.instagram, 'tiktok', o.tiktok,
    'facebook', o.facebook, 'linkedin', o.linkedin, 'website', o.website,
    'city', o.city, 'country', o.country,
    'org_year_founded', o.org_year_founded, 'org_team_size_range', o.org_team_size_range,
    'favicon_url', o.favicon_url, 'og_image_url', o.og_image_url,
    'registration_banner_url', o.registration_page_config->>'banner_url'
  ), o.id
  INTO v_org, v_org_id
  FROM public.organizations o
  WHERE o.slug = org_slug
    AND o.is_blocked IS NOT TRUE
    AND o.portfolio_enabled = true;

  IF v_org IS NULL THEN RETURN NULL; END IF;

  -- Stats: videos produced (all content + 1000 legacy), clients, projects, creators
  SELECT jsonb_build_object(
    'total_videos_produced', (SELECT count(*) FROM content WHERE organization_id = v_org_id) + 1000,
    'total_clients', (SELECT count(*) FROM clients WHERE organization_id = v_org_id),
    'total_projects', (SELECT count(*) FROM client_packages cp JOIN clients cl ON cl.id = cp.client_id WHERE cl.organization_id = v_org_id),
    'total_creators', (SELECT count(*) FROM organization_members WHERE organization_id = v_org_id AND role IN ('creator','editor','strategist'))
  ) INTO v_stats;

  -- Fetch random approved content with video
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb), '[]'::jsonb)
  INTO v_content
  FROM (
    SELECT c.id, c.title, c.description, c.video_url, c.bunny_embed_url, c.thumbnail_url,
      c.status::text, COALESCE(c.views_count,0) as views_count, COALESCE(c.likes_count,0) as likes_count,
      c.approved_at, c.created_at, c.sphere_phase::text,
      p.full_name AS creator_name, p.avatar_url AS creator_avatar
    FROM public.content c
    LEFT JOIN public.profiles p ON p.id = c.creator_id
    WHERE c.organization_id = v_org_id
      AND c.approved_at IS NOT NULL
      AND (c.video_url IS NOT NULL OR c.bunny_embed_url IS NOT NULL)
    ORDER BY random()
    LIMIT LEAST(max_items, 50)
  ) t;

  RETURN jsonb_build_object('org', v_org, 'stats', v_stats, 'content', v_content);
END;
$$;

GRANT EXECUTE ON FUNCTION public.get_public_org_content_page(text, int) TO anon, authenticated;

-- 3. Performance index
CREATE INDEX IF NOT EXISTS idx_content_org_approved_video
  ON public.content(organization_id)
  WHERE approved_at IS NOT NULL
    AND (video_url IS NOT NULL OR bunny_embed_url IS NOT NULL);

-- ========== 20260225200000_fix_public_registration_permissions.sql ==========
-- ══════════════════════════════════════════════════════════════════
-- Fix Public Registration Permissions
--
-- Problem 1: exchange_rates returns 401 for unauthenticated users
--   - Pages like /unete/talento need to read exchange rates before login
--   - Only GRANT SELECT TO authenticated existed
--
-- Problem 2: capture-lead returns 500 (service_role write access)
--   - Edge function uses service_role key which should bypass RLS
--   - Adding explicit grants as safety net
--
-- Applied: 2026-02-25
-- ══════════════════════════════════════════════════════════════════

-- 1. Allow anonymous users to read exchange rates (needed for currency display)
GRANT SELECT ON exchange_rates TO anon;
GRANT SELECT ON supported_currencies TO anon;

-- 2. Ensure service_role has full access to CRM tables (for edge functions)
GRANT ALL ON platform_leads TO service_role;
GRANT ALL ON platform_lead_interactions TO service_role;
GRANT ALL ON platform_user_health TO service_role;

-- 3. Ensure sequences are accessible for inserts
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO service_role;

-- 4. Create RLS policy to allow service_role inserts (belt and suspenders)
-- Note: service_role should bypass RLS, but explicit policy helps with debugging
DO $$
BEGIN
  -- Drop existing policy if it exists to avoid conflicts
  DROP POLICY IF EXISTS "platform_leads_service_role_insert" ON platform_leads;

  -- Create policy that allows any insert (service_role bypasses anyway)
  CREATE POLICY "platform_leads_service_role_insert" ON platform_leads
    FOR INSERT
    TO service_role
    WITH CHECK (true);
EXCEPTION WHEN OTHERS THEN
  NULL; -- Ignore if table doesn't exist
END $$;

-- 5. Refresh PostgREST schema cache
NOTIFY pgrst, 'reload schema';

-- ========== 20260225300000_fix_get_full_user_detail.sql ==========
-- =====================================================
-- Fix: get_full_user_detail RPC — split into parts to avoid 100 arg limit
-- Migration: 20260225300000_fix_get_full_user_detail
-- Problems fixed:
--   1. auth.sessions is not accessible (removed)
--   2. PostgreSQL limit: cannot pass more than 100 arguments to jsonb_build_object
-- Solution: Build JSON in 7 parts and concatenate with ||
-- =====================================================

CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB;
  profile_base JSONB;
  profile_social JSONB;
  profile_extras JSONB;
  creator_data JSONB;
  health_data JSONB;
  org_data JSONB;
  arrays_data JSONB;
BEGIN
  -- Part 1: Basic profile fields
  SELECT jsonb_build_object(
    'id', p.id,
    'email', p.email,
    'full_name', p.full_name,
    'username', p.username,
    'avatar_url', p.avatar_url,
    'phone', p.phone,
    'bio', p.bio,
    'tagline', p.tagline,
    'cover_url', p.cover_url,
    'document_type', p.document_type,
    'document_number', p.document_number,
    'address', p.address,
    'city', p.city,
    'country', p.country,
    'created_at', p.created_at
  ) INTO profile_base
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 2: Social links and content preferences
  SELECT jsonb_build_object(
    'instagram', p.instagram,
    'tiktok', p.tiktok,
    'facebook', p.facebook,
    'social_linkedin', p.social_linkedin,
    'social_twitter', p.social_twitter,
    'social_youtube', p.social_youtube,
    'portfolio_url', p.portfolio_url,
    'featured_video_url', p.featured_video_url,
    'content_categories', COALESCE(p.content_categories, ARRAY[]::TEXT[]),
    'specialties_tags', COALESCE(p.specialties_tags, ARRAY[]::TEXT[]),
    'style_keywords', COALESCE(p.style_keywords, ARRAY[]::TEXT[]),
    'industries', COALESCE(p.industries, ARRAY[]::TEXT[]),
    'interests', COALESCE(p.interests, ARRAY[]::TEXT[]),
    'languages', COALESCE(p.languages, ARRAY[]::TEXT[])
  ) INTO profile_social
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 3: Profile extras (scores, flags, etc)
  SELECT jsonb_build_object(
    'experience_level', p.experience_level,
    'availability_status', p.availability_status,
    'best_at', p.best_at,
    'rate_per_content', p.rate_per_content,
    'rate_currency', p.rate_currency,
    'quality_score_avg', p.quality_score_avg,
    'reliability_score', p.reliability_score,
    'velocity_score', p.velocity_score,
    'editor_rating', p.editor_rating,
    'is_ambassador', COALESCE(p.is_ambassador, false),
    'is_platform_founder', COALESCE(p.is_platform_founder, false),
    'founder_badge_type', p.founder_badge_type,
    'active_role', p.active_role,
    'ai_recommended_level', p.ai_recommended_level,
    'ai_risk_flag', p.ai_risk_flag,
    'is_active', COALESCE(p.is_active, true),
    'crm_custom_fields', COALESCE(p.crm_custom_fields, '{}'::jsonb)
  ) INTO profile_extras
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 4: Creator profile data
  SELECT jsonb_build_object(
    'creator_profile_id', cp.id,
    'slug', cp.slug,
    'bio_full', cp.bio_full,
    'banner_url', cp.banner_url,
    'creator_social_links', cp.social_links,
    'level', cp.level,
    'is_verified', COALESCE(cp.is_verified, false),
    'is_available', COALESCE(cp.is_available, false),
    'rating_avg', COALESCE(cp.rating_avg, 0),
    'rating_count', COALESCE(cp.rating_count, 0),
    'completed_projects', COALESCE(cp.completed_projects, 0),
    'base_price', cp.base_price,
    'currency', COALESCE(cp.currency, 'USD'),
    'categories', COALESCE(cp.categories, ARRAY[]::TEXT[]),
    'content_types', COALESCE(cp.content_types, ARRAY[]::TEXT[]),
    'platforms', COALESCE(cp.platforms, ARRAY[]::TEXT[]),
    'marketplace_roles', COALESCE(cp.marketplace_roles, ARRAY[]::TEXT[]),
    'accepts_product_exchange', COALESCE(cp.accepts_product_exchange, false),
    'response_time_hours', cp.response_time_hours,
    'on_time_delivery_pct', cp.on_time_delivery_pct,
    'repeat_clients_pct', cp.repeat_clients_pct,
    'showreel_video_id', cp.showreel_video_id,
    'showreel_url', cp.showreel_url,
    'showreel_thumbnail', cp.showreel_thumbnail
  ) INTO creator_data
  FROM profiles p
  LEFT JOIN creator_profiles cp ON cp.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 5: Health data
  SELECT jsonb_build_object(
    'health_score', COALESCE(h.health_score, 0),
    'health_status', COALESCE(h.health_status, 'healthy'),
    'total_logins', COALESCE(h.total_logins, 0),
    'days_since_last_activity', h.days_since_last_activity,
    'last_login_at', h.last_login_at,
    'total_actions', 0,
    'needs_attention', COALESCE(h.needs_attention, false),
    'total_applications', COALESCE(h.total_applications, 0),
    'total_completed_projects', COALESCE(h.total_completed_projects, 0),
    'total_spent', COALESCE(h.total_spent, 0)
  ) INTO health_data
  FROM profiles p
  LEFT JOIN platform_user_health h ON h.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 6: Organization context
  SELECT jsonb_build_object(
    'organization_id', om.organization_id,
    'organization_name', o.name,
    'is_owner', COALESCE(om.is_owner, false),
    'ambassador_level', om.ambassador_level
  ) INTO org_data
  FROM profiles p
  LEFT JOIN organization_members om ON om.user_id = p.id AND om.organization_id = p.current_organization_id
  LEFT JOIN organizations o ON o.id = om.organization_id
  WHERE p.id = p_user_id;

  -- Part 7: Nested arrays
  SELECT jsonb_build_object(
    'organizations', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'organization_id', om2.organization_id,
        'organization_name', o2.name,
        'role', (SELECT omr3.role FROM organization_member_roles omr3 WHERE omr3.user_id = p_user_id AND omr3.organization_id = om2.organization_id LIMIT 1),
        'is_owner', om2.is_owner,
        'joined_at', om2.joined_at
      ) ORDER BY om2.joined_at ASC)
      FROM organization_members om2
      LEFT JOIN organizations o2 ON o2.id = om2.organization_id
      WHERE om2.user_id = p_user_id
    ), '[]'::jsonb),
    'companies', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'client_id', c2.id,
        'client_name', c2.name,
        'organization_id', c2.organization_id,
        'organization_name', o3.name,
        'role', cu2.role,
        'created_at', cu2.created_at
      ) ORDER BY cu2.created_at ASC)
      FROM client_users cu2
      JOIN clients c2 ON c2.id = cu2.client_id
      LEFT JOIN organizations o3 ON o3.id = c2.organization_id
      WHERE cu2.user_id = p_user_id
    ), '[]'::jsonb),
    'roles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'role', omr.role,
        'organization_id', omr.organization_id,
        'organization_name', o2.name
      ))
      FROM organization_member_roles omr
      LEFT JOIN organizations o2 ON o2.id = omr.organization_id
      WHERE omr.user_id = p_user_id
    ), '[]'::jsonb),
    'badges', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'badge', omb.badge,
        'level', omb.level,
        'is_active', omb.is_active,
        'granted_at', omb.granted_at
      ))
      FROM organization_member_badges omb
      WHERE omb.user_id = p_user_id AND omb.is_active = true
    ), '[]'::jsonb),
    'portfolio', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', pi.id,
        'title', pi.title,
        'media_type', pi.media_type,
        'media_url', pi.media_url,
        'thumbnail_url', pi.thumbnail_url,
        'bunny_video_id', pi.bunny_video_id,
        'category', pi.category,
        'is_featured', pi.is_featured
      ) ORDER BY pi.is_featured DESC, pi.display_order ASC)
      FROM portfolio_items pi
      JOIN creator_profiles cp ON cp.id = pi.creator_id
      WHERE cp.user_id = p_user_id AND pi.is_public = true
      LIMIT 12
    ), '[]'::jsonb),
    'services', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', cs.id,
        'title', cs.title,
        'service_type', cs.service_type,
        'price_type', cs.price_type,
        'price_amount', cs.price_amount,
        'price_currency', cs.price_currency,
        'delivery_days', cs.delivery_days,
        'is_featured', cs.is_featured
      ) ORDER BY cs.is_featured DESC, cs.display_order ASC)
      FROM creator_services cs
      WHERE cs.user_id = p_user_id AND cs.is_active = true
    ), '[]'::jsonb)
  ) INTO arrays_data;

  -- Combine all parts
  result := COALESCE(profile_base, '{}'::jsonb)
    || COALESCE(profile_social, '{}'::jsonb)
    || COALESCE(profile_extras, '{}'::jsonb)
    || COALESCE(creator_data, '{}'::jsonb)
    || COALESCE(health_data, '{}'::jsonb)
    || COALESCE(org_data, '{}'::jsonb)
    || COALESCE(arrays_data, '{}'::jsonb);

  RETURN result;
END;
$$;

