-- ========== 20260226100003_add_platform_access_to_users_rpc.sql ==========
-- =====================================================
-- Add platform_access_unlocked to users RPC
-- Migration: 20260226100003_add_platform_access_to_users_rpc
-- Purpose: Allow CRM to see which users need referral keys
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            -- Use organization_member_roles as source of truth (can be empty = no role)
            -- Falls back to profiles.active_role, then NULL
            COALESCE(omr.role::text, p.active_role) AS role,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- Auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin,
            -- Referral/key status
            COALESCE(p.platform_access_unlocked, FALSE) AS platform_access_unlocked,
            p.user_type
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.organization_id, om2.is_owner
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN LATERAL (
            SELECT omr2.role
            FROM organization_member_roles omr2
            WHERE omr2.user_id = au.id
              AND omr2.organization_id = om.organization_id
            LIMIT 1
        ) omr ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
    ) t;

    RETURN result;
END;
$$;

-- ========== 20260226100004_fix_users_rpc_user_type.sql ==========
-- =====================================================
-- Fix: user_type field does not exist in profiles table
-- Migration: 20260226100004_fix_users_rpc_user_type
-- Problem: The previous migration referenced p.user_type which doesn't exist
-- Fix: Use raw_user_meta_data->>'user_type' from auth.users instead
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            -- Use organization_member_roles as source of truth (can be empty = no role)
            -- Falls back to profiles.active_role, then NULL
            COALESCE(omr.role::text, p.active_role) AS role,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- Auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin,
            -- Referral/key status (from profiles table)
            COALESCE(p.platform_access_unlocked, FALSE) AS platform_access_unlocked,
            -- user_type from auth.users metadata
            au.raw_user_meta_data->>'user_type' AS user_type
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.organization_id, om2.is_owner
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN LATERAL (
            SELECT omr2.role
            FROM organization_member_roles omr2
            WHERE omr2.user_id = au.id
              AND omr2.organization_id = om.organization_id
            LIMIT 1
        ) omr ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
    ) t;

    RETURN result;
END;
$$;

-- ========== 20260226160746_brand_client_integration.sql ==========
-- ============================================================================
-- BRAND CLIENT INTEGRATION
-- Permite que las brands independientes tengan las mismas funcionalidades
-- que los clientes de organizaciones (productos, contenido, paquetes, etc.)
-- ============================================================================

-- 1. Agregar columna brand_id a clients
ALTER TABLE clients ADD COLUMN IF NOT EXISTS brand_id UUID REFERENCES brands(id) ON DELETE SET NULL;

-- 2. Crear índice para búsquedas por brand_id
CREATE INDEX IF NOT EXISTS idx_clients_brand_id ON clients(brand_id) WHERE brand_id IS NOT NULL;

-- 3. Constraint: un cliente por brand (similar a is_internal_brand per org)
CREATE UNIQUE INDEX IF NOT EXISTS idx_unique_client_per_brand
ON clients(brand_id)
WHERE brand_id IS NOT NULL;

-- 4. RLS Policy: Brand members pueden ver su cliente
DROP POLICY IF EXISTS "Brand members can view their brand client" ON clients;
CREATE POLICY "Brand members can view their brand client" ON clients
    FOR SELECT
    TO authenticated
    USING (
        brand_id IS NOT NULL
        AND brand_id IN (
            SELECT bm.brand_id FROM brand_members bm
            WHERE bm.user_id = auth.uid() AND bm.status = 'active'
        )
    );

-- 5. RLS Policy: Brand owners pueden actualizar su cliente
DROP POLICY IF EXISTS "Brand owners can update their brand client" ON clients;
CREATE POLICY "Brand owners can update their brand client" ON clients
    FOR UPDATE
    TO authenticated
    USING (
        brand_id IS NOT NULL
        AND brand_id IN (
            SELECT bm.brand_id FROM brand_members bm
            WHERE bm.user_id = auth.uid()
            AND bm.status = 'active'
            AND bm.role = 'owner'
        )
    );

-- 6. RLS Policy: Brand owners pueden insertar cliente para su brand
DROP POLICY IF EXISTS "Brand owners can insert client for their brand" ON clients;
CREATE POLICY "Brand owners can insert client for their brand" ON clients
    FOR INSERT
    TO authenticated
    WITH CHECK (
        brand_id IS NOT NULL
        AND brand_id IN (
            SELECT bm.brand_id FROM brand_members bm
            WHERE bm.user_id = auth.uid()
            AND bm.status = 'active'
            AND bm.role = 'owner'
        )
    );

-- 7. Función para crear cliente de brand automáticamente
CREATE OR REPLACE FUNCTION create_brand_client(
    p_brand_id UUID,
    p_user_id UUID
) RETURNS UUID AS $$
DECLARE
    v_client_id UUID;
    v_brand_name TEXT;
BEGIN
    -- Verificar que el usuario sea owner de la brand
    IF NOT EXISTS (
        SELECT 1 FROM brand_members
        WHERE brand_id = p_brand_id
        AND user_id = p_user_id
        AND role = 'owner'
        AND status = 'active'
    ) THEN
        RAISE EXCEPTION 'Usuario no es owner de la brand';
    END IF;

    -- Verificar si ya existe cliente para esta brand
    SELECT id INTO v_client_id
    FROM clients
    WHERE brand_id = p_brand_id
    LIMIT 1;

    IF v_client_id IS NOT NULL THEN
        -- Ya existe, verificar que el usuario esté en client_users
        INSERT INTO client_users (client_id, user_id, role)
        VALUES (v_client_id, p_user_id, 'owner')
        ON CONFLICT (client_id, user_id) DO NOTHING;

        RETURN v_client_id;
    END IF;

    -- Obtener nombre de la brand
    SELECT name INTO v_brand_name FROM brands WHERE id = p_brand_id;

    -- Crear el cliente
    INSERT INTO clients (
        name,
        brand_id,
        is_internal_brand,
        is_public,
        bio,
        created_by
    ) VALUES (
        v_brand_name,
        p_brand_id,
        false,  -- No es interno de org, es de brand independiente
        false,
        'Cliente de marca independiente: ' || v_brand_name,
        p_user_id
    )
    RETURNING id INTO v_client_id;

    -- Agregar al owner como usuario del cliente
    INSERT INTO client_users (client_id, user_id, role)
    VALUES (v_client_id, p_user_id, 'owner');

    RETURN v_client_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 8. Trigger para crear cliente automáticamente cuando se crea una brand
CREATE OR REPLACE FUNCTION on_brand_created() RETURNS TRIGGER AS $$
BEGIN
    -- Crear cliente para la nueva brand
    PERFORM create_brand_client(NEW.id, NEW.owner_id);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS trg_brand_created ON brands;
CREATE TRIGGER trg_brand_created
    AFTER INSERT ON brands
    FOR EACH ROW
    EXECUTE FUNCTION on_brand_created();

-- 9. Agregar brand members a client_users cuando se unen a la brand
CREATE OR REPLACE FUNCTION on_brand_member_added() RETURNS TRIGGER AS $$
DECLARE
    v_client_id UUID;
BEGIN
    -- Solo si el miembro está activo
    IF NEW.status = 'active' THEN
        -- Buscar el cliente de la brand
        SELECT id INTO v_client_id
        FROM clients
        WHERE brand_id = NEW.brand_id
        LIMIT 1;

        IF v_client_id IS NOT NULL THEN
            -- Agregar al cliente con rol apropiado
            INSERT INTO client_users (client_id, user_id, role)
            VALUES (
                v_client_id,
                NEW.user_id,
                CASE WHEN NEW.role = 'owner' THEN 'owner' ELSE 'viewer' END
            )
            ON CONFLICT (client_id, user_id) DO UPDATE SET role = EXCLUDED.role;
        END IF;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS trg_brand_member_added ON brand_members;
CREATE TRIGGER trg_brand_member_added
    AFTER INSERT OR UPDATE ON brand_members
    FOR EACH ROW
    EXECUTE FUNCTION on_brand_member_added();

-- 10. Migrar brands existentes: crear clientes para brands que no tienen
DO $$
DECLARE
    r RECORD;
    v_client_id UUID;
BEGIN
    FOR r IN
        SELECT b.id as brand_id, b.name, b.owner_id
        FROM brands b
        WHERE NOT EXISTS (
            SELECT 1 FROM clients c WHERE c.brand_id = b.id
        )
        AND b.owner_id IS NOT NULL
    LOOP
        -- Crear cliente para esta brand
        INSERT INTO clients (
            name,
            brand_id,
            is_internal_brand,
            is_public,
            bio,
            created_by
        ) VALUES (
            r.name,
            r.brand_id,
            false,
            false,
            'Cliente de marca independiente: ' || r.name,
            r.owner_id
        )
        RETURNING id INTO v_client_id;

        -- Agregar owner a client_users
        INSERT INTO client_users (client_id, user_id, role)
        VALUES (v_client_id, r.owner_id, 'owner')
        ON CONFLICT DO NOTHING;

        -- Agregar otros miembros activos
        INSERT INTO client_users (client_id, user_id, role)
        SELECT v_client_id, bm.user_id,
            CASE WHEN bm.role = 'owner' THEN 'owner' ELSE 'viewer' END
        FROM brand_members bm
        WHERE bm.brand_id = r.brand_id
        AND bm.status = 'active'
        AND bm.user_id != r.owner_id
        ON CONFLICT DO NOTHING;

        RAISE NOTICE 'Created client for brand: %', r.name;
    END LOOP;
END $$;

-- 11. Grant permisos
GRANT EXECUTE ON FUNCTION create_brand_client(UUID, UUID) TO authenticated;

-- ========== 20260226180000_fix_create_brand_client.sql ==========
-- Fix create_brand_client function to check brands.owner_id for new brands
-- The issue was that when creating a new brand, the brand_members row doesn't exist yet
-- so we need to also check if the user is the owner_id in the brands table

CREATE OR REPLACE FUNCTION create_brand_client(p_brand_id UUID, p_user_id UUID)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_client_id UUID;
    v_brand_name TEXT;
    v_is_owner BOOLEAN;
BEGIN
    -- Check if user is owner in brand_members (may not exist yet for new brands)
    SELECT EXISTS (
        SELECT 1 FROM brand_members
        WHERE brand_id = p_brand_id
        AND user_id = p_user_id
        AND role = 'owner'
        AND status = 'active'
    ) INTO v_is_owner;

    -- If not owner in brand_members, check if user is owner_id in brands table
    -- This handles the case of newly created brands where membership doesn't exist yet
    IF NOT v_is_owner THEN
        SELECT EXISTS (
            SELECT 1 FROM brands
            WHERE id = p_brand_id
            AND owner_id = p_user_id
        ) INTO v_is_owner;
    END IF;

    IF NOT v_is_owner THEN
        RAISE EXCEPTION 'Usuario no es owner de la brand';
    END IF;

    -- Check if client already exists for this brand
    SELECT id INTO v_client_id
    FROM clients
    WHERE brand_id = p_brand_id
    LIMIT 1;

    IF v_client_id IS NOT NULL THEN
        -- Already exists, ensure user is in client_users
        INSERT INTO client_users (client_id, user_id, role)
        VALUES (v_client_id, p_user_id, 'owner')
        ON CONFLICT (client_id, user_id) DO NOTHING;

        RETURN v_client_id;
    END IF;

    -- Get brand name
    SELECT name INTO v_brand_name FROM brands WHERE id = p_brand_id;

    -- Create the client
    INSERT INTO clients (
        name,
        brand_id,
        is_internal_brand,
        is_public,
        bio,
        created_by
    ) VALUES (
        v_brand_name,
        p_brand_id,
        false,
        false,
        'Cliente de marca independiente: ' || v_brand_name,
        p_user_id
    )
    RETURNING id INTO v_client_id;

    -- Add owner as client user
    INSERT INTO client_users (client_id, user_id, role)
    VALUES (v_client_id, p_user_id, 'owner');

    RETURN v_client_id;
END;
$$;

-- ========== 20260226200000_fix_referral_qualification.sql ==========
-- ============================================================================
-- FIX REFERRAL QUALIFICATION LOGIC
-- Update count_qualified_referrals to match useMarketplaceReadiness:
-- Portfolio can come from portfolio_items, published content, OR portfolio_posts
-- Also fix avatar check to include fallback to profiles.avatar_url
-- ============================================================================

-- Update count_qualified_referrals to use all portfolio sources
CREATE OR REPLACE FUNCTION count_qualified_referrals(p_user_id UUID)
RETURNS INT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(DISTINCT rr.referred_id) INTO v_count
  FROM referral_relationships rr
  JOIN creator_profiles cp ON cp.user_id = rr.referred_id
  LEFT JOIN profiles p ON p.id = rr.referred_id
  WHERE rr.referrer_id = p_user_id
    AND rr.status = 'active'
    AND cp.is_active = true
    -- Avatar check: creator_profiles OR profiles fallback (same as useMarketplaceReadiness)
    AND (cp.avatar_url IS NOT NULL OR p.avatar_url IS NOT NULL)
    -- Portfolio check: any of 3 sources (same as useMarketplaceReadiness)
    AND (
      EXISTS (SELECT 1 FROM portfolio_items pi WHERE pi.creator_profile_id = cp.id)
      OR EXISTS (SELECT 1 FROM content c WHERE c.creator_id = rr.referred_id AND c.is_published = true)
      OR EXISTS (SELECT 1 FROM portfolio_posts pp WHERE pp.user_id = rr.referred_id)
    );

  RETURN COALESCE(v_count, 0);
END;
$$;

-- Update get_referral_gate_status to use same logic
CREATE OR REPLACE FUNCTION get_referral_gate_status(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_unlocked BOOLEAN;
  v_qualified INT;
  v_referral_code TEXT;
  v_referrals JSONB;
BEGIN
  -- Current unlock status
  SELECT platform_access_unlocked INTO v_unlocked
  FROM profiles WHERE id = p_user_id;

  IF v_unlocked = true THEN
    RETURN jsonb_build_object(
      'unlocked', true,
      'qualified_count', 3,
      'remaining', 0,
      'referral_code', NULL,
      'referrals', '[]'::jsonb
    );
  END IF;

  -- Count qualified
  v_qualified := count_qualified_referrals(p_user_id);

  -- Get the user's primary referral code
  SELECT code INTO v_referral_code
  FROM referral_codes
  WHERE user_id = p_user_id AND is_active = true
  ORDER BY created_at ASC
  LIMIT 1;

  -- Get referrals with qualification details (updated to match new logic)
  SELECT COALESCE(jsonb_agg(row_to_json(r)::jsonb), '[]'::jsonb) INTO v_referrals
  FROM (
    SELECT
      rr.referred_id,
      rr.status,
      rr.created_at,
      p.full_name,
      COALESCE(cp.avatar_url, p.avatar_url) AS referred_avatar,
      cp.id IS NOT NULL AND cp.is_active = true AS has_active_profile,
      (cp.avatar_url IS NOT NULL OR p.avatar_url IS NOT NULL) AS has_avatar,
      (
        EXISTS (SELECT 1 FROM portfolio_items pi WHERE pi.creator_profile_id = cp.id)
        OR EXISTS (SELECT 1 FROM content c WHERE c.creator_id = rr.referred_id AND c.is_published = true)
        OR EXISTS (SELECT 1 FROM portfolio_posts pp WHERE pp.user_id = rr.referred_id)
      ) AS has_portfolio,
      (
        cp.id IS NOT NULL AND cp.is_active = true
        AND (cp.avatar_url IS NOT NULL OR p.avatar_url IS NOT NULL)
        AND (
          EXISTS (SELECT 1 FROM portfolio_items pi WHERE pi.creator_profile_id = cp.id)
          OR EXISTS (SELECT 1 FROM content c WHERE c.creator_id = rr.referred_id AND c.is_published = true)
          OR EXISTS (SELECT 1 FROM portfolio_posts pp WHERE pp.user_id = rr.referred_id)
        )
      ) AS is_qualified
    FROM referral_relationships rr
    JOIN profiles p ON p.id = rr.referred_id
    LEFT JOIN creator_profiles cp ON cp.user_id = rr.referred_id
    WHERE rr.referrer_id = p_user_id
      AND rr.status = 'active'
    ORDER BY rr.created_at DESC
  ) r;

  RETURN jsonb_build_object(
    'unlocked', false,
    'qualified_count', v_qualified,
    'remaining', GREATEST(3 - v_qualified, 0),
    'referral_code', v_referral_code,
    'referrals', v_referrals
  );
END;
$$;

-- Update trigger to also fire on content and portfolio_posts changes
CREATE OR REPLACE FUNCTION trigger_check_referrer_unlock()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_referrer_id UUID;
  v_user_id UUID;
BEGIN
  -- Determine user_id based on which table triggered
  IF TG_TABLE_NAME = 'creator_profiles' THEN
    v_user_id := NEW.user_id;
  ELSIF TG_TABLE_NAME = 'portfolio_items' THEN
    SELECT cp.user_id INTO v_user_id
    FROM creator_profiles cp
    WHERE cp.id = NEW.creator_profile_id;
  ELSIF TG_TABLE_NAME = 'content' THEN
    v_user_id := NEW.creator_id;
  ELSIF TG_TABLE_NAME = 'portfolio_posts' THEN
    v_user_id := NEW.user_id;
  ELSIF TG_TABLE_NAME = 'profiles' THEN
    v_user_id := NEW.id;
  END IF;

  -- Find the referrer of this user
  IF v_user_id IS NOT NULL THEN
    SELECT rr.referrer_id INTO v_referrer_id
    FROM referral_relationships rr
    WHERE rr.referred_id = v_user_id
      AND rr.status = 'active'
    LIMIT 1;
  END IF;

  IF v_referrer_id IS NOT NULL THEN
    PERFORM check_and_unlock_access(v_referrer_id);
  END IF;

  RETURN NEW;
END;
$$;

-- Drop existing triggers and recreate with updated conditions

-- Trigger on creator_profiles: when avatar_url or is_active changes
DROP TRIGGER IF EXISTS trg_check_referrer_on_profile_update ON creator_profiles;
CREATE TRIGGER trg_check_referrer_on_profile_update
  AFTER UPDATE OF avatar_url, is_active ON creator_profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- Trigger on portfolio_items: when a new item is inserted
DROP TRIGGER IF EXISTS trg_check_referrer_on_portfolio_insert ON portfolio_items;
CREATE TRIGGER trg_check_referrer_on_portfolio_insert
  AFTER INSERT ON portfolio_items
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- NEW: Trigger on content: when content is published
DROP TRIGGER IF EXISTS trg_check_referrer_on_content_publish ON content;
CREATE TRIGGER trg_check_referrer_on_content_publish
  AFTER INSERT OR UPDATE OF is_published ON content
  FOR EACH ROW
  WHEN (NEW.is_published = true)
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- NEW: Trigger on portfolio_posts: when a new post is created
DROP TRIGGER IF EXISTS trg_check_referrer_on_portfolio_post ON portfolio_posts;
CREATE TRIGGER trg_check_referrer_on_portfolio_post
  AFTER INSERT ON portfolio_posts
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- NEW: Trigger on profiles: when avatar_url changes (fallback avatar)
DROP TRIGGER IF EXISTS trg_check_referrer_on_profiles_avatar ON profiles;
CREATE TRIGGER trg_check_referrer_on_profiles_avatar
  AFTER UPDATE OF avatar_url ON profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_check_referrer_unlock();

-- Ensure GRANTs are in place
GRANT EXECUTE ON FUNCTION count_qualified_referrals(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION check_and_unlock_access(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_referral_gate_status(UUID) TO authenticated;

-- ========== 20260226300000_fix_portfolio_trigger_field_name.sql ==========
-- Fix: trigger_check_referrer_unlock uses wrong field name for portfolio_items
-- The field is 'creator_id', not 'creator_profile_id'

CREATE OR REPLACE FUNCTION trigger_check_referrer_unlock()
RETURNS TRIGGER
LANGUAGE plpgsql SECURITY DEFINER
SET search_path = 'public'
AS $$
DECLARE
  v_referrer_id UUID;
  v_user_id UUID;
BEGIN
  -- Determine user_id based on which table triggered
  IF TG_TABLE_NAME = 'creator_profiles' THEN
    v_user_id := NEW.user_id;
  ELSIF TG_TABLE_NAME = 'portfolio_items' THEN
    -- FIX: The field is 'creator_id', not 'creator_profile_id'
    SELECT cp.user_id INTO v_user_id
    FROM creator_profiles cp
    WHERE cp.id = NEW.creator_id;
  ELSIF TG_TABLE_NAME = 'content' THEN
    v_user_id := NEW.creator_id;
  ELSIF TG_TABLE_NAME = 'portfolio_posts' THEN
    v_user_id := NEW.user_id;
  ELSIF TG_TABLE_NAME = 'profiles' THEN
    v_user_id := NEW.id;
  END IF;

  -- Find the referrer of this user
  IF v_user_id IS NOT NULL THEN
    SELECT rr.referrer_id INTO v_referrer_id
    FROM referral_relationships rr
    WHERE rr.referred_id = v_user_id
      AND rr.status = 'active'
    LIMIT 1;

    IF v_referrer_id IS NOT NULL THEN
      PERFORM check_and_unlock_access(v_referrer_id);
    END IF;
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Don't block the insert if the referral check fails
  RETURN NEW;
END;
$$;

-- ========== 20260227000000_partner_communities.sql ==========
-- ============================================================================
-- PARTNER COMMUNITIES SYSTEM
-- Sistema de comunidades partner para referidos con beneficios especiales
-- ============================================================================

-- Tabla principal de comunidades
CREATE TABLE IF NOT EXISTS partner_communities (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    slug TEXT NOT NULL UNIQUE,
    name TEXT NOT NULL,
    description TEXT,
    logo_url TEXT,

    -- Beneficios
    free_months INTEGER DEFAULT 0,
    commission_discount_points INTEGER DEFAULT 0,  -- Puntos de descuento (ej: 5 = 30% -> 25%)
    bonus_ai_tokens INTEGER DEFAULT 0,
    custom_badge_text TEXT,
    custom_badge_color TEXT DEFAULT '#9333ea',

    -- Restricciones
    target_types TEXT[] DEFAULT ARRAY['brand'],  -- 'brand', 'creator', 'organization'
    max_redemptions INTEGER,  -- NULL = ilimitado
    current_redemptions INTEGER DEFAULT 0,

    -- Vigencia
    is_active BOOLEAN DEFAULT true,
    start_date TIMESTAMPTZ DEFAULT NOW(),
    end_date TIMESTAMPTZ,  -- NULL = sin fecha límite

    -- Metadata
    partner_contact_email TEXT,
    notes TEXT,
    metadata JSONB DEFAULT '{}',
    created_by UUID REFERENCES auth.users(id),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Membresías de usuarios/marcas en comunidades
CREATE TABLE IF NOT EXISTS partner_community_memberships (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    community_id UUID NOT NULL REFERENCES partner_communities(id) ON DELETE CASCADE,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,
    brand_id UUID REFERENCES brands(id) ON DELETE CASCADE,

    -- Beneficios aplicados
    free_months_granted INTEGER DEFAULT 0,
    commission_discount_applied INTEGER DEFAULT 0,
    bonus_tokens_granted INTEGER DEFAULT 0,

    -- Estado
    status TEXT DEFAULT 'active' CHECK (status IN ('active', 'expired', 'revoked')),

    -- Timestamps
    applied_at TIMESTAMPTZ DEFAULT NOW(),
    expires_at TIMESTAMPTZ,  -- NULL = perpetuo
    metadata JSONB DEFAULT '{}',

    -- Constraints: solo uno por comunidad por usuario/marca
    CONSTRAINT unique_user_community UNIQUE (community_id, user_id),
    CONSTRAINT unique_brand_community UNIQUE (community_id, brand_id),
    -- Al menos uno debe estar definido
    CONSTRAINT membership_has_target CHECK (user_id IS NOT NULL OR brand_id IS NOT NULL)
);

-- Agregar columnas de badge a brands (si no existen)
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'brands' AND column_name = 'partner_community_id') THEN
        ALTER TABLE brands ADD COLUMN partner_community_id UUID REFERENCES partner_communities(id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'brands' AND column_name = 'community_badge_text') THEN
        ALTER TABLE brands ADD COLUMN community_badge_text TEXT;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'brands' AND column_name = 'community_badge_color') THEN
        ALTER TABLE brands ADD COLUMN community_badge_color TEXT;
    END IF;
END $$;

-- Índices
CREATE INDEX IF NOT EXISTS idx_partner_communities_slug ON partner_communities(slug);
CREATE INDEX IF NOT EXISTS idx_partner_communities_active ON partner_communities(is_active) WHERE is_active = true;
CREATE INDEX IF NOT EXISTS idx_partner_community_memberships_user ON partner_community_memberships(user_id);
CREATE INDEX IF NOT EXISTS idx_partner_community_memberships_brand ON partner_community_memberships(brand_id);
CREATE INDEX IF NOT EXISTS idx_partner_community_memberships_community ON partner_community_memberships(community_id);

