  BEGIN DELETE FROM organization_members WHERE user_id = target_user_id; EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN DELETE FROM user_roles WHERE user_id = target_user_id; EXCEPTION WHEN OTHERS THEN NULL; END;
