-- ========== 20260227200003_booking_policies.sql ==========
-- Políticas de cancelación y reprogramación
-- Agrega configuración de políticas al tipo de evento

-- Agregar columna de políticas al tipo de evento
ALTER TABLE booking_event_types
ADD COLUMN IF NOT EXISTS cancellation_policy JSONB DEFAULT '{
  "allow_cancellation": true,
  "min_hours_before": 24,
  "allow_reschedule": true,
  "reschedule_limit": 2,
  "policy_text": null
}'::jsonb;

-- Agregar columnas para tracking de reprogramaciones en bookings
ALTER TABLE bookings
ADD COLUMN IF NOT EXISTS reschedule_count INT DEFAULT 0,
ADD COLUMN IF NOT EXISTS original_start_time TIMESTAMPTZ,
ADD COLUMN IF NOT EXISTS rescheduled_at TIMESTAMPTZ,
ADD COLUMN IF NOT EXISTS rescheduled_by TEXT CHECK (rescheduled_by IN ('host', 'guest')),
ADD COLUMN IF NOT EXISTS cancel_token TEXT UNIQUE,
ADD COLUMN IF NOT EXISTS reschedule_token TEXT UNIQUE;

-- Generar tokens automáticamente para nuevas reservas
CREATE OR REPLACE FUNCTION generate_booking_tokens()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.cancel_token IS NULL THEN
    NEW.cancel_token = replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', '');
  END IF;
  IF NEW.reschedule_token IS NULL THEN
    NEW.reschedule_token = replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', '');
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_generate_booking_tokens
  BEFORE INSERT ON bookings
  FOR EACH ROW
  EXECUTE FUNCTION generate_booking_tokens();

-- Actualizar tokens existentes que no tienen
UPDATE bookings
SET
  cancel_token = replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', ''),
  reschedule_token = replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', '')
WHERE cancel_token IS NULL OR reschedule_token IS NULL;

-- Índices
CREATE INDEX IF NOT EXISTS idx_bookings_cancel_token ON bookings(cancel_token);
CREATE INDEX IF NOT EXISTS idx_bookings_reschedule_token ON bookings(reschedule_token);

COMMENT ON COLUMN booking_event_types.cancellation_policy IS 'Configuración de políticas de cancelación y reprogramación en JSON';
COMMENT ON COLUMN bookings.cancel_token IS 'Token único para enlace de cancelación por email';
COMMENT ON COLUMN bookings.reschedule_token IS 'Token único para enlace de reprogramación por email';

-- ========== 20260227200004_booking_reminders.sql ==========
-- Recordatorios configurables por tipo de evento
-- Permite configurar múltiples recordatorios con diferentes tiempos y canales

CREATE TABLE IF NOT EXISTS booking_reminder_settings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event_type_id UUID REFERENCES booking_event_types(id) ON DELETE CASCADE NOT NULL,
  reminder_type TEXT CHECK (reminder_type IN ('email', 'sms')) DEFAULT 'email',
  hours_before INT NOT NULL CHECK (hours_before > 0 AND hours_before <= 168), -- máx 1 semana
  enabled BOOLEAN DEFAULT true,
  template_subject TEXT,
  template_body TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Logs de recordatorios enviados
CREATE TABLE IF NOT EXISTS booking_reminder_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id UUID REFERENCES bookings(id) ON DELETE CASCADE NOT NULL,
  reminder_setting_id UUID REFERENCES booking_reminder_settings(id) ON DELETE SET NULL,
  reminder_type TEXT NOT NULL,
  hours_before INT NOT NULL,
  sent_at TIMESTAMPTZ DEFAULT now(),
  status TEXT DEFAULT 'sent' CHECK (status IN ('sent', 'failed', 'pending')),
  error_message TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_reminder_settings_event_type ON booking_reminder_settings(event_type_id);
CREATE INDEX IF NOT EXISTS idx_reminder_settings_enabled ON booking_reminder_settings(event_type_id, enabled);
CREATE INDEX IF NOT EXISTS idx_reminder_logs_booking ON booking_reminder_logs(booking_id);
CREATE INDEX IF NOT EXISTS idx_reminder_logs_sent_at ON booking_reminder_logs(sent_at);

-- RLS
ALTER TABLE booking_reminder_settings ENABLE ROW LEVEL SECURITY;
ALTER TABLE booking_reminder_logs ENABLE ROW LEVEL SECURITY;

-- Propietarios pueden gestionar settings de recordatorios
CREATE POLICY "Owners can manage reminder settings"
  ON booking_reminder_settings
  FOR ALL
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM booking_event_types et
      WHERE et.id = booking_reminder_settings.event_type_id
      AND et.user_id = auth.uid()
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM booking_event_types et
      WHERE et.id = booking_reminder_settings.event_type_id
      AND et.user_id = auth.uid()
    )
  );

-- Propietarios pueden ver logs de sus recordatorios
CREATE POLICY "Hosts can view reminder logs"
  ON booking_reminder_logs
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM bookings b
      WHERE b.id = booking_reminder_logs.booking_id
      AND b.host_user_id = auth.uid()
    )
  );

-- Service role puede insertar logs
CREATE POLICY "Service can insert reminder logs"
  ON booking_reminder_logs
  FOR INSERT
  TO service_role
  WITH CHECK (true);

-- Grants
GRANT ALL ON booking_reminder_settings TO authenticated;
GRANT ALL ON booking_reminder_logs TO authenticated;
GRANT ALL ON booking_reminder_logs TO service_role;

-- Trigger updated_at
CREATE TRIGGER trg_reminder_settings_updated_at
  BEFORE UPDATE ON booking_reminder_settings
  FOR EACH ROW
  EXECUTE FUNCTION update_booking_questions_updated_at();

-- Crear recordatorios por defecto cuando se crea un event type
CREATE OR REPLACE FUNCTION create_default_reminders()
RETURNS TRIGGER AS $$
BEGIN
  -- Recordatorio 24h antes
  INSERT INTO booking_reminder_settings (event_type_id, reminder_type, hours_before, enabled)
  VALUES (NEW.id, 'email', 24, true);

  -- Recordatorio 1h antes
  INSERT INTO booking_reminder_settings (event_type_id, reminder_type, hours_before, enabled)
  VALUES (NEW.id, 'email', 1, true);

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_create_default_reminders
  AFTER INSERT ON booking_event_types
  FOR EACH ROW
  EXECUTE FUNCTION create_default_reminders();

COMMENT ON TABLE booking_reminder_settings IS 'Configuración de recordatorios por tipo de evento';
COMMENT ON TABLE booking_reminder_logs IS 'Registro de recordatorios enviados';

-- ========== 20260227200005_calendar_integrations.sql ==========
-- Integraciones de calendario externo (Google Calendar, Outlook, etc.)
-- Permite sincronizar eventos bidireccional con calendarios externos

CREATE TABLE IF NOT EXISTS calendar_integrations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  provider TEXT CHECK (provider IN ('google', 'outlook', 'apple')) NOT NULL,
  access_token TEXT,
  refresh_token TEXT,
  token_expires_at TIMESTAMPTZ,
  calendar_id TEXT, -- ID del calendario seleccionado
  calendar_name TEXT, -- Nombre del calendario para mostrar
  sync_enabled BOOLEAN DEFAULT true,
  check_conflicts BOOLEAN DEFAULT true, -- Verificar conflictos con eventos externos
  create_events BOOLEAN DEFAULT true, -- Crear eventos en calendario externo
  last_sync_at TIMESTAMPTZ,
  sync_errors JSONB,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),

  -- Un usuario solo puede tener una integración por proveedor
  UNIQUE(user_id, provider)
);

-- Tabla para mapear eventos de Kreoon a eventos externos
CREATE TABLE IF NOT EXISTS calendar_event_mappings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id UUID REFERENCES bookings(id) ON DELETE CASCADE NOT NULL,
  integration_id UUID REFERENCES calendar_integrations(id) ON DELETE CASCADE NOT NULL,
  external_event_id TEXT NOT NULL, -- ID del evento en el calendario externo
  external_calendar_id TEXT NOT NULL,
  last_synced_at TIMESTAMPTZ DEFAULT now(),
  sync_status TEXT DEFAULT 'synced' CHECK (sync_status IN ('synced', 'pending', 'error')),
  created_at TIMESTAMPTZ DEFAULT now(),

  UNIQUE(booking_id, integration_id)
);

-- Eventos externos que bloquean disponibilidad
CREATE TABLE IF NOT EXISTS calendar_blocked_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  integration_id UUID REFERENCES calendar_integrations(id) ON DELETE CASCADE NOT NULL,
  external_event_id TEXT NOT NULL,
  title TEXT,
  start_time TIMESTAMPTZ NOT NULL,
  end_time TIMESTAMPTZ NOT NULL,
  is_all_day BOOLEAN DEFAULT false,
  last_synced_at TIMESTAMPTZ DEFAULT now(),
  created_at TIMESTAMPTZ DEFAULT now(),

  UNIQUE(integration_id, external_event_id)
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_calendar_integrations_user ON calendar_integrations(user_id);
CREATE INDEX IF NOT EXISTS idx_calendar_integrations_provider ON calendar_integrations(user_id, provider);
CREATE INDEX IF NOT EXISTS idx_calendar_mappings_booking ON calendar_event_mappings(booking_id);
CREATE INDEX IF NOT EXISTS idx_calendar_mappings_external ON calendar_event_mappings(external_event_id);
CREATE INDEX IF NOT EXISTS idx_calendar_blocked_times ON calendar_blocked_events(integration_id, start_time, end_time);

-- RLS
ALTER TABLE calendar_integrations ENABLE ROW LEVEL SECURITY;
ALTER TABLE calendar_event_mappings ENABLE ROW LEVEL SECURITY;
ALTER TABLE calendar_blocked_events ENABLE ROW LEVEL SECURITY;

-- Usuarios pueden gestionar sus integraciones
CREATE POLICY "Users can manage their calendar integrations"
  ON calendar_integrations
  FOR ALL
  TO authenticated
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

-- Usuarios pueden ver mapeos de sus bookings
CREATE POLICY "Users can view their event mappings"
  ON calendar_event_mappings
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM calendar_integrations ci
      WHERE ci.id = calendar_event_mappings.integration_id
      AND ci.user_id = auth.uid()
    )
  );

-- Service role puede gestionar mapeos
CREATE POLICY "Service can manage event mappings"
  ON calendar_event_mappings
  FOR ALL
  TO service_role
  WITH CHECK (true);

-- Usuarios pueden ver sus eventos bloqueados
CREATE POLICY "Users can view their blocked events"
  ON calendar_blocked_events
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM calendar_integrations ci
      WHERE ci.id = calendar_blocked_events.integration_id
      AND ci.user_id = auth.uid()
    )
  );

-- Service role puede gestionar eventos bloqueados
CREATE POLICY "Service can manage blocked events"
  ON calendar_blocked_events
  FOR ALL
  TO service_role
  WITH CHECK (true);

-- Grants
GRANT ALL ON calendar_integrations TO authenticated;
GRANT ALL ON calendar_event_mappings TO authenticated;
GRANT ALL ON calendar_event_mappings TO service_role;
GRANT ALL ON calendar_blocked_events TO authenticated;
GRANT ALL ON calendar_blocked_events TO service_role;

-- Trigger updated_at
CREATE TRIGGER trg_calendar_integrations_updated_at
  BEFORE UPDATE ON calendar_integrations
  FOR EACH ROW
  EXECUTE FUNCTION update_booking_questions_updated_at();

COMMENT ON TABLE calendar_integrations IS 'Integraciones con calendarios externos como Google Calendar';
COMMENT ON TABLE calendar_event_mappings IS 'Mapeo entre reservas de Kreoon y eventos en calendarios externos';
COMMENT ON TABLE calendar_blocked_events IS 'Eventos externos que bloquean disponibilidad';

-- ========== 20260227200006_booking_webhooks.sql ==========
-- Webhooks para notificar sistemas externos sobre eventos de booking
-- Permite a los usuarios configurar URLs que reciben notificaciones

CREATE TABLE IF NOT EXISTS booking_webhooks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  name TEXT, -- Nombre descriptivo del webhook
  url TEXT NOT NULL,
  events TEXT[] DEFAULT ARRAY['booking.created', 'booking.confirmed', 'booking.cancelled', 'booking.rescheduled', 'booking.completed'],
  secret TEXT, -- Secret para firmar los payloads
  headers JSONB DEFAULT '{}'::jsonb, -- Headers personalizados
  active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Logs de webhooks enviados
