-- ========== 20260227500000_fix_platform_users_role_source.sql ==========
-- Fix: Support multi-role users
-- Users can have multiple roles (creator, editor, strategist, ambassador, etc.)
-- Return both the primary role (from organization_members) and all roles (from organization_member_roles)
-- Frontend will use all_roles to show users in multiple tabs

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            -- Primary role from organization_members (for display)
            COALESCE(om.role::text, p.active_role) AS role,
            -- All roles from organization_member_roles (for multi-tab classification)
            COALESCE(all_roles.roles, ARRAY[]::text[]) AS all_roles,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- Auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin,
            -- Referral/key status (from profiles table)
            COALESCE(p.platform_access_unlocked, FALSE) AS platform_access_unlocked,
            -- user_type from auth.users metadata
            au.raw_user_meta_data->>'user_type' AS user_type
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.organization_id, om2.is_owner, om2.role
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN LATERAL (
            SELECT array_agg(DISTINCT omr.role::text) AS roles
            FROM organization_member_roles omr
            WHERE omr.user_id = au.id
              AND omr.organization_id = om.organization_id
        ) all_roles ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
    ) t;

    RETURN result;
END;
$$;

-- ========== 20260227600000_community_benefits_on_email_confirm.sql ==========
-- ============================================================================
-- APLICAR BENEFICIOS DE COMUNIDAD AL CONFIRMAR EMAIL
-- Trigger que se ejecuta cuando email_confirmed_at cambia de NULL a un valor
-- ============================================================================

-- Función que aplica los beneficios de comunidad
CREATE OR REPLACE FUNCTION public.apply_community_benefits_on_confirm()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
LANGUAGE plpgsql
AS $$
DECLARE
  v_community_slug TEXT;
  v_user_type TEXT;
  v_community RECORD;
  v_membership_id UUID;
  v_is_brand BOOLEAN;
  v_tier subscription_tier;
  v_trial_end TIMESTAMPTZ;
  v_pricing JSONB;
  v_existing_sub UUID;
  v_existing_membership UUID;
BEGIN
  -- Solo procesar si email_confirmed_at cambió de NULL a un valor
  IF OLD.email_confirmed_at IS NOT NULL OR NEW.email_confirmed_at IS NULL THEN
    RETURN NEW;
  END IF;

  -- Obtener community slug y user_type del metadata
  v_community_slug := NEW.raw_user_meta_data->>'partner_community';
  v_user_type := NEW.raw_user_meta_data->>'user_type';

  -- Si no hay comunidad, salir
  IF v_community_slug IS NULL OR v_community_slug = '' THEN
    RETURN NEW;
  END IF;

  RAISE LOG 'apply_community_benefits_on_confirm: user=%, community=%, user_type=%',
    NEW.id, v_community_slug, v_user_type;

  -- Buscar la comunidad
  SELECT * INTO v_community
  FROM partner_communities
  WHERE slug = v_community_slug
    AND is_active = true
    AND (start_date IS NULL OR start_date <= NOW())
    AND (end_date IS NULL OR end_date >= NOW())
    AND (max_redemptions IS NULL OR current_redemptions < max_redemptions);

  IF v_community.id IS NULL THEN
    RAISE LOG 'apply_community_benefits_on_confirm: community not found or inactive: %', v_community_slug;
    RETURN NEW;
  END IF;

  -- Verificar si ya tiene membresía
  SELECT id INTO v_existing_membership
  FROM partner_community_memberships
  WHERE community_id = v_community.id
    AND user_id = NEW.id
  LIMIT 1;

  IF v_existing_membership IS NOT NULL THEN
    RAISE LOG 'apply_community_benefits_on_confirm: user already has membership: %', v_existing_membership;
    RETURN NEW;
  END IF;

  v_is_brand := v_user_type = 'brand';

  -- 1. Crear membresía
  INSERT INTO partner_community_memberships (
    community_id,
    user_id,
    free_months_granted,
    commission_discount_applied,
    bonus_tokens_granted,
    status,
    metadata
  ) VALUES (
    v_community.id,
    NEW.id,
    v_community.free_months,
    CASE WHEN v_is_brand THEN v_community.commission_discount_points ELSE 0 END,
    v_community.bonus_ai_tokens,
    'active',
    jsonb_build_object(
      'applied_via', 'email_confirmation_trigger',
      'applied_at_redemptions', v_community.current_redemptions,
      'user_type', v_user_type
    )
  )
  RETURNING id INTO v_membership_id;

  RAISE LOG 'apply_community_benefits_on_confirm: created membership %', v_membership_id;

  -- 2. Crear custom_pricing_agreement si hay descuento en comisiones (SOLO BRANDS)
  IF v_is_brand AND v_community.commission_discount_points > 0 THEN
    INSERT INTO custom_pricing_agreements (
      user_id,
      marketplace_fee_override,
      campaign_fee_override,
      is_active,
      notes,
      valid_from
    ) VALUES (
      NEW.id,
      GREATEST(0.05, 0.30 - (v_community.commission_discount_points::NUMERIC / 100)),
      GREATEST(0.05, 0.30 - (v_community.commission_discount_points::NUMERIC / 100)),
      true,
      'Descuento comunidad ' || v_community.name || ' (-' || v_community.commission_discount_points || ' pts) membership_id=' || v_membership_id,
      CURRENT_DATE
    );
    RAISE LOG 'apply_community_benefits_on_confirm: created pricing agreement for brand';
  END IF;

  -- 3. Desbloquear acceso sin llaves (SOLO BRANDS)
  IF v_is_brand THEN
    UPDATE profiles
    SET platform_access_unlocked = true
    WHERE id = NEW.id;
    RAISE LOG 'apply_community_benefits_on_confirm: unlocked platform access for brand';
  END IF;

  -- 4. Incrementar contador de redenciones
  UPDATE partner_communities
  SET current_redemptions = current_redemptions + 1
  WHERE id = v_community.id;

  -- 5. Otorgar tokens bonus si aplica
  -- Nota: balance_total es columna generada, solo insertamos balance_bonus
  IF v_community.bonus_ai_tokens > 0 THEN
    INSERT INTO ai_token_balances (user_id, balance_bonus)
    VALUES (NEW.id, v_community.bonus_ai_tokens)
    ON CONFLICT (user_id) DO UPDATE
    SET balance_bonus = COALESCE(ai_token_balances.balance_bonus, 0) + v_community.bonus_ai_tokens;
    RAISE LOG 'apply_community_benefits_on_confirm: granted % bonus tokens', v_community.bonus_ai_tokens;
  END IF;

  -- 6. Crear suscripción con meses gratis si aplica
  IF v_community.free_months > 0 THEN
    -- Verificar si ya tiene suscripción
    SELECT id INTO v_existing_sub
    FROM platform_subscriptions
    WHERE user_id = NEW.id
    LIMIT 1;

    IF v_existing_sub IS NULL THEN
      -- Determinar tier según tipo de usuario (usar cast a subscription_tier)
      v_tier := CASE WHEN v_is_brand
        THEN 'brand_starter'::subscription_tier
        ELSE 'creator_pro'::subscription_tier
      END;

      -- Precios según tier
      v_pricing := CASE WHEN v_is_brand
        THEN '{"monthly": 39, "annual": 390, "limits": {"users": 3, "ai_tokens": 4000, "storage_gb": 5, "content_per_month": 30}}'::jsonb
        ELSE '{"monthly": 29, "annual": 290, "limits": {"projects": 20, "ai_tokens": 3000, "storage_gb": 10}}'::jsonb
      END;

      v_trial_end := NOW() + (v_community.free_months || ' months')::INTERVAL;

      INSERT INTO platform_subscriptions (
        user_id,
        tier,
        status,
        billing_cycle,
        price_monthly,
        price_annual,
        current_price,
        trial_ends_at,
        current_period_start,
        current_period_end,
        plan_limits,
        metadata
      ) VALUES (
        NEW.id,
        v_tier,
        'trialing',
        'community_benefit',
        (v_pricing->>'monthly')::INTEGER,
        (v_pricing->>'annual')::INTEGER,
        0,
        v_trial_end,
        NOW(),
        v_trial_end,
        v_pricing->'limits',
        jsonb_build_object(
          'source', 'community_benefit_email_confirm',
          'free_months', v_community.free_months,
          'community_id', v_community.id,
          'community_slug', v_community.slug,
          'community_membership_id', v_membership_id,
          'user_type', v_user_type,
          'activated_at', NOW()
        )
      );
      RAISE LOG 'apply_community_benefits_on_confirm: created % subscription with % free months', v_tier, v_community.free_months;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;

-- Crear trigger en auth.users
DROP TRIGGER IF EXISTS trg_apply_community_benefits ON auth.users;

CREATE TRIGGER trg_apply_community_benefits
  AFTER UPDATE OF email_confirmed_at ON auth.users
  FOR EACH ROW
  WHEN (OLD.email_confirmed_at IS NULL AND NEW.email_confirmed_at IS NOT NULL)
  EXECUTE FUNCTION public.apply_community_benefits_on_confirm();

-- Dar permisos necesarios
GRANT EXECUTE ON FUNCTION public.apply_community_benefits_on_confirm() TO service_role;

-- Comentario para documentación
COMMENT ON FUNCTION public.apply_community_benefits_on_confirm() IS
'Aplica automáticamente los beneficios de comunidad cuando un usuario confirma su email.
Lee partner_community y user_type del raw_user_meta_data y crea:
- Membresía en partner_community_memberships
- Custom pricing agreement con descuento (solo brands)
- Desbloqueo de acceso sin llaves (solo brands)
- Tokens bonus en ai_token_balances
- Suscripción con trial gratis en platform_subscriptions

Diferencias por tipo de usuario:
- BRANDS: brand_starter plan + acceso sin llaves + descuento comisiones
- FREELANCERS: creator_pro plan + tokens bonus (SIN acceso ni descuento)';

-- ========== 20260228100000_live_hosting_system.sql ==========
-- ============================================================================
-- KREOON LIVE HOSTING SYSTEM
-- Sistema híbrido de contratación de hosts para transmisiones en vivo
-- Migración: 20260228100000_live_hosting_system.sql
-- ============================================================================

-- ============================================================================
-- PARTE 1: ENUMS
-- ============================================================================

-- Canal de contratación
DO $$ BEGIN
    CREATE TYPE hosting_channel_type AS ENUM (
        'marketplace',     -- Canal A: Publicación abierta, creadores aplican
        'direct',          -- Canal B: Invitación directa a creador específico
        'org_managed'      -- Canal C: Organización vende a cliente, asigna creador interno
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Estado de la solicitud de hosting
DO $$ BEGIN
    CREATE TYPE hosting_request_status AS ENUM (
        'draft',               -- Borrador, no publicado
        'pending_payment',     -- Esperando pago/escrow
        'open',                -- Publicado, aceptando aplicaciones (marketplace)
        'reviewing',           -- Revisando aplicaciones
        'host_selected',       -- Host seleccionado, pendiente confirmación
        'negotiating',         -- En negociación (direct)
        'confirmed',           -- Host confirmado, esperando live
        'in_progress',         -- Live en curso
        'completed',           -- Live finalizado exitosamente
        'cancelled',           -- Cancelado
        'disputed'             -- En disputa
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Estado del host en la solicitud
DO $$ BEGIN
    CREATE TYPE hosting_host_status AS ENUM (
        'invited',             -- Invitado (direct)
        'applied',             -- Aplicó (marketplace)
        'shortlisted',         -- Preseleccionado
        'selected',            -- Seleccionado
        'counter_offered',     -- Envió contraoferta
        'negotiating',         -- En negociación
        'confirmed',           -- Confirmado
        'rejected',            -- Rechazado
        'withdrawn',           -- Se retiró
        'completed',           -- Completó el live
        'no_show'              -- No se presentó
    );
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- ============================================================================
-- PARTE 2: TABLA live_hosting_requests
-- Solicitudes de host para transmisiones en vivo
-- ============================================================================

CREATE TABLE IF NOT EXISTS live_hosting_requests (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    -- Canal de contratación
    channel hosting_channel_type NOT NULL DEFAULT 'marketplace',

    -- Relaciones organizacionales
    organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
    client_id UUID REFERENCES clients(id),      -- Cliente externo (Canal C)
    brand_id UUID REFERENCES brands(id),        -- Marca solicitante (Canal A/B)
    created_by UUID NOT NULL REFERENCES auth.users(id),

    -- Información básica
    title TEXT NOT NULL,
    description TEXT,
    requirements JSONB DEFAULT '[]'::jsonb,     -- Lista de requisitos del host
    preferred_niches TEXT[] DEFAULT '{}',       -- Nichos preferidos
    preferred_languages TEXT[] DEFAULT '{es}'::text[],

    -- Programación
    scheduled_date DATE NOT NULL,
    scheduled_time_start TIME NOT NULL,
    scheduled_time_end TIME,
    timezone TEXT DEFAULT 'America/Bogota',
    estimated_duration_minutes INTEGER DEFAULT 60,

    -- Configuración del live
    live_type streaming_session_type DEFAULT 'live_shopping',
    products_to_showcase JSONB DEFAULT '[]'::jsonb, -- IDs de productos
    target_audience TEXT,
    content_guidelines TEXT,

    -- Presupuesto y pagos
    budget_min_usd DECIMAL(10,2),
    budget_max_usd DECIMAL(10,2),
    fixed_rate_usd DECIMAL(10,2),               -- Tarifa fija acordada
    commission_on_sales_pct DECIMAL(5,2),       -- % comisión sobre ventas

    -- Comisiones de plataforma
    platform_commission_rate DECIMAL(5,4) DEFAULT 0.20,  -- 20% para A/B, 10-12% para C
    org_markup_rate DECIMAL(5,4) DEFAULT 0,              -- Solo Canal C: markup de la org
    org_markup_amount_usd DECIMAL(10,2) DEFAULT 0,

    -- Estado
    status hosting_request_status NOT NULL DEFAULT 'draft',

    -- Relaciones con otros módulos
    streaming_session_id UUID REFERENCES streaming_sessions_v2(id), -- Se crea al confirmar pago
    escrow_hold_id UUID REFERENCES escrow_holds(id),
    campaign_id UUID REFERENCES marketplace_campaigns(id),         -- Canal A: campaña asociada
    template_id UUID,                                              -- Template usado

    -- Métricas post-live
    actual_duration_minutes INTEGER,
    actual_revenue_usd DECIMAL(12,2),
    actual_orders INTEGER,
    host_rating DECIMAL(3,2),
    client_rating DECIMAL(3,2),

    -- Metadata
    metadata JSONB DEFAULT '{}'::jsonb,

    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_org ON live_hosting_requests(organization_id);
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_channel ON live_hosting_requests(channel);
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_status ON live_hosting_requests(status);
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_date ON live_hosting_requests(scheduled_date);
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_brand ON live_hosting_requests(brand_id);
CREATE INDEX IF NOT EXISTS idx_live_hosting_requests_client ON live_hosting_requests(client_id);

-- ============================================================================
-- PARTE 3: TABLA live_hosting_hosts
-- Hosts asignados/aplicantes para cada solicitud
-- ============================================================================

CREATE TABLE IF NOT EXISTS live_hosting_hosts (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    request_id UUID NOT NULL REFERENCES live_hosting_requests(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES auth.users(id),
    creator_profile_id UUID REFERENCES creator_profiles(id),

    -- Estado
    status hosting_host_status NOT NULL DEFAULT 'applied',

    -- Propuesta económica
    proposed_rate_usd DECIMAL(10,2),            -- Tarifa propuesta por el host
    agreed_rate_usd DECIMAL(10,2),              -- Tarifa acordada final
    commission_on_sales_pct DECIMAL(5,2),       -- % comisión sobre ventas

    -- Negociación (Canal B)
    counter_offer_usd DECIMAL(10,2),
    counter_offer_message TEXT,
    counter_offer_at TIMESTAMPTZ,

    -- Aplicación (Canal A)
    application_message TEXT,
    portfolio_links TEXT[] DEFAULT '{}',
    experience_description TEXT,

    -- Evaluación
    fit_score INTEGER DEFAULT 0,                -- Score de compatibilidad 0-100
    shortlist_notes TEXT,
    rejection_reason TEXT,

    -- Post-live
    actual_performance_score DECIMAL(3,2),
    host_feedback TEXT,
    client_feedback TEXT,

    -- Pago
    payment_status TEXT DEFAULT 'pending',      -- pending, processing, paid, disputed
    payment_released_at TIMESTAMPTZ,

    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),

    UNIQUE(request_id, user_id)
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_live_hosting_hosts_request ON live_hosting_hosts(request_id);
CREATE INDEX IF NOT EXISTS idx_live_hosting_hosts_user ON live_hosting_hosts(user_id);
CREATE INDEX IF NOT EXISTS idx_live_hosting_hosts_status ON live_hosting_hosts(status);
CREATE INDEX IF NOT EXISTS idx_live_hosting_hosts_creator_profile ON live_hosting_hosts(creator_profile_id);

-- ============================================================================
-- PARTE 4: TABLA live_hosting_status_history
-- Auditoría de cambios de estado
-- ============================================================================

CREATE TABLE IF NOT EXISTS live_hosting_status_history (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    request_id UUID NOT NULL REFERENCES live_hosting_requests(id) ON DELETE CASCADE,
    host_id UUID REFERENCES live_hosting_hosts(id) ON DELETE CASCADE,

    -- Cambio
    entity_type TEXT NOT NULL,                  -- 'request' o 'host'
    from_status TEXT,
    to_status TEXT NOT NULL,

    -- Contexto
    changed_by UUID REFERENCES auth.users(id),
    change_reason TEXT,
    metadata JSONB DEFAULT '{}'::jsonb,

    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Índice
CREATE INDEX IF NOT EXISTS idx_live_hosting_history_request ON live_hosting_status_history(request_id);

-- ============================================================================
-- PARTE 5: TABLA live_hosting_templates
-- Templates reutilizables para solicitudes
-- ============================================================================

CREATE TABLE IF NOT EXISTS live_hosting_templates (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
    created_by UUID NOT NULL REFERENCES auth.users(id),

    -- Info
    name TEXT NOT NULL,
    description TEXT,

    -- Template data
    default_channel hosting_channel_type DEFAULT 'marketplace',
    default_requirements JSONB DEFAULT '[]'::jsonb,
    default_niches TEXT[] DEFAULT '{}',
    default_duration_minutes INTEGER DEFAULT 60,
    default_budget_min_usd DECIMAL(10,2),
    default_budget_max_usd DECIMAL(10,2),
    default_live_type streaming_session_type DEFAULT 'live_shopping',
    default_content_guidelines TEXT,

    -- Uso
    times_used INTEGER DEFAULT 0,
    is_active BOOLEAN DEFAULT true,

    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Índice
CREATE INDEX IF NOT EXISTS idx_live_hosting_templates_org ON live_hosting_templates(organization_id);

-- ============================================================================
-- PARTE 6: TRIGGERS PARA TIMESTAMPS
-- ============================================================================

-- Función genérica para updated_at
CREATE OR REPLACE FUNCTION update_live_hosting_timestamp()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Triggers de updated_at
