-- ========== 20260302110000_fix_brands_insert_policy.sql ==========
-- ============================================================================
-- FIX: Permitir que platform root cree brands para otros usuarios
-- El admin de plataforma necesita crear marcas asignando owner_id a otros usuarios
-- ============================================================================

-- 1. Eliminar la política actual de INSERT
DROP POLICY IF EXISTS brands_insert ON brands;

-- 2. Crear nueva política que permite:
--    a) Usuario crea su propia brand (owner_id = auth.uid())
--    b) Platform root crea brand para cualquier usuario
CREATE POLICY brands_insert ON brands
    FOR INSERT
    TO authenticated
    WITH CHECK (
        owner_id = auth.uid()
        OR public.is_platform_root(auth.uid())
    );

-- 3. También actualizar UPDATE y DELETE para que platform root pueda gestionar todas las brands
DROP POLICY IF EXISTS brands_update ON brands;
CREATE POLICY brands_update ON brands
    FOR UPDATE
    TO authenticated
    USING (
        owner_id = auth.uid()
        OR public.is_platform_root(auth.uid())
    )
    WITH CHECK (
        owner_id = auth.uid()
        OR public.is_platform_root(auth.uid())
    );

DROP POLICY IF EXISTS brands_delete ON brands;
CREATE POLICY brands_delete ON brands
    FOR DELETE
    TO authenticated
    USING (
        owner_id = auth.uid()
        OR public.is_platform_root(auth.uid())
    );

-- ========== 20260302120000_fix_brand_members_rls.sql ==========
-- ============================================================================
-- FIX: Permitir que platform root gestione brand_members
-- El admin de plataforma necesita agregar/eliminar miembros de brands
-- ============================================================================

-- 1. Actualizar política de INSERT para brand_members
DROP POLICY IF EXISTS brand_members_insert ON brand_members;
CREATE POLICY brand_members_insert ON brand_members
    FOR INSERT
    TO authenticated
    WITH CHECK (
        -- Usuario se agrega a sí mismo
        user_id = auth.uid()
        -- O es dueño de la brand
        OR brand_id IN (SELECT b.id FROM brands b WHERE b.owner_id = auth.uid())
        -- O es platform root
        OR public.is_platform_root(auth.uid())
    );

-- 2. Actualizar política de UPDATE para brand_members
DROP POLICY IF EXISTS brand_members_update ON brand_members;
CREATE POLICY brand_members_update ON brand_members
    FOR UPDATE
    TO authenticated
    USING (
        -- Es dueño de la brand
        brand_id IN (SELECT b.id FROM brands b WHERE b.owner_id = auth.uid())
        -- O es el propio usuario
        OR user_id = auth.uid()
        -- O es platform root
        OR public.is_platform_root(auth.uid())
    );

-- 3. Actualizar política de DELETE para brand_members
DROP POLICY IF EXISTS brand_members_delete ON brand_members;
CREATE POLICY brand_members_delete ON brand_members
    FOR DELETE
    TO authenticated
    USING (
        -- Es dueño de la brand
        brand_id IN (SELECT b.id FROM brands b WHERE b.owner_id = auth.uid())
        -- O es el propio usuario (puede salirse)
        OR user_id = auth.uid()
        -- O es platform root
        OR public.is_platform_root(auth.uid())
    );

-- 4. También actualizar clients para que platform root pueda insertar clientes de brand
DROP POLICY IF EXISTS "Brand owners can insert client for their brand" ON clients;
CREATE POLICY "Brand owners can insert client for their brand" ON clients
    FOR INSERT
    TO authenticated
    WITH CHECK (
        brand_id IS NOT NULL
        AND (
            -- Es owner de la brand
            brand_id IN (
                SELECT bm.brand_id FROM brand_members bm
                WHERE bm.user_id = auth.uid()
                AND bm.status = 'active'
                AND bm.role = 'owner'
            )
            -- O es platform root
            OR public.is_platform_root(auth.uid())
        )
    );

-- 5. Platform root puede insertar cualquier cliente (incluyendo de organizaciones)
DROP POLICY IF EXISTS "Platform root can insert any client" ON clients;
CREATE POLICY "Platform root can insert any client" ON clients
    FOR INSERT
    TO authenticated
    WITH CHECK (public.is_platform_root(auth.uid()));

-- ========== 20260302130000_fix_clients_insert_policy.sql ==========
-- ============================================================================
-- FIX: Corregir política de INSERT para clients con brand_id
-- La política anterior tenía un bug con OR brand_id IS NULL
-- ============================================================================

-- 1. Corregir la política de brand clients
DROP POLICY IF EXISTS "Brand owners can insert client for their brand" ON clients;
CREATE POLICY "Brand owners can insert client for their brand" ON clients
    FOR INSERT
    TO authenticated
    WITH CHECK (
        brand_id IS NOT NULL
        AND (
            -- Es owner de la brand
            brand_id IN (
                SELECT bm.brand_id FROM brand_members bm
                WHERE bm.user_id = auth.uid()
                AND bm.status = 'active'
                AND bm.role = 'owner'
            )
            -- O es platform root
            OR public.is_platform_root(auth.uid())
        )
    );

-- 2. Platform root puede insertar cualquier cliente
DROP POLICY IF EXISTS "Platform root can insert any client" ON clients;
CREATE POLICY "Platform root can insert any client" ON clients
    FOR INSERT
    TO authenticated
    WITH CHECK (public.is_platform_root(auth.uid()));

-- 3. Platform root puede actualizar cualquier cliente
DROP POLICY IF EXISTS "Platform root can update any client" ON clients;
CREATE POLICY "Platform root can update any client" ON clients
