-- ============================================================================
-- Product DNA Prompts para sistema de dos pasos (Perplexity + Gemini)
-- ============================================================================

-- Prompt de investigación (Perplexity)
INSERT INTO platform_prompts (module, prompt_key, name, description, system_prompt, is_active)
VALUES (
  'dna',
  'product_research',
