-- Comentarios
COMMENT ON TABLE public.talent_dna IS 'ADN de Talento generado por IA a partir de audio del freelancer';
COMMENT ON COLUMN public.talent_dna.dna_data IS 'Perfil profesional estructurado generado por IA';
