-- ========== 20260303210000_fix_pending_assignments.sql ==========
-- Corregir asignaciones que quedaron en estado 'pending' cuando deberían estar en 'accepted'
-- Las asignaciones internas de equipo van directamente a 'accepted' (no requieren aceptación)

UPDATE project_assignments
SET
  status = 'accepted',
  accepted_at = COALESCE(accepted_at, created_at)
WHERE
  status = 'pending'
  AND invited_at IS NULL;  -- Solo las que nunca fueron invitaciones formales

-- Agregar comentario explicativo
COMMENT ON COLUMN project_assignments.status IS
  'Estado de la asignación. Las asignaciones internas de equipo inician en accepted.';

-- ========== 20260303220000_sync_assignments_to_content.sql ==========
-- Corregir asignaciones en estado 'invited' y 'pending' a 'accepted'
-- Las asignaciones internas de equipo van directamente a 'accepted'

UPDATE project_assignments
SET
  status = 'accepted',
  accepted_at = COALESCE(accepted_at, invited_at, created_at)
WHERE
  status IN ('pending', 'invited');

-- Sincronizar asignaciones de project_assignments con campos escalares de content
-- Esto permite que las tarjetas del tablero muestren los creadores/editores asignados

-- Sincronizar creator_id
UPDATE content c
SET creator_id = pa.user_id
FROM project_assignments pa
WHERE pa.content_id = c.id
  AND pa.role_id = 'creator'
  AND pa.status NOT IN ('cancelled')
  AND c.creator_id IS NULL;

-- Sincronizar editor_id
UPDATE content c
SET editor_id = pa.user_id
FROM project_assignments pa
WHERE pa.content_id = c.id
  AND pa.role_id = 'editor'
  AND pa.status NOT IN ('cancelled')
  AND c.editor_id IS NULL;

-- Sincronizar strategist_id
UPDATE content c
SET strategist_id = pa.user_id
FROM project_assignments pa
WHERE pa.content_id = c.id
  AND pa.role_id = 'strategist'
  AND pa.status NOT IN ('cancelled')
  AND c.strategist_id IS NULL;

-- Sincronizar pagos de creator
UPDATE content c
SET creator_payment = pa.payment_amount
FROM project_assignments pa
WHERE pa.content_id = c.id
  AND pa.role_id = 'creator'
  AND pa.status NOT IN ('cancelled')
  AND pa.payment_amount IS NOT NULL
  AND (c.creator_payment IS NULL OR c.creator_payment = 0);

-- Sincronizar pagos de editor
UPDATE content c
SET editor_payment = pa.payment_amount
FROM project_assignments pa
WHERE pa.content_id = c.id
  AND pa.role_id = 'editor'
  AND pa.status NOT IN ('cancelled')
  AND pa.payment_amount IS NOT NULL
  AND (c.editor_payment IS NULL OR c.editor_payment = 0);

-- ========== 20260303230000_fix_hidden_assignments.sql ==========
-- Problema: hay asignaciones en estado 'cancelled' que bloquean nuevas asignaciones
-- por el constraint de unicidad, pero no se muestran en la UI.

-- Solución 1: Eliminar físicamente las asignaciones canceladas (ya no son útiles)
DELETE FROM project_assignments WHERE status = 'cancelled';

-- Solución 2: Actualizar el índice único para excluir las canceladas
-- Primero eliminar el índice existente
DROP INDEX IF EXISTS idx_assignment_unique_user_role_content;
DROP INDEX IF EXISTS idx_assignment_unique_user_role_marketplace;

-- Recrear con exclusión de canceladas
CREATE UNIQUE INDEX idx_assignment_unique_user_role_content
  ON project_assignments(user_id, role_id, content_id)
  WHERE content_id IS NOT NULL AND status != 'cancelled';

CREATE UNIQUE INDEX idx_assignment_unique_user_role_marketplace
  ON project_assignments(user_id, role_id, marketplace_project_id)
  WHERE marketplace_project_id IS NOT NULL AND status != 'cancelled';

-- Verificar y mostrar asignaciones que estaban ocultas
-- (Esto es solo informativo, se ejecutará pero no afecta datos)
DO $$
DECLARE
  hidden_count INT;
BEGIN
  SELECT COUNT(*) INTO hidden_count FROM project_assignments WHERE status NOT IN ('accepted', 'in_progress', 'delivered', 'approved', 'paid');
  RAISE NOTICE 'Asignaciones en estados no activos: %', hidden_count;
END $$;

-- ========== 20260303240000_cleanup_all_stale_assignments.sql ==========
-- Mostrar asignaciones actuales que podrían estar ocultas
DO $$
DECLARE
  rec RECORD;
BEGIN
  RAISE NOTICE '=== ASIGNACIONES ACTUALES ===';
  FOR rec IN
    SELECT
      pa.id,
      pa.status,
      pa.role_id,
      pa.content_id,
      p.full_name
    FROM project_assignments pa
    LEFT JOIN profiles p ON p.id = pa.user_id
    ORDER BY pa.created_at DESC
    LIMIT 50
  LOOP
    RAISE NOTICE 'ID: %, Status: %, Role: %, Content: %, User: %',
      rec.id, rec.status, rec.role_id, rec.content_id, rec.full_name;
  END LOOP;
END $$;

-- Actualizar TODAS las asignaciones que no están en estados finales a 'accepted'
UPDATE project_assignments
SET
  status = 'accepted',
  accepted_at = COALESCE(accepted_at, created_at)
WHERE status IN ('pending', 'invited');

-- Mostrar conteo por estado después de la limpieza
DO $$
DECLARE
  rec RECORD;
BEGIN
  RAISE NOTICE '=== CONTEO POR ESTADO DESPUÉS DE LIMPIEZA ===';
  FOR rec IN
    SELECT status, COUNT(*) as cnt
    FROM project_assignments
    GROUP BY status
    ORDER BY cnt DESC
  LOOP
    RAISE NOTICE 'Status: %, Count: %', rec.status, rec.cnt;
  END LOOP;
END $$;

-- ========== 20260303250000_increase_registration_rate_limits.sql ==========
-- Aumentar límites de rate limiting para registro abierto de freelancers
-- El límite anterior de 5 intentos por hora era muy restrictivo

-- 1. Actualizar función de rate limit para registro (de 5 a 100 por hora)
CREATE OR REPLACE FUNCTION public.check_registration_rate_limit(ip TEXT, org_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  failed_attempts INT;
BEGIN
  -- Count failed attempts in last hour
  SELECT COUNT(*) INTO failed_attempts
  FROM public.registration_attempts
  WHERE ip_address = ip
    AND organization_id = org_id
    AND success = false
    AND created_at > now() - interval '1 hour';

  -- Return false if more than 100 failed attempts (antes era 5)
  RETURN failed_attempts < 100;
END;
$$;

-- 2. Actualizar función genérica de rate limit (aumentar límites)
CREATE OR REPLACE FUNCTION public.check_rate_limit(
  _identifier TEXT,
  _identifier_type TEXT,
  _action_type TEXT,
  _max_attempts INT DEFAULT 100,  -- Aumentado de 10 a 100
  _window_minutes INT DEFAULT 60,
  _block_minutes INT DEFAULT 5    -- Reducido de 15 a 5
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  current_record rate_limits%ROWTYPE;
  is_blocked BOOLEAN := false;
  remaining_attempts INT := _max_attempts;
  block_remaining_seconds INT := 0;
BEGIN
  -- Get or create rate limit record
  INSERT INTO public.rate_limits (identifier, identifier_type, action_type)
  VALUES (_identifier, _identifier_type, _action_type)
  ON CONFLICT (identifier, identifier_type, action_type)
  DO UPDATE SET
    attempts = CASE
      WHEN rate_limits.first_attempt_at < now() - (_window_minutes || ' minutes')::interval
      THEN 1
      ELSE rate_limits.attempts + 1
    END,
    first_attempt_at = CASE
      WHEN rate_limits.first_attempt_at < now() - (_window_minutes || ' minutes')::interval
      THEN now()
      ELSE rate_limits.first_attempt_at
    END,
    last_attempt_at = now(),
    blocked_until = CASE
      WHEN rate_limits.attempts >= _max_attempts - 1
        AND rate_limits.first_attempt_at >= now() - (_window_minutes || ' minutes')::interval
      THEN now() + (_block_minutes || ' minutes')::interval
      ELSE rate_limits.blocked_until
    END
  RETURNING * INTO current_record;

  -- Check if currently blocked
  IF current_record.blocked_until IS NOT NULL AND current_record.blocked_until > now() THEN
    is_blocked := true;
    block_remaining_seconds := EXTRACT(EPOCH FROM (current_record.blocked_until - now()))::INT;
  END IF;

  remaining_attempts := GREATEST(0, _max_attempts - current_record.attempts);

  RETURN jsonb_build_object(
    'allowed', NOT is_blocked AND remaining_attempts > 0,
    'attempts', current_record.attempts,
    'remaining_attempts', remaining_attempts,
    'is_blocked', is_blocked,
    'block_remaining_seconds', block_remaining_seconds
  );
END;
$$;

-- 3. Limpiar registros de rate limit antiguos (más de 24 horas)
DELETE FROM public.rate_limits WHERE last_attempt_at < now() - interval '24 hours';
DELETE FROM public.registration_attempts WHERE created_at < now() - interval '24 hours';

-- 4. Comentario explicativo
COMMENT ON FUNCTION public.check_registration_rate_limit IS
  'Rate limit para registros: 100 intentos fallidos por hora por IP (aumentado para producción)';

-- ========== 20260304100000_pancake_crm_sync.sql ==========
-- ============================================================
-- PANCAKE CRM SYNC - Tablas de estado de sincronización
-- Integración bidireccional Kreoon ↔ Pancake CRM POS
-- ============================================================

-- Tabla de mapeo Kreoon ↔ Pancake (registro de IDs externos)
CREATE TABLE IF NOT EXISTS pancake_sync_map (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  kreoon_entity_type TEXT NOT NULL CHECK (kreoon_entity_type IN ('user', 'organization')),
  kreoon_entity_id UUID NOT NULL,
  pancake_record_id TEXT,  -- ID del registro en Pancake CRM
  pancake_table_name TEXT NOT NULL CHECK (pancake_table_name IN ('kreoon_users', 'kreoon_organizations')),
  sync_status TEXT NOT NULL DEFAULT 'pending' CHECK (sync_status IN ('pending', 'synced', 'error', 'skip')),
  last_synced_at TIMESTAMPTZ,
  error_message TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(kreoon_entity_type, kreoon_entity_id)
);

-- Tabla de log de sincronización (auditoría)
CREATE TABLE IF NOT EXISTS pancake_sync_log (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  direction TEXT NOT NULL CHECK (direction IN ('kreoon_to_pancake', 'pancake_to_kreoon')),
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  action TEXT NOT NULL CHECK (action IN ('create', 'update', 'delete')),
  payload JSONB,
  response JSONB,
  status TEXT NOT NULL CHECK (status IN ('success', 'error')),
  error_message TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Tabla de configuración de la integración (por plataforma)
CREATE TABLE IF NOT EXISTS pancake_integration_config (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  config_key TEXT UNIQUE NOT NULL,
  config_value TEXT,
  updated_at TIMESTAMPTZ DEFAULT now(),
  updated_by UUID REFERENCES auth.users(id)
);

-- Insertar configuración inicial (Shop ID se rellena en setup)
INSERT INTO pancake_integration_config (config_key, config_value) VALUES
  ('shop_id', NULL),
  ('sync_users_enabled', 'true'),
  ('sync_organizations_enabled', 'true'),
  ('webhook_secret', gen_random_uuid()::text)
ON CONFLICT (config_key) DO NOTHING;

-- Índices
CREATE INDEX IF NOT EXISTS idx_pancake_sync_map_entity ON pancake_sync_map(kreoon_entity_type, kreoon_entity_id);
CREATE INDEX IF NOT EXISTS idx_pancake_sync_map_status ON pancake_sync_map(sync_status);
CREATE INDEX IF NOT EXISTS idx_pancake_sync_map_record ON pancake_sync_map(pancake_record_id, pancake_table_name);
CREATE INDEX IF NOT EXISTS idx_pancake_sync_log_created ON pancake_sync_log(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_pancake_sync_log_entity ON pancake_sync_log(entity_type, entity_id);

-- RLS
ALTER TABLE pancake_sync_map ENABLE ROW LEVEL SECURITY;
ALTER TABLE pancake_sync_log ENABLE ROW LEVEL SECURITY;
ALTER TABLE pancake_integration_config ENABLE ROW LEVEL SECURITY;

-- Políticas: solo admins de plataforma y service_role pueden acceder
CREATE POLICY "admin_pancake_sync_map" ON pancake_sync_map
  FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM profiles p
      WHERE p.id = auth.uid() AND p.is_platform_admin = true
    )
  );

CREATE POLICY "admin_pancake_sync_log" ON pancake_sync_log
  FOR SELECT TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM profiles p
      WHERE p.id = auth.uid() AND p.is_platform_admin = true
    )
  );

CREATE POLICY "admin_pancake_config" ON pancake_integration_config
  FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM profiles p
      WHERE p.id = auth.uid() AND p.is_platform_admin = true
    )
  );

-- Service role siempre tiene acceso
CREATE POLICY "service_role_pancake_sync_map" ON pancake_sync_map
  FOR ALL TO service_role USING (true) WITH CHECK (true);

CREATE POLICY "service_role_pancake_sync_log" ON pancake_sync_log
  FOR ALL TO service_role USING (true) WITH CHECK (true);

CREATE POLICY "service_role_pancake_config" ON pancake_integration_config
  FOR ALL TO service_role USING (true) WITH CHECK (true);

-- GRANTs
GRANT ALL ON pancake_sync_map TO authenticated;
GRANT ALL ON pancake_sync_map TO service_role;
GRANT ALL ON pancake_sync_log TO authenticated;
GRANT ALL ON pancake_sync_log TO service_role;
GRANT ALL ON pancake_integration_config TO authenticated;
GRANT ALL ON pancake_integration_config TO service_role;

-- Trigger para updated_at en pancake_sync_map
CREATE OR REPLACE FUNCTION update_pancake_sync_map_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_pancake_sync_map_updated_at ON pancake_sync_map;
CREATE TRIGGER trg_pancake_sync_map_updated_at
  BEFORE UPDATE ON pancake_sync_map
  FOR EACH ROW
  EXECUTE FUNCTION update_pancake_sync_map_updated_at();

NOTIFY pgrst, 'reload schema';

