-- ========== 20260305100000_pancake_auto_sync_triggers.sql ==========
-- ============================================================
-- PANCAKE CRM AUTO-SYNC TRIGGERS
-- Sincronización automática de usuarios hacia Pancake CRM
-- ============================================================

-- Habilitar extensión pg_net para llamadas HTTP asíncronas
CREATE EXTENSION IF NOT EXISTS pg_net;

-- ============================================================
-- FUNCIÓN: Llamar a pancake-sync-user de forma asíncrona
-- ============================================================
CREATE OR REPLACE FUNCTION sync_user_to_pancake(p_user_id UUID)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_sync_enabled TEXT;
BEGIN
  -- Verificar si la sincronización está habilitada
  SELECT config_value INTO v_sync_enabled
  FROM pancake_integration_config
  WHERE config_key = 'sync_users_enabled';

  IF v_sync_enabled IS NULL OR v_sync_enabled != 'true' THEN
    RETURN; -- Sincronización deshabilitada
  END IF;

  -- Llamar a la edge function de forma asíncrona usando pg_net
  -- Fire-and-forget: no esperamos respuesta para no bloquear la transacción
  -- No requiere autenticación porque verify_jwt = false en la edge function
  PERFORM net.http_post(
    url := 'https://wjkbqcrxwsmvtxmqgiqc.supabase.co/functions/v1/pancake-sync-user',
    headers := '{"Content-Type": "application/json"}'::jsonb,
    body := jsonb_build_object('user_id', p_user_id)
  );

EXCEPTION
  WHEN OTHERS THEN
    -- Log del error pero no falla la transacción principal
    RAISE WARNING 'Error sincronizando usuario % a Pancake: %', p_user_id, SQLERRM;
END;
$$;

-- ============================================================
-- TRIGGER: Sincronizar al crear/actualizar perfil
-- ============================================================
CREATE OR REPLACE FUNCTION trigger_sync_profile_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  -- Sincronizar después de INSERT o UPDATE
  -- Usamos un pequeño delay para asegurar que todos los datos relacionados estén listos
  PERFORM pg_sleep(0.5);
  PERFORM sync_user_to_pancake(NEW.id);
  RETURN NEW;
END;
$$;

-- Trigger en profiles (INSERT)
DROP TRIGGER IF EXISTS trg_pancake_sync_profile_insert ON profiles;
CREATE TRIGGER trg_pancake_sync_profile_insert
  AFTER INSERT ON profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_sync_profile_to_pancake();

-- Trigger en profiles (UPDATE) - solo si cambian campos relevantes
DROP TRIGGER IF EXISTS trg_pancake_sync_profile_update ON profiles;
CREATE TRIGGER trg_pancake_sync_profile_update
  AFTER UPDATE ON profiles
  FOR EACH ROW
  WHEN (
    OLD.full_name IS DISTINCT FROM NEW.full_name OR
    OLD.email IS DISTINCT FROM NEW.email OR
    OLD.phone IS DISTINCT FROM NEW.phone OR
    OLD.username IS DISTINCT FROM NEW.username OR
    OLD.country IS DISTINCT FROM NEW.country OR
    OLD.city IS DISTINCT FROM NEW.city OR
    OLD.current_organization_id IS DISTINCT FROM NEW.current_organization_id OR
    OLD.active_brand_id IS DISTINCT FROM NEW.active_brand_id
  )
  EXECUTE FUNCTION trigger_sync_profile_to_pancake();

-- ============================================================
-- TRIGGER: Sincronizar al crear/actualizar creator_profile
-- ============================================================
CREATE OR REPLACE FUNCTION trigger_sync_creator_profile_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  PERFORM pg_sleep(0.5);
  PERFORM sync_user_to_pancake(NEW.user_id);
  RETURN NEW;
END;
$$;

-- Trigger en creator_profiles (INSERT)
DROP TRIGGER IF EXISTS trg_pancake_sync_creator_insert ON creator_profiles;
CREATE TRIGGER trg_pancake_sync_creator_insert
  AFTER INSERT ON creator_profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_sync_creator_profile_to_pancake();

-- Trigger en creator_profiles (UPDATE)
DROP TRIGGER IF EXISTS trg_pancake_sync_creator_update ON creator_profiles;
CREATE TRIGGER trg_pancake_sync_creator_update
  AFTER UPDATE ON creator_profiles
  FOR EACH ROW
  WHEN (
    OLD.categories IS DISTINCT FROM NEW.categories OR
    OLD.marketplace_roles IS DISTINCT FROM NEW.marketplace_roles
  )
  EXECUTE FUNCTION trigger_sync_creator_profile_to_pancake();

-- ============================================================
-- TRIGGER: Sincronizar cuando cambia membresía de organización
-- ============================================================
CREATE OR REPLACE FUNCTION trigger_sync_org_member_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
BEGIN
  -- Determinar el user_id afectado
  IF TG_OP = 'DELETE' THEN
    v_user_id := OLD.user_id;
  ELSE
    v_user_id := NEW.user_id;
  END IF;

  PERFORM pg_sleep(0.5);
  PERFORM sync_user_to_pancake(v_user_id);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$;

-- Trigger en organization_members (INSERT, UPDATE, DELETE)
DROP TRIGGER IF EXISTS trg_pancake_sync_org_member ON organization_members;
CREATE TRIGGER trg_pancake_sync_org_member
  AFTER INSERT OR UPDATE OR DELETE ON organization_members
  FOR EACH ROW
  EXECUTE FUNCTION trigger_sync_org_member_to_pancake();

-- ============================================================
-- TRIGGER: Sincronizar cuando cambian roles en organización
-- ============================================================
CREATE OR REPLACE FUNCTION trigger_sync_org_roles_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_user_id := OLD.user_id;
  ELSE
    v_user_id := NEW.user_id;
  END IF;

  PERFORM pg_sleep(0.5);
  PERFORM sync_user_to_pancake(v_user_id);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$;

-- Trigger en organization_member_roles (INSERT, UPDATE, DELETE)
DROP TRIGGER IF EXISTS trg_pancake_sync_org_roles ON organization_member_roles;
CREATE TRIGGER trg_pancake_sync_org_roles
  AFTER INSERT OR UPDATE OR DELETE ON organization_member_roles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_sync_org_roles_to_pancake();

-- ============================================================
-- COMENTARIOS
-- ============================================================
COMMENT ON FUNCTION sync_user_to_pancake IS 'Sincroniza un usuario a Pancake CRM de forma asíncrona';
COMMENT ON FUNCTION trigger_sync_profile_to_pancake IS 'Trigger para sincronizar perfil a Pancake';
COMMENT ON FUNCTION trigger_sync_creator_profile_to_pancake IS 'Trigger para sincronizar creator_profile a Pancake';
COMMENT ON FUNCTION trigger_sync_org_member_to_pancake IS 'Trigger para sincronizar cambios de membresía a Pancake';
COMMENT ON FUNCTION trigger_sync_org_roles_to_pancake IS 'Trigger para sincronizar cambios de roles a Pancake';

NOTIFY pgrst, 'reload schema';

-- ========== 20260305100002_fix_pancake_trigger_complete_profile.sql ==========
-- Fix: Solo sincronizar a Pancake cuando el perfil esté completo
-- Evita múltiples sincronizaciones durante el registro paso a paso

-- Actualizar el trigger de INSERT en profiles
-- Solo sincroniza si tiene nombre Y email completos
CREATE OR REPLACE FUNCTION trigger_sync_profile_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  -- Solo sincronizar si el perfil tiene datos mínimos completos
  -- Nombre y email son requeridos para considerar el perfil "listo"
  IF NEW.full_name IS NOT NULL
     AND NEW.full_name != ''
     AND NEW.email IS NOT NULL
     AND NEW.email != '' THEN

    -- Para INSERT: esperar un poco más para que se completen otros datos
    IF TG_OP = 'INSERT' THEN
      -- No sincronizar en INSERT, esperar al UPDATE con datos completos
      RETURN NEW;
    END IF;

    -- Para UPDATE: sincronizar solo si ya tiene los datos básicos
    PERFORM sync_user_to_pancake(NEW.id);
  END IF;

  RETURN NEW;
END;
$$;

-- Nuevo trigger que se activa después de que el registro esté completo
-- Se activa cuando se actualiza el perfil con datos completos
DROP TRIGGER IF EXISTS trg_pancake_sync_profile_insert ON profiles;
DROP TRIGGER IF EXISTS trg_pancake_sync_profile_update ON profiles;

-- Solo trigger en UPDATE (no en INSERT)
CREATE TRIGGER trg_pancake_sync_profile_update
  AFTER UPDATE ON profiles
  FOR EACH ROW
  WHEN (
    -- Solo si tiene datos mínimos
    NEW.full_name IS NOT NULL AND NEW.full_name != '' AND
    NEW.email IS NOT NULL AND NEW.email != '' AND
    (
      -- Y si cambió algún campo relevante
      OLD.full_name IS DISTINCT FROM NEW.full_name OR
      OLD.email IS DISTINCT FROM NEW.email OR
      OLD.phone IS DISTINCT FROM NEW.phone OR
      OLD.username IS DISTINCT FROM NEW.username OR
      OLD.country IS DISTINCT FROM NEW.country OR
      OLD.city IS DISTINCT FROM NEW.city OR
      OLD.current_organization_id IS DISTINCT FROM NEW.current_organization_id OR
      OLD.active_brand_id IS DISTINCT FROM NEW.active_brand_id
    )
  )
  EXECUTE FUNCTION trigger_sync_profile_to_pancake();

-- Trigger especial para primera sincronización
-- Se activa cuando el perfil pasa de incompleto a completo
CREATE OR REPLACE FUNCTION trigger_sync_profile_first_complete()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  -- Detectar cuando el perfil se "completa" por primera vez
  -- Es decir, cuando pasa de no tener nombre/email a tenerlos
  IF (OLD.full_name IS NULL OR OLD.full_name = '' OR OLD.email IS NULL OR OLD.email = '')
     AND (NEW.full_name IS NOT NULL AND NEW.full_name != '' AND NEW.email IS NOT NULL AND NEW.email != '') THEN

    -- Perfil recién completado, sincronizar
    PERFORM sync_user_to_pancake(NEW.id);
  END IF;

  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_pancake_sync_profile_first_complete
  AFTER UPDATE ON profiles
  FOR EACH ROW
  EXECUTE FUNCTION trigger_sync_profile_first_complete();

-- También actualizar el trigger de creator_profiles para que no se dispare inmediatamente
DROP TRIGGER IF EXISTS trg_pancake_sync_creator_insert ON creator_profiles;
DROP TRIGGER IF EXISTS trg_pancake_sync_creator_update ON creator_profiles;

CREATE OR REPLACE FUNCTION trigger_sync_creator_profile_to_pancake()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_profile_complete BOOLEAN;
BEGIN
  -- Verificar si el perfil base está completo antes de sincronizar
  SELECT (full_name IS NOT NULL AND full_name != '' AND email IS NOT NULL AND email != '')
  INTO v_profile_complete
  FROM profiles
  WHERE id = NEW.user_id;

  -- Solo sincronizar si el perfil base está completo
  IF v_profile_complete THEN
    PERFORM sync_user_to_pancake(NEW.user_id);
  END IF;

  RETURN NEW;
END;
$$;

-- Solo en UPDATE de creator_profiles (no en INSERT)
CREATE TRIGGER trg_pancake_sync_creator_update
  AFTER UPDATE ON creator_profiles
  FOR EACH ROW
  WHEN (
    OLD.categories IS DISTINCT FROM NEW.categories OR
    OLD.marketplace_roles IS DISTINCT FROM NEW.marketplace_roles
  )
  EXECUTE FUNCTION trigger_sync_creator_profile_to_pancake();

NOTIFY pgrst, 'reload schema';

-- ========== 20260305120000_legal_documents_consent.sql ==========
-- ============================================
-- MIGRACIÓN: Sistema de Documentos Legales y Consentimiento
-- Fecha: 2026-03-05
-- Descripción: Tablas para gestión de documentos legales versionados,
--              registro de consentimientos de usuarios, y verificación
--              de cumplimiento por tipo de usuario.
-- ============================================

-- ============================================
-- TABLA: legal_documents
-- Documentos legales versionados de la plataforma
-- ============================================
CREATE TABLE IF NOT EXISTS legal_documents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  -- Tipo de documento
  document_type TEXT NOT NULL CHECK (document_type IN (
    'terms_of_service',
    'privacy_policy',
    'cookie_policy',
    'creator_agreement',
    'brand_agreement',
    'acceptable_use_policy',
    'dmca_policy',
    'content_moderation_policy',
    'escrow_payment_terms',
    'live_shopping_terms',
    'referral_terms',
    'data_processing_agreement',
    'white_label_agreement',
    'ai_usage_disclosure',
    'age_verification_policy'
  )),

  -- Versión
  version TEXT NOT NULL,             -- Ej: "1.0", "1.1", "2.0"
  version_date DATE NOT NULL,

  -- Contenido
  title TEXT NOT NULL,               -- Título en español
  title_en TEXT,                     -- Título en inglés
  content_html TEXT NOT NULL,        -- Contenido completo en HTML
  content_html_en TEXT,              -- Versión en inglés
  summary TEXT,                      -- Resumen en lenguaje claro

  -- Metadatos
  is_current BOOLEAN DEFAULT false,  -- ¿Es la versión vigente?
  is_required BOOLEAN DEFAULT true,  -- ¿Es obligatorio aceptar?
  applies_to TEXT[] DEFAULT '{all}', -- A quién aplica: ['all'], ['creator'], ['brand'], ['organization']

  -- Checksums para verificar integridad
  content_hash TEXT,                 -- SHA-256 del content_html

  -- Control
  published_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  created_by UUID REFERENCES auth.users(id)
);

-- Comentarios
COMMENT ON TABLE legal_documents IS 'Documentos legales versionados de la plataforma KREOON';
COMMENT ON COLUMN legal_documents.document_type IS 'Tipo de documento legal';
COMMENT ON COLUMN legal_documents.is_current IS 'Indica si es la versión vigente del documento';
COMMENT ON COLUMN legal_documents.content_hash IS 'Hash SHA-256 para verificar integridad';

-- Solo un documento vigente por tipo
CREATE UNIQUE INDEX IF NOT EXISTS idx_legal_docs_current
ON legal_documents(document_type)
WHERE is_current = true;

-- ============================================
-- TABLA: user_legal_consents
-- Registro de aceptación de cada usuario
-- ============================================
CREATE TABLE IF NOT EXISTS user_legal_consents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  document_id UUID NOT NULL REFERENCES legal_documents(id),
  document_type TEXT NOT NULL,
  document_version TEXT NOT NULL,

  -- Aceptación
  accepted BOOLEAN NOT NULL DEFAULT false,
  accepted_at TIMESTAMPTZ,

  -- Contexto de aceptación (prueba legal)
  ip_address INET,
  user_agent TEXT,
  consent_method TEXT DEFAULT 'clickwrap', -- 'clickwrap', 'browsewrap', 'sign'

  -- Para re-consentimiento
  superseded_by UUID REFERENCES user_legal_consents(id),
  is_current BOOLEAN DEFAULT true,

  -- Revocación (donde aplique)
  revoked BOOLEAN DEFAULT false,
  revoked_at TIMESTAMPTZ,
  revocation_reason TEXT,

  created_at TIMESTAMPTZ DEFAULT NOW(),

  UNIQUE(user_id, document_id)
);

COMMENT ON TABLE user_legal_consents IS 'Registro de aceptación de documentos legales por usuario';
COMMENT ON COLUMN user_legal_consents.consent_method IS 'Método de consentimiento: clickwrap (checkbox), browsewrap (uso implica aceptación), sign (firma)';

-- ============================================
-- TABLA: legal_consent_requirements
-- Define qué documentos debe aceptar cada tipo de usuario
-- ============================================
CREATE TABLE IF NOT EXISTS legal_consent_requirements (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  document_type TEXT NOT NULL,
  user_role TEXT NOT NULL,            -- 'all', 'creator', 'brand', 'organization', 'client'
  is_required BOOLEAN DEFAULT true,
  required_at TEXT DEFAULT 'registration', -- 'registration', 'first_upload', 'first_transaction', 'first_live'

  created_at TIMESTAMPTZ DEFAULT NOW(),

  UNIQUE(document_type, user_role)
);

COMMENT ON TABLE legal_consent_requirements IS 'Define qué documentos debe aceptar cada tipo de usuario';

-- ============================================
-- TABLA: age_verifications
-- Registro de verificaciones de edad
-- ============================================
CREATE TABLE IF NOT EXISTS age_verifications (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,

  -- Declaración
  declared_age_18_plus BOOLEAN NOT NULL DEFAULT false,
  declared_at TIMESTAMPTZ,

  -- Contexto
  ip_address INET,
  user_agent TEXT,

  -- Verificación adicional (opcional, para contenido restringido)
  verification_method TEXT, -- 'self_declaration', 'document_upload', 'third_party'
  verification_status TEXT DEFAULT 'pending', -- 'pending', 'verified', 'rejected'
  verified_at TIMESTAMPTZ,

  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

COMMENT ON TABLE age_verifications IS 'Registro de verificaciones de edad de usuarios';

-- ============================================
-- ÍNDICES
-- ============================================
CREATE INDEX IF NOT EXISTS idx_legal_docs_type ON legal_documents(document_type);
CREATE INDEX IF NOT EXISTS idx_legal_docs_current_flag ON legal_documents(is_current);
CREATE INDEX IF NOT EXISTS idx_consents_user ON user_legal_consents(user_id);
CREATE INDEX IF NOT EXISTS idx_consents_document ON user_legal_consents(document_id);
CREATE INDEX IF NOT EXISTS idx_consents_current ON user_legal_consents(user_id, is_current) WHERE is_current = true;
CREATE INDEX IF NOT EXISTS idx_consent_reqs_role ON legal_consent_requirements(user_role);
CREATE INDEX IF NOT EXISTS idx_age_verifications_user ON age_verifications(user_id);

-- ============================================
-- RLS (Row Level Security)
-- ============================================
ALTER TABLE legal_documents ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_legal_consents ENABLE ROW LEVEL SECURITY;
ALTER TABLE legal_consent_requirements ENABLE ROW LEVEL SECURITY;
ALTER TABLE age_verifications ENABLE ROW LEVEL SECURITY;

-- Documentos legales: todos pueden leer, solo admin puede escribir
CREATE POLICY "anyone_can_read_legal_docs" ON legal_documents
FOR SELECT TO authenticated USING (true);

CREATE POLICY "anon_can_read_legal_docs" ON legal_documents
FOR SELECT TO anon USING (is_current = true);

CREATE POLICY "admin_can_manage_legal_docs" ON legal_documents
FOR ALL TO authenticated
USING (
  EXISTS (
    SELECT 1 FROM organization_members om
    JOIN organization_member_roles omr ON om.id = omr.member_id
    WHERE om.user_id = auth.uid() AND omr.role = 'admin'
  )
);

-- Consentimientos: usuario ve los suyos, admin ve todos
CREATE POLICY "user_sees_own_consents" ON user_legal_consents
FOR SELECT TO authenticated
USING (user_id = auth.uid());

CREATE POLICY "user_creates_own_consent" ON user_legal_consents
FOR INSERT TO authenticated
WITH CHECK (user_id = auth.uid());

CREATE POLICY "user_updates_own_consent" ON user_legal_consents
FOR UPDATE TO authenticated
USING (user_id = auth.uid());

-- Requirements: todos pueden leer
CREATE POLICY "anyone_reads_requirements" ON legal_consent_requirements
FOR SELECT TO authenticated USING (true);

CREATE POLICY "anon_reads_requirements" ON legal_consent_requirements
FOR SELECT TO anon USING (true);

-- Age verifications: usuario ve las suyas
CREATE POLICY "user_sees_own_age_verification" ON age_verifications
FOR SELECT TO authenticated
USING (user_id = auth.uid());

CREATE POLICY "user_creates_own_age_verification" ON age_verifications
FOR INSERT TO authenticated
WITH CHECK (user_id = auth.uid());

-- ============================================
-- GRANTS
-- ============================================
GRANT SELECT ON legal_documents TO anon;
GRANT ALL ON legal_documents TO authenticated;
GRANT ALL ON legal_documents TO service_role;
GRANT SELECT ON legal_consent_requirements TO anon;
GRANT ALL ON user_legal_consents TO authenticated;
GRANT ALL ON user_legal_consents TO service_role;
GRANT ALL ON legal_consent_requirements TO authenticated;
GRANT ALL ON legal_consent_requirements TO service_role;
GRANT ALL ON age_verifications TO authenticated;
GRANT ALL ON age_verifications TO service_role;

