-- ========== 20260305190000_add_onboarding_fields_to_user_detail.sql ==========
-- =====================================================
-- Fix: Agregar campos de onboarding a get_full_user_detail
-- Migration: 20260305180000_add_onboarding_fields_to_user_detail
-- Campos agregados:
--   - nationality
--   - date_of_birth
--   - is_banned
--   - is_platform_admin
--   - onboarding_completed
-- =====================================================

CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB;
  profile_base JSONB;
  profile_social JSONB;
  profile_extras JSONB;
  creator_data JSONB;
  health_data JSONB;
  org_data JSONB;
  arrays_data JSONB;
BEGIN
  -- Part 1: Basic profile fields (including nationality, date_of_birth, onboarding_completed)
  SELECT jsonb_build_object(
    'id', p.id,
    'email', p.email,
    'full_name', p.full_name,
    'username', p.username,
    'avatar_url', p.avatar_url,
    'phone', p.phone,
    'bio', p.bio,
    'tagline', p.tagline,
    'cover_url', p.cover_url,
    'document_type', p.document_type,
    'document_number', p.document_number,
    'address', p.address,
    'city', p.city,
    'country', p.country,
    'nationality', p.nationality,
    'date_of_birth', p.date_of_birth,
    'onboarding_completed', COALESCE(p.onboarding_completed, false),
    'created_at', p.created_at
  ) INTO profile_base
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 2: Social links and content preferences
  SELECT jsonb_build_object(
    'instagram', p.instagram,
    'tiktok', p.tiktok,
    'facebook', p.facebook,
    'social_linkedin', p.social_linkedin,
    'social_twitter', p.social_twitter,
    'social_youtube', p.social_youtube,
    'portfolio_url', p.portfolio_url,
    'featured_video_url', p.featured_video_url,
    'content_categories', COALESCE(p.content_categories, ARRAY[]::TEXT[]),
    'specialties_tags', COALESCE(p.specialties_tags, ARRAY[]::TEXT[]),
    'style_keywords', COALESCE(p.style_keywords, ARRAY[]::TEXT[]),
    'industries', COALESCE(p.industries, ARRAY[]::TEXT[]),
    'interests', COALESCE(p.interests, ARRAY[]::TEXT[]),
    'languages', COALESCE(p.languages, ARRAY[]::TEXT[])
  ) INTO profile_social
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 3: Profile extras (scores, flags, is_banned, is_platform_admin)
  SELECT jsonb_build_object(
    'experience_level', p.experience_level,
    'availability_status', p.availability_status,
    'best_at', p.best_at,
    'rate_per_content', p.rate_per_content,
    'rate_currency', p.rate_currency,
    'quality_score_avg', p.quality_score_avg,
    'reliability_score', p.reliability_score,
    'velocity_score', p.velocity_score,
    'editor_rating', p.editor_rating,
    'is_ambassador', COALESCE(p.is_ambassador, false),
    'is_platform_founder', COALESCE(p.is_platform_founder, false),
    'founder_badge_type', p.founder_badge_type,
    'active_role', p.active_role,
    'ai_recommended_level', p.ai_recommended_level,
    'ai_risk_flag', p.ai_risk_flag,
    'is_active', COALESCE(p.is_active, true),
    'is_banned', COALESCE(p.is_banned, false),
    'is_platform_admin', COALESCE(p.is_platform_admin, false),
    'crm_custom_fields', COALESCE(p.crm_custom_fields, '{}'::jsonb)
  ) INTO profile_extras
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 4: Creator profile data
  SELECT jsonb_build_object(
    'creator_profile_id', cp.id,
    'slug', cp.slug,
    'bio_full', cp.bio_full,
    'banner_url', cp.banner_url,
    'creator_social_links', cp.social_links,
    'level', cp.level,
    'is_verified', COALESCE(cp.is_verified, false),
    'is_available', COALESCE(cp.is_available, false),
    'rating_avg', COALESCE(cp.rating_avg, 0),
    'rating_count', COALESCE(cp.rating_count, 0),
    'completed_projects', COALESCE(cp.completed_projects, 0),
    'base_price', cp.base_price,
    'currency', COALESCE(cp.currency, 'USD'),
    'categories', COALESCE(cp.categories, ARRAY[]::TEXT[]),
    'content_types', COALESCE(cp.content_types, ARRAY[]::TEXT[]),
    'platforms', COALESCE(cp.platforms, ARRAY[]::TEXT[]),
    'marketplace_roles', COALESCE(cp.marketplace_roles, ARRAY[]::TEXT[]),
    'accepts_product_exchange', COALESCE(cp.accepts_product_exchange, false),
    'response_time_hours', cp.response_time_hours,
    'on_time_delivery_pct', cp.on_time_delivery_pct,
    'repeat_clients_pct', cp.repeat_clients_pct,
    'showreel_video_id', cp.showreel_video_id,
    'showreel_url', cp.showreel_url,
    'showreel_thumbnail', cp.showreel_thumbnail
  ) INTO creator_data
  FROM profiles p
  LEFT JOIN creator_profiles cp ON cp.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 5: Health data
  SELECT jsonb_build_object(
    'health_score', COALESCE(h.health_score, 0),
    'health_status', COALESCE(h.health_status, 'healthy'),
    'total_logins', COALESCE(h.total_logins, 0),
    'days_since_last_activity', h.days_since_last_activity,
    'last_login_at', h.last_login_at,
    'total_actions', 0,
    'needs_attention', COALESCE(h.needs_attention, false),
    'total_applications', COALESCE(h.total_applications, 0),
    'total_completed_projects', COALESCE(h.total_completed_projects, 0),
    'total_spent', COALESCE(h.total_spent, 0)
  ) INTO health_data
  FROM profiles p
  LEFT JOIN platform_user_health h ON h.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 6: Organization context
  SELECT jsonb_build_object(
    'organization_id', om.organization_id,
    'organization_name', o.name,
    'is_owner', COALESCE(om.is_owner, false),
    'ambassador_level', om.ambassador_level
  ) INTO org_data
  FROM profiles p
  LEFT JOIN organization_members om ON om.user_id = p.id AND om.organization_id = p.current_organization_id
  LEFT JOIN organizations o ON o.id = om.organization_id
  WHERE p.id = p_user_id;

  -- Part 7: Nested arrays
  SELECT jsonb_build_object(
    'organizations', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'organization_id', om2.organization_id,
        'organization_name', o2.name,
        'role', (SELECT omr3.role FROM organization_member_roles omr3 WHERE omr3.user_id = p_user_id AND omr3.organization_id = om2.organization_id LIMIT 1),
        'is_owner', om2.is_owner,
        'joined_at', om2.joined_at
      ) ORDER BY om2.joined_at ASC)
      FROM organization_members om2
      LEFT JOIN organizations o2 ON o2.id = om2.organization_id
      WHERE om2.user_id = p_user_id
    ), '[]'::jsonb),
    'companies', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'client_id', c2.id,
        'client_name', c2.name,
        'organization_id', c2.organization_id,
        'organization_name', o3.name,
        'role', cu2.role,
        'created_at', cu2.created_at
      ) ORDER BY cu2.created_at ASC)
      FROM client_users cu2
      JOIN clients c2 ON c2.id = cu2.client_id
      LEFT JOIN organizations o3 ON o3.id = c2.organization_id
      WHERE cu2.user_id = p_user_id
    ), '[]'::jsonb),
    'roles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'role', omr.role,
        'organization_id', omr.organization_id,
        'organization_name', o2.name
      ))
      FROM organization_member_roles omr
      LEFT JOIN organizations o2 ON o2.id = omr.organization_id
      WHERE omr.user_id = p_user_id
    ), '[]'::jsonb),
    'badges', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'badge', omb.badge,
        'level', omb.level,
        'is_active', omb.is_active,
        'granted_at', omb.granted_at
      ))
      FROM organization_member_badges omb
      WHERE omb.user_id = p_user_id AND omb.is_active = true
    ), '[]'::jsonb),
    'portfolio', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', pi.id,
        'title', pi.title,
        'media_type', pi.media_type,
        'media_url', pi.media_url,
        'thumbnail_url', pi.thumbnail_url,
        'bunny_video_id', pi.bunny_video_id,
        'category', pi.category,
        'is_featured', pi.is_featured
      ) ORDER BY pi.is_featured DESC, pi.display_order ASC)
      FROM portfolio_items pi
      JOIN creator_profiles cp ON cp.id = pi.creator_id
      WHERE cp.user_id = p_user_id AND pi.is_public = true
      LIMIT 12
    ), '[]'::jsonb),
    'services', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', cs.id,
        'title', cs.title,
        'service_type', cs.service_type,
        'price_type', cs.price_type,
        'price_amount', cs.price_amount,
        'price_currency', cs.price_currency,
        'delivery_days', cs.delivery_days,
        'is_featured', cs.is_featured
      ) ORDER BY cs.is_featured DESC, cs.display_order ASC)
      FROM creator_services cs
      WHERE cs.user_id = p_user_id AND cs.is_active = true
    ), '[]'::jsonb)
  ) INTO arrays_data;

  -- Combine all parts
  result := COALESCE(profile_base, '{}'::jsonb)
    || COALESCE(profile_social, '{}'::jsonb)
    || COALESCE(profile_extras, '{}'::jsonb)
    || COALESCE(creator_data, '{}'::jsonb)
    || COALESCE(health_data, '{}'::jsonb)
    || COALESCE(org_data, '{}'::jsonb)
    || COALESCE(arrays_data, '{}'::jsonb);

  RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_full_user_detail(uuid) TO authenticated;

-- ========== 20260305200000_content_soft_delete_protection.sql ==========
-- ============================================================================
-- SISTEMA DE PROTECCIÓN DE CONTENIDO: SOFT DELETE + BACKUP + PAPELERA
-- ============================================================================
-- Este sistema protege contra pérdida de datos:
-- 1. Soft Delete: El contenido no se elimina, solo se marca como eliminado
-- 2. Backup automático: Antes de marcar como eliminado, se guarda copia completa
-- 3. Papelera: Los usuarios pueden ver y restaurar contenido eliminado
-- 4. Solo root puede hacer hard delete (eliminación permanente)
-- ============================================================================

-- 1. AGREGAR CAMPOS DE SOFT DELETE A LA TABLA CONTENT
-- ============================================================================
ALTER TABLE content
ADD COLUMN IF NOT EXISTS deleted_at TIMESTAMPTZ DEFAULT NULL,
ADD COLUMN IF NOT EXISTS deleted_by UUID REFERENCES profiles(id) DEFAULT NULL,
ADD COLUMN IF NOT EXISTS deletion_reason TEXT DEFAULT NULL;

-- Índice para filtrar contenido activo rápidamente
CREATE INDEX IF NOT EXISTS idx_content_deleted_at ON content(deleted_at) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_content_deleted_at_not_null ON content(deleted_at) WHERE deleted_at IS NOT NULL;

COMMENT ON COLUMN content.deleted_at IS 'Fecha de eliminación (soft delete). NULL = contenido activo';
COMMENT ON COLUMN content.deleted_by IS 'Usuario que eliminó el contenido';
COMMENT ON COLUMN content.deletion_reason IS 'Razón de la eliminación (opcional)';

-- 2. CREAR TABLA DE BACKUP COMPLETO DE CONTENIDO
-- ============================================================================
CREATE TABLE IF NOT EXISTS content_backup (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  content_id UUID NOT NULL,
  organization_id UUID REFERENCES organizations(id),

  -- Snapshot completo del contenido
  content_snapshot JSONB NOT NULL,

  -- Metadata del backup
  backup_type TEXT NOT NULL CHECK (backup_type IN ('soft_delete', 'hard_delete', 'manual', 'auto')),
  backed_up_at TIMESTAMPTZ DEFAULT NOW(),
  backed_up_by UUID REFERENCES profiles(id),

  -- Para restauración
  restored_at TIMESTAMPTZ DEFAULT NULL,
  restored_by UUID REFERENCES profiles(id),

  -- Índices para búsqueda
  content_title TEXT,
  client_id UUID,

  CONSTRAINT content_backup_unique_per_delete UNIQUE (content_id, backed_up_at)
);

-- Índices para búsqueda eficiente
CREATE INDEX IF NOT EXISTS idx_content_backup_org ON content_backup(organization_id);
CREATE INDEX IF NOT EXISTS idx_content_backup_content_id ON content_backup(content_id);
CREATE INDEX IF NOT EXISTS idx_content_backup_date ON content_backup(backed_up_at DESC);
CREATE INDEX IF NOT EXISTS idx_content_backup_not_restored ON content_backup(restored_at) WHERE restored_at IS NULL;

-- RLS para content_backup
ALTER TABLE content_backup ENABLE ROW LEVEL SECURITY;

CREATE POLICY "content_backup_org_read" ON content_backup
  FOR SELECT USING (
    organization_id IN (
      SELECT organization_id FROM organization_members WHERE user_id = auth.uid()
    )
  );

-- Solo admins pueden ver backups
CREATE POLICY "content_backup_admin_all" ON content_backup
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM organization_member_roles omr
      WHERE omr.user_id = auth.uid()
        AND omr.organization_id = content_backup.organization_id
        AND omr.role = 'admin'
    )
  );

COMMENT ON TABLE content_backup IS 'Respaldo automático de contenido antes de eliminación';

-- 3. CREAR TABLA DE BACKUP DE SCRIPTS (VERSIONES)
-- ============================================================================
CREATE TABLE IF NOT EXISTS content_script_backup (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  content_id UUID NOT NULL,
  content_backup_id UUID REFERENCES content_backup(id) ON DELETE CASCADE,

  -- Copia de todas las versiones de script
  script_versions JSONB NOT NULL,

  backed_up_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_script_backup_content ON content_script_backup(content_id);

-- 4. FUNCIÓN PARA CREAR BACKUP COMPLETO
-- ============================================================================
CREATE OR REPLACE FUNCTION create_content_backup(
  p_content_id UUID,
  p_backup_type TEXT DEFAULT 'soft_delete',
  p_user_id UUID DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_backup_id UUID;
  v_content JSONB;
  v_script_versions JSONB;
  v_org_id UUID;
  v_title TEXT;
  v_client_id UUID;
BEGIN
  -- Obtener contenido completo como JSON
  SELECT
    to_jsonb(c.*),
    c.organization_id,
    c.title,
    c.client_id
  INTO v_content, v_org_id, v_title, v_client_id
  FROM content c
  WHERE c.id = p_content_id;

  IF v_content IS NULL THEN
    RAISE EXCEPTION 'Contenido no encontrado: %', p_content_id;
  END IF;

  -- Obtener todas las versiones de script
  SELECT COALESCE(jsonb_agg(to_jsonb(csv.*) ORDER BY csv.version DESC), '[]'::jsonb)
  INTO v_script_versions
  FROM content_script_versions csv
  WHERE csv.content_id = p_content_id;

  -- Crear backup del contenido
  INSERT INTO content_backup (
    content_id,
    organization_id,
    content_snapshot,
    backup_type,
    backed_up_by,
    content_title,
    client_id
  ) VALUES (
    p_content_id,
    v_org_id,
    v_content,
    p_backup_type,
    COALESCE(p_user_id, auth.uid()),
    v_title,
    v_client_id
  )
  RETURNING id INTO v_backup_id;

  -- Crear backup de versiones de script si existen
  IF jsonb_array_length(v_script_versions) > 0 THEN
    INSERT INTO content_script_backup (
      content_id,
      content_backup_id,
      script_versions
    ) VALUES (
      p_content_id,
      v_backup_id,
      v_script_versions
    );
  END IF;

  RETURN v_backup_id;
END;
$$;

-- 5. FUNCIÓN PARA SOFT DELETE (MOVER A PAPELERA)
-- ============================================================================
CREATE OR REPLACE FUNCTION soft_delete_content(
  p_content_id UUID,
  p_reason TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_backup_id UUID;
  v_user_id UUID;
  v_content_title TEXT;
BEGIN
  v_user_id := auth.uid();

  -- Verificar que el contenido existe y no está ya eliminado
  SELECT title INTO v_content_title
  FROM content
  WHERE id = p_content_id AND deleted_at IS NULL;

  IF v_content_title IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Contenido no encontrado o ya eliminado'
    );
  END IF;

  -- Crear backup antes de eliminar
  v_backup_id := create_content_backup(p_content_id, 'soft_delete', v_user_id);

  -- Marcar como eliminado (soft delete)
  UPDATE content
  SET
    deleted_at = NOW(),
    deleted_by = v_user_id,
    deletion_reason = p_reason
  WHERE id = p_content_id;

  -- Registrar en audit_log
  INSERT INTO audit_logs (user_id, action, entity_type, entity_id, entity_name, details)
  VALUES (
    v_user_id,
    'content_soft_deleted',
    'content',
    p_content_id,
    v_content_title,
    jsonb_build_object(
      'backup_id', v_backup_id,
      'reason', p_reason,
      'can_restore', true
    )
  );

  RETURN jsonb_build_object(
    'success', true,
    'backup_id', v_backup_id,
    'message', 'Contenido movido a papelera. Puede ser restaurado.'
  );
END;
$$;

-- 6. FUNCIÓN PARA RESTAURAR DESDE PAPELERA
-- ============================================================================
CREATE OR REPLACE FUNCTION restore_content_from_trash(
  p_content_id UUID
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
  v_content_title TEXT;
  v_backup_id UUID;
BEGIN
  v_user_id := auth.uid();

  -- Verificar que el contenido está eliminado
  SELECT title INTO v_content_title
  FROM content
  WHERE id = p_content_id AND deleted_at IS NOT NULL;

  IF v_content_title IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Contenido no encontrado en papelera'
    );
  END IF;

  -- Restaurar (quitar marca de eliminado)
  UPDATE content
  SET
    deleted_at = NULL,
    deleted_by = NULL,
    deletion_reason = NULL
  WHERE id = p_content_id;

  -- Marcar backup como restaurado
  UPDATE content_backup
  SET
    restored_at = NOW(),
    restored_by = v_user_id
  WHERE content_id = p_content_id
    AND restored_at IS NULL
  ORDER BY backed_up_at DESC
  LIMIT 1
  RETURNING id INTO v_backup_id;

  -- Registrar en audit_log
  INSERT INTO audit_logs (user_id, action, entity_type, entity_id, entity_name, details)
  VALUES (
    v_user_id,
    'content_restored',
    'content',
    p_content_id,
    v_content_title,
    jsonb_build_object('restored_from_backup', v_backup_id)
  );

  RETURN jsonb_build_object(
    'success', true,
    'message', 'Contenido restaurado exitosamente'
  );
END;
$$;

-- 7. FUNCIÓN PARA RESTAURAR DESDE BACKUP (INCLUYENDO HARD DELETE)
-- ============================================================================
CREATE OR REPLACE FUNCTION restore_content_from_backup(
  p_backup_id UUID
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
  v_backup RECORD;
  v_content_exists BOOLEAN;
  v_new_content_id UUID;
  v_script_backup RECORD;
BEGIN
  v_user_id := auth.uid();

  -- Obtener backup
  SELECT * INTO v_backup
  FROM content_backup
  WHERE id = p_backup_id AND restored_at IS NULL;

  IF v_backup IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Backup no encontrado o ya restaurado'
    );
  END IF;

  -- Verificar si el contenido original existe
  SELECT EXISTS(SELECT 1 FROM content WHERE id = v_backup.content_id)
  INTO v_content_exists;

  IF v_content_exists THEN
    -- Si existe, solo quitar soft delete
    UPDATE content
    SET
      deleted_at = NULL,
      deleted_by = NULL,
      deletion_reason = NULL
    WHERE id = v_backup.content_id;

    v_new_content_id := v_backup.content_id;
  ELSE
    -- Si no existe (fue hard deleted), recrear desde backup
    INSERT INTO content
    SELECT * FROM jsonb_populate_record(NULL::content, v_backup.content_snapshot)
    RETURNING id INTO v_new_content_id;

    -- Restaurar versiones de script si existen
    SELECT * INTO v_script_backup
    FROM content_script_backup
    WHERE content_backup_id = p_backup_id;

    IF v_script_backup IS NOT NULL THEN
      INSERT INTO content_script_versions
      SELECT * FROM jsonb_populate_recordset(NULL::content_script_versions, v_script_backup.script_versions);
    END IF;
  END IF;

  -- Marcar backup como restaurado
  UPDATE content_backup
  SET
    restored_at = NOW(),
    restored_by = v_user_id
  WHERE id = p_backup_id;

  -- Registrar en audit_log
  INSERT INTO audit_logs (user_id, action, entity_type, entity_id, entity_name, details)
  VALUES (
    v_user_id,
    'content_restored_from_backup',
    'content',
    v_new_content_id,
    v_backup.content_title,
    jsonb_build_object(
      'backup_id', p_backup_id,
      'was_hard_deleted', NOT v_content_exists
    )
  );

  RETURN jsonb_build_object(
    'success', true,
    'content_id', v_new_content_id,
    'message', 'Contenido restaurado desde backup'
  );
END;
$$;

-- 8. FUNCIÓN PARA HARD DELETE (SOLO ROOT)
-- ============================================================================
CREATE OR REPLACE FUNCTION hard_delete_content(
  p_content_id UUID,
  p_reason TEXT DEFAULT 'Eliminación permanente por root'
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
  v_is_root BOOLEAN;
  v_backup_id UUID;
  v_content_title TEXT;
BEGIN
  v_user_id := auth.uid();

  -- Verificar si es root (platform admin)
  SELECT EXISTS(
    SELECT 1 FROM profiles
    WHERE id = v_user_id
    AND (
      email IN ('root@kreoon.com', 'admin@kreoon.com')
      OR is_platform_admin = true
    )
  ) INTO v_is_root;

  IF NOT v_is_root THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Solo el administrador root puede eliminar permanentemente'
    );
  END IF;

  -- Obtener título antes de eliminar
  SELECT title INTO v_content_title
  FROM content WHERE id = p_content_id;

  IF v_content_title IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Contenido no encontrado'
    );
  END IF;

  -- Crear backup final antes de hard delete
  v_backup_id := create_content_backup(p_content_id, 'hard_delete', v_user_id);

  -- Eliminar versiones de script
  DELETE FROM content_script_versions WHERE content_id = p_content_id;

  -- Eliminar contenido permanentemente
  DELETE FROM content WHERE id = p_content_id;

  -- Registrar en audit_log
  INSERT INTO audit_logs (user_id, action, entity_type, entity_id, entity_name, details)
  VALUES (
    v_user_id,
    'content_hard_deleted',
    'content',
    p_content_id,
    v_content_title,
    jsonb_build_object(
      'backup_id', v_backup_id,
      'reason', p_reason,
      'can_restore', true,
      'deleted_by_root', true
    )
  );

  RETURN jsonb_build_object(
    'success', true,
    'backup_id', v_backup_id,
    'message', 'Contenido eliminado permanentemente. Backup disponible para restauración.'
  );
END;
$$;

-- 9. BLOQUEAR DELETE DIRECTO EN LA TABLA CONTENT
-- ============================================================================
-- Trigger que previene DELETE directo y fuerza soft delete
CREATE OR REPLACE FUNCTION prevent_hard_delete_content()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_is_root BOOLEAN;
  v_user_id UUID;
BEGIN
  v_user_id := auth.uid();

  -- Permitir si es una operación de servicio (no hay usuario)
  IF v_user_id IS NULL THEN
    -- Crear backup antes de permitir
    PERFORM create_content_backup(OLD.id, 'hard_delete', NULL);
    RETURN OLD;
  END IF;

  -- Verificar si es root
  SELECT EXISTS(
    SELECT 1 FROM profiles
    WHERE id = v_user_id
    AND (
      email IN ('root@kreoon.com', 'admin@kreoon.com')
      OR is_platform_admin = true
    )
  ) INTO v_is_root;

  IF v_is_root THEN
    -- Root puede eliminar, pero siempre hacer backup
    PERFORM create_content_backup(OLD.id, 'hard_delete', v_user_id);
    RETURN OLD;
  END IF;

  -- Para usuarios normales, convertir a soft delete
  UPDATE content
  SET
    deleted_at = NOW(),
    deleted_by = v_user_id,
    deletion_reason = 'Eliminación convertida a soft delete'
  WHERE id = OLD.id;

  -- Crear backup
  PERFORM create_content_backup(OLD.id, 'soft_delete', v_user_id);

  -- Registrar intento de hard delete convertido
  INSERT INTO audit_logs (user_id, action, entity_type, entity_id, entity_name, details)
  VALUES (
    v_user_id,
    'content_delete_blocked',
    'content',
    OLD.id,
    OLD.title,
    jsonb_build_object(
      'action_taken', 'converted_to_soft_delete',
      'message', 'Intento de eliminación permanente convertido a papelera'
    )
  );

  -- Prevenir el DELETE real
  RETURN NULL;
END;
$$;

-- Crear el trigger
DROP TRIGGER IF EXISTS trigger_prevent_hard_delete_content ON content;
CREATE TRIGGER trigger_prevent_hard_delete_content
  BEFORE DELETE ON content
  FOR EACH ROW
  EXECUTE FUNCTION prevent_hard_delete_content();

-- 10. VISTAS ÚTILES
-- ============================================================================

-- Vista de contenido activo (excluye eliminados)
CREATE OR REPLACE VIEW content_active AS
SELECT * FROM content WHERE deleted_at IS NULL;

-- Vista de papelera
CREATE OR REPLACE VIEW content_trash AS
SELECT
  c.*,
  p.full_name as deleted_by_name,
  cb.id as backup_id
FROM content c
LEFT JOIN profiles p ON p.id = c.deleted_by
LEFT JOIN content_backup cb ON cb.content_id = c.id
  AND cb.backup_type = 'soft_delete'
  AND cb.restored_at IS NULL
WHERE c.deleted_at IS NOT NULL
ORDER BY c.deleted_at DESC;

-- Vista de backups disponibles para restaurar
CREATE OR REPLACE VIEW content_backups_available AS
SELECT
  cb.*,
  p.full_name as backed_up_by_name,
  c.id as current_content_id,
  CASE
    WHEN c.id IS NULL THEN 'hard_deleted'
    WHEN c.deleted_at IS NOT NULL THEN 'in_trash'
    ELSE 'active'
  END as content_status
FROM content_backup cb
LEFT JOIN profiles p ON p.id = cb.backed_up_by
LEFT JOIN content c ON c.id = cb.content_id
WHERE cb.restored_at IS NULL
ORDER BY cb.backed_up_at DESC;

-- 11. FUNCIÓN PARA VACIAR PAPELERA (SOLO ROOT, DESPUÉS DE X DÍAS)
-- ============================================================================
CREATE OR REPLACE FUNCTION empty_trash_older_than(
  p_days INTEGER DEFAULT 30
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_user_id UUID;
  v_is_root BOOLEAN;
  v_count INTEGER;
BEGIN
  v_user_id := auth.uid();

  -- Verificar si es root
  SELECT EXISTS(
    SELECT 1 FROM profiles
    WHERE id = v_user_id
    AND (
      email IN ('root@kreoon.com', 'admin@kreoon.com')
      OR is_platform_admin = true
    )
  ) INTO v_is_root;

  IF NOT v_is_root THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Solo root puede vaciar la papelera'
    );
  END IF;

  -- Contar elementos a eliminar
  SELECT COUNT(*) INTO v_count
  FROM content
  WHERE deleted_at IS NOT NULL
    AND deleted_at < NOW() - (p_days || ' days')::INTERVAL;

  -- Eliminar permanentemente (el trigger creará backups)
  DELETE FROM content
  WHERE deleted_at IS NOT NULL
    AND deleted_at < NOW() - (p_days || ' days')::INTERVAL;

  RETURN jsonb_build_object(
    'success', true,
    'deleted_count', v_count,
    'message', format('Eliminados %s elementos de la papelera (más de %s días)', v_count, p_days)
  );
END;
$$;

-- 12. AGREGAR CAMPO is_platform_admin SI NO EXISTE
-- ============================================================================
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'profiles' AND column_name = 'is_platform_admin'
  ) THEN
    ALTER TABLE profiles ADD COLUMN is_platform_admin BOOLEAN DEFAULT FALSE;
  END IF;
END $$;

-- 13. COMENTARIOS FINALES
-- ============================================================================
COMMENT ON FUNCTION soft_delete_content IS 'Mueve contenido a papelera (soft delete). Crea backup automático.';
COMMENT ON FUNCTION restore_content_from_trash IS 'Restaura contenido desde papelera.';
COMMENT ON FUNCTION restore_content_from_backup IS 'Restaura contenido desde backup, incluso si fue hard deleted.';
COMMENT ON FUNCTION hard_delete_content IS 'Elimina permanentemente. SOLO ROOT. Siempre crea backup.';
COMMENT ON FUNCTION empty_trash_older_than IS 'Vacía papelera de elementos antiguos. SOLO ROOT.';
COMMENT ON VIEW content_active IS 'Contenido activo (excluye papelera)';
COMMENT ON VIEW content_trash IS 'Contenido en papelera';
COMMENT ON VIEW content_backups_available IS 'Backups disponibles para restaurar';

-- ========== 20260305210000_sync_user_health_from_sessions.sql ==========
-- =====================================================
-- Sincronizar datos de actividad de usuarios desde auth.users
-- Migration: 20260305210000_sync_user_health_from_sessions
-- =====================================================

-- Función para sincronizar/inicializar health de un usuario
CREATE OR REPLACE FUNCTION sync_user_health(p_user_id UUID)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_last_sign_in TIMESTAMPTZ;
  v_created_at TIMESTAMPTZ;
  v_days_inactive INTEGER;
  v_completed_projects INTEGER;
  v_total_applications INTEGER;
BEGIN
  -- Obtener datos del usuario de auth.users
  SELECT
    last_sign_in_at,
    created_at
  INTO v_last_sign_in, v_created_at
  FROM auth.users
  WHERE id = p_user_id;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  -- Calcular días de inactividad
  IF v_last_sign_in IS NOT NULL THEN
    v_days_inactive := EXTRACT(DAY FROM (NOW() - v_last_sign_in));
  ELSE
    v_days_inactive := EXTRACT(DAY FROM (NOW() - v_created_at));
  END IF;

  -- Obtener proyectos completados del creator_profile si existe
  SELECT COALESCE(cp.completed_projects, 0)
  INTO v_completed_projects
  FROM creator_profiles cp
  WHERE cp.user_id = p_user_id;

  IF NOT FOUND THEN
    v_completed_projects := 0;
  END IF;

  -- Obtener aplicaciones del marketplace
  SELECT COUNT(*)
  INTO v_total_applications
  FROM campaign_applications
  WHERE creator_id IN (SELECT id FROM creator_profiles WHERE user_id = p_user_id);

  -- Insertar o actualizar platform_user_health
  INSERT INTO platform_user_health (
    user_id,
    last_login_at,
    total_logins,
    days_since_last_activity,
    total_completed_projects,
    total_applications,
    health_score,
    health_status,
    needs_attention,
    updated_at
  ) VALUES (
    p_user_id,
    v_last_sign_in,
    1,
    v_days_inactive,
    v_completed_projects,
    COALESCE(v_total_applications, 0),
    CASE
      WHEN v_days_inactive <= 7 THEN 70
      WHEN v_days_inactive <= 14 THEN 50
      WHEN v_days_inactive <= 30 THEN 30
      ELSE 10
    END,
    CASE
      WHEN v_days_inactive <= 7 THEN 'healthy'
      WHEN v_days_inactive <= 14 THEN 'at_risk'
      WHEN v_days_inactive <= 30 THEN 'churning'
      ELSE 'churned'
    END,
    v_days_inactive > 14,
    NOW()
  )
  ON CONFLICT (user_id) DO UPDATE SET
    last_login_at = COALESCE(EXCLUDED.last_login_at, platform_user_health.last_login_at),
    total_logins = platform_user_health.total_logins + 1,
    days_since_last_activity = EXCLUDED.days_since_last_activity,
    total_completed_projects = EXCLUDED.total_completed_projects,
    total_applications = EXCLUDED.total_applications,
    health_score = EXCLUDED.health_score,
    health_status = EXCLUDED.health_status,
    needs_attention = EXCLUDED.needs_attention,
    updated_at = NOW();
END;
$$;

GRANT EXECUTE ON FUNCTION sync_user_health(UUID) TO authenticated;

-- Función para sincronizar TODOS los usuarios (admin)
CREATE OR REPLACE FUNCTION sync_all_users_health()
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_count INTEGER := 0;
  v_user_id UUID;
BEGIN
  FOR v_user_id IN
    SELECT id FROM auth.users
  LOOP
    PERFORM sync_user_health(v_user_id);
    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$$;

GRANT EXECUTE ON FUNCTION sync_all_users_health() TO authenticated;

-- Actualizar update_user_health_score para crear el registro si no existe
CREATE OR REPLACE FUNCTION update_user_health_score(p_user_id UUID)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_days_inactive INTEGER;
    v_completed INTEGER;
    v_rating DECIMAL;
    v_logins INTEGER;
    v_score INTEGER := 50;
    v_status TEXT;
BEGIN
    -- Asegurar que existe el registro
    IF NOT EXISTS (SELECT 1 FROM platform_user_health WHERE user_id = p_user_id) THEN
      PERFORM sync_user_health(p_user_id);
    END IF;

    -- Obtener métricas actuales
    SELECT
        days_since_last_activity,
        total_completed_projects,
        average_rating,
        total_logins
    INTO v_days_inactive, v_completed, v_rating, v_logins
    FROM platform_user_health
    WHERE user_id = p_user_id;

    -- Si no existe el registro, no hacer nada
    IF NOT FOUND THEN
        RETURN;
    END IF;

    -- Calcular score base (0-100)
    v_score := 50;

    -- Factor actividad: -2 puntos por día inactivo (max -30)
    IF v_days_inactive IS NOT NULL THEN
        v_score := v_score - LEAST(v_days_inactive * 2, 30);
    END IF;

    -- Factor proyectos: +3 puntos por proyecto completado (max +15)
    IF v_completed IS NOT NULL THEN
        v_score := v_score + LEAST(v_completed * 3, 15);
    END IF;

    -- Factor rating: +5 por rating >= 4.5, +3 por >= 4.0, -5 por < 3.0
    IF v_rating IS NOT NULL THEN
        IF v_rating >= 4.5 THEN v_score := v_score + 5;
        ELSIF v_rating >= 4.0 THEN v_score := v_score + 3;
        ELSIF v_rating < 3.0 THEN v_score := v_score - 5;
        END IF;
    END IF;

    -- Factor logins: +2 por cada 10 logins (max +10)
    IF v_logins IS NOT NULL THEN
        v_score := v_score + LEAST((v_logins / 10) * 2, 10);
    END IF;

    -- Clamp entre 0 y 100
    v_score := GREATEST(0, LEAST(100, v_score));

    -- Determinar status
    IF v_score > 70 THEN
        v_status := 'healthy';
    ELSIF v_score >= 40 THEN
        v_status := 'at_risk';
    ELSE
        v_status := 'churning';
    END IF;

    -- Actualizar
    UPDATE platform_user_health
    SET
        health_score = v_score,
        health_status = v_status,
        needs_attention = (v_score < 50)
    WHERE user_id = p_user_id;
END;
$$;

GRANT EXECUTE ON FUNCTION update_user_health_score(UUID) TO authenticated;

-- Ejecutar sincronización inicial para todos los usuarios existentes
SELECT sync_all_users_health();

