-- Política para que platform_admin vea todos los consentimientos
DROP POLICY IF EXISTS "admin_sees_all_consents" ON user_legal_consents;
CREATE POLICY "admin_sees_all_consents" ON user_legal_consents
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM profiles
      WHERE profiles.id = auth.uid()
      AND profiles.is_platform_admin = true
    )
  );

-- Política para que platform_admin vea todas las firmas
DROP POLICY IF EXISTS "admin_sees_all_signatures" ON digital_signatures;
CREATE POLICY "admin_sees_all_signatures" ON digital_signatures
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM profiles
      WHERE profiles.id = auth.uid()
      AND profiles.is_platform_admin = true
    )
  );

-- ========== 20260305240000_admin_consents_rpc.sql ==========
-- =====================================================
-- RPCs para que admins vean consentimientos de otros usuarios
-- Migration: 20260305240000_admin_consents_rpc
-- =====================================================

-- Función para obtener consentimientos de un usuario (admin only)
CREATE OR REPLACE FUNCTION get_user_consents(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_consents JSONB;
BEGIN
  -- Verificar si el usuario actual es admin o es el mismo usuario
  SELECT (
    is_platform_admin = true
    OR id = p_user_id
    OR email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com')
  )
  INTO v_is_admin
  FROM profiles
  WHERE id = auth.uid();

  IF NOT v_is_admin THEN
    RETURN '[]'::jsonb;
  END IF;

  -- Obtener consentimientos
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', id,
        'document_type', document_type,
        'document_version', document_version,
        'accepted', accepted,
        'accepted_at', accepted_at,
        'consent_method', consent_method,
        'ip_address', ip_address,
        'user_agent', user_agent
      ) ORDER BY accepted_at DESC
    ),
    '[]'::jsonb
  )
  INTO v_consents
  FROM user_legal_consents
  WHERE user_id = p_user_id;

  RETURN v_consents;
END;
$$;

GRANT EXECUTE ON FUNCTION get_user_consents(UUID) TO authenticated;

-- Función para obtener firmas digitales de un usuario (admin only)
CREATE OR REPLACE FUNCTION get_user_signatures(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_signatures JSONB;
BEGIN
  -- Verificar si el usuario actual es admin o es el mismo usuario
  SELECT (
    is_platform_admin = true
    OR id = p_user_id
    OR email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com')
  )
  INTO v_is_admin
  FROM profiles
  WHERE id = auth.uid();

  IF NOT v_is_admin THEN
    RETURN '[]'::jsonb;
  END IF;

  -- Obtener firmas
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', id,
        'document_type', document_type,
        'document_version', document_version,
        'signer_full_name', signer_full_name,
        'signature_method', signature_method,
        'typed_signature', typed_signature,
        'signature_image_url', signature_image_url,
        'declaration_text', declaration_text,
        'ip_address', ip_address,
        'timestamp_utc', timestamp_utc,
        'status', status
      ) ORDER BY created_at DESC
    ),
    '[]'::jsonb
  )
  INTO v_signatures
  FROM digital_signatures
  WHERE user_id = p_user_id;

  RETURN v_signatures;
END;
$$;

GRANT EXECUTE ON FUNCTION get_user_signatures(UUID) TO authenticated;

-- Función para obtener resumen de documentos requeridos vs firmados
CREATE OR REPLACE FUNCTION get_user_legal_summary(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_consents_count INTEGER;
  v_signatures_count INTEGER;
  v_onboarding_completed BOOLEAN;
  v_required_docs TEXT[];
  v_signed_docs TEXT[];
  v_missing_docs TEXT[];
BEGIN
  -- Verificar si el usuario actual es admin o es el mismo usuario
  SELECT (
    is_platform_admin = true
    OR id = p_user_id
    OR email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com')
  )
  INTO v_is_admin
  FROM profiles
  WHERE id = auth.uid();

  IF NOT v_is_admin THEN
    RETURN jsonb_build_object('error', 'unauthorized');
  END IF;

  -- Contar consentimientos
  SELECT COUNT(*) INTO v_consents_count
  FROM user_legal_consents WHERE user_id = p_user_id AND accepted = true;

  -- Contar firmas
  SELECT COUNT(*) INTO v_signatures_count
  FROM digital_signatures WHERE user_id = p_user_id AND status = 'valid';

  -- Estado de onboarding
  SELECT COALESCE(onboarding_completed, false)
  INTO v_onboarding_completed
  FROM profiles WHERE id = p_user_id;

  -- Documentos firmados
  SELECT ARRAY_AGG(DISTINCT document_type)
  INTO v_signed_docs
  FROM user_legal_consents
  WHERE user_id = p_user_id AND accepted = true;

  -- Documentos requeridos (basado en permission_group 'all')
  SELECT ARRAY_AGG(document_type)
  INTO v_required_docs
  FROM legal_documents
  WHERE is_current = true
    AND requires_signature = true
    AND is_mandatory = true
    AND 'all' = ANY(permission_groups);

  -- Calcular faltantes
  IF v_required_docs IS NOT NULL AND v_signed_docs IS NOT NULL THEN
    v_missing_docs := ARRAY(
      SELECT unnest(v_required_docs)
      EXCEPT
      SELECT unnest(v_signed_docs)
    );
  ELSE
    v_missing_docs := v_required_docs;
  END IF;

  RETURN jsonb_build_object(
    'consents_count', COALESCE(v_consents_count, 0),
    'signatures_count', COALESCE(v_signatures_count, 0),
    'onboarding_completed', v_onboarding_completed,
    'signed_docs', COALESCE(v_signed_docs, ARRAY[]::TEXT[]),
    'required_docs', COALESCE(v_required_docs, ARRAY[]::TEXT[]),
    'missing_docs', COALESCE(v_missing_docs, ARRAY[]::TEXT[])
  );
END;
$$;

GRANT EXECUTE ON FUNCTION get_user_legal_summary(UUID) TO authenticated;

-- ========== 20260305250000_force_update_get_full_user_detail.sql ==========
-- =====================================================
-- Forzar actualización de get_full_user_detail
-- Migration: 20260305250000_force_update_get_full_user_detail
-- Esta migración fuerza la actualización del RPC para asegurar
-- que incluya nationality, date_of_birth, username, etc.
-- =====================================================

-- Eliminar función existente
DROP FUNCTION IF EXISTS get_full_user_detail(UUID);

-- Recrear la función con todos los campos actualizados
CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB;
  profile_base JSONB;
  profile_social JSONB;
  profile_extras JSONB;
  creator_data JSONB;
  health_data JSONB;
  org_data JSONB;
  arrays_data JSONB;
BEGIN
  -- Part 1: Basic profile fields (incluye nationality, date_of_birth, username)
  SELECT jsonb_build_object(
    'id', p.id,
    'email', p.email,
    'full_name', p.full_name,
    'username', p.username,
    'avatar_url', p.avatar_url,
    'phone', p.phone,
    'bio', p.bio,
    'tagline', p.tagline,
    'cover_url', p.cover_url,
    'document_type', p.document_type,
    'document_number', p.document_number,
    'address', p.address,
    'city', p.city,
    'country', p.country,
    'nationality', p.nationality,
    'date_of_birth', p.date_of_birth,
    'onboarding_completed', COALESCE(p.onboarding_completed, false),
    'created_at', p.created_at
  ) INTO profile_base
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 2: Social links and content preferences
  SELECT jsonb_build_object(
    'instagram', p.instagram,
    'tiktok', p.tiktok,
    'facebook', p.facebook,
    'social_linkedin', p.social_linkedin,
    'social_twitter', p.social_twitter,
    'social_youtube', p.social_youtube,
    'portfolio_url', p.portfolio_url,
    'featured_video_url', p.featured_video_url,
    'content_categories', COALESCE(p.content_categories, ARRAY[]::TEXT[]),
    'specialties_tags', COALESCE(p.specialties_tags, ARRAY[]::TEXT[]),
    'style_keywords', COALESCE(p.style_keywords, ARRAY[]::TEXT[]),
    'industries', COALESCE(p.industries, ARRAY[]::TEXT[]),
    'interests', COALESCE(p.interests, ARRAY[]::TEXT[]),
    'languages', COALESCE(p.languages, ARRAY[]::TEXT[])
  ) INTO profile_social
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 3: Profile extras (scores, flags)
  SELECT jsonb_build_object(
    'experience_level', p.experience_level,
    'availability_status', p.availability_status,
    'best_at', p.best_at,
    'rate_per_content', p.rate_per_content,
    'rate_currency', p.rate_currency,
    'quality_score_avg', p.quality_score_avg,
    'reliability_score', p.reliability_score,
    'velocity_score', p.velocity_score,
    'editor_rating', p.editor_rating,
    'is_ambassador', COALESCE(p.is_ambassador, false),
    'is_platform_founder', COALESCE(p.is_platform_founder, false),
    'founder_badge_type', p.founder_badge_type,
    'active_role', p.active_role,
    'ai_recommended_level', p.ai_recommended_level,
    'ai_risk_flag', p.ai_risk_flag,
    'is_active', COALESCE(p.is_active, true),
    'is_banned', COALESCE(p.is_banned, false),
    'is_platform_admin', COALESCE(p.is_platform_admin, false),
    'crm_custom_fields', COALESCE(p.crm_custom_fields, '{}'::jsonb)
  ) INTO profile_extras
  FROM profiles p WHERE p.id = p_user_id;

  -- Part 4: Creator profile data
  SELECT jsonb_build_object(
    'creator_profile_id', cp.id,
    'slug', cp.slug,
    'bio_full', cp.bio_full,
    'banner_url', cp.banner_url,
    'creator_social_links', cp.social_links,
    'level', cp.level,
    'is_verified', COALESCE(cp.is_verified, false),
    'is_available', COALESCE(cp.is_available, false),
    'rating_avg', COALESCE(cp.rating_avg, 0),
    'rating_count', COALESCE(cp.rating_count, 0),
    'completed_projects', COALESCE(cp.completed_projects, 0),
    'base_price', cp.base_price,
    'currency', COALESCE(cp.currency, 'USD'),
    'categories', COALESCE(cp.categories, ARRAY[]::TEXT[]),
    'content_types', COALESCE(cp.content_types, ARRAY[]::TEXT[]),
    'platforms', COALESCE(cp.platforms, ARRAY[]::TEXT[]),
    'marketplace_roles', COALESCE(cp.marketplace_roles, ARRAY[]::TEXT[]),
    'accepts_product_exchange', COALESCE(cp.accepts_product_exchange, false),
    'response_time_hours', cp.response_time_hours,
    'on_time_delivery_pct', cp.on_time_delivery_pct,
    'repeat_clients_pct', cp.repeat_clients_pct,
    'showreel_video_id', cp.showreel_video_id,
    'showreel_url', cp.showreel_url,
    'showreel_thumbnail', cp.showreel_thumbnail
  ) INTO creator_data
  FROM profiles p
  LEFT JOIN creator_profiles cp ON cp.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 5: Health data
  SELECT jsonb_build_object(
    'health_score', COALESCE(h.health_score, 0),
    'health_status', COALESCE(h.health_status, 'healthy'),
    'total_logins', COALESCE(h.total_logins, 0),
    'days_since_last_activity', h.days_since_last_activity,
    'last_login_at', h.last_login_at,
    'total_actions', 0,
    'needs_attention', COALESCE(h.needs_attention, false),
    'total_applications', COALESCE(h.total_applications, 0),
    'total_completed_projects', COALESCE(h.total_completed_projects, 0),
    'total_spent', COALESCE(h.total_spent, 0)
  ) INTO health_data
  FROM profiles p
  LEFT JOIN platform_user_health h ON h.user_id = p.id
  WHERE p.id = p_user_id;

  -- Part 6: Organization context
  SELECT jsonb_build_object(
    'organization_id', om.organization_id,
    'organization_name', o.name,
    'is_owner', COALESCE(om.is_owner, false),
    'ambassador_level', om.ambassador_level
  ) INTO org_data
  FROM profiles p
  LEFT JOIN organization_members om ON om.user_id = p.id AND om.organization_id = p.current_organization_id
  LEFT JOIN organizations o ON o.id = om.organization_id
  WHERE p.id = p_user_id;

  -- Part 7: Nested arrays
  SELECT jsonb_build_object(
    'organizations', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'organization_id', om2.organization_id,
        'organization_name', o2.name,
        'role', (SELECT omr3.role FROM organization_member_roles omr3 WHERE omr3.user_id = p_user_id AND omr3.organization_id = om2.organization_id LIMIT 1),
        'is_owner', om2.is_owner,
        'joined_at', om2.joined_at
      ) ORDER BY om2.joined_at ASC)
      FROM organization_members om2
      LEFT JOIN organizations o2 ON o2.id = om2.organization_id
      WHERE om2.user_id = p_user_id
    ), '[]'::jsonb),
    'companies', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'client_id', c2.id,
        'client_name', c2.name,
        'organization_id', c2.organization_id,
        'organization_name', o3.name,
        'role', cu2.role,
        'created_at', cu2.created_at
      ) ORDER BY cu2.created_at ASC)
      FROM client_users cu2
      JOIN clients c2 ON c2.id = cu2.client_id
      LEFT JOIN organizations o3 ON o3.id = c2.organization_id
      WHERE cu2.user_id = p_user_id
    ), '[]'::jsonb),
    'roles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'role', omr.role,
        'organization_id', omr.organization_id,
        'organization_name', o2.name
      ))
      FROM organization_member_roles omr
      LEFT JOIN organizations o2 ON o2.id = omr.organization_id
      WHERE omr.user_id = p_user_id
    ), '[]'::jsonb),
    'badges', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'badge', omb.badge,
        'level', omb.level,
        'is_active', omb.is_active,
        'granted_at', omb.granted_at
      ))
      FROM organization_member_badges omb
      WHERE omb.user_id = p_user_id AND omb.is_active = true
    ), '[]'::jsonb),
    'portfolio', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', pi.id,
        'title', pi.title,
        'media_type', pi.media_type,
        'media_url', pi.media_url,
        'thumbnail_url', pi.thumbnail_url,
        'bunny_video_id', pi.bunny_video_id,
        'category', pi.category,
        'is_featured', pi.is_featured
      ) ORDER BY pi.is_featured DESC, pi.display_order ASC)
      FROM portfolio_items pi
      JOIN creator_profiles cp ON cp.id = pi.creator_id
      WHERE cp.user_id = p_user_id AND pi.is_public = true
      LIMIT 12
    ), '[]'::jsonb),
    'services', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', cs.id,
        'title', cs.title,
        'service_type', cs.service_type,
        'price_type', cs.price_type,
        'price_amount', cs.price_amount,
        'price_currency', cs.price_currency,
        'delivery_days', cs.delivery_days,
        'is_featured', cs.is_featured
      ) ORDER BY cs.is_featured DESC, cs.display_order ASC)
      FROM creator_services cs
      WHERE cs.user_id = p_user_id AND cs.is_active = true
    ), '[]'::jsonb)
  ) INTO arrays_data;

  -- Combine all parts
  result := COALESCE(profile_base, '{}'::jsonb)
    || COALESCE(profile_social, '{}'::jsonb)
    || COALESCE(profile_extras, '{}'::jsonb)
    || COALESCE(creator_data, '{}'::jsonb)
    || COALESCE(health_data, '{}'::jsonb)
    || COALESCE(org_data, '{}'::jsonb)
    || COALESCE(arrays_data, '{}'::jsonb);

  RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_full_user_detail(uuid) TO authenticated;

-- También asegurar que las columnas existen en profiles
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS nationality TEXT;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS date_of_birth DATE;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS is_banned BOOLEAN DEFAULT false;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS is_platform_admin BOOLEAN DEFAULT false;

-- ========== 20260305260000_add_onboarding_to_users_rpc.sql ==========
-- =====================================================
-- Agregar onboarding_completed al RPC de usuarios
-- Migration: 20260305260000_add_onboarding_to_users_rpc
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_users_with_health()
RETURNS JSONB
LANGUAGE plpgsql SECURITY DEFINER
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            au.id,
            COALESCE(p.email, au.email) AS email,
            COALESCE(p.full_name, au.raw_user_meta_data->>'full_name', 'Sin nombre') AS full_name,
            p.avatar_url,
            -- Primary role from organization_members (for display)
            COALESCE(om.role::text, p.active_role) AS role,
            -- All roles from organization_member_roles (for multi-tab classification)
            COALESCE(all_roles.roles, ARRAY[]::text[]) AS all_roles,
            om.organization_id,
            o.name AS organization_name,
            COALESCE(h.health_score, 50) AS health_score,
            COALESCE(h.health_status, 'healthy') AS health_status,
            COALESCE(h.total_logins, 0) AS total_logins,
            COALESCE(h.days_since_last_activity,
                EXTRACT(DAY FROM NOW() - COALESCE(au.last_sign_in_at, au.created_at))
            )::integer AS days_since_last_activity,
            COALESCE(h.last_login_at, au.last_sign_in_at) AS last_login_at,
            COALESCE(h.total_applications, 0)
                + COALESCE(h.total_completed_projects, 0)
                + COALESCE(h.total_campaigns_created, 0)
                + COALESCE(h.total_content_received, 0) AS total_actions,
            COALESCE(h.needs_attention, FALSE) AS needs_attention,
            COALESCE(p.created_at, au.created_at) AS created_at,
            -- Auth-level fields
            au.email_confirmed_at,
            CASE WHEN au.banned_until IS NOT NULL AND au.banned_until > NOW() THEN TRUE ELSE FALSE END AS is_banned,
            (p.id IS NOT NULL) AS has_profile,
            EXISTS(SELECT 1 FROM user_roles ur WHERE ur.user_id = au.id AND ur.role = 'admin') AS is_platform_admin,
            -- Referral/key status (from profiles table)
            COALESCE(p.platform_access_unlocked, FALSE) AS platform_access_unlocked,
            -- user_type from auth.users metadata
            au.raw_user_meta_data->>'user_type' AS user_type,
            -- Onboarding status
            COALESCE(p.onboarding_completed, FALSE) AS onboarding_completed,
            -- Consentimientos (cantidad aceptados)
            COALESCE(consents.consent_count, 0) AS consent_count
        FROM auth.users au
        LEFT JOIN profiles p ON p.id = au.id
        LEFT JOIN LATERAL (
            SELECT om2.organization_id, om2.is_owner, om2.role
            FROM organization_members om2
            WHERE om2.user_id = au.id
            ORDER BY om2.is_owner DESC, om2.joined_at ASC
            LIMIT 1
        ) om ON TRUE
        LEFT JOIN LATERAL (
            SELECT array_agg(DISTINCT omr.role::text) AS roles
            FROM organization_member_roles omr
            WHERE omr.user_id = au.id
              AND omr.organization_id = om.organization_id
        ) all_roles ON TRUE
        LEFT JOIN organizations o ON o.id = om.organization_id
        LEFT JOIN platform_user_health h ON h.user_id = au.id
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::integer AS consent_count
            FROM user_legal_consents ulc
            WHERE ulc.user_id = au.id AND ulc.accepted = TRUE
        ) consents ON TRUE
    ) t;

    RETURN result;
END;
$$;

-- ========== 20260305270000_cookie_consents_table.sql ==========
-- =====================================================
-- Tabla para consentimientos de cookies (GDPR)
-- Migration: 20260305270000_cookie_consents_table
-- =====================================================

CREATE TABLE IF NOT EXISTS public.user_cookie_consents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  consent_version TEXT NOT NULL DEFAULT '1.0',

  -- Categorías de cookies
  essential BOOLEAN NOT NULL DEFAULT true,
  analytics BOOLEAN NOT NULL DEFAULT false,
  marketing BOOLEAN NOT NULL DEFAULT false,
  personalization BOOLEAN NOT NULL DEFAULT false,

  -- Datos técnicos para prueba legal
  ip_address TEXT,
  user_agent TEXT,

  -- Timestamps
  consented_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),

  -- Un registro por usuario
  CONSTRAINT user_cookie_consents_user_unique UNIQUE (user_id)
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_cookie_consents_user ON user_cookie_consents(user_id);

-- RLS
ALTER TABLE user_cookie_consents ENABLE ROW LEVEL SECURITY;

-- Usuarios pueden ver y actualizar su propio consentimiento
CREATE POLICY "users_own_cookie_consent" ON user_cookie_consents
  FOR ALL
  USING (auth.uid() = user_id)
  WITH CHECK (auth.uid() = user_id);

-- Admins pueden ver todos los consentimientos
CREATE POLICY "admins_view_cookie_consents" ON user_cookie_consents
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM profiles
      WHERE profiles.id = auth.uid()
      AND profiles.is_platform_admin = true
    )
  );

-- Trigger para updated_at
CREATE OR REPLACE FUNCTION update_cookie_consent_timestamp()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_cookie_consent_updated ON user_cookie_consents;
CREATE TRIGGER trigger_cookie_consent_updated
  BEFORE UPDATE ON user_cookie_consents
  FOR EACH ROW
  EXECUTE FUNCTION update_cookie_consent_timestamp();

-- Comentarios
COMMENT ON TABLE user_cookie_consents IS 'Consentimientos de cookies por usuario (GDPR compliance)';
COMMENT ON COLUMN user_cookie_consents.essential IS 'Cookies esenciales (siempre true)';
COMMENT ON COLUMN user_cookie_consents.analytics IS 'Cookies de analítica (Google Analytics, etc.)';
COMMENT ON COLUMN user_cookie_consents.marketing IS 'Cookies de marketing (Facebook Pixel, etc.)';
COMMENT ON COLUMN user_cookie_consents.personalization IS 'Cookies de personalización';

-- ========== 20260305280000_add_onboarding_to_creators_rpc.sql ==========
-- =====================================================
-- Agregar campos de onboarding a get_platform_creators_with_metrics
-- Migration: 20260305280000_add_onboarding_to_creators_rpc
-- =====================================================

CREATE OR REPLACE FUNCTION get_platform_creators_with_metrics()
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO result
    FROM (
        SELECT
            cp.id,
            cp.user_id,
            p.full_name,
            p.email,
            p.username,
            p.avatar_url,
            cp.categories,
            cp.content_types,
            cp.platforms,
            cp.marketplace_roles,
            cp.level,
            cp.is_verified,
            cp.is_active,
            cp.is_available,
            cp.rating_avg,
            cp.rating_count,
            cp.completed_projects,
            cp.base_price,
            cp.currency,
            cp.location_city,
            cp.location_country,
            cp.created_at,
            COALESCE(earn.total_earned, 0) AS total_earned,
            -- Campos de onboarding
            COALESCE(p.onboarding_completed, false) AS onboarding_completed,
            COALESCE(consent.consent_count, 0) AS consent_count
        FROM creator_profiles cp
        JOIN profiles p ON p.id = cp.user_id
        LEFT JOIN (
            SELECT
                creator_id,
                COALESCE(SUM(creator_payout), 0) AS total_earned
            FROM marketplace_projects
            WHERE status = 'completed'
            GROUP BY creator_id
        ) earn ON earn.creator_id = cp.user_id
        LEFT JOIN (
            SELECT
                user_id,
                COUNT(*) AS consent_count
            FROM user_legal_consents
            WHERE accepted = true AND is_current = true
            GROUP BY user_id
        ) consent ON consent.user_id = cp.user_id
    ) t;

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_platform_creators_with_metrics() TO authenticated;

-- ========== 20260305290000_unified_creator_stats.sql ==========
-- =====================================================
-- Estadísticas unificadas del creador (marketplace + organizaciones)
-- Migration: 20260305290000_unified_creator_stats
-- =====================================================

-- Función para obtener estadísticas unificadas de un creador
CREATE OR REPLACE FUNCTION get_creator_unified_stats(p_user_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result JSONB;
    v_marketplace_completed INT := 0;
    v_org_content_completed INT := 0;
    v_total_completed INT := 0;
    v_rating_avg NUMERIC := 0;
    v_rating_count INT := 0;
    v_response_time_hours NUMERIC := 24;
    v_on_time_delivery_pct INT := 100;
    v_repeat_clients_pct INT := 0;
    v_total_earned NUMERIC := 0;
    v_creator_profile_id UUID;
BEGIN
    -- Obtener creator_profile_id
    SELECT id INTO v_creator_profile_id
    FROM creator_profiles
    WHERE user_id = p_user_id
    LIMIT 1;

    -- 1. Contar proyectos completados del MARKETPLACE
    SELECT COUNT(*)
    INTO v_marketplace_completed
    FROM marketplace_projects
    WHERE creator_id = p_user_id
    AND status = 'completed';

    -- 2. Contar contenido completado en ORGANIZACIONES
    -- Contamos contenido con status 'published' o 'approved' o 'delivered'
    SELECT COUNT(*)
    INTO v_org_content_completed
    FROM content
    WHERE creator_id = p_user_id
    AND (
        status IN ('published', 'approved', 'delivered')
        OR is_published = true
    );

    -- Total de proyectos
    v_total_completed := v_marketplace_completed + v_org_content_completed;

    -- 3. Calcular rating promedio (de creator_reviews)
    IF v_creator_profile_id IS NOT NULL THEN
        SELECT
            COALESCE(AVG(rating), 0),
            COUNT(*)
        INTO v_rating_avg, v_rating_count
        FROM creator_reviews
        WHERE creator_id = v_creator_profile_id;
    END IF;

    -- 4. Obtener métricas adicionales del perfil del creador
    SELECT
        COALESCE(response_time_hours, 24),
        COALESCE(on_time_delivery_pct, 100),
        COALESCE(repeat_clients_pct, 0)
    INTO v_response_time_hours, v_on_time_delivery_pct, v_repeat_clients_pct
    FROM creator_profiles
    WHERE user_id = p_user_id;

    -- 5. Calcular total ganado (del marketplace)
    SELECT COALESCE(SUM(creator_payout), 0)
    INTO v_total_earned
    FROM marketplace_projects
    WHERE creator_id = p_user_id
    AND status = 'completed';

    -- 6. Calcular porcentaje de entrega a tiempo basado en proyectos reales
    -- Solo si hay proyectos del marketplace con deadline
    DECLARE
        v_on_time_count INT := 0;
        v_deadline_projects INT := 0;
    BEGIN
        SELECT
            COUNT(*) FILTER (WHERE completed_at <= deadline),
            COUNT(*)
        INTO v_on_time_count, v_deadline_projects
        FROM marketplace_projects
        WHERE creator_id = p_user_id
        AND status = 'completed'
        AND deadline IS NOT NULL;

        IF v_deadline_projects > 0 THEN
            v_on_time_delivery_pct := ROUND((v_on_time_count::NUMERIC / v_deadline_projects) * 100);
        END IF;
    END;

    -- 7. Calcular clientes recurrentes
    DECLARE
        v_unique_clients INT := 0;
        v_repeat_count INT := 0;
    BEGIN
        SELECT COUNT(DISTINCT brand_id)
        INTO v_unique_clients
        FROM marketplace_projects
        WHERE creator_id = p_user_id
        AND status = 'completed';

        SELECT COUNT(*)
        INTO v_repeat_count
        FROM (
            SELECT brand_id
            FROM marketplace_projects
            WHERE creator_id = p_user_id
            AND status = 'completed'
            GROUP BY brand_id
            HAVING COUNT(*) > 1
        ) repeat_brands;

        IF v_unique_clients > 0 THEN
            v_repeat_clients_pct := ROUND((v_repeat_count::NUMERIC / v_unique_clients) * 100);
        END IF;
    END;

    -- Construir resultado
    result := jsonb_build_object(
        'completed_projects', v_total_completed,
        'marketplace_projects', v_marketplace_completed,
        'org_projects', v_org_content_completed,
        'rating_avg', ROUND(v_rating_avg::NUMERIC, 1),
        'rating_count', v_rating_count,
        'response_time_hours', v_response_time_hours,
        'on_time_delivery_pct', v_on_time_delivery_pct,
        'repeat_clients_pct', v_repeat_clients_pct,
        'total_earned', v_total_earned
    );

    RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION get_creator_unified_stats(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_creator_unified_stats(UUID) TO anon;

COMMENT ON FUNCTION get_creator_unified_stats IS
'Calcula estadísticas unificadas del creador incluyendo proyectos del marketplace y organizaciones';

