-- ========== 20260305800000_fix_platform_admin_superadmin.sql ==========
-- Fix is_platform_admin() to also check is_superadmin field from profiles

CREATE OR REPLACE FUNCTION is_platform_admin()
RETURNS BOOLEAN
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id UUID;
  v_is_admin BOOLEAN := false;
  v_is_superadmin BOOLEAN := false;
  v_email TEXT;
BEGIN
  v_user_id := auth.uid();

  IF v_user_id IS NULL THEN
    RETURN false;
  END IF;

  -- 1. Check is_platform_admin OR is_superadmin flag in profiles table
  SELECT
    COALESCE(is_platform_admin, false),
    COALESCE(is_superadmin, false)
  INTO v_is_admin, v_is_superadmin
  FROM profiles
  WHERE id = v_user_id;

  IF v_is_admin = true OR v_is_superadmin = true THEN
    RETURN true;
  END IF;

  -- 2. Check hardcoded admin emails
  SELECT email INTO v_email
  FROM auth.users
  WHERE id = v_user_id;

  IF v_email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com') THEN
    RETURN true;
  END IF;

  -- 3. Check if user has 'admin' role in user_roles (platform-level)
  IF EXISTS (
    SELECT 1 FROM user_roles
    WHERE user_id = v_user_id AND role = 'admin'
  ) THEN
    RETURN true;
  END IF;

  RETURN false;
END;
$$;

-- Grant execute on the function
GRANT EXECUTE ON FUNCTION is_platform_admin() TO authenticated;
GRANT EXECUTE ON FUNCTION is_platform_admin() TO anon;

-- ========== 20260305810000_set_root_admin_flags.sql ==========
-- Set is_platform_admin and is_superadmin for root users
-- This is more reliable than checking email in the function

UPDATE profiles
SET
  is_platform_admin = true,
  is_superadmin = true
WHERE email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com');

-- Also ensure these columns exist (in case they were added later)
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'profiles' AND column_name = 'is_platform_admin') THEN
    ALTER TABLE profiles ADD COLUMN is_platform_admin BOOLEAN DEFAULT false;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'profiles' AND column_name = 'is_superadmin') THEN
    ALTER TABLE profiles ADD COLUMN is_superadmin BOOLEAN DEFAULT false;
  END IF;
END $$;

-- Run the update again after ensuring columns exist
UPDATE profiles
SET
  is_platform_admin = true,
  is_superadmin = true
WHERE email IN ('jacsolucionesgraficas@gmail.com', 'kairosgp.sas@gmail.com');

-- ========== 20260305820000_improve_portfolio_thumbnail_search.sql ==========
-- ============================================================
-- IMPROVE: Buscar thumbnail en más fuentes de contenido
-- Migration: 20260305800000_improve_portfolio_thumbnail_search
-- ============================================================

DROP FUNCTION IF EXISTS search_marketplace_creators(text, text[], text, text, text[], numeric, numeric, boolean, boolean, integer, integer);

CREATE OR REPLACE FUNCTION search_marketplace_creators(
  p_query              text    DEFAULT '',
  p_roles              text[]  DEFAULT NULL,
  p_location_country   text    DEFAULT NULL,
  p_location_city      text    DEFAULT NULL,
  p_niches             text[]  DEFAULT NULL,
  p_min_rating         numeric DEFAULT NULL,
  p_max_price          numeric DEFAULT NULL,
  p_accepts_exchange   boolean DEFAULT NULL,
  p_is_available       boolean DEFAULT NULL,
  p_limit              integer DEFAULT 20,
  p_offset             integer DEFAULT 0
)
RETURNS TABLE (
  id                  uuid,
  user_id             uuid,
  display_name        text,
  username            text,
  slug                text,
  avatar_url          text,
  bio                 text,
  primary_role        text,
  location_city       text,
  location_country    text,
  rating_avg          numeric,
  rating_count        integer,
  total_projects      integer,
  response_time_hours integer,
  base_price          numeric,
  currency            text,
  accepts_exchange    boolean,
  is_verified         boolean,
  portfolio_count     integer,
  portfolio_thumbnail text,
  search_score        numeric,
  quality_score       numeric,
  activity_score      numeric,
  text_rank           real,
  final_rank          numeric,
  organization_id     uuid,
  organization_name   text,
  organization_logo   text,
  marketplace_roles   text[],
  categories          text[],
  content_types       text[],
  languages           text[],
  level               text
)
LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
  v_tsquery tsquery;
BEGIN
  IF p_query IS NOT NULL AND length(trim(p_query)) > 0 THEN
    v_tsquery := websearch_to_tsquery('spanish', p_query);
  END IF;

  RETURN QUERY
  WITH ranked_creators AS (
    SELECT DISTINCT ON (cp.id)
      cp.id,
      cp.user_id,
      cp.display_name,
      cp.username,
      cp.slug,
      cp.avatar_url,
      cp.bio,
      cp.primary_role,
      cp.location_city,
      cp.location_country,
      cp.rating_avg,
      cp.rating_count,
      cp.total_projects,
      cp.response_time_hours,
      cp.base_price,
      cp.currency,
      cp.accepts_product_exchange AS accepts_exchange,
      cp.is_verified,
      cp.portfolio_count,
      -- Buscar thumbnail en orden de prioridad
      COALESCE(
        -- 1. portfolio_items con thumbnail
        (SELECT pi.thumbnail_url FROM portfolio_items pi
         WHERE pi.creator_id = cp.id AND pi.is_public = true AND pi.thumbnail_url IS NOT NULL AND pi.thumbnail_url != ''
         ORDER BY pi.is_featured DESC, pi.display_order ASC LIMIT 1),
        -- 2. portfolio_items sin thumbnail (usar media_url para imágenes)
        (SELECT pi.media_url FROM portfolio_items pi
         WHERE pi.creator_id = cp.id AND pi.is_public = true AND pi.media_type = 'image' AND pi.media_url IS NOT NULL
         ORDER BY pi.is_featured DESC, pi.display_order ASC LIMIT 1),
        -- 3. content con thumbnail
        (SELECT c.thumbnail_url FROM content c
         WHERE c.creator_id = cp.user_id AND c.is_published = true AND c.thumbnail_url IS NOT NULL AND c.thumbnail_url != ''
         ORDER BY c.created_at DESC LIMIT 1),
        -- 4. content con bunny_embed_url (extraer thumbnail)
        (SELECT REPLACE(c.bunny_embed_url, '/embed/', '/thumbnail/') || '?time=1' FROM content c
         WHERE c.creator_id = cp.user_id AND c.is_published = true AND c.bunny_embed_url IS NOT NULL AND c.bunny_embed_url LIKE '%bunny%'
         ORDER BY c.created_at DESC LIMIT 1),
        -- 5. content con video_url de bunny
        (SELECT REPLACE(REPLACE(c.video_url, 'iframe.mediadelivery.net/embed', 'vz-cedd5f9c-a36.b-cdn.net'), '/video/', '/') || '/thumbnail.jpg' FROM content c
         WHERE c.creator_id = cp.user_id AND c.is_published = true AND c.video_url IS NOT NULL AND c.video_url LIKE '%bunny%'
         ORDER BY c.created_at DESC LIMIT 1),
        -- 6. portfolio_posts con thumbnail
        (SELECT pp.thumbnail_url FROM portfolio_posts pp
         WHERE pp.user_id = cp.user_id AND pp.thumbnail_url IS NOT NULL AND pp.thumbnail_url != ''
         ORDER BY pp.created_at DESC LIMIT 1),
        -- 7. portfolio_posts imagen
        (SELECT pp.media_url FROM portfolio_posts pp
         WHERE pp.user_id = cp.user_id AND pp.media_type = 'image' AND pp.media_url IS NOT NULL
         ORDER BY pp.created_at DESC LIMIT 1)
      ) AS portfolio_thumbnail,
      cp.search_score,
      cp.quality_score,
      cp.activity_score,
      CASE
        WHEN v_tsquery IS NOT NULL THEN ts_rank_cd(cp.search_vector, v_tsquery, 32)
        ELSE 0.0
      END AS text_rank,
      CASE
        WHEN v_tsquery IS NOT NULL THEN
          ROUND((COALESCE(cp.search_score, 0) * 0.60 + ts_rank_cd(cp.search_vector, v_tsquery, 32) * 0.40)::numeric, 4)
        ELSE COALESCE(cp.search_score, 0)
      END AS final_rank,
      om.organization_id,
      o.name AS organization_name,
      o.logo_url AS organization_logo,
      cp.marketplace_roles,
      cp.categories,
      cp.content_types,
      cp.languages,
      cp.level,
      cp.last_active_at
    FROM creator_profiles cp
    LEFT JOIN organization_members om ON om.user_id = cp.user_id
    LEFT JOIN organizations o ON o.id = om.organization_id
    WHERE
      cp.is_active = true
      AND COALESCE(cp.is_published, true) = true
      AND COALESCE(cp.portfolio_count, 0) > 0
      AND cp.user_id NOT IN (
        SELECT cu.user_id FROM public.client_users cu
        UNION
        SELECT omx.user_id FROM public.organization_members omx WHERE omx.role = 'client'::app_role
      )
      AND (v_tsquery IS NULL OR cp.search_vector @@ v_tsquery)
      AND (p_roles IS NULL OR cp.primary_role = ANY(p_roles) OR cp.marketplace_roles && p_roles)
      AND (p_location_country IS NULL OR cp.location_country ILIKE p_location_country OR cp.location_country ILIKE '%' || p_location_country || '%')
      AND (p_location_city IS NULL OR cp.location_city ILIKE '%' || p_location_city || '%')
      AND (p_niches IS NULL OR cp.niches && p_niches OR cp.categories && p_niches)
      AND (p_min_rating IS NULL OR cp.rating_avg >= p_min_rating)
      AND (p_max_price IS NULL OR cp.base_price <= p_max_price)
      AND (p_accepts_exchange IS NULL OR cp.accepts_product_exchange = p_accepts_exchange)
      AND (p_is_available IS NULL OR cp.is_available = p_is_available)
    ORDER BY cp.id
  )
  SELECT
    rc.id,
    rc.user_id,
    rc.display_name,
    rc.username,
    rc.slug,
    rc.avatar_url,
    rc.bio,
    rc.primary_role,
    rc.location_city,
    rc.location_country,
    rc.rating_avg,
    rc.rating_count,
    rc.total_projects,
    rc.response_time_hours,
    rc.base_price,
    rc.currency,
    rc.accepts_exchange,
    rc.is_verified,
    rc.portfolio_count,
    rc.portfolio_thumbnail,
    rc.search_score,
    rc.quality_score,
    rc.activity_score,
    rc.text_rank,
    rc.final_rank,
    rc.organization_id,
    rc.organization_name,
    rc.organization_logo,
    rc.marketplace_roles,
    rc.categories,
    rc.content_types,
    rc.languages,
    rc.level
  FROM ranked_creators rc
  ORDER BY rc.final_rank DESC, rc.last_active_at DESC NULLS LAST
  LIMIT p_limit OFFSET p_offset;
END;
$$;

GRANT EXECUTE ON FUNCTION search_marketplace_creators TO authenticated;
GRANT EXECUTE ON FUNCTION search_marketplace_creators TO anon;

NOTIFY pgrst, 'reload schema';

-- ========== 20260306100000_fix_validate_registration_code_v3.sql ==========
-- Fix: Recrear funciones de validación de registro

-- Eliminar funciones existentes
DROP FUNCTION IF EXISTS public.check_registration_rate_limit(TEXT, UUID);
DROP FUNCTION IF EXISTS public.validate_registration_code(TEXT, TEXT, TEXT);

-- Crear tabla de intentos de registro si no existe
CREATE TABLE IF NOT EXISTS public.registration_attempts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  ip_address TEXT NOT NULL,
  organization_id UUID REFERENCES public.organizations(id) ON DELETE CASCADE,
  attempted_code TEXT,
  success BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Índice para rate limiting
CREATE INDEX IF NOT EXISTS idx_registration_attempts_rate_limit
ON public.registration_attempts(ip_address, organization_id, created_at);

-- Función auxiliar para rate limiting
CREATE OR REPLACE FUNCTION public.check_registration_rate_limit(p_ip TEXT, p_org_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  failed_attempts INT;
BEGIN
  SELECT COUNT(*) INTO failed_attempts
  FROM public.registration_attempts
  WHERE ip_address = p_ip
    AND organization_id = p_org_id
    AND success = false
    AND created_at > now() - interval '1 hour';

  RETURN failed_attempts < 10;
END;
$$;

-- Función principal para validar código de registro
CREATE OR REPLACE FUNCTION public.validate_registration_code(org_slug TEXT, code TEXT, ip TEXT DEFAULT 'unknown')
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  org_record RECORD;
BEGIN
  SELECT * INTO org_record
  FROM public.organizations
  WHERE slug = org_slug;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('valid', false, 'message', 'Organización no encontrada');
  END IF;

  IF NOT COALESCE(org_record.is_registration_open, false) THEN
    RETURN jsonb_build_object('valid', false, 'message', 'El registro no está habilitado para esta organización');
  END IF;

  IF ip NOT IN ('client', 'unknown') THEN
    IF NOT check_registration_rate_limit(ip, org_record.id) THEN
      RETURN jsonb_build_object('valid', false, 'message', 'Demasiados intentos. Intenta más tarde.');
    END IF;
  END IF;

  IF COALESCE(org_record.registration_require_invite, true) THEN
    IF org_record.registration_code IS NULL OR upper(org_record.registration_code) != upper(code) THEN
      INSERT INTO public.registration_attempts (ip_address, organization_id, attempted_code, success)
      VALUES (COALESCE(NULLIF(ip, 'client'), 'unknown'), org_record.id, code, false);

      RETURN jsonb_build_object('valid', false, 'message', 'Código inválido o expirado');
    END IF;
  END IF;

  INSERT INTO public.registration_attempts (ip_address, organization_id, attempted_code, success)
  VALUES (COALESCE(NULLIF(ip, 'client'), 'unknown'), org_record.id, code, true);

  RETURN jsonb_build_object(
    'valid', true,
    'organization_id', org_record.id,
    'organization_name', org_record.name,
    'default_role', COALESCE(org_record.default_role, 'creator'),
    'page_config', COALESCE(org_record.registration_page_config, '{}'::jsonb)
  );
END;
$$;

GRANT EXECUTE ON FUNCTION public.check_registration_rate_limit(TEXT, UUID) TO anon;
GRANT EXECUTE ON FUNCTION public.check_registration_rate_limit(TEXT, UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION public.validate_registration_code(TEXT, TEXT, TEXT) TO anon;
GRANT EXECUTE ON FUNCTION public.validate_registration_code(TEXT, TEXT, TEXT) TO authenticated;

NOTIFY pgrst, 'reload schema';

-- ========== 20260306160000_fix_get_pending_consents.sql ==========
-- =====================================================
-- Fix: get_pending_consents usaba member_id que no existe
-- La tabla organization_member_roles tiene user_id directamente
-- También se arregla el cast de app_role a TEXT
-- =====================================================

CREATE OR REPLACE FUNCTION get_pending_consents(p_user_id UUID)
RETURNS TABLE (
  document_id UUID,
  document_type TEXT,
  title TEXT,
  version TEXT,
  summary TEXT,
  is_required BOOLEAN
) AS $$
DECLARE
  v_user_roles TEXT[];
  v_org_roles TEXT[];
BEGIN
  -- Inicializar con 'all'
  v_user_roles := ARRAY['all'];

  -- Verificar si tiene creator_profile
  IF EXISTS (SELECT 1 FROM creator_profiles WHERE user_id = p_user_id) THEN
    v_user_roles := array_append(v_user_roles, 'creator');
  END IF;

  -- Agregar roles organizacionales (corregido: usar user_id directamente y cast a TEXT)
  SELECT COALESCE(array_agg(DISTINCT omr.role::TEXT), ARRAY[]::TEXT[])
  INTO v_org_roles
  FROM organization_member_roles omr
  WHERE omr.user_id = p_user_id;

  v_user_roles := v_user_roles || v_org_roles;

  -- Verificar si es cliente/marca
  IF EXISTS (SELECT 1 FROM client_users WHERE user_id = p_user_id) THEN
    v_user_roles := array_append(v_user_roles, 'brand');
    v_user_roles := array_append(v_user_roles, 'client');
  END IF;

  -- Verificar si pertenece a una organización
  IF EXISTS (SELECT 1 FROM organization_members WHERE user_id = p_user_id) THEN
    v_user_roles := array_append(v_user_roles, 'organization');
  END IF;

  RETURN QUERY
  SELECT
    ld.id AS document_id,
    ld.document_type,
    ld.title,
    ld.version,
    ld.summary,
    lcr.is_required
  FROM legal_documents ld
  JOIN legal_consent_requirements lcr ON lcr.document_type = ld.document_type
  WHERE ld.is_current = true
    AND lcr.user_role = ANY(v_user_roles)
    AND NOT EXISTS (
      SELECT 1 FROM user_legal_consents ulc
      WHERE ulc.user_id = p_user_id
        AND ulc.document_id = ld.id
        AND ulc.accepted = true
        AND ulc.is_current = true
    );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION get_pending_consents(UUID) TO authenticated;

NOTIFY pgrst, 'reload schema';

-- ========== 20260306220000_adn_recargado_v3.sql ==========
-- =============================================
-- ADN RECARGADO v3 - DATABASE SCHEMA
-- Nuevas columnas y tabla de sesiones para el
-- sistema de research de 22 pasos
-- =============================================

-- =============================================
-- 1. NUEVAS COLUMNAS EN TABLA PRODUCTS
-- =============================================

-- Columna para almacenar las 22 pestañas del research v3
ALTER TABLE products
ADD COLUMN IF NOT EXISTS full_research_v3 JSONB DEFAULT NULL;

COMMENT ON COLUMN products.full_research_v3 IS 'ADN Recargado v3: 22 pestañas de research completo. Estructura: { version: 3, generated_at: timestamp, tabs: { tab_1_market: {...}, ..., tab_22_summary: {...} }, metadata: { inputs_used: {...}, ai_providers: [...], tokens_consumed: number } }';

-- Columna para tracking del progreso en tiempo real
ALTER TABLE products
ADD COLUMN IF NOT EXISTS research_v3_progress JSONB DEFAULT NULL;

COMMENT ON COLUMN products.research_v3_progress IS 'Progreso del research v3 en tiempo real. Estructura: { current_step: number, total_steps: 22, steps: [ { id: string, name: string, status: pending|running|completed|error, started_at: timestamp, completed_at: timestamp, tokens_used: number } ] }';

-- Índice para búsqueda de productos con research v3 completado
CREATE INDEX IF NOT EXISTS idx_products_research_v3_status
ON products USING btree ((full_research_v3 IS NOT NULL));

-- =============================================
-- 2. NUEVAS COLUMNAS EN TABLA PRODUCT_DNA
-- =============================================

-- Columna para Social Intelligence (reviews, comentarios, vocabulario real)
ALTER TABLE product_dna
ADD COLUMN IF NOT EXISTS social_intelligence JSONB DEFAULT NULL;

COMMENT ON COLUMN product_dna.social_intelligence IS 'Inteligencia social scrapeada: reviews, comentarios, vocabulario real del mercado. Estructura: { reviews_data: [...], social_comments: [...], vocabulary_extracted: { pain_words: [...], desire_words: [...], objection_phrases: [...] }, scraped_at: timestamp }';

-- Columna para Ad Intelligence (análisis de ads de competidores)
ALTER TABLE product_dna
ADD COLUMN IF NOT EXISTS ad_intelligence JSONB DEFAULT NULL;

COMMENT ON COLUMN product_dna.ad_intelligence IS 'Inteligencia de ads de competidores. Estructura: { meta_ads: {...}, tiktok_ads: {...}, dominant_hooks: [...], dominant_formats: [...], competitor_social: [...], analyzed_at: timestamp }';

-- Columna para snapshot del ADN de Marca al momento de generar el research
ALTER TABLE product_dna
ADD COLUMN IF NOT EXISTS client_dna_snapshot JSONB DEFAULT NULL;

COMMENT ON COLUMN product_dna.client_dna_snapshot IS 'Snapshot del ADN de Marca usado para coherencia. Estructura: { dna_id: string, dna_data: {...full dna_data...}, used_in_research: boolean, snapshot_at: timestamp }';

-- Columna para análisis emocional del audio (si no existe)
ALTER TABLE product_dna
ADD COLUMN IF NOT EXISTS emotional_analysis JSONB DEFAULT NULL;

COMMENT ON COLUMN product_dna.emotional_analysis IS 'Análisis emocional del audio del usuario: mood, confidence_level, passion_topics, concern_areas, recommended_tone';

-- =============================================
-- 3. NUEVA TABLA: ADN_RESEARCH_SESSIONS
-- Tracking de sesiones de research
-- =============================================

CREATE TABLE IF NOT EXISTS adn_research_sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  -- Relaciones
  product_id UUID NOT NULL REFERENCES products(id) ON DELETE CASCADE,
  product_dna_id UUID REFERENCES product_dna(id) ON DELETE SET NULL,
  client_dna_id UUID REFERENCES client_dna(id) ON DELETE SET NULL,
  organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  created_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,

  -- Configuración de inputs
  inputs_config JSONB NOT NULL DEFAULT '{}'::jsonb,
  -- { include_client_dna: boolean, include_social_intelligence: boolean, include_ad_intelligence: boolean, locations: [...] }

  -- Estado de la sesión
  status TEXT NOT NULL DEFAULT 'initializing'
    CHECK (status IN ('initializing', 'gathering_intelligence', 'researching', 'completed', 'error', 'cancelled')),

  -- Progreso detallado
  progress JSONB DEFAULT '{}'::jsonb,
  current_step INTEGER DEFAULT 0,
  total_steps INTEGER DEFAULT 22,

  -- Tokens y costos
  tokens_consumed INTEGER DEFAULT 0,
  estimated_cost_usd NUMERIC(10,4) DEFAULT 0,

  -- Resultado y errores
  result_snapshot JSONB,
  error_message TEXT,
  error_details JSONB,

  -- Timestamps
  started_at TIMESTAMPTZ DEFAULT now(),
  intelligence_completed_at TIMESTAMPTZ,
  research_completed_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- =============================================
-- 4. ÍNDICES PARA PERFORMANCE
-- =============================================

CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_product
ON adn_research_sessions(product_id);

CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_org
ON adn_research_sessions(organization_id);

CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_status
ON adn_research_sessions(status);

CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_created
ON adn_research_sessions(created_at DESC);

CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_product_status
ON adn_research_sessions(product_id, status);

-- Índice para encontrar la sesión más reciente completada por producto
CREATE INDEX IF NOT EXISTS idx_adn_research_sessions_product_completed
ON adn_research_sessions(product_id, completed_at DESC)
WHERE status = 'completed';

-- =============================================
-- 5. TRIGGER PARA UPDATED_AT
-- =============================================

CREATE OR REPLACE FUNCTION update_adn_research_sessions_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_adn_research_sessions_timestamp ON adn_research_sessions;
CREATE TRIGGER update_adn_research_sessions_timestamp
  BEFORE UPDATE ON adn_research_sessions
  FOR EACH ROW
  EXECUTE FUNCTION update_adn_research_sessions_updated_at();

-- =============================================
-- 6. RLS PARA ADN_RESEARCH_SESSIONS
-- =============================================

ALTER TABLE adn_research_sessions ENABLE ROW LEVEL SECURITY;

-- Los miembros de la organización pueden ver sesiones de su org
CREATE POLICY "members_select_research_sessions"
ON adn_research_sessions FOR SELECT TO authenticated
USING (
  organization_id IN (
    SELECT organization_id FROM organization_members
    WHERE user_id = auth.uid()
  )
);

-- Los miembros de la organización pueden crear sesiones
CREATE POLICY "members_insert_research_sessions"
ON adn_research_sessions FOR INSERT TO authenticated
WITH CHECK (
  organization_id IN (
    SELECT organization_id FROM organization_members
    WHERE user_id = auth.uid()
  )
);

-- Los miembros de la organización pueden actualizar sesiones
CREATE POLICY "members_update_research_sessions"
ON adn_research_sessions FOR UPDATE TO authenticated
USING (
  organization_id IN (
    SELECT organization_id FROM organization_members
    WHERE user_id = auth.uid()
  )
);

-- Los miembros de la organización pueden eliminar sesiones (solo borradores o con error)
CREATE POLICY "members_delete_research_sessions"
ON adn_research_sessions FOR DELETE TO authenticated
USING (
  organization_id IN (
    SELECT organization_id FROM organization_members
    WHERE user_id = auth.uid()
  )
  AND status IN ('initializing', 'error', 'cancelled')
);

-- =============================================
-- 7. GRANTS
-- =============================================

GRANT ALL ON adn_research_sessions TO authenticated;
GRANT ALL ON adn_research_sessions TO service_role;

-- =============================================
-- 8. FUNCIÓN HELPER PARA OBTENER ÚLTIMA SESIÓN COMPLETADA
-- =============================================

CREATE OR REPLACE FUNCTION get_latest_completed_research_session(p_product_id UUID)
RETURNS TABLE (
  session_id UUID,
  completed_at TIMESTAMPTZ,
  tokens_consumed INTEGER,
  tabs_count INTEGER
) AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id AS session_id,
    s.completed_at,
    s.tokens_consumed,
    COALESCE(jsonb_object_keys(p.full_research_v3->'tabs')::INTEGER, 0) AS tabs_count
  FROM adn_research_sessions s
  LEFT JOIN products p ON p.id = s.product_id
  WHERE s.product_id = p_product_id
    AND s.status = 'completed'
  ORDER BY s.completed_at DESC
  LIMIT 1;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION get_latest_completed_research_session(UUID) TO authenticated;

-- =============================================
-- 9. FUNCIÓN PARA ACTUALIZAR PROGRESO EN TIEMPO REAL
-- =============================================

CREATE OR REPLACE FUNCTION update_research_session_progress(
  p_session_id UUID,
  p_current_step INTEGER,
  p_step_status TEXT,
  p_step_name TEXT DEFAULT NULL,
  p_tokens_used INTEGER DEFAULT 0
)
RETURNS VOID AS $$
DECLARE
  v_progress JSONB;
BEGIN
  -- Obtener progreso actual
  SELECT progress INTO v_progress
  FROM adn_research_sessions
  WHERE id = p_session_id;

  -- Inicializar si es necesario
  IF v_progress IS NULL OR v_progress = '{}'::jsonb THEN
    v_progress = jsonb_build_object(
      'steps', '[]'::jsonb,
      'started_at', now()
    );
  END IF;

  -- Actualizar el paso específico
  v_progress = jsonb_set(
    v_progress,
    ARRAY['steps', (p_current_step - 1)::text],
    jsonb_build_object(
      'step', p_current_step,
      'name', COALESCE(p_step_name, 'Step ' || p_current_step),
      'status', p_step_status,
      'tokens_used', p_tokens_used,
      'updated_at', now()
    )
  );

  -- Actualizar la sesión
  UPDATE adn_research_sessions
  SET
    current_step = p_current_step,
    progress = v_progress,
    tokens_consumed = tokens_consumed + p_tokens_used,
    status = CASE
      WHEN p_step_status = 'error' THEN 'error'
      WHEN p_current_step >= 22 AND p_step_status = 'completed' THEN 'completed'
      ELSE status
    END,
    completed_at = CASE
      WHEN p_current_step >= 22 AND p_step_status = 'completed' THEN now()
      ELSE completed_at
    END,
    updated_at = now()
  WHERE id = p_session_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION update_research_session_progress(UUID, INTEGER, TEXT, TEXT, INTEGER) TO service_role;

