-- ========== 20260325100000_user_board_preferences.sql ==========
-- Migration: User Board Preferences
-- Stores per-user board customization settings with hybrid localStorage + Supabase sync

-- Create table for user board preferences
CREATE TABLE IF NOT EXISTS user_board_preferences (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,

  -- General preferences
  preferences JSONB NOT NULL DEFAULT '{
    "preferredView": "kanban",
    "cardSize": "normal",
    "compactMode": false,
    "defaultSort": {"field": "created_at", "direction": "desc"}
  }'::jsonb,

  -- Saved views (custom + presets)
  saved_views JSONB NOT NULL DEFAULT '[]'::jsonb,

  -- Active view ID (null = default)
  active_view_id TEXT,

  -- Table column configuration
  table_config JSONB NOT NULL DEFAULT '{
    "visibleColumns": ["title", "status", "client", "responsible", "deadline"],
    "columnOrder": ["title", "status", "client", "responsible", "deadline"],
    "columnWidths": {}
  }'::jsonb,

  -- Timestamps
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),

  -- Unique constraint per user per org
  UNIQUE(user_id, organization_id)
);

-- Add indexes
CREATE INDEX IF NOT EXISTS idx_user_board_prefs_user ON user_board_preferences(user_id);
CREATE INDEX IF NOT EXISTS idx_user_board_prefs_org ON user_board_preferences(organization_id);

-- Enable RLS
ALTER TABLE user_board_preferences ENABLE ROW LEVEL SECURITY;

-- RLS Policies
-- Users can read their own preferences
CREATE POLICY "Users can read own board preferences"
  ON user_board_preferences
  FOR SELECT
  USING (auth.uid() = user_id);

-- Users can insert their own preferences
CREATE POLICY "Users can insert own board preferences"
  ON user_board_preferences
  FOR INSERT
  WITH CHECK (auth.uid() = user_id);

-- Users can update their own preferences
CREATE POLICY "Users can update own board preferences"
  ON user_board_preferences
  FOR UPDATE
  USING (auth.uid() = user_id)
  WITH CHECK (auth.uid() = user_id);

-- Users can delete their own preferences
CREATE POLICY "Users can delete own board preferences"
  ON user_board_preferences
  FOR DELETE
  USING (auth.uid() = user_id);

-- Function to update updated_at timestamp
CREATE OR REPLACE FUNCTION update_board_preferences_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger for updated_at
DROP TRIGGER IF EXISTS trigger_board_preferences_updated_at ON user_board_preferences;
CREATE TRIGGER trigger_board_preferences_updated_at
  BEFORE UPDATE ON user_board_preferences
  FOR EACH ROW
  EXECUTE FUNCTION update_board_preferences_updated_at();

-- RPC function to upsert preferences (for sync)
CREATE OR REPLACE FUNCTION upsert_board_preferences(
  p_organization_id UUID,
  p_preferences JSONB DEFAULT NULL,
  p_saved_views JSONB DEFAULT NULL,
  p_active_view_id TEXT DEFAULT NULL,
  p_table_config JSONB DEFAULT NULL
)
RETURNS user_board_preferences
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_result user_board_preferences;
BEGIN
  INSERT INTO user_board_preferences (
    user_id,
    organization_id,
    preferences,
    saved_views,
    active_view_id,
    table_config
  )
  VALUES (
    auth.uid(),
    p_organization_id,
    COALESCE(p_preferences, '{"preferredView": "kanban", "cardSize": "normal"}'::jsonb),
    COALESCE(p_saved_views, '[]'::jsonb),
    p_active_view_id,
    COALESCE(p_table_config, '{"visibleColumns": [], "columnOrder": [], "columnWidths": {}}'::jsonb)
  )
  ON CONFLICT (user_id, organization_id)
  DO UPDATE SET
    preferences = COALESCE(p_preferences, user_board_preferences.preferences),
    saved_views = COALESCE(p_saved_views, user_board_preferences.saved_views),
    active_view_id = COALESCE(p_active_view_id, user_board_preferences.active_view_id),
    table_config = COALESCE(p_table_config, user_board_preferences.table_config),
    updated_at = now()
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;

-- RPC function to get preferences with defaults
CREATE OR REPLACE FUNCTION get_board_preferences(p_organization_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_prefs user_board_preferences;
BEGIN
  SELECT * INTO v_prefs
  FROM user_board_preferences
  WHERE user_id = auth.uid()
    AND organization_id = p_organization_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'preferences', '{"preferredView": "kanban", "cardSize": "normal", "compactMode": false}'::jsonb,
      'saved_views', '[]'::jsonb,
      'active_view_id', null,
      'table_config', '{"visibleColumns": ["title", "status", "client", "responsible", "deadline"], "columnOrder": [], "columnWidths": {}}'::jsonb,
      'updated_at', null
    );
  END IF;

  RETURN jsonb_build_object(
    'preferences', v_prefs.preferences,
    'saved_views', v_prefs.saved_views,
    'active_view_id', v_prefs.active_view_id,
    'table_config', v_prefs.table_config,
    'updated_at', v_prefs.updated_at
  );
END;
$$;

-- Grant execute permissions
GRANT EXECUTE ON FUNCTION upsert_board_preferences TO authenticated;
GRANT EXECUTE ON FUNCTION get_board_preferences TO authenticated;

COMMENT ON TABLE user_board_preferences IS 'Per-user board customization settings with hybrid sync support';

-- ========== 20260327_social_verification_tables.sql ==========
-- ============================================================================
-- KREOON SOCIAL VERIFICATION TABLES
-- Tables for social API integrations and influencer verification
-- ============================================================================

-- 1. OAuth states for social connections (temporary storage)
CREATE TABLE IF NOT EXISTS public.oauth_states (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  state text UNIQUE NOT NULL,
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  platform text NOT NULL,
  creator_profile_id uuid REFERENCES public.creator_profiles(id) ON DELETE SET NULL,
  return_url text,
  code_verifier text, -- For PKCE
  expires_at timestamptz NOT NULL,
  created_at timestamptz DEFAULT now()
);

-- Auto-cleanup expired states
CREATE INDEX IF NOT EXISTS idx_oauth_states_expires ON public.oauth_states(expires_at);

-- 2. Creator social connections (OAuth tokens and metrics)
CREATE TABLE IF NOT EXISTS public.creator_social_connections (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  creator_profile_id uuid REFERENCES public.creator_profiles(id) ON DELETE SET NULL,
  platform text NOT NULL, -- 'instagram', 'tiktok', 'youtube', 'twitter'
  platform_user_id text NOT NULL,
  platform_username text,
  -- OAuth tokens
  access_token text NOT NULL,
  refresh_token text,
  token_expires_at timestamptz,
  refresh_token_expires_at timestamptz,
  -- Metrics (synced from API)
  followers_count integer DEFAULT 0,
  following_count integer DEFAULT 0,
  posts_count integer DEFAULT 0,
  likes_count integer DEFAULT 0, -- Total likes received (TikTok)
  engagement_rate numeric(5,2) DEFAULT 0,
  -- Verification
  is_verified boolean DEFAULT false,
  verification_status text, -- 'verified', 'mismatch', 'pending', 'error', 'expired'
  declared_followers integer,
  actual_followers integer,
  variance_pct numeric(5,2),
  verified_at timestamptz,
  -- Metadata
  last_synced_at timestamptz,
  metadata jsonb DEFAULT '{}',
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now(),
  -- Constraints
  CONSTRAINT unique_user_platform UNIQUE(user_id, platform)
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_creator_social_profile ON public.creator_social_connections(creator_profile_id);
CREATE INDEX IF NOT EXISTS idx_creator_social_platform ON public.creator_social_connections(platform);
CREATE INDEX IF NOT EXISTS idx_creator_social_verified ON public.creator_social_connections(is_verified) WHERE is_verified = true;

-- 3. Creator verified metrics (historical snapshots)
CREATE TABLE IF NOT EXISTS public.creator_verified_metrics (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  creator_profile_id uuid REFERENCES public.creator_profiles(id) ON DELETE SET NULL,
  platform text NOT NULL,
  -- Metrics at verification time
  followers_count integer NOT NULL,
  following_count integer DEFAULT 0,
  posts_count integer DEFAULT 0,
  likes_count integer DEFAULT 0,
  engagement_rate numeric(5,2),
  avg_views integer,
  avg_likes integer,
  avg_comments integer,
  -- Verification details
  declared_followers integer,
  variance_pct numeric(5,2),
  is_verified boolean DEFAULT false,
  verification_status text,
  verification_source text, -- 'api', 'manual', 'screenshot'
  verified_at timestamptz NOT NULL,
  -- Timestamps
  created_at timestamptz DEFAULT now()
);

-- Index for historical queries
CREATE INDEX IF NOT EXISTS idx_verified_metrics_profile ON public.creator_verified_metrics(creator_profile_id, verified_at DESC);

-- 4. Creator verification history (audit trail)
CREATE TABLE IF NOT EXISTS public.creator_verification_history (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  creator_profile_id uuid NOT NULL REFERENCES public.creator_profiles(id) ON DELETE CASCADE,
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  -- Verification result
  overall_verified boolean NOT NULL,
  verification_score integer DEFAULT 0, -- 0-100
  platforms_data jsonb DEFAULT '[]', -- Array of platform verification results
  badges_earned text[] DEFAULT '{}',
  alerts jsonb DEFAULT '[]',
  -- Who verified
  verified_by uuid REFERENCES auth.users(id) ON DELETE SET NULL,
  verified_at timestamptz NOT NULL,
  -- Timestamps
  created_at timestamptz DEFAULT now()
);

-- Index
CREATE INDEX IF NOT EXISTS idx_verification_history_profile ON public.creator_verification_history(creator_profile_id, verified_at DESC);

-- 5. Campaign ROI metrics (aggregated)
CREATE TABLE IF NOT EXISTS public.campaign_roi_metrics (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id uuid NOT NULL REFERENCES public.marketplace_campaigns(id) ON DELETE CASCADE,
  -- Period
  period_start date NOT NULL,
  period_end date NOT NULL,
  -- Investment
  total_investment numeric(12,2) DEFAULT 0,
  currency text DEFAULT 'USD',
  total_videos integer DEFAULT 0,
  total_creators integer DEFAULT 0,
  -- Performance metrics
  total_views bigint DEFAULT 0,
  total_likes bigint DEFAULT 0,
  total_comments bigint DEFAULT 0,
  total_shares bigint DEFAULT 0,
  total_saves bigint DEFAULT 0,
  avg_engagement_rate numeric(5,2) DEFAULT 0,
  -- Cost metrics
  cost_per_video numeric(10,2) DEFAULT 0,
  cost_per_view numeric(10,6) DEFAULT 0,
  cost_per_engagement numeric(10,4) DEFAULT 0,
  cost_per_thousand_views numeric(10,2) DEFAULT 0,
  -- Value estimation
  estimated_value numeric(12,2) DEFAULT 0,
  roi_multiplier numeric(6,2) DEFAULT 0,
  roi_percentage numeric(8,2) DEFAULT 0,
  -- Timestamps
  calculated_at timestamptz DEFAULT now(),
  created_at timestamptz DEFAULT now(),
  -- Unique per campaign/period
  CONSTRAINT unique_campaign_period UNIQUE(campaign_id, period_start, period_end)
);

-- Index
CREATE INDEX IF NOT EXISTS idx_roi_metrics_campaign ON public.campaign_roi_metrics(campaign_id);

-- 6. Add verification columns to creator_profiles if not exist
DO $$
BEGIN
  -- Add verification_score column
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'creator_profiles' AND column_name = 'verification_score'
  ) THEN
    ALTER TABLE public.creator_profiles ADD COLUMN verification_score integer DEFAULT 0;
  END IF;

  -- Add verification_badges column
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'creator_profiles' AND column_name = 'verification_badges'
  ) THEN
    ALTER TABLE public.creator_profiles ADD COLUMN verification_badges text[] DEFAULT '{}';
  END IF;

  -- Add verified_at column if not exists
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'creator_profiles' AND column_name = 'verified_at'
  ) THEN
    ALTER TABLE public.creator_profiles ADD COLUMN verified_at timestamptz;
  END IF;
END $$;

