-- ========== 20260330_sync_social_links_bidirectional.sql ==========
-- ============================================================================
-- Migracion: Sincronizacion bidireccional de redes sociales
-- profiles <-> creator_profiles
-- Fecha: 2026-03-30
-- ============================================================================
--
-- PROBLEMA:
-- - profiles tiene columnas individuales: instagram, tiktok, facebook,
--   social_linkedin, social_youtube, social_twitter
-- - creator_profiles tiene columna JSONB: social_links
-- - No habia sincronizacion completa entre ambas tablas
--
-- SOLUCION:
-- 1. Actualizar trigger profiles -> creator_profiles (todas las redes)
-- 2. Crear nuevo trigger creator_profiles -> profiles (direccion inversa)
-- ============================================================================

-- 1. Actualizar funcion profiles -> creator_profiles (incluir TODAS las redes)
CREATE OR REPLACE FUNCTION public.sync_profile_updates_to_marketplace()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
BEGIN
  UPDATE public.creator_profiles
  SET
    display_name = COALESCE(NULLIF(TRIM(NEW.full_name), ''), display_name),
    avatar_url = COALESCE(NEW.avatar_url, avatar_url),
    location_city = COALESCE(NEW.city, location_city),
    location_country = COALESCE(NEW.country, location_country),
    -- Sincronizar TODAS las redes sociales
    social_links = jsonb_strip_nulls(
      COALESCE(social_links, '{}'::jsonb)
      || jsonb_build_object(
        'instagram', NULLIF(NEW.instagram, ''),
        'tiktok', NULLIF(NEW.tiktok, ''),
        'facebook', NULLIF(NEW.facebook, ''),
        'youtube', NULLIF(NEW.social_youtube, ''),
        'linkedin', NULLIF(NEW.social_linkedin, ''),
        'twitter', NULLIF(NEW.social_twitter, '')
      )
    ),
    updated_at = now()
  WHERE user_id = NEW.id;

  RETURN NEW;
END;
$function$;

-- 2. Crear funcion creator_profiles -> profiles (direccion inversa)
CREATE OR REPLACE FUNCTION public.sync_marketplace_to_profile()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
BEGIN
  -- Solo sincronizar si social_links cambio
  IF OLD.social_links IS DISTINCT FROM NEW.social_links THEN
    UPDATE public.profiles
    SET
      instagram = COALESCE(NEW.social_links->>'instagram', instagram),
      tiktok = COALESCE(NEW.social_links->>'tiktok', tiktok),
      facebook = COALESCE(NEW.social_links->>'facebook', facebook),
      social_youtube = COALESCE(NEW.social_links->>'youtube', social_youtube),
      social_linkedin = COALESCE(NEW.social_links->>'linkedin', social_linkedin),
      social_twitter = COALESCE(NEW.social_links->>'twitter', social_twitter),
      updated_at = now()
    WHERE id = NEW.user_id;
  END IF;

  RETURN NEW;
END;
$function$;

-- 3. Crear trigger para creator_profiles -> profiles
DROP TRIGGER IF EXISTS trigger_sync_marketplace_to_profile ON public.creator_profiles;

CREATE TRIGGER trigger_sync_marketplace_to_profile
  AFTER UPDATE OF social_links ON public.creator_profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_marketplace_to_profile();

-- 4. Comentarios para documentacion
COMMENT ON FUNCTION public.sync_profile_updates_to_marketplace() IS
'Sincroniza cambios de profiles a creator_profiles (redes sociales, avatar, ubicacion)';

COMMENT ON FUNCTION public.sync_marketplace_to_profile() IS
'Sincroniza cambios de social_links en creator_profiles de vuelta a profiles';

-- 5. Sincronizacion inicial de datos existentes (one-time)
-- Actualizar creator_profiles con datos de profiles que no esten sincronizados
UPDATE public.creator_profiles cp
SET social_links = jsonb_strip_nulls(
  COALESCE(cp.social_links, '{}'::jsonb)
  || jsonb_build_object(
    'instagram', NULLIF(p.instagram, ''),
    'tiktok', NULLIF(p.tiktok, ''),
    'facebook', NULLIF(p.facebook, ''),
    'youtube', NULLIF(p.social_youtube, ''),
    'linkedin', NULLIF(p.social_linkedin, ''),
    'twitter', NULLIF(p.social_twitter, '')
  )
)
FROM public.profiles p
WHERE cp.user_id = p.id
AND (
  p.instagram IS NOT NULL OR
  p.tiktok IS NOT NULL OR
  p.facebook IS NOT NULL OR
  p.social_youtube IS NOT NULL OR
  p.social_linkedin IS NOT NULL OR
  p.social_twitter IS NOT NULL
);

-- ========== 20260330_user_specializations.sql ==========
-- ============================================================================
-- MIGRATION: user_specializations table
-- Date: 2026-03-30
-- Description: Tabla para almacenar especializaciones de usuarios
-- ============================================================================

-- Crear tabla user_specializations
CREATE TABLE IF NOT EXISTS user_specializations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  specialization TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(user_id, specialization)
);

-- Comentario de tabla
COMMENT ON TABLE user_specializations IS 'Especializaciones seleccionadas por usuarios (max 5 por usuario)';
COMMENT ON COLUMN user_specializations.specialization IS 'ID de especializacion: ugc, video_editor, seo, etc.';

-- Indices para busquedas
CREATE INDEX IF NOT EXISTS idx_user_specializations_user ON user_specializations(user_id);
CREATE INDEX IF NOT EXISTS idx_user_specializations_spec ON user_specializations(specialization);

-- Habilitar RLS
ALTER TABLE user_specializations ENABLE ROW LEVEL SECURITY;

-- Politica: Usuarios pueden ver sus propias especializaciones
CREATE POLICY "Users can view own specializations"
  ON user_specializations FOR SELECT
  USING (auth.uid() = user_id);

-- Politica: Usuarios pueden gestionar sus propias especializaciones
CREATE POLICY "Users can insert own specializations"
  ON user_specializations FOR INSERT
  WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can delete own specializations"
  ON user_specializations FOR DELETE
  USING (auth.uid() = user_id);

-- Politica: Perfiles publicos permiten ver especializaciones
CREATE POLICY "Anyone can view specializations of public profiles"
  ON user_specializations FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM profiles
      WHERE profiles.id = user_specializations.user_id
      AND profiles.is_public = true
    )
  );

-- Politica: Admins de plataforma pueden ver todas
CREATE POLICY "Platform admins can view all specializations"
  ON user_specializations FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM profiles
      WHERE profiles.id = auth.uid()
      AND profiles.is_superadmin = true
    )
  );

-- Funcion para validar limite de especializaciones (max 5)
CREATE OR REPLACE FUNCTION check_specializations_limit()
RETURNS TRIGGER AS $$
BEGIN
  IF (
    SELECT COUNT(*) FROM user_specializations WHERE user_id = NEW.user_id
  ) >= 5 THEN
    RAISE EXCEPTION 'Maximum 5 specializations per user allowed';
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger para validar limite antes de insertar
DROP TRIGGER IF EXISTS enforce_specializations_limit ON user_specializations;
CREATE TRIGGER enforce_specializations_limit
  BEFORE INSERT ON user_specializations
  FOR EACH ROW
  EXECUTE FUNCTION check_specializations_limit();

-- ========== 20260330100000_add_specializations_to_search.sql ==========
-- ============================================================
-- ADD: Specializations al RPC search_marketplace_creators
-- Migration: 20260330100000_add_specializations_to_search
-- ============================================================

DROP FUNCTION IF EXISTS search_marketplace_creators(text, text[], text, text, text[], text[], numeric, numeric, boolean, boolean, integer, integer);
DROP FUNCTION IF EXISTS search_marketplace_creators(text, text[], text, text, text[], numeric, numeric, boolean, boolean, integer, integer);

CREATE OR REPLACE FUNCTION search_marketplace_creators(
  p_query              text    DEFAULT '',
  p_roles              text[]  DEFAULT NULL,
  p_location_country   text    DEFAULT NULL,
  p_location_city      text    DEFAULT NULL,
  p_niches             text[]  DEFAULT NULL,
  p_specializations    text[]  DEFAULT NULL,  -- NUEVO parámetro
  p_min_rating         numeric DEFAULT NULL,
  p_max_price          numeric DEFAULT NULL,
  p_accepts_exchange   boolean DEFAULT NULL,
  p_is_available       boolean DEFAULT NULL,
  p_limit              integer DEFAULT 20,
  p_offset             integer DEFAULT 0
)
RETURNS TABLE (
  id                  uuid,
  user_id             uuid,
  display_name        text,
  username            text,
  slug                text,
  avatar_url          text,
  bio                 text,
  primary_role        text,
  location_city       text,
  location_country    text,
  rating_avg          numeric,
  rating_count        integer,
  total_projects      integer,
  response_time_hours integer,
  base_price          numeric,
  currency            text,
  accepts_exchange    boolean,
  is_verified         boolean,
  portfolio_count     integer,
  portfolio_thumbnail text,
  search_score        numeric,
  quality_score       numeric,
  activity_score      numeric,
  text_rank           real,
  final_rank          numeric,
  organization_id     uuid,
  organization_name   text,
  organization_logo   text,
  marketplace_roles   text[],
  categories          text[],
  content_types       text[],
  languages           text[],
  level               text,
  specializations     text[]  -- NUEVO campo de retorno
)
LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
  v_tsquery tsquery;
BEGIN
  IF p_query IS NOT NULL AND length(trim(p_query)) > 0 THEN
    v_tsquery := websearch_to_tsquery('spanish', p_query);
  END IF;

  RETURN QUERY
  WITH creator_specs AS (
    SELECT
      us.user_id,
      array_agg(us.specialization ORDER BY us.created_at) as specs
    FROM user_specializations us
    GROUP BY us.user_id
  ),
  ranked_creators AS (
    SELECT DISTINCT ON (cp.id)
      cp.id,
      cp.user_id,
      cp.display_name,
      cp.username,
      cp.slug,
      cp.avatar_url,
      cp.bio,
      cp.primary_role,
      cp.location_city,
      cp.location_country,
      cp.rating_avg,
      cp.rating_count,
      cp.total_projects,
      cp.response_time_hours,
      cp.base_price,
      cp.currency,
      cp.accepts_product_exchange AS accepts_exchange,
      cp.is_verified,
      cp.portfolio_count,
      COALESCE(
        (SELECT pi.thumbnail_url FROM portfolio_items pi
         WHERE pi.creator_id = cp.id AND pi.is_public = true AND pi.thumbnail_url IS NOT NULL AND pi.thumbnail_url != ''
         ORDER BY pi.is_featured DESC, pi.display_order ASC LIMIT 1),
        (SELECT pi.media_url FROM portfolio_items pi
         WHERE pi.creator_id = cp.id AND pi.is_public = true AND pi.media_type = 'image' AND pi.media_url IS NOT NULL
         ORDER BY pi.is_featured DESC, pi.display_order ASC LIMIT 1),
        (SELECT c.thumbnail_url FROM content c
         WHERE c.creator_id = cp.user_id AND c.is_published = true AND c.thumbnail_url IS NOT NULL AND c.thumbnail_url != ''
         ORDER BY c.created_at DESC LIMIT 1),
        (SELECT REPLACE(c.bunny_embed_url, '/embed/', '/thumbnail/') || '?time=1' FROM content c
         WHERE c.creator_id = cp.user_id AND c.is_published = true AND c.bunny_embed_url IS NOT NULL AND c.bunny_embed_url LIKE '%bunny%'
         ORDER BY c.created_at DESC LIMIT 1),
        (SELECT pp.thumbnail_url FROM portfolio_posts pp
         WHERE pp.user_id = cp.user_id AND pp.thumbnail_url IS NOT NULL AND pp.thumbnail_url != ''
         ORDER BY pp.created_at DESC LIMIT 1)
      ) AS portfolio_thumbnail,
      cp.search_score,
      cp.quality_score,
      cp.activity_score,
      CASE
        WHEN v_tsquery IS NOT NULL THEN ts_rank_cd(cp.search_vector, v_tsquery, 32)
        ELSE 0.0
      END AS text_rank,
      CASE
        WHEN v_tsquery IS NOT NULL THEN
          ROUND((COALESCE(cp.search_score, 0) * 0.60 + ts_rank_cd(cp.search_vector, v_tsquery, 32) * 0.40)::numeric, 4)
        ELSE COALESCE(cp.search_score, 0)
      END AS final_rank,
      om.organization_id,
      o.name AS organization_name,
      o.logo_url AS organization_logo,
      cp.marketplace_roles,
      cp.categories,
      cp.content_types,
      cp.languages,
      cp.level,
      COALESCE(cs.specs, ARRAY[]::text[]) AS specializations,
      cp.last_active_at
    FROM creator_profiles cp
    LEFT JOIN organization_members om ON om.user_id = cp.user_id
    LEFT JOIN organizations o ON o.id = om.organization_id
    LEFT JOIN creator_specs cs ON cs.user_id = cp.user_id
    WHERE
      cp.is_active = true
      AND COALESCE(cp.is_published, true) = true
      AND COALESCE(cp.portfolio_count, 0) > 0
      AND cp.user_id NOT IN (
        SELECT cu.user_id FROM public.client_users cu
        UNION
        SELECT omx.user_id FROM public.organization_members omx WHERE omx.role = 'client'::app_role
      )
      AND (v_tsquery IS NULL OR cp.search_vector @@ v_tsquery)
      AND (p_roles IS NULL OR cp.primary_role = ANY(p_roles) OR cp.marketplace_roles && p_roles)
      AND (p_location_country IS NULL OR cp.location_country ILIKE p_location_country OR cp.location_country ILIKE '%' || p_location_country || '%')
      AND (p_location_city IS NULL OR cp.location_city ILIKE '%' || p_location_city || '%')
      AND (p_niches IS NULL OR cp.niches && p_niches OR cp.categories && p_niches)
      AND (p_specializations IS NULL OR cs.specs && p_specializations)
      AND (p_min_rating IS NULL OR cp.rating_avg >= p_min_rating)
      AND (p_max_price IS NULL OR cp.base_price <= p_max_price)
      AND (p_accepts_exchange IS NULL OR cp.accepts_product_exchange = p_accepts_exchange)
      AND (p_is_available IS NULL OR cp.is_available = p_is_available)
    ORDER BY cp.id
  )
  SELECT
    rc.id,
    rc.user_id,
    rc.display_name,
    rc.username,
    rc.slug,
    rc.avatar_url,
    rc.bio,
    rc.primary_role,
    rc.location_city,
    rc.location_country,
    rc.rating_avg,
    rc.rating_count,
    rc.total_projects,
    rc.response_time_hours,
    rc.base_price,
    rc.currency,
    rc.accepts_exchange,
    rc.is_verified,
    rc.portfolio_count,
    rc.portfolio_thumbnail,
    rc.search_score,
    rc.quality_score,
    rc.activity_score,
    rc.text_rank,
    rc.final_rank,
    rc.organization_id,
    rc.organization_name,
    rc.organization_logo,
    rc.marketplace_roles,
    rc.categories,
    rc.content_types,
    rc.languages,
    rc.level,
    rc.specializations
  FROM ranked_creators rc
  ORDER BY rc.final_rank DESC, rc.last_active_at DESC NULLS LAST
  LIMIT p_limit OFFSET p_offset;
END;
$$;

GRANT EXECUTE ON FUNCTION search_marketplace_creators TO authenticated;
GRANT EXECUTE ON FUNCTION search_marketplace_creators TO anon;

NOTIFY pgrst, 'reload schema';

