-- ========== 20260330130000_fix_marketplace_rls.sql ==========
-- =============================================================================
-- FIX: Marketplace RLS - PARTE 1: Agregar status 'open' al enum campaign_status
-- NOTA: Esta migración se aplicó en dos partes porque PostgreSQL requiere
-- commit del nuevo valor de enum antes de usarlo en otras sentencias.
-- =============================================================================

-- Agregar 'open' al enum campaign_status
-- 'open' representa una campaña publicada y receptiva a aplicaciones.
-- Es el estado previo a 'active' (cuando ya hay creators asignados).
ALTER TYPE public.campaign_status ADD VALUE IF NOT EXISTS 'open' AFTER 'draft';

-- ========== 20260330130001_fix_marketplace_rls_policies.sql ==========
-- =============================================================================
-- FIX: Marketplace RLS - PARTE 2: Actualizar políticas RLS
-- Problema raíz:
--   1. La política SELECT de marketplace_campaigns solo permitía leer campañas
--      con status IN ('active','in_progress','completed'), bloqueando 'open'.
--   2. campaign_applications no tiene política para usuarios sin creator_profile.
--   3. marketplace_projects no permite lectura a admins de org sin participación
--      directa, bloqueando algunas vistas administrativas.
-- =============================================================================

-- ----------------------------------------------------------------------------
-- 1. ACTUALIZAR POLÍTICA RLS SELECT DE marketplace_campaigns
-- Reemplaza "Campaigns visible based on visibility rules" para incluir 'open'.
-- ----------------------------------------------------------------------------

DROP POLICY IF EXISTS "Campaigns visible based on visibility rules" ON public.marketplace_campaigns;

CREATE POLICY "Campaigns visible based on visibility rules"
  ON public.marketplace_campaigns FOR SELECT
  USING (
    -- El creador de la campaña siempre la ve
    created_by = auth.uid()
    -- Miembros de la brand siempre la ven
    OR (brand_id IS NOT NULL AND public.is_brand_member(brand_id))
    -- Miembros de la org siempre la ven
    OR (organization_id IS NOT NULL AND public.is_org_member(organization_id))
    -- Campañas públicas con status visible (incluye 'open')
    OR (
      visibility = 'public'
      AND status IN ('open', 'active', 'in_progress', 'completed')
    )
    -- Campañas selectivas para usuarios invitados
    OR (
      visibility = 'selective'
      AND status IN ('open', 'active', 'in_progress', 'completed')
      AND EXISTS (
        SELECT 1 FROM public.campaign_invitations ci
        WHERE ci.campaign_id = marketplace_campaigns.id
          AND ci.invited_profile_id = auth.uid()
          AND ci.status IN ('pending', 'accepted')
      )
    )
  );

-- Permitir acceso anon a campañas públicas con status visible
-- (necesario para el marketplace público sin login)
DROP POLICY IF EXISTS "Anon can view public open campaigns" ON public.marketplace_campaigns;

CREATE POLICY "Anon can view public open campaigns"
  ON public.marketplace_campaigns FOR SELECT
  TO anon
  USING (
    visibility = 'public'
    AND status IN ('open', 'active', 'in_progress', 'completed')
  );

-- ----------------------------------------------------------------------------
-- 2. ACTUALIZAR FUNCIÓN can_see_campaign para incluir 'open'
-- Sincronizar la función helper con los nuevos valores permitidos.
-- ----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.can_see_campaign(_campaign_id uuid, _user_id uuid)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
STABLE
AS $$
DECLARE
  _visibility text;
  _org_id uuid;
  _brand_id uuid;
  _status text;
BEGIN
  SELECT visibility, organization_id, brand_id, status
  INTO _visibility, _org_id, _brand_id, _status
  FROM public.marketplace_campaigns
  WHERE id = _campaign_id;

  IF NOT FOUND THEN
    RETURN false;
  END IF;

  -- El creador siempre ve su propia campaña
  IF EXISTS (
    SELECT 1 FROM public.marketplace_campaigns
    WHERE id = _campaign_id AND created_by = _user_id
  ) THEN
    RETURN true;
  END IF;

  -- Miembros de la brand siempre la ven
  IF _brand_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.brand_members
    WHERE brand_id = _brand_id AND user_id = _user_id AND status = 'active'
  ) THEN
    RETURN true;
  END IF;

  -- Miembros de la org siempre la ven
  IF _org_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE organization_id = _org_id AND user_id = _user_id
  ) THEN
    RETURN true;
  END IF;

  -- Campañas públicas visibles con status abierto/activo/completado
  IF _visibility = 'public' AND _status IN ('open', 'active', 'in_progress', 'completed') THEN
    RETURN true;
  END IF;

  -- Campañas internas: solo miembros (ya cubierto arriba)
  IF _visibility = 'internal' THEN
    RETURN false;
  END IF;

  -- Campañas selectivas: solo si el usuario fue invitado
  IF _visibility = 'selective' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.campaign_invitations
      WHERE campaign_id = _campaign_id
        AND invited_profile_id = _user_id
        AND status IN ('pending', 'accepted')
    );
  END IF;

  RETURN false;
END;
$$;

-- ----------------------------------------------------------------------------
-- 3. CORREGIR POLÍTICA SELECT DE campaign_applications
-- Agregar acceso para administradores de la organización que gestionan campañas
-- y para usuarios autenticados que revisan sus propias aplicaciones por user_id
-- (no solo por creator_profile.user_id, cubriendo el caso de perfil no creado).
-- ----------------------------------------------------------------------------

DROP POLICY IF EXISTS "Applications visible to campaign brand and applicant" ON public.campaign_applications;

CREATE POLICY "Applications visible to campaign brand and applicant"
  ON public.campaign_applications FOR SELECT
  USING (
    -- El creator dueño del perfil ve sus aplicaciones
    EXISTS (
      SELECT 1 FROM public.creator_profiles cp
      WHERE cp.id = campaign_applications.creator_id
        AND cp.user_id = auth.uid()
    )
    -- Miembros de la brand de la campaña ven todas las aplicaciones
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_applications.campaign_id
        AND mc.brand_id IS NOT NULL
        AND public.is_brand_member(mc.brand_id)
    )
    -- Miembros de la org de la campaña ven todas las aplicaciones
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_applications.campaign_id
        AND mc.organization_id IS NOT NULL
        AND public.is_org_member(mc.organization_id)
    )
    -- El creador de la campaña ve todas sus aplicaciones
    OR EXISTS (
      SELECT 1 FROM public.marketplace_campaigns mc
      WHERE mc.id = campaign_applications.campaign_id
        AND mc.created_by = auth.uid()
    )
  );

-- ----------------------------------------------------------------------------
-- 4. CORREGIR POLÍTICA SELECT DE marketplace_projects
-- Agregar acceso para creadores de campaña y admins de org que necesitan
-- ver proyectos derivados de sus campañas sin ser participantes directos.
-- ----------------------------------------------------------------------------

DROP POLICY IF EXISTS "Project participants can view projects" ON public.marketplace_projects;

CREATE POLICY "Project participants can view projects"
  ON public.marketplace_projects FOR SELECT
  USING (
    -- Participante directo (creator, editor, brand member)
    public.is_project_participant(id)
    -- El creador de la campaña origen puede ver el proyecto
    OR (
      campaign_id IS NOT NULL
      AND EXISTS (
        SELECT 1 FROM public.marketplace_campaigns mc
        WHERE mc.id = marketplace_projects.campaign_id
          AND mc.created_by = auth.uid()
      )
    )
    -- Admin de la org de la campaña origen puede ver el proyecto
    OR (
      campaign_id IS NOT NULL
      AND EXISTS (
        SELECT 1 FROM public.marketplace_campaigns mc
        WHERE mc.id = marketplace_projects.campaign_id
          AND mc.organization_id IS NOT NULL
          AND public.is_org_admin(mc.organization_id)
      )
    )
  );

-- ========== 20260330140000_unify_marketplace_board_statuses.sql ==========
-- =============================================================================
-- Migración: Unificar estados del Marketplace con estados del Board de Org
-- Fecha: 30 de marzo de 2026
-- Descripción: Agregar estados faltantes al enum marketplace_project_status
--              para que el marketplace use los mismos estados que el board
-- =============================================================================

-- El enum marketplace_project_status actual tiene:
-- pending, briefing, in_progress, review, revision, approved, completed, cancelled

-- Los estados del board de organización son:
-- draft, script_pending, script_approved, assigned, recording, recorded,
-- editing, delivered, issue, corrected, approved, paid, en_campaa

-- Mapeo: Agregamos los estados de org que faltan en marketplace

-- 1. Agregar estados faltantes al enum (PostgreSQL solo permite ADD, no reorder)
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'draft';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'script_pending';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'script_approved';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'assigned';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'recording';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'recorded';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'editing';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'delivered';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'issue';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'corrected';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'paid';
ALTER TYPE public.marketplace_project_status ADD VALUE IF NOT EXISTS 'en_campaa';

-- ========== 20260330200000_add_user_type_to_profiles.sql ==========
-- ============================================================================
-- Migration: Add user_type to profiles
-- Description: Adds account type field to differentiate platform versions
--              (client, organization, talent)
-- ============================================================================

-- Add user_type column to profiles
ALTER TABLE profiles
ADD COLUMN IF NOT EXISTS user_type TEXT
CHECK (user_type IN ('client', 'organization', 'talent'));

-- Create index for queries by user type
CREATE INDEX IF NOT EXISTS idx_profiles_user_type ON profiles(user_type);

-- Add comment
COMMENT ON COLUMN profiles.user_type IS 'Tipo de cuenta: client (marca/empresa), organization (agencia), talent (creador independiente)';

-- ============================================================================
-- Migrate existing users based on their current data
-- ============================================================================

UPDATE profiles p
SET user_type = CASE
    -- Users with client role -> client
    WHEN p.active_role = 'client' THEN 'client'

    -- Users in client_users table -> client
    WHEN EXISTS (
        SELECT 1 FROM client_users cu WHERE cu.user_id = p.id
    ) THEN 'client'

    -- Organization owners -> organization
    WHEN EXISTS (
        SELECT 1 FROM organization_members om
        WHERE om.user_id = p.id
        AND om.is_owner = true
        AND om.deleted_at IS NULL
    ) THEN 'organization'

    -- Everyone else -> talent (default)
    ELSE 'talent'
END
WHERE p.user_type IS NULL;

-- ============================================================================
-- Update get_full_user_detail RPC to include user_type
-- ============================================================================

CREATE OR REPLACE FUNCTION get_full_user_detail(p_user_id uuid)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    result json;
BEGIN
    SELECT json_build_object(
        'id', p.id,
        'email', p.email,
        'full_name', p.full_name,
        'username', p.username,
        'avatar_url', p.avatar_url,
        'phone', p.phone,
        'bio', p.bio,
        'city', p.city,
        'country', p.country,
        'nationality', p.nationality,
        'date_of_birth', p.date_of_birth,
        'gender', p.gender,
        'document_type', p.document_type,
        'document_number', p.document_number,
        'active_role', p.active_role,
        'user_type', p.user_type,
        'current_organization_id', p.current_organization_id,
        'is_active', p.is_active,
        'is_superadmin', p.is_superadmin,
        'is_platform_admin', p.is_platform_admin,
        'platform_access_unlocked', p.platform_access_unlocked,
        'profile_completed', p.profile_completed,
        'onboarding_completed', p.onboarding_completed,
        'legal_consents_completed', p.legal_consents_completed,
        'age_verified', p.age_verified,
        'created_at', p.created_at,
        'updated_at', p.updated_at,
        -- Social links
        'instagram', p.instagram,
        'facebook', p.facebook,
        'tiktok', p.tiktok,
        'social_instagram', p.social_instagram,
        'social_facebook', p.social_facebook,
        'social_tiktok', p.social_tiktok,
        'social_youtube', p.social_youtube,
        'social_linkedin', p.social_linkedin,
        'social_twitter', p.social_twitter,
        'social_x', p.social_x,
        -- Organization info
        'organization', (
            SELECT json_build_object(
                'id', o.id,
                'name', o.name,
                'slug', o.slug
            )
            FROM organizations o
            WHERE o.id = p.current_organization_id
        ),
        -- Roles in current organization
        'organization_roles', (
            SELECT COALESCE(json_agg(omr.role), '[]'::json)
            FROM organization_member_roles omr
            WHERE omr.user_id = p.id
            AND omr.organization_id = p.current_organization_id
        ),
        -- Specializations
        'specializations', (
            SELECT COALESCE(json_agg(us.specialization), '[]'::json)
            FROM user_specializations us
            WHERE us.user_id = p.id
        )
    ) INTO result
    FROM profiles p
    WHERE p.id = p_user_id;

    RETURN result;
END;
$$;

